def _install_python_stack_dump_handler(log_path=None):
    """Append all-thread Python tracebacks to a log when SIGUSR2 arrives."""
    global _PYTHON_STACK_DUMP_FILE
    if _PYTHON_STACK_DUMP_FILE is not None:
        return True
    sigusr2 = getattr(signal, "SIGUSR2", None)
    if sigusr2 is None:
        return False
    path = Path(log_path) if log_path is not None else PYTHON_STACK_DUMP_LOG
    dump_file = None
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        dump_file = open(path, "a", buffering=1)
        dump_file.write(
            f"\n=== CCC Python stack handler started "
            f"{datetime.now(tz=timezone.utc).isoformat()} pid={os.getpid()} ===\n"
        )
        dump_file.flush()
        faulthandler.register(sigusr2, file=dump_file, all_threads=True, chain=False)
    except (OSError, RuntimeError, ValueError) as exc:
        if dump_file is not None:
            try:
                dump_file.close()
            except OSError:
                pass
        print(f"⚠️  Could not install Python stack diagnostics: {exc}", file=sys.stderr)
        return False
    _PYTHON_STACK_DUMP_FILE = dump_file
    return True


# AskUserQuestion relay: headless `claude -p` auto-declines AskUserQuestion
# (no TUI picker), so for CCC-spawned sessions the PreToolUse hook blocks and
# waits here for the dashboard to drop an answer file. Kept in sync with
# QUESTION_RELAY_DIR in hooks/pre-tool-use.py. CCC marks the sessions it wants
# intercepted by setting QUESTION_RELAY_ENV on the spawned process.
QUESTION_RELAY_DIR = COMMAND_CENTER_STATE_DIR / "questions"
QUESTION_RELAY_ENV = "CCC_QUESTION_RELAY"
# Claude Code kills a hook that runs past its registered timeout. The
# PreToolUse hook blocks here while a relayed AskUserQuestion waits for an
# answer, so it needs a generous ceiling — kept above the hook's own
# CCC_QUESTION_TIMEOUT (default 1740s) so the hook returns its own clean
# message before Claude Code force-kills it.
PRETOOLUSE_HOOK_TIMEOUT = 1800


def _question_relay_env():
    """Child env that opts a spawned session into AskUserQuestion relay."""
    return dict(os.environ, **{QUESTION_RELAY_ENV: "1"})


def _read_question_request(session_id):
    """Return the pending AskUserQuestion relay request for a session, or None.

    The PreToolUse hook writes this {nonce, questions, ...} file while it
    blocks waiting for an answer; the dashboard reads it to render the modal.
    """
    if not session_id:
        return None
    path = QUESTION_RELAY_DIR / f"{session_id}.request.json"
    try:
        with open(path) as f:
            data = json.load(f)
    except (OSError, ValueError):
        return None
    if not isinstance(data, dict) or not data.get("nonce"):
        return None
    return data


def _write_question_answer(session_id, answers):
    """Drop the user's AskUserQuestion picks for the blocking hook to consume.

    `answers` is aligned to the request's questions; each entry is
    {"index": int, "text": str} — a non-negative index selects that option,
    otherwise `text` is used as a free-text answer. The nonce from the live
    request is stamped in so a stale hook never consumes a fresh answer.
    """
    req = _read_question_request(session_id)
    if not req:
        return {"ok": False, "error": "no pending question for this session"}
    if not isinstance(answers, list) or not answers:
        return {"ok": False, "error": "answers must be a non-empty list"}
    # CCC-46: the blocking PreToolUse hook (in the headless `claude -p` process)
    # is the ONLY consumer of the answer file. If that process is gone, writing
    # the answer succeeds silently but nothing ever reads it — the classic
    # "I answered and nothing happened" symptom. Verify the hook's pid is alive
    # before pretending the answer was delivered.
    hook_pid = req.get("pid")
    if hook_pid and not _pid_alive(hook_pid):
        # Stale request from a dead process — clear it so the waiting indicator
        # doesn't keep prompting for an answer that can never land.
        try:
            (QUESTION_RELAY_DIR / f"{session_id}.request.json").unlink()
        except OSError:
            pass
        try:
            marker = SIDECAR_STATE_DIR / f"{session_id}_in_flight.json"
            if marker.exists():
                marker.unlink()
        except (OSError, ValueError):
            pass
        return {
            "ok": False,
            "dead": True,
            "error": "this session's process is no longer running - "
                     "the answer can't reach it. Resume the session to continue.",
        }
    norm = []
    for a in answers:
        if isinstance(a, dict):
            idx = a.get("index")
            norm.append({
                "index": idx if isinstance(idx, int) else -1,
                "text": str(a.get("text") or ""),
            })
        else:
            norm.append({"index": -1, "text": str(a or "")})
    try:
        QUESTION_RELAY_DIR.mkdir(parents=True, exist_ok=True)
        path = QUESTION_RELAY_DIR / f"{session_id}.answer.json"
        tmp = str(path) + ".tmp"
        with open(tmp, "w") as f:
            json.dump({"nonce": req["nonce"], "answers": norm, "ts": time.time()}, f)
        os.replace(tmp, path)
    except OSError as e:
        return {"ok": False, "error": f"could not write answer: {e}"}
    # The user just answered — proactively drop the AskUserQuestion in-flight
    # marker so the "Question waiting for answer" indicator clears on the very
    # next status poll, instead of lingering (with stale preamble text) until
    # the tool_result round-trips back into the transcript. That lag is the
    # "question synchronization isn't working" symptom: the prompt is already
    # answered but the live indicator keeps showing it as waiting.
    try:
        marker = SIDECAR_STATE_DIR / f"{session_id}_in_flight.json"
        if marker.exists():
            data = json.loads(marker.read_text())
            if isinstance(data, dict) and data.get("tool") == "AskUserQuestion":
                marker.unlink()
    except (OSError, ValueError):
        pass
    return {"ok": True, "questions": len(req.get("questions") or [])}
