_WT_HOME = Path(os.environ.get("WATCHTOWER_HOME") or (Path.home() / ".watchtower"))

# Matches the "{ts} UTC  {queue:<14}  {verb:<9}{detail}" format written by
# watchtower.queue._log(); group(1) is the queue column (or "reconciler").
_WT_LOG_LINE_QUEUE_RE = re.compile(r"^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2} UTC\s+(\S+)")


def _wt_log_line_queue(line):
    m = _WT_LOG_LINE_QUEUE_RE.match(line)
    return m.group(1).upper() if m else ""


def _wt_config_path():
    return Path(os.environ.get("WATCHTOWER_CONFIG_FILE")
                or (_WT_HOME / "queue-config.json"))


def _wt_workers_path():
    return Path(os.environ.get("WATCHTOWER_WORKERS_FILE")
                or (_WT_HOME / "workers.json"))


def _wt_read_config():
    """{queue: {auto_drain, repo_path, ...}} read straight from queue-config.json.
    Empty dict if the file is absent/unreadable. No watchtower import needed."""
    try:
        with open(_wt_config_path()) as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except (OSError, ValueError):
        return {}


_QUEUE_CONFIG_NAME_RE = re.compile(r"^[A-Z0-9][A-Z0-9_-]{0,63}$")
_QUEUE_CONFIG_DEFAULTS = {
    "auto_drain": False,
    "desired_workers": 1,
    "backend": "file",
    "engine": "claude",
    "claim_types": [],
}
_QUEUE_CONFIG_EFFORTS = {"", "low", "medium", "high", "xhigh", "max"}


def _queue_config_from_payload(payload):
    """Validate and normalize the complete WatchTower queue form payload.

    CCC owns a small, dependency-free mirror of ``wt config`` so the dashboard
    remains useful when the WatchTower Python package is not importable by the
    server. Keeping defaults here makes a newly-created queue explicit and
    editable instead of relying on undocumented CLI defaults.
    """
    if not isinstance(payload, dict):
        raise ValueError("expected JSON object")
    queue = str(payload.get("queue") or "").strip().upper()
    if not _QUEUE_CONFIG_NAME_RE.fullmatch(queue):
        raise ValueError("queue must use 1-64 letters, numbers, _ or -")
    backend = str(payload.get("backend") or "file").strip().lower()
    if backend not in ("file", "github"):
        raise ValueError("backend must be file or github")
    engine = str(payload.get("engine", "claude") or "").strip().lower()
    if engine not in ("", "claude", "codex"):
        raise ValueError("engine must be claude, codex, or blank for CCC spawn default")
    try:
        workers = int(payload.get("workers", 1))
    except (TypeError, ValueError):
        raise ValueError("workers must be a whole number")
    if not 1 <= workers <= 16:
        raise ValueError("workers must be between 1 and 16")
    raw_types = payload.get("claim_types") or []
    if not isinstance(raw_types, list):
        raise ValueError("claim_types must be a list")
    claim_types = [t for t in ("bug", "feature") if t in raw_types]
    config = dict(_QUEUE_CONFIG_DEFAULTS)
    config.update({
        "auto_drain": bool(payload.get("auto_drain", False)),
        "desired_workers": workers,
        "backend": backend,
        "claim_types": claim_types,
    })
    if engine:
        config["engine"] = engine
    else:
        config.pop("engine", None)
    effort = str(payload.get("effort") or "").strip().lower()
    if effort not in _QUEUE_CONFIG_EFFORTS:
        raise ValueError("effort must be low, medium, high, xhigh, max, or blank")
    if effort:
        config["effort"] = effort
    for source, target in (("repo_path", "repo_path"), ("model", "model"),
                           ("github_repo", "github_repo"),
                           ("github_assignee", "github_assignee")):
        value = str(payload.get(source) or "").strip()
        if value:
            if "\n" in value or "\r" in value:
                raise ValueError(f"{source} must be one line")
            config[target] = value
    if backend == "github" and not config.get("github_repo"):
        raise ValueError("GitHub repository is required for the GitHub backend")
    if backend != "github":
        config.pop("github_repo", None)
        config.pop("github_assignee", None)
    return {"queue": queue, "config": config}


def _queue_config_options():
    """Small, local suggestions for the queue-management dialog."""
    cfg = _wt_read_config() or {}
    repo_paths, github_repos = set(), set()
    models_by_engine = {
        engine: {str(option["id"]): str(option["label"])
                 for option in options}
        for engine, options in _ENGINE_CURATED_MODELS.items()
        if engine in ("claude", "codex")
    }
    queues = []
    for name, conf in cfg.items():
        conf = conf if isinstance(conf, dict) else {}
        queues.append({"queue": str(name).upper(), "config": conf})
        if conf.get("repo_path"):
            repo_paths.add(str(conf["repo_path"]))
        if conf.get("github_repo"):
            github_repos.add(str(conf["github_repo"]))
        engine = str(conf.get("engine") or "claude").lower()
        model = str(conf.get("model") or "").strip()
        if model and engine in models_by_engine:
            models_by_engine[engine].setdefault(model, model)
    repo_paths.add(str(Path.cwd()))
    return {
        "ok": True,
        "defaults": dict(_QUEUE_CONFIG_DEFAULTS),
        "queues": sorted(queues, key=lambda row: row["queue"]),
        "repo_paths": sorted(repo_paths),
        "github_repos": sorted(github_repos),
        "models_by_engine": {
            engine: [model for model in choices]
            for engine, choices in models_by_engine.items()
        },
    }


def _wt_queue_deletions_path():
    return _WT_HOME / "queue-deletions.json"


def _wt_read_queue_deletions():
    """{QUEUE_NAME: deleted_at_epoch} tombstones written by /api/queue/delete.

    A deleted queue must not resurrect in the health strip just because it
    still has old closed-ticket history (CCC-425 reopen) — it only reappears
    once it gets NEW activity (a ticket filed after the deletion)."""
    try:
        with open(_wt_queue_deletions_path()) as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except (OSError, ValueError):
        return {}


def _wt_read_workers():
    """Live WatchTower worker records read straight from workers.json.

    Each row is annotated with ``alive`` (os.kill liveness) and carries the
    fields WatchTower persists, notably ``queue`` and ``session_id`` (the cloud
    UUID, backfilled by WT) so the dashboard can link a worker to its session.
    Only live workers are returned. No watchtower import needed."""
    try:
        with open(_wt_workers_path()) as f:
            data = json.load(f)
        rows = data.get("workers", []) if isinstance(data, dict) else []
    except (OSError, ValueError):
        return []
    out = []
    for w in rows:
        if not isinstance(w, dict):
            continue
        pid = int(w.get("pid", 0) or 0)
        alive = False
        if pid:
            try:
                os.kill(pid, 0)
                alive = True
            except ProcessLookupError:
                alive = False
            except PermissionError:
                alive = True
            except OSError:
                alive = False
        if not alive:
            continue
        row = dict(w)
        row["alive"] = True
        # Self-heal: if WT hasn't backfilled this worker's cloud session_id into
        # the file yet, resolve it from the worker's stream-json log in-memory
        # (no file write -> no race with WT's own writer) so the dashboard can
        # link the worker to its conversation immediately.
        if not row.get("session_id") and row.get("log"):
            try:
                sid = extract_session_id(row["log"])
                if sid:
                    row["session_id"] = sid
            except Exception:
                pass
        out.append(row)
    return out


def _wt_live_worker_guard():
    """(pids, session_ids) of live WT-tracked workers, from workers.json.

    WatchTower owns its workers' lifecycle — release/reap decisions live in
    watchtower.workers, not here. CCC's reapers (idle sweep, System Health)
    must treat these as off-limits rather than applying CCC's own idle
    heuristics to them."""
    pids, sids = set(), set()
    for w in _wt_read_workers():
        try:
            pid = int(w.get("pid", 0) or 0)
        except (TypeError, ValueError):
            pid = 0
        if pid:
            pids.add(pid)
        sid = w.get("session_id")
        if sid:
            sids.add(str(sid))
    return pids, sids


def _wt_worker_sessions_path():
    return Path(os.environ.get("WATCHTOWER_WORKER_SESSIONS_FILE")
                or (_WT_HOME / "worker-sessions.json"))


def _wt_read_worker_session_ids():
    """Persistent set of every cloud session_id that was EVER a WT worker.

    Read straight from worker-sessions.json (WatchTower's append-only ledger that
    survives worker pruning). CCC uses this to hide past/present worker sessions
    from the Current-sessions list -- a reaped worker leaves a dead session
    behind. Returns a list of session_ids; empty list if absent/unreadable. No
    watchtower import needed."""
    try:
        with open(_wt_worker_sessions_path()) as f:
            data = json.load(f)
    except (OSError, ValueError):
        return []
    if not isinstance(data, dict):
        return []
    ids = data.get("session_ids")
    if not isinstance(ids, list):
        return []
    return [str(s) for s in ids if isinstance(s, str)]


def _wt_clip_title(text, limit=60):
    text = " ".join(str(text or "").split()).strip()
    if limit and len(text) > limit:
        return text[:limit].rstrip() + "..."
    return text


def _wt_ticket_context(item, limit=60):
    res = item.get("resolution") if isinstance(item, dict) else {}
    summary = ""
    if isinstance(res, str):
        summary = res
    elif isinstance(res, dict):
        summary = str(res.get("summary") or "")
    for value in (summary, item.get("title"), item.get("note"), item.get("text")):
        text = _wt_clip_title(value, limit=limit)
        if text:
            return text
    return ""


def _wt_compact_ref(queue, ref):
    """Mirror WT's own workers._compact_ref so CCC and WT agree on the
    ticket-reference shape (e.g. "THROUGHPUT-25" -> "THROUGHPUT#25")."""
    prefix = str(queue or "WT").strip() or "WT"
    raw = str(ref or "").strip()
    if raw:
        head, sep, tail = raw.rpartition("-")
        if sep and tail.isdigit():
            return f"{head or prefix}#{tail}"
        return raw.replace("-", "#", 1)
    return prefix


def _wt_display_name(queue, ref, context=""):
    queue = str(queue or "WT").strip() or "WT"
    ref = str(ref or "").strip()
    context = _wt_clip_title(context)
    if not ref:
        return f"{queue} worker"
    # 🧵 flags a row as a WT worker actively holding (or having held) a
    # ticket, distinct from the plain "<queue> worker" never-claimed state.
    label = "🧵 " + _wt_compact_ref(queue, ref)
    if context:
        return f"{label}: {context}"
    return label


def _wt_row_name_is_generic(row, queue):
    raw = str((row or {}).get("display_name") or "").strip()
    if not raw:
        return True
    q = str(queue or "").strip()
    # Strip the 🧵 badge prefix (and any stray whitespace around it) before
    # matching, so a previously-badged row is still recognized as WT-owned.
    low = raw.lower().lstrip("🧵").strip()
    qlow = q.lower()
    if qlow and low == f"{qlow} queue worker":
        return True
    if qlow and low.startswith(f"drain the {qlow} watchtower queue"):
        return True
    # A name this function itself applied on an earlier serve (e.g. from a
    # ticket this session has since moved past, or the older "<queue> worker:
    # <ref>" shape from before the #<seq> format) is safe to refresh too —
    # otherwise the badge freezes on the first ticket a long-lived worker
    # session ever closed, since _archive_all_rows_cached only re-runs this
    # at cold rebuild, not on every cache-hit serve.
    if qlow and (low == f"{qlow} worker" or low.startswith(f"{qlow} worker:")):
        return True
    if qlow and low.startswith(f"{qlow}#"):
        return True
    return False


def _wt_item_ts(item):
    for key in ("claimed_at", "closed_at", "updated_at", "created_at"):
        try:
            ts = datetime.fromisoformat(str(item.get(key) or "").replace("Z", "+00:00"))
            return ts.timestamp()
        except (ValueError, TypeError):
            continue
    return 0


def _apply_watchtower_worker_display_names(rows):
    """Layer WT ticket names onto live WT worker session rows.

    Claude workers usually carry this through transcript custom-title events.
    Non-Claude engines, especially Codex exec, do not expose that same title
    primitive, and old pre-fix Claude workers may still overwrite themselves
    with a generic spawn name. This display-only overlay keeps CCC's row title
    tied to the WT ticket while preserving user-renamed sessions.
    """
    if not rows:
        return rows
    try:
        workers = _wt_read_workers()
    except Exception:
        workers = []
    sid_to_worker = {}
    worker_ids = {}
    for w in workers or []:
        sid = str(w.get("session_id") or "").strip()
        wid = str(w.get("worker_id") or "").strip()
        if sid:
            sid_to_worker[sid] = w
        if wid and sid:
            worker_ids[wid] = sid
    try:
        items = _q.list_items() or []
    except Exception:
        items = []
    titles_by_sid = {}
    for it in items:
        if not isinstance(it, dict):
            continue
        status = str(it.get("status") or "")
        if status not in ("in_progress", "closed"):
            continue
        sid = str(it.get("claimed_session_id") or "").strip()
        if not sid:
            sid = worker_ids.get(str(it.get("claimed_by") or "").strip(), "")
        if not sid:
            continue
        rank = 1 if status == "in_progress" else 0
        score = (rank, _wt_item_ts(it))
        prev = titles_by_sid.get(sid)
        if prev and prev[0] >= score:
            continue
        # Clipped context feeds the bold display_name (sidebar/breadcrumb rely
        # on CSS ellipsis, but the *source string* was still hard-cut with a
        # baked-in "..." that threw away the rest forever). Keep the full,
        # unclipped context alongside it so a roomier surface (the status
        # rail head) can show the remainder instead of losing it (CCC-505).
        full_context = _wt_ticket_context(it, limit=0)
        clipped_context = _wt_clip_title(full_context, limit=60)
        rest_context = ""
        if clipped_context.endswith("...") and full_context.startswith(clipped_context[:-3]):
            rest_context = full_context[len(clipped_context) - 3:].strip()
        titles_by_sid[sid] = (
            score,
            str(it.get("project") or ""),
            _wt_display_name(it.get("project"), it.get("ref"), clipped_context),
            rest_context,
        )
    if not titles_by_sid and not sid_to_worker:
        return rows
    for row in rows:
        if not isinstance(row, dict) or row.get("name_overridden"):
            continue
        sid = str(row.get("session_id") or row.get("id") or "").strip()
        titled = titles_by_sid.get(sid)
        worker = sid_to_worker.get(sid)
        if not titled and not worker:
            continue
        queue = (worker or {}).get("queue") or (titled[1] if titled else "")
        if not _wt_row_name_is_generic(row, queue):
            continue
        if titled:
            row["display_name"] = titled[2]
            if titled[3]:
                row["wt_ticket_context_rest"] = titled[3]
        else:
            # Live WT worker that hasn't claimed a ticket yet (still
            # bootstrapping, or between tickets) — without this a fresh
            # spawn shows whatever generic fallback the row's ai_title/
            # first_message logic produces (WT-104) instead of a name
            # that actually says what it is.
            row["display_name"] = _wt_display_name(queue, None)
    return rows


_HEX_SFX_RE = re.compile(r'^(.+)-([0-9a-f]{8})$')


def _wt_past_workers(hours=24, max_per_queue=3):
    """Past (exited) WT workers whose log was modified within the last N hours.

    Scans ~/.watchtower/logs/*.log, skips currently-live workers (still in
    workers.json), extracts worker_id + queue from the filename
    ({queue}-{hex_suffix}.log) and mtime as ended_at. Returns a list of dicts:
    {worker_id, queue, ended_at_iso, ended_ago_seconds}. Light-weight — no
    subprocess, no per-file full-read. Empty list on any error.

    ``max_per_queue`` caps how many recent dead workers are returned PER queue
    (most-recent first) so a churn episode — e.g. a misconfigured queue that
    spawned 30+ short-lived workers — doesn't flood the Triggered Workers list
    with historical noise. 0/None means no cap."""
    try:
        logs_dir = _WT_HOME / "logs"
        if not logs_dir.is_dir():
            return []
        now = time.time()
        cutoff = now - hours * 3600
        live_ids = set()
        try:
            live = _wt_read_workers()
            live_ids = {str(w.get("worker_id", "")) for w in live if w.get("worker_id")}
        except Exception:
            live_ids = set()
        out = []
        per_queue = {}  # queue → count emitted (for max_per_queue cap)
        for p in sorted(logs_dir.iterdir(), key=lambda x: -x.stat().st_mtime if not x.name.endswith('.stdin') else 0):
            if p.suffix != '.log' or p.name.endswith('.stdin.log'):
                continue
            worker_id = p.stem
            if worker_id in live_ids:
                continue
            try:
                st = p.stat()
            except OSError:
                continue
            if st.st_mtime < cutoff:
                continue
            m = _HEX_SFX_RE.match(worker_id)
            queue = m.group(1).upper() if m else worker_id.upper()
            # Cap per queue (logs are walked most-recent-first, so we keep the
            # freshest N and drop older churn for the same queue).
            if max_per_queue:
                if per_queue.get(queue, 0) >= max_per_queue:
                    continue
                per_queue[queue] = per_queue.get(queue, 0) + 1
            ended_ago = int(now - st.st_mtime)
            ended_iso = datetime.fromtimestamp(st.st_mtime, timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')
            # Extract session_id from first matching line in log so chips can be clickable.
            session_id = ""
            try:
                with open(p, "r", errors="replace") as lf:
                    for raw in lf:
                        try:
                            obj = json.loads(raw)
                            sid = obj.get("session_id", "")
                            if sid:
                                session_id = str(sid)
                                break
                        except (ValueError, AttributeError):
                            continue
            except OSError:
                pass
            out.append({
                "worker_id": worker_id,
                "queue": queue,
                "ended_at_iso": ended_iso,
                "ended_ago_seconds": ended_ago,
                "session_id": session_id,
            })
        return out
    except Exception:
        return []


_queue_answer = _q.answer


def _uxq_item_timeline(item):
    """Return ticket activity even when CCC uses its stdlib-only queue fallback.

    WatchTower provides a normalized ``timeline`` helper when it is importable.
    The fallback queue reads the same durable items, including their canonical
    history, so retain those events instead of sending the detail modal an
    empty Activity section.
    """
    timeline_fn = getattr(_q, "timeline", None)
    if callable(timeline_fn):
        try:
            timeline = timeline_fn(item)
            if isinstance(timeline, list):
                return timeline
        except Exception:
            pass

    history = item.get("history") if isinstance(item, dict) else None
    if not isinstance(history, list):
        return []
    return [dict(event) for event in history
            if isinstance(event, dict) and str(event.get("event") or "").strip()]


def _uxq_item_payload(item):
    if not item:
        return item
    out = dict(item)
    out["timeline"] = _uxq_item_timeline(item)
    return out


import objects_store  # durable server-side Flow object/parent/order state (GOAL-3/4)
PROJECTS_ROOT = Path.home() / ".claude" / "projects"
# User-picked repos that live outside the $HOME scan (e.g. ~/dev/foo, /workspaces/bar).
# One absolute path per line. Written by /api/repo/add, read by load_known_repos.
_CUSTOM_REPOS_FILE = COMMAND_CENTER_STATE_DIR / "custom-repos.txt"
# Recently-used repos (most recent first). Written when a concrete repo path is
# used so the dropdown/modal can surface them at the top.
_RECENT_REPOS_FILE = COMMAND_CENTER_STATE_DIR / "recent-repos.txt"
_RECENT_REPOS_CAP = 10
# Idle-session reaper: SIGTERM any `claude` process whose JSONL has had no
# meaningful event (user/assistant/result — admin writes like custom-title
# don't count) in the last N hours. Sweep runs every M seconds while the
# server is alive. Archive-time kill catches sessions you explicitly retire;
# this catches the long tail you abandoned without archiving (and the cron
# agents nobody remembered to stop).
_IDLE_REAPER_AGE_HOURS = 24
_IDLE_REAPER_INTERVAL_S = 1800  # 30 min
# Spawn idle-TTL reaper: CCC-spawned persistent headless Claude workers get
# their stdin from a FIFO opened O_RDWR (see _make_stdin_fifo). The child's
# own fd 0 inherits the RDWR mode, so the kernel counts the child as a writer
# of its OWN stdin — the FIFO's writer count never drops to zero and the
# child never sees EOF, even orphaned after a CCC restart. Finished workers
# therefore idle forever (~80MB RSS + a spin-polling main thread each).
# This TTL retires them: idle (no spawn-log/FIFO/transcript activity) longer
# than the TTL AND not mid-turn -> graceful SIGTERM, registry entry marked
# retired (the transcript survives, so the session stays resumable).
# Tunable via CCC_SPAWN_IDLE_TTL_HOURS; <= 0 disables the sweep.
_SPAWN_IDLE_TTL_HOURS_DEFAULT = 3.0
# Stable scratch cwd for short-lived background `claude -p` calls (title
# summarizers, morning braindump, etc.). Without this, those calls
# could run in whichever directory launched the server and pollute an unrelated
# project conversation store. Pinning cwd here makes those JSONLs easy to avoid
# in repo-specific scans and easy to garbage-collect on demand.
_SCRATCH_DIR = COMMAND_CENTER_STATE_DIR / "scratch"
FLOW_STATE_DIR = COMMAND_CENTER_STATE_DIR / "flow"
FLOW_INDEX_FILE = FLOW_STATE_DIR / "index.json"
_FLOW_INDEX_LOCK = threading.Lock()
_FLOW_FIELD_LABELS = {
    "status": "Status",
    "goal": "Goal",
    "target_date": "Target date",
    "eta": "ETA",
    "owner": "Owner",
    "color_seed": "Color seed",
}
_PASTED_IMAGE_EXTS = (".png", ".jpg", ".jpeg", ".gif", ".webp")
_PASTED_IMAGE_PATH_RE = re.compile(
    r"(?:file://)?(/[^\s<>\"')]+/\.claude/(?:command-center/)?"
    r"pasted-images/paste-[\w.-]+\.(?:png|jpe?g|gif|webp))",
    re.IGNORECASE,
)
_MANAGED_ATTACHMENT_IMAGE_PATH_RE = re.compile(
    r"(?:file://)?(/[^\s<>\"')]+/\.claude/command-center/"
    r"attachments/attachment-[\w.-]+\.(?:png|jpe?g|gif|webp))",
    re.IGNORECASE,
)

# Files-from-conversation: extension whitelist driving both the
# /api/conversations/<id>/files extractor and the /api/reveal-file
# opener's allow-list. Closed set by design — adding `.app` / `.sh` /
# `.command` here would re-introduce the macOS-`open`-as-RCE risk that
# /api/open's path sandbox prevents (see SECURITY.md). Keep this list
# tight; the opener has no path-prefix clamp because this clamp does
# the work.
FILE_CATEGORIES = {
    "images":        {".png", ".jpg", ".jpeg", ".gif", ".webp", ".svg",
                      ".heic", ".bmp", ".tiff"},
    "videos":        {".mp4", ".mov", ".webm", ".avi", ".mkv", ".m4v"},
    "pdfs":          {".pdf"},
    "docs":          {".docx", ".doc", ".odt", ".rtf", ".pages",
                      ".xlsx", ".xls", ".csv", ".ods", ".numbers"},
    "presentations": {".pptx", ".ppt", ".key", ".odp"},
    "markdown":      {".md", ".mdx"},
    "html":          {".html", ".htm"},
}
FILE_EXT_TO_CATEGORY = {
    ext: cat for cat, exts in FILE_CATEGORIES.items() for ext in exts
}


def _categorize_file_target(target):
    """Return the category name for `target` (a path or URL), or None
    if its extension is not in the whitelist. Case-insensitive on the
    extension. URLs lose any query string / fragment before the lookup
    so `foo.pdf?token=…` still classifies as `pdfs`."""
    if not target:
        return None
    s = target
    # Strip URL query / fragment so foo.pdf?x=1 → foo.pdf
    for sep in ("?", "#"):
        if sep in s:
            s = s.split(sep, 1)[0]
    # os.path.splitext handles trailing-dot / no-dot cleanly.
    _, ext = os.path.splitext(s)
    return FILE_EXT_TO_CATEGORY.get(ext.lower())


def _path_is_within(child, parent):
    try:
        child_p = Path(child).expanduser().resolve(strict=False)
        parent_p = Path(parent).expanduser().resolve(strict=False)
    except (OSError, RuntimeError):
        return False
    return child_p == parent_p or parent_p in child_p.parents


def _open_target_path(target):
    """Normalize a transcript path token before resolving it on disk."""
    s = html.unescape(str(target or "").strip())
    for _ in range(2):
        if len(s) >= 2 and (
            (s[0] == "<" and s[-1] == ">")
            or (s[0] == '"' and s[-1] == '"')
            or (s[0] == "'" and s[-1] == "'")
        ):
            s = s[1:-1].strip()
        else:
            break
    if s.startswith("file://"):
        s = s[len("file://"):]
    for sep in ("?", "#"):
        if sep in s:
            s = s.split(sep, 1)[0]
    # Common chat references use file.md:12 or file.md:12:4. Finder cannot
    # jump to a line, so reveal the file itself.
    m = re.match(r"^(.+\.[A-Za-z0-9]{1,12})(?::\d+(?::\d+)?)$", s)
    if m:
        s = m.group(1)
    return s


CCC_MAC_BUNDLE_ID = "com.github.claude-command-center"


def _is_local_ccc_popout_url(url):
    """True when *url* is a localhost CCC conversation pop-out link."""
    raw = str(url or "").strip()
    if not raw:
        return False
    if "ccc_popout=conversation" not in raw and "popout=conversation" not in raw:
        return False
    try:
        parsed = urllib.parse.urlparse(raw)
    except Exception:
        return False
    host = (parsed.hostname or "").lower()
    return host in ("127.0.0.1", "localhost", "0.0.0.0", "")


def _try_open_in_ccc_mac_app(url):
    """Hand a pop-out URL to the native CCC.app (if installed)."""
    try:
        proc = subprocess.run(
            ["open", "-b", CCC_MAC_BUNDLE_ID, url],
            capture_output=True,
            timeout=8,
        )
        return proc.returncode == 0
    except Exception:
        return False


def _resolve_pasted_image_path(target, *, require_file=False):
    """Return resolved path when target is one of CCC's pasted-image files."""
    raw = urllib.parse.unquote(str(target or "").strip())
    if raw.startswith("file://"):
        raw = raw[len("file://"):]
    ext = os.path.splitext(raw)[1].lower()
    if not raw or ext not in _PASTED_IMAGE_EXTS:
        return None
    try:
        resolved = Path(raw).expanduser().resolve(strict=False)
        home = Path.home().resolve()
    except (OSError, RuntimeError):
        return None
    if not _path_is_within(resolved, home):
        return None
    in_legacy_paste_dir = (
        len(resolved.parts) >= 3
        and resolved.parts[-2] == "pasted-images"
        and resolved.parts[-3] == ".claude"
    )
    in_state_paste_dir = _path_is_within(resolved, COMMAND_CENTER_PASTED_IMAGES_DIR)
    if not (in_legacy_paste_dir or in_state_paste_dir):
        return None
    if require_file and not resolved.is_file():
        return None
    return resolved


def _resolve_managed_attachment_path(target, *, require_file=False):
    """Return a resolved path when target is a CCC-managed dropped file."""
    raw = urllib.parse.unquote(str(target or "").strip())
    if raw.startswith("file://"):
        raw = raw[len("file://"):]
    try:
        resolved = Path(raw).expanduser().resolve(strict=False)
    except (OSError, RuntimeError):
        return None
    if not _path_is_within(resolved, COMMAND_CENTER_ATTACHMENTS_DIR):
        return None
    if require_file and not resolved.is_file():
        return None
    return resolved


def _session_referenced_open_path(session_id, resolved_target):
    """True when `resolved_target` is an exact file path referenced by a
    session tool call.

    This intentionally authorizes only the single file the transcript names,
    not its parent directory. The extension allowlist in _resolve_open_target
    still decides whether non-core paths are revealable/launchable.
    """
    if not session_id or not resolved_target:
        return False
    try:
        target = Path(resolved_target).expanduser().resolve(strict=False)
    except (OSError, ValueError, RuntimeError):
        return False
    try:
        file_paths, _cd_targets = _scan_session_tool_paths(session_id, max_events=2000)
    except Exception:
        return False
    for raw in file_paths:
        if not isinstance(raw, str):
            continue
        try:
            normalized = _open_target_path(raw)
            if not normalized:
                continue
            candidate = Path(normalized).expanduser().resolve(strict=False)
        except (OSError, ValueError, RuntimeError):
            continue
        if candidate == target:
            return True
    return False


def _session_artifact_open_path(session_id, resolved_target):
    """True for files under this session's own agent artifact directory.

    Antigravity keeps task/plan artifacts under
    ~/.gemini/antigravity[-cli]/brain/<session_id>/. Those are not repo
    files, but they are displayed by the same session's Files panel and
    should be readable/revealable subject to the existing extension clamps.
    """
    sid = str(session_id or "").strip()
    if not sid or not re.fullmatch(
        r"[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}",
        sid,
        re.IGNORECASE,
    ):
        return False
    try:
        target = Path(resolved_target).expanduser().resolve(strict=False)
    except (OSError, ValueError, RuntimeError):
        return False
    roots = []
    for name in ("ANTIGRAVITY_BRAIN", "ANTIGRAVITY_CLI_BRAIN"):
        root = globals().get(name)
        if root:
            roots.append(Path(root) / sid)
    return any(_path_is_within(target, root) for root in roots)


def _non_repo_file_sandbox(session_id, resolved_target):
    try:
        target = Path(resolved_target).expanduser().resolve(strict=False)
    except (OSError, ValueError, RuntimeError):
        return False
    return (
        _resolve_pasted_image_path(target, require_file=True) is not None
        or _path_is_within(target, Path.home() / ".claude")
        or _path_is_within(target, COMMAND_CENTER_STATE_DIR)
        or _session_artifact_open_path(session_id, target)
        or _session_referenced_open_path(session_id, target)
    )


def _safe_local_file_open_path(resolved_target, *, categories=None):
    """True for existing local files with a Files-panel-safe extension.

    These are files the conversation extractor already surfaces in the UI:
    markdown, images, videos, PDFs, office docs, presentations, and HTML.
    Keep executable/script types out of FILE_CATEGORIES instead of widening
    this helper.
    """
    try:
        target = Path(resolved_target).expanduser().resolve(strict=False)
    except (OSError, ValueError, RuntimeError):
        return False
    if not target.is_file():
        return False
    category = _categorize_file_target(str(target))
    if not category:
        return False
    return not categories or category in set(categories)


def _extract_pasted_image_paths(text):
    """Extract CCC-managed images from prompt text for CLI attachment."""
    out = []
    seen = set()
    for path_re, resolver in (
        (_PASTED_IMAGE_PATH_RE, _resolve_pasted_image_path),
        (_MANAGED_ATTACHMENT_IMAGE_PATH_RE, _resolve_managed_attachment_path),
    ):
        for m in path_re.finditer(str(text or "")):
            resolved = resolver(m.group(1), require_file=True)
            if not resolved:
                continue
            path = str(resolved)
            if path in seen:
                continue
            seen.add(path)
            out.append(path)
    return out


def _resolve_open_target(target, *, session_id=None, cwd=None, repo_path=None):
    """Resolve /api/open targets without widening the macOS-open sandbox.

    Historical behavior allowed only the active repo/log dir. Inline
    transcript links often point at files relative to the session cwd. Those
    cwd-relative files are allowed only as Finder reveals and only for the
    same whitelisted file extensions used by /api/reveal-file. Absolute files
    that a session explicitly touched via Read/Edit/Write are allowed by exact
    path match only, never by parent directory.
    """
    target = _open_target_path(target)
    if not target:
        return {"ok": False, "error": "missing path", "status": 400}

    session_roots = []

    def add_session_root(root):
        if not root:
            return
        try:
            rp = Path(root).expanduser().resolve(strict=False)
        except (OSError, RuntimeError):
            return
        if rp.is_dir() and all(rp != existing for existing in session_roots):
            session_roots.append(rp)

    ctx_payload = {"session_id": session_id, "cwd": cwd, "repo_path": repo_path}
    try:
        ctx = require_repo_context(ctx_payload, allow_session=True)
    except RepoContextError as e:
        # Archive rows can carry a display-only folder slug as repo_path while
        # still carrying a concrete cwd/session id. Don't let that stale/virtual
        # repo value poison a file-open request that can be resolved from cwd.
        if repo_path and (cwd or session_id):
            try:
                ctx = require_repo_context(
                    {"session_id": session_id, "cwd": cwd},
                    allow_session=True,
                )
            except RepoContextError:
                return e.as_payload() | {"status": e.status}
        else:
            return e.as_payload() | {"status": e.status}

    repo_root = Path(ctx["repo_path"]).expanduser().resolve(strict=False)
    log_root = repo_log_dir(ctx["repo_path"]).resolve(strict=False)
    add_session_root(ctx.get("cwd"))
    found_cwd = find_session_cwd(session_id) if session_id else None
    add_session_root(found_cwd)
    # Prefer the server-derived cwd for known sessions. The client-provided cwd
    # covers spawned / external rows that do not have a Claude JSONL lookup.
    if cwd and (not found_cwd or (_path_is_within(found_cwd, cwd) and _path_is_within(cwd, found_cwd))):
        add_session_root(cwd)
    elif cwd and not session_id:
        add_session_root(cwd)

    candidates = []
    # Treat `~/...` as absolute too — Path.expanduser() resolves it against
    # $HOME the same way the shell would. Without this, tilde paths fall to
    # the relative branch and get joined onto session/repo roots, which never
    # exists on disk.
    if os.path.isabs(target) or target.startswith("~/") or target == "~":
        candidates.append(Path(target).expanduser())
        # Inline transcript paths like `/growth-machine/content/landing/index.html`
        # often *look* absolute but are actually project-relative — the user (or
        # an LLM) wrote `/foo/bar` to mean "foo/bar under the project". The real
        # FS-rooted candidate above wins when it exists; otherwise fall through
        # to a relative interpretation against session cwd / repo root so the
        # link opens what the writer meant.
        if not target.startswith("~"):
            relative = target.lstrip("/")
            if relative:
                for root in session_roots:
                    candidates.append(root / relative)
                candidates.append(repo_root / relative)
    else:
        for root in session_roots:
            candidates.append(root / target)
        candidates.append(repo_root / target)

    resolved = None
    # Set when a match comes from the CCC-143 bounded reveal-only search below.
    # Such results are revealed in Finder, never launched/executed.
    bounded_reveal_only = False
    tried = []
    for candidate in candidates:
        tried.append(str(candidate))
        if candidate.exists():
            try:
                resolved = candidate.resolve(strict=False)
            except (OSError, RuntimeError):
                resolved = candidate
            break

    # Bare-name fallback. An inline link like `SYNTHESIS.md` carries only the
    # basename, but the agent may have created/touched it in a directory the
    # session visited — not its launch cwd or the repo root. When every
    # root-joined candidate misses, resolve the bare name against the absolute
    # file paths this session actually referenced via tool calls ("open the
    # file in the directory we were really working in"). Authorization is
    # unchanged: the resolved path still passes the sandbox checks below — a
    # session-referenced file already satisfies _session_referenced_open_path.
    # Bare names match on basename. Multi-segment relative paths (CCC-121:
    # `deliverables/.../shots/x.png` rendered by a session whose cwd is
    # elsewhere) match when a session-referenced absolute path ENDS with the
    # full relative path — the transcript knows where the work really
    # happened even when the session cwd doesn't.
    if not resolved and session_id and target and not target.startswith("~") and not os.path.isabs(target):
        want = os.path.basename(target)
        rel_tail = "/" + target.strip().strip("/")
        try:
            referenced_paths, _cd_targets = _scan_session_tool_paths(session_id, max_events=2000)
        except Exception:
            referenced_paths = []
        # Newest-referenced first, so the file the agent most recently worked
        # with wins when several share a basename.
        for raw in reversed(referenced_paths or []):
            if not isinstance(raw, str):
                continue
            try:
                normalized = _open_target_path(raw)
                if not normalized:
                    continue
                cand = Path(normalized).expanduser()
            except (OSError, ValueError, RuntimeError):
                continue
            if "/" in target:
                if not str(cand).endswith(rel_tail):
                    continue
            elif cand.name != want:
                continue
            tried.append(str(cand))
            if cand.exists():
                try:
                    resolved = cand.resolve(strict=False)
                except (OSError, RuntimeError):
                    resolved = cand
                break
        # Second pass (CCC-121): tool-path scanning loses spaces, so the
        # referenced path can be a truncated cousin of the real one. Join
        # the relative target onto ancestor directories of everywhere the
        # session demonstrably worked (cd targets + referenced-path parents)
        # and take the first that exists. `..` segments are rejected so a
        # crafted link can't climb out of those roots.
        if not resolved and "/" in target and ".." not in target.split("/"):
            roots = []

            def _add_root(d):
                d = str(d or "").rstrip("/")
                if d and d != "/" and d not in roots:
                    roots.append(d)

            for raw in reversed(_cd_targets or []):
                if isinstance(raw, str):
                    _add_root(raw)
            for raw in reversed(referenced_paths or []):
                if not isinstance(raw, str):
                    continue
                parent = os.path.dirname(raw)
                for _ in range(6):
                    if not parent or parent == "/":
                        break
                    _add_root(parent)
                    parent = os.path.dirname(parent)
            rel = target.strip().strip("/")
            for root in roots:
                cand = Path(root).expanduser() / rel
                tried.append(str(cand))
                if cand.exists():
                    try:
                        resolved = cand.resolve(strict=False)
                    except (OSError, RuntimeError):
                        resolved = cand
                    break

            # Third pass (CCC-143, REVEAL-ONLY): the link can be relative to a
            # deeper dir the session cd'd into for one command (e.g. it rendered
            # `renders/x.png` from inside builder-stack-v3/campaign-linkedin-daily
            # while only builder-stack-v3 is a known root), so the missing middle
            # segment makes a direct join miss. Do a BOUNDED, depth-limited walk
            # under each session root for a file whose path ENDS WITH the clicked
            # relative path. SAFETY (see SECURITY.md): only Files-panel-safe
            # extensions match (never scripts/executables, via
            # _safe_local_file_open_path), AND the hit is flagged
            # bounded_reveal_only so the /api/open route reveals it in Finder and
            # NEVER launches/executes it. Strictly capped (depth ≤3 + entry count)
            # so a click can't trigger an unbounded scan.
            if not resolved and "/" in rel:
                rel_suffix = "/" + rel
                base = os.path.basename(rel)
                scanned = 0
                SCAN_CAP = 2500
                _PRUNE = {".git", "node_modules", ".next", "dist", "build", ".venv", "__pycache__", ".cache"}
                for root in roots:
                    if resolved or scanned >= SCAN_CAP:
                        break
                    root_path = Path(root).expanduser()
                    try:
                        root_depth = len(root_path.parts)
                        for dirpath, dirnames, filenames in os.walk(root_path):
                            scanned += 1
                            if scanned >= SCAN_CAP:
                                break
                            if len(Path(dirpath).parts) - root_depth > 3:
                                dirnames[:] = []
                                continue
                            dirnames[:] = [d for d in dirnames if d not in _PRUNE and not d.startswith(".")]
                            if base in filenames:
                                cand = Path(dirpath) / base
                                if str(cand).endswith(rel_suffix) and _safe_local_file_open_path(cand):
                                    tried.append(str(cand))
                                    try:
                                        resolved = cand.resolve(strict=False)
                                    except (OSError, RuntimeError):
                                        resolved = cand
                                    bounded_reveal_only = True
                                    break
                    except OSError:
                        continue

    if not resolved:
        return {"ok": False, "error": "not found", "tried": tried, "status": 404}

    core_sandbox = _path_is_within(resolved, repo_root) or _path_is_within(resolved, log_root)
    session_sandbox = any(_path_is_within(resolved, root) for root in session_roots)
    pasted_image_sandbox = _resolve_pasted_image_path(resolved, require_file=True) is not None
    session_artifact_sandbox = _session_artifact_open_path(session_id, resolved)
    session_file_sandbox = False
    if (
        not core_sandbox
        and not session_sandbox
        and not pasted_image_sandbox
        and not session_artifact_sandbox
    ):
        session_file_sandbox = _session_referenced_open_path(session_id, resolved)
    return {
        "ok": True,
        "path": str(resolved),
        "core_sandbox": core_sandbox,
        "session_sandbox": session_sandbox,
        "pasted_image_sandbox": pasted_image_sandbox,
        "session_file_sandbox": session_file_sandbox,
        "reveal_only": bounded_reveal_only,
        "tried": tried,
    }


def _open_launch_allowed(resolved_target):
    """Whether /api/open may launch, not just reveal, a resolved target."""
    return True


