def _load_custom_repos():
    """Return the list of user-picked repo paths (absolute, deduped, existing dirs)."""
    try:
        raw = _CUSTOM_REPOS_FILE.read_text()
    except OSError:
        return []
    out = []
    seen = set()
    for line in raw.splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        try:
            p = Path(line).expanduser().resolve()
        except (OSError, ValueError):
            continue
        s = str(p)
        if s in seen or not p.is_dir():
            continue
        seen.add(s)
        out.append(s)
    return out


def _load_recent_repos():
    """Return recently-used repo paths, most-recent first (deduped, existing dirs only)."""
    try:
        raw = _RECENT_REPOS_FILE.read_text()
    except OSError:
        return []
    out = []
    seen = set()
    for line in raw.splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        try:
            p = Path(line).expanduser().resolve()
        except (OSError, ValueError):
            continue
        s = str(p)
        if s in seen or not p.is_dir():
            continue
        seen.add(s)
        out.append(s)
        if len(out) >= _RECENT_REPOS_CAP:
            break
    return out


def _spawn_cwd_outside_home_allowed(candidate):
    """A spawn cwd outside $HOME is allowed if it's an existing directory.
    The $HOME clamp is a typo-guard, not a hard security boundary (loopback
    already grants full command access — see SECURITY.md), and the caller has
    already verified the path exists and is a directory before reaching here,
    so a typo'd/nonexistent path can never get this far. Any real external
    volume the user typed/pasted/picked (e.g. /Volumes/Drive/proj) is honored
    and auto-registered as a recent repo so it surfaces in the picker next
    time. `candidate` must be an already-resolved Path."""
    try:
        cand = str(candidate)
    except Exception:
        return False
    try:
        if not Path(candidate).is_dir():
            return False
    except OSError:
        return False
    # Already an existing directory — auto-register so future spawns/pickers
    # see it without a separate "Add repo" step. Best-effort; never blocks.
    try:
        _record_recent_repo(cand)
    except Exception:
        pass
    return True


def _record_recent_repo(path_str):
    """Prepend a switch event to the recent list. Silent on I/O error — the
    recency ordering is a UX nicety, not load-bearing."""
    try:
        p = Path(path_str).expanduser().resolve()
    except (OSError, ValueError):
        return
    if not p.is_dir():
        return
    existing = _load_recent_repos()
    new_list = [str(p)] + [x for x in existing if x != str(p)]
    new_list = new_list[:_RECENT_REPOS_CAP]
    try:
        _RECENT_REPOS_FILE.parent.mkdir(parents=True, exist_ok=True)
        _RECENT_REPOS_FILE.write_text("\n".join(new_list) + "\n")
    except OSError:
        pass


def _append_custom_repo(path_str):
    """Persist a user-picked repo path. Returns the absolute resolved path.
    Raises ValueError if the path isn't an existing directory."""
    p = Path(path_str).expanduser().resolve()
    if not p.is_dir():
        raise ValueError(f"not a directory: {p}")
    existing = set(_load_custom_repos())
    if str(p) in existing:
        return str(p)
    _CUSTOM_REPOS_FILE.parent.mkdir(parents=True, exist_ok=True)
    with _CUSTOM_REPOS_FILE.open("a") as f:
        f.write(str(p) + "\n")
    return str(p)


# Visual-only override of which repo a session appears under in the all-repos
# archive view. {session_id: repo_path}. Does not touch the JSONL transcript —
# the session's recorded cwd is unchanged, only the row's grouping is moved.
# Used when a session was launched in repo A but the work logically belongs
# under repo B and the user wants the row to appear there for scanning.
_REPO_PINS_FILE = Path.home() / ".claude" / "command-center" / "repo-pins.json"
_SESSION_LANE_VALUES = {"coding", "workers", "messages"}


def _load_repo_pins():
    try:
        with open(_REPO_PINS_FILE) as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        return {}
    if not isinstance(data, dict):
        return {}
    return {str(k): str(v) for k, v in data.items() if k and v}


def _save_repo_pins(pins):
    _REPO_PINS_FILE.parent.mkdir(parents=True, exist_ok=True)
    tmp = _REPO_PINS_FILE.with_suffix(".json.tmp")
    with open(tmp, "w") as f:
        json.dump(pins, f, indent=2, sort_keys=True)
    tmp.replace(_REPO_PINS_FILE)


def _normalize_session_lane(lane):
    lane = str(lane or "").strip().lower()
    return lane if lane in _SESSION_LANE_VALUES else ""


def _load_session_lane_overrides():
    """Return {session_id: all-tab lane override}."""
    try:
        with open(SESSION_LANE_OVERRIDES_FILE) as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        return {}
    if not isinstance(data, dict):
        return {}
    out = {}
    for sid, lane in data.items():
        clean = _normalize_session_lane(lane)
        if isinstance(sid, str) and sid and clean:
            out[sid] = clean
    return out


def _save_session_lane_overrides(overrides):
    SESSION_LANE_OVERRIDES_FILE.parent.mkdir(parents=True, exist_ok=True)
    tmp = SESSION_LANE_OVERRIDES_FILE.with_suffix(".json.tmp")
    clean = {}
    for sid, lane in (overrides or {}).items():
        clean_lane = _normalize_session_lane(lane)
        if sid and clean_lane:
            clean[str(sid)] = clean_lane
    with open(tmp, "w") as f:
        json.dump(clean, f, indent=2, sort_keys=True)
    tmp.replace(SESSION_LANE_OVERRIDES_FILE)
    return clean


def _get_session_lane_override(session_id):
    sid = str(session_id or "").strip()
    if not sid:
        return ""
    return _load_session_lane_overrides().get(sid, "")


def _set_session_lane_override(session_id, lane):
    """Persist an All-tab lane override. Empty/invalid lane clears it."""
    sid = str(session_id or "").strip()
    if not sid:
        raise ValueError("missing session_id")
    clean = _normalize_session_lane(lane)
    overrides = _load_session_lane_overrides()
    if clean:
        overrides[sid] = clean
    else:
        overrides.pop(sid, None)
    _save_session_lane_overrides(overrides)
    return clean


def _set_session_lane_overrides(session_ids, lane):
    """Persist an All-tab lane override for every known alias of a row."""
    ids = []
    seen = set()
    for raw in session_ids or []:
        sid = str(raw or "").strip()
        if not sid or sid in seen:
            continue
        seen.add(sid)
        ids.append(sid)
    if not ids:
        raise ValueError("missing session_id")
    clean = _normalize_session_lane(lane)
    overrides = _load_session_lane_overrides()
    for sid in ids:
        if clean:
            overrides[sid] = clean
        else:
            overrides.pop(sid, None)
    _save_session_lane_overrides(overrides)
    return clean, ids


def _apply_session_lane_overrides(rows, overrides=None):
    """Stamp per-session All-tab lane overrides onto any row shape."""
    if overrides is None:
        try:
            overrides = _load_session_lane_overrides()
        except Exception:
            overrides = {}
    for row in rows or []:
        if not isinstance(row, dict):
            continue
        sid = row.get("session_id") or row.get("id")
        if sid:
            row["all_lane_override"] = overrides.get(str(sid), "")
    return rows


def _load_session_overrides():
    """Return {session_id: {model, context_1m, engine, set_at}} or {}."""
    try:
        with open(SESSION_OVERRIDES_FILE) as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        return {}
    return data if isinstance(data, dict) else {}


def _save_session_overrides(overrides):
    SESSION_OVERRIDES_FILE.parent.mkdir(parents=True, exist_ok=True)
    tmp = SESSION_OVERRIDES_FILE.with_suffix(".json.tmp")
    with open(tmp, "w") as f:
        json.dump(overrides, f, indent=2, sort_keys=True)
    tmp.replace(SESSION_OVERRIDES_FILE)


def _get_session_override(session_id):
    if not session_id:
        return None
    entry = _load_session_overrides().get(session_id)
    if not isinstance(entry, dict):
        return None
    return entry


# Codex's `-c model_reasoning_effort=<value>` config override (confirmed via
# `codex --help` / the user's own ~/.codex/config.toml) accepts these values.
CODEX_REASONING_EFFORTS = {"", "low", "medium", "high", "xhigh"}


def _set_session_override(session_id, model, context_1m, engine, reasoning_effort=""):
    overrides = _load_session_overrides()
    engine = str(engine or "claude")
    overrides[session_id] = {
        "model": str(model),
        "context_1m": _model_context_1m_allowed(model, context_1m, engine),
        "engine": engine,
        "reasoning_effort": str(reasoning_effort or ""),
        "set_at": datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ"),
    }
    _save_session_overrides(overrides)


def _clear_session_override(session_id):
    overrides = _load_session_overrides()
    if session_id in overrides:
        del overrides[session_id]
        _save_session_overrides(overrides)


def _short_model_alias(model):
    """Turn `claude-sonnet-4-6` / `claude-sonnet-4-6[1m]` / `sonnet` into the
    alias form `/model` accepts: drop the `claude-` prefix and any `[1m]`
    suffix the caller may have included. Non-Claude model strings pass
    through unchanged (callers shouldn't be invoking this for them, but
    being permissive is cheap)."""
    if not model:
        return ""
    alias = model.strip()
    if alias.lower().startswith("claude-"):
        alias = alias[len("claude-"):]
    # Strip any trailing `[1m]`/`[1M]` — the slash command adds it back when
    # context_1m is true, and we don't want a double suffix.
    for tail in ("[1m]", "[1M]"):
        if alias.endswith(tail):
            alias = alias[: -len(tail)]
    return alias.strip()


def _claude_model_supports_1m(model):
    alias = _short_model_alias(model).lower()
    return alias in ("opus-4-8", "opus-4-7")


def _model_context_1m_allowed(model, context_1m, engine="claude"):
    return bool(context_1m) and str(engine or "claude") == "claude" and _claude_model_supports_1m(model)


def _cli_model_flag(model):
    """Normalize a model string for use as a --model CLI argument.

    The /model slash command accepts short aliases like ``sonnet-4-6``, but the
    ``--model`` CLI flag requires the full prefixed ID ``claude-sonnet-4-6`` for
    versioned 4.x models (the CLI rejects bare ``sonnet-4-6``).  The ``[1m]``
    suffix is TUI-only; 1M context is enabled via ``--betas`` instead.
    """
    if not model:
        return ""
    m = model.strip()
    for tail in ("[1m]", "[1M]"):
        if m.endswith(tail):
            m = m[: -len(tail)].strip()
    if not m:
        return ""
    # Versioned aliases like 'sonnet-4-6', 'opus-4-8', 'haiku-4-5', 'fable-5'
    # need the 'claude-' prefix for --model (the /model slash command accepts
    # the bare alias, but the CLI flag does not for these models).
    if not m.lower().startswith("claude-") and re.match(r"^(sonnet|opus|haiku|fable)-\d", m.lower()):
        m = "claude-" + m
    return m


def _build_slash_model_command(model, context_1m):
    """Compose the `/model <id>[1m]` text injected into a live Claude
    session. Returns an empty string if model is missing — caller should
    treat that as a no-op.

    Use the FULL prefixed model ID (e.g. ``claude-haiku-4-5``), not the bare
    versioned alias. The TUI `/model` command only resolves bare *family*
    names (``haiku``/``sonnet``/``opus``/``fable``) or a full model ID; a
    versioned bare alias like ``haiku-4-5`` is rejected at runtime with
    "Model 'haiku-4-5' not found" and the switch silently no-ops (the bug this
    fixes — it hit every versioned model, just first noticed on Haiku).
    ``_cli_model_flag`` prefixes ``claude-`` for versioned 4.x ids and passes
    families / already-prefixed ids through unchanged. The ``[1m]`` suffix is
    a TUI-only affordance the slash command accepts on a full id
    (``claude-opus-4-8[1m]``)."""
    alias = _cli_model_flag(model)
    if not alias:
        return ""
    if _model_context_1m_allowed(model, context_1m, "claude"):
        return f"/model {alias}[1m]"
    return f"/model {alias}"


