# CCC bundled skills that build fleet workflows on the spawn/inject/ask API.
_SKILLS_CCC_SYNERGY_NOTE = {
    "ccc-orchestration": "The spawn / inject / ask API bible every other pack skill builds on.",
    "superpowers-to-watchtower": "Bridge: turn a superpowers plan into wt tickets, then dispatch a CCC lane per ticket.",
    "fleet-verify": "Spawn a verification lane that drives gstack browse (or puppeteer) and reports a visual verdict.",
    "fleet-lane-dispatch": "Dispatch autonomous worker lanes with mission briefs; verify their reports before trusting them.",
}

_skills_ecosystem_cache = {"sig": None, "data": None}


def _skills_dir_sig(paths):
    """Cheap change signature over a set of dirs: (path, mtime_ns) tuples.
    Only stats the top-level dirs, never walks — enough to know when a pack was
    added/removed/updated so the cached inventory can be reused otherwise."""
    sig = []
    for p in paths:
        try:
            sig.append((str(p), p.stat().st_mtime_ns))
        except OSError:
            sig.append((str(p), 0))
    return tuple(sig)


def _build_skills_ecosystem():
    """Inventory installed skill packs and CCC's own bundled skills, annotated
    with honest fleet-synergy flags. mtime-cached; stdlib-only; no subprocess."""
    skills_root = Path.home() / ".claude" / "skills"
    plugins_cache = Path.home() / ".claude" / "plugins" / "cache"
    bundled_root = CCC_ROOT / "skills"
    sig = _skills_dir_sig([skills_root, plugins_cache, bundled_root])
    if _skills_ecosystem_cache["sig"] == sig and _skills_ecosystem_cache["data"] is not None:
        return _skills_ecosystem_cache["data"]

    # 1) CCC's own bundled skills (source of truth = repo skills/*.md), with an
    #    "installed" flag (present under ~/.claude/skills/<name>/SKILL.md).
    ccc_bundled = []
    try:
        bundled = sorted(bundled_root.glob("*.md"), key=lambda p: p.name.lower())
    except OSError:
        bundled = []
    for src in bundled:
        name = src.stem
        if name.lower() == "readme":
            continue
        installed = (skills_root / name / "SKILL.md").is_file()
        ccc_bundled.append({
            "name": name,
            "installed": installed,
            "description": _markdown_summary(src, ""),
            "fleet_note": _SKILLS_CCC_SYNERGY_NOTE.get(name, ""),
        })

    # 2) Installed skill dirs under ~/.claude/skills (includes symlinked packs
    #    like browse/watchtower and the recall family).
    installed_names = set()
    try:
        for child in skills_root.iterdir():
            if child.name.startswith("."):
                continue
            if (child / "SKILL.md").is_file() or (child / "skill.md").is_file():
                installed_names.add(child.name)
    except OSError:
        pass

    # 3) Plugin-cache packs: <publisher>/<plugin>/<version>. Count SKILL.md files
    #    (capped) so the card can show "N skills" without a deep walk cost.
    plugin_packs = {}
    try:
        publishers = sorted(plugins_cache.iterdir(), key=lambda p: p.name.lower())
    except OSError:
        publishers = []
    for publisher in publishers:
        if not publisher.is_dir() or publisher.name.startswith("."):
            continue
        if publisher.name.startswith("temp_git") or publisher.name.startswith("temp"):
            continue  # transient clone leftovers, not real marketplaces
        try:
            plugins = sorted(publisher.iterdir(), key=lambda p: p.name.lower())
        except OSError:
            continue
        for plugin in plugins:
            if not plugin.is_dir() or plugin.name.startswith("."):
                continue
            count = 0
            try:
                for skill_md in plugin.rglob("SKILL.md"):
                    count += 1
                    if count >= 200:  # cap: don't pay an unbounded walk
                        break
            except OSError:
                pass
            # A real pack has skills, a plugin manifest, or a commands dir.
            # Skip bare dirs (docs/tests/etc.) that are not actually packs.
            is_pack = (
                count > 0
                or (plugin / ".claude-plugin").is_dir()
                or (plugin / "commands").is_dir()
                or any(plugin.glob("*/.claude-plugin"))
            )
            if not is_pack:
                continue
            prev = plugin_packs.get(plugin.name, {"skill_count": 0})
            if count >= prev.get("skill_count", 0):
                plugin_packs[plugin.name] = {
                    "publisher": publisher.name,
                    "skill_count": count,
                }

    # Assemble the pack list: union of known packs, installed skill dirs, and
    # plugin-cache packs, de-duplicated by name.
    names = set(_SKILLS_KNOWN_PACKS) | installed_names | set(plugin_packs)
    packs = []
    for name in sorted(names, key=str.lower):
        known = _SKILLS_KNOWN_PACKS.get(name, {})
        plug = plugin_packs.get(name, {})
        present = (name in installed_names) or (name in plugin_packs)
        kind = "plugin" if name in plugin_packs else (
            "skills-dir" if name in installed_names else "known")
        packs.append({
            "name": name,
            "label": known.get("label", name),
            "kind": kind,
            "present": present,
            "publisher": plug.get("publisher"),
            "skill_count": plug.get("skill_count"),
            "spawns_subagents": known.get("spawns_subagents"),
            "fleet_aware": known.get("fleet_aware"),
            "drives_browser": known.get("drives_browser"),
            "ccc_synergy": known.get("ccc_synergy") if present else None,
            "note": known.get("note", ""),
        })

    data = {
        "ok": True,
        "version": __version__,
        "ccc_bundled": ccc_bundled,
        "packs": packs,
        "counts": {
            "ccc_bundled": len(ccc_bundled),
            "ccc_installed": sum(1 for s in ccc_bundled if s["installed"]),
            "packs_present": sum(1 for p in packs if p["present"]),
        },
    }
    _skills_ecosystem_cache["sig"] = sig
    _skills_ecosystem_cache["data"] = data
    return data


def _local_slash_commands_for_session(session_id):
    commands = []
    command_roots = [Path.home() / ".claude" / "commands"]
    skill_roots = [Path.home() / ".claude" / "skills"]
    cwd = find_session_cwd(session_id) if session_id else ""
    if cwd:
        cwd_path = Path(cwd).expanduser()
        candidates = [cwd_path]
        repo_root = _git_toplevel_for_existing_dir(cwd)
        if repo_root:
            candidates.append(Path(repo_root))
        for base in candidates:
            command_roots.append(base / ".claude" / "commands")
            skill_roots.append(base / ".claude" / "skills")
    seen_roots = set()
    for root in command_roots:
        key = str(root)
        if key in seen_roots:
            continue
        seen_roots.add(key)
        commands.extend(_slash_commands_from_command_dir(root))
    seen_roots.clear()
    for root in skill_roots:
        key = str(root)
        if key in seen_roots:
            continue
        seen_roots.add(key)
        commands.extend(_slash_commands_from_skill_dir(root))
    commands.extend(_slash_commands_from_plugin_cache())
    return commands


def extract_session_slash_commands(session_id):
    """Return slash commands for the session's engine.

    The Claude Agent SDK exposes dispatchable slash commands in `system/init`.
    Reading that list from the transcript lets CCC support built-ins and custom
    skills without hardcoding a stale command catalog. If the transcript is
    missing or predates the field, fall back to a small common set.

    Codex exposes its own slash-command layer in the interactive CLI. Codex
    transcripts do not currently advertise a per-session command catalog, so
    CCC returns the documented built-in CLI set.
    """
    engine = _detect_session_engine(session_id)
    if engine == "codex":
        return {
            "ok": True,
            "session_id": session_id,
            "engine": "codex",
            "commands": list(_CODEX_FALLBACK_SLASH_COMMANDS),
            "source": "codex-fallback",
        }
    result = {
        "ok": True,
        "session_id": session_id,
        "engine": "claude",
        "commands": list(_FALLBACK_SLASH_COMMANDS),
        "source": "fallback",
    }
    if not session_id or engine != "claude":
        return {**result, "engine": engine, "commands": []}
    local_commands = _local_slash_commands_for_session(session_id)
    path = _find_session_jsonl(session_id)
    if path is None:
        commands = _merge_slash_commands(local_commands, _FALLBACK_SLASH_COMMANDS)
        result["commands"] = commands
        result["source"] = "filesystem" if local_commands else "fallback"
        return result

    discovered = []
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as fh:
            for line in fh:
                line = line.strip()
                if not line:
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                containers = [ev]
                msg = ev.get("message")
                if isinstance(msg, dict):
                    containers.append(msg)
                data = ev.get("data")
                if isinstance(data, dict):
                    containers.append(data)
                for obj in containers:
                    raw = obj.get("slash_commands") or obj.get("slashCommands")
                    if isinstance(raw, list):
                        discovered.extend(raw)
    except OSError:
        return result

    commands = _merge_slash_commands(discovered, local_commands, _FALLBACK_SLASH_COMMANDS)
    if commands:
        result["commands"] = commands
        if discovered:
            result["source"] = "transcript"
        elif local_commands:
            result["source"] = "filesystem"
        else:
            result["source"] = "fallback"
    return result


# Per-session engine cache. A session's engine is immutable, but the detection
# fallback is expensive — _is_gemini_session JSON-parses every Gemini chat on
# disk, so for a Claude session (no match) it scans the whole Gemini store.
# This ran per-session on every live-activity poll AND per-participant on every
# group-chat open. Memoise: a non-"claude" result is definitive (an engine
# store exists) and cached forever; "claude" may be premature for a just-spawned
# non-Claude session whose store appears a beat later, so it's cached with a
# short TTL and re-checked.
_ENGINE_DETECT_CACHE = {}            # sid -> (engine, expiry_ts or None)
_ENGINE_DETECT_TTL = 30.0
_engine_detect_lock = threading.Lock()


def _detect_session_engine(session_id):
    """Best-effort: non-Claude engines are detected by their per-engine session
    stores; everything else is treated as `claude`. Memoised — see
    _ENGINE_DETECT_CACHE."""
    if not session_id:
        return "claude"
    now = time.time()
    with _engine_detect_lock:
        hit = _ENGINE_DETECT_CACHE.get(session_id)
        if hit is not None:
            engine, expiry = hit
            if expiry is None or now < expiry:
                return engine
    engine = _detect_session_engine_uncached(session_id)
    with _engine_detect_lock:
        _ENGINE_DETECT_CACHE[session_id] = (
            engine,
            None if engine != "claude" else now + _ENGINE_DETECT_TTL,
        )
    return engine


def _detect_session_engine_uncached(session_id):
    if not session_id:
        return "claude"
    for s in _spawned_sessions:
        if s.get("session_id") == session_id or s.get("resumed_sid") == session_id:
            engine = s.get("engine")
            if engine in ("claude", "codex", "gemini", "cursor", "antigravity", "kilo", "hermes"):
                return engine
    spawned = _spawn_registry_entry_for_session(session_id)
    if spawned and spawned.get("engine") in ("claude", "codex", "gemini", "cursor", "antigravity", "kilo", "hermes"):
        return spawned.get("engine")
    if _is_codex_session(session_id):
        return "codex"
    if _is_cursor_session(session_id):
        return "cursor"
    if _is_antigravity_session(session_id):
        return "antigravity"
    if _is_gemini_session(session_id):
        return "gemini"
    if _is_kilo_session(session_id):
        return "kilo"
    if _is_hermes_session(session_id):
        return "hermes"
    return "claude"


def _native_pick_folder(prompt_text="Pick a repo folder for Command Center"):
    """Open the OS-native folder chooser and return the selected absolute path.

    Returns a dict:
      {"ok": True, "path": "/abs/path"}               — user picked a folder
      {"ok": False, "cancelled": True}                — user clicked Cancel
      {"ok": False, "error": "..."}                   — something else failed

    macOS only today — shells out to osascript. Other platforms return an
    error so the client can show an explanatory message instead of crashing.
    """
    if platform.system() != "Darwin":
        _log_macos_only("folderPicker")
        return {"ok": False, "error": "native folder picker is macOS-only today; type a path instead"}
    # Two -e args: activate brings the chooser to front (otherwise it can
    # appear behind the browser on some setups). `with prompt` sets the title
    # of the dialog so the user knows what they're picking for.
    safe_prompt = prompt_text.replace('"', '\\"')
    activate_script = 'tell application "System Events" to activate'
    pick_script = f'POSIX path of (choose folder with prompt "{safe_prompt}")'
    try:
        r = subprocess.run(
            ["osascript", "-e", activate_script, "-e", pick_script],
            capture_output=True, text=True, timeout=600,
        )
    except subprocess.TimeoutExpired:
        return {"ok": False, "error": "folder picker timed out (10 min)"}
    except OSError as e:
        return {"ok": False, "error": f"osascript not available: {e}"}
    if r.returncode == 0:
        path = (r.stdout or "").strip().rstrip("/")
        if not path:
            return {"ok": False, "error": "no path returned"}
        return {"ok": True, "path": path}
    stderr = (r.stderr or "").strip()
    # osascript exits 1 with "User canceled. (-128)" when Cancel is clicked.
    if "-128" in stderr or "User canceled" in stderr:
        return {"ok": False, "cancelled": True}
    return {"ok": False, "error": stderr or f"osascript exited {r.returncode}"}


def _encode_project_slug(path):
    """Encode an absolute filesystem path the way claude-code does when
    naming subdirs under ~/.claude/projects/.

    Claude Code 2.x replaces every non-alphanumeric character with '-'
    (so '/foo/.claude/BYM+Finie' becomes '-foo--claude-BYM-Finie').
    Older claude-code versions only replaced '/', which is why some
    legacy project dirs still contain '+', '.', etc.

    CCC has to match the current encoder — otherwise sessions spawned
    in repos whose path contains '+', '.', '_', or spaces land in a
    project dir CCC isn't scanning, and they're invisible on the kanban.
    """
    return re.sub(r"[^A-Za-z0-9]", "-", str(path))

def _legacy_project_slug(path):
    """Pre-2.x claude-code only replaced '/' with '-' — leaving '+',
    '.', '_', and spaces intact. We still need to surface conversations
    that historic claude-code versions wrote into those dirs, so the
    scan covers both the modern and legacy slugs for a given repo path.
    """
    return "-" + str(path).lstrip("/").replace("/", "-")

_fs_case_cache: dict = {}
_git_root_cache: dict = {}

def _slug_to_label(slug: str) -> str:
    """Strip the home-directory prefix and common top-level dirs from a raw
    project slug so the display label is just the project name.

    e.g.  '-Users-amirfish-Apps-amirfish-com'  →  'amirfish-com'
          '-Users-amirfish-dev-my-finance-app'  →  'my-finance-app'
          '-Users-amirfish-agent-workshop'       →  'agent-workshop'
    """
    import os as _os
    home_prefix = "-" + _os.path.expanduser("~").lstrip("/").replace("/", "-") + "-"
    if not slug.startswith(home_prefix):
        return slug
    rest = slug[len(home_prefix):]
    for _top in ("Apps-", "dev-", "Dev-", "Work-", "Projects-",
                 "Research-", "Documents-", "Desktop-"):
        if rest.startswith(_top):
            rest = rest[len(_top):]
            break
    return rest or slug

def _find_git_root(folder_path: str) -> "str | None":
    """Walk up from folder_path to find the nearest ancestor that is a git
    repo root (contains a .git file or dir).  Returns the root path string,
    or None if no git repo is found up to the filesystem root.  Cached."""
    if not folder_path:
        return None
    if folder_path in _git_root_cache:
        return _git_root_cache[folder_path]
    p = Path(folder_path)
    candidate = p if p.is_dir() else p.parent
    while True:
        try:
            if (candidate / ".git").exists():
                result = str(candidate)
                _git_root_cache[folder_path] = result
                return result
        except OSError:
            pass
        parent = candidate.parent
        if parent == candidate:
            break
        candidate = parent
    _git_root_cache[folder_path] = None
    return None


def _resolve_dir_case(folder_path: str) -> str:
    """Return the directory's name using the actual filesystem capitalisation.

    On macOS (case-insensitive, case-preserving) a path stored as
    'David-library' and the real directory 'david-library' are the same
    entry.  Python's Path.resolve() does NOT normalise case, so we look up
    the parent's entries and find the first name that matches case-insensitively.
    Results are cached per parent directory so bulk session scans stay fast.
    """
    try:
        p = Path(folder_path)
        parent_str = str(p.parent)
        if parent_str not in _fs_case_cache:
            try:
                _fs_case_cache[parent_str] = {
                    e.name.lower(): e.name for e in p.parent.iterdir()
                }
            except OSError:
                _fs_case_cache[parent_str] = {}
        return _fs_case_cache[parent_str].get(p.name.lower(), p.name)
    except Exception:
        return Path(folder_path).name


def _candidate_conversation_dirs(path):
    """Every ~/.claude/projects/<slug>/ that could hold conversations for
    `path`. Both encoders are tried; only existing dirs are returned.
    Modern slug first so it wins on shared keys (newer is fresher).
    Also includes sibling worktree slugs (<slug>-wt-*) so sessions run
    in a worktree appear under their parent repo."""
    seen = set()
    candidates = []
    root = Path.home() / ".claude" / "projects"
    for slug in (_encode_project_slug(path), _legacy_project_slug(path)):
        if slug in seen:
            continue
        seen.add(slug)
        d = root / slug
        if d.is_dir():
            candidates.append(d)
        # Include sibling worktree project dirs (<slug>-wt-*)
        for wt_dir in sorted(root.glob(f"{slug}-wt-*")):
            if wt_dir.is_dir() and str(wt_dir) not in seen:
                seen.add(str(wt_dir))
                candidates.append(wt_dir)
    return candidates

class RepoContextError(ValueError):
    """Structured error for repo-explicit API validation."""

    def __init__(self, code, message, *, status=400, path=None):
        super().__init__(message)
        self.code = code
        self.status = status
        self.path = path

    def as_payload(self):
        out = {"ok": False, "error": self.code, "code": self.code, "message": str(self)}
        if self.path:
            out["path"] = self.path
        return out


def _repo_error_payload(code, message, *, path=None):
    out = {"ok": False, "error": code, "code": code, "message": message}
    if path:
        out["path"] = path
    return out


def repo_log_dir(repo_path):
    return Path(repo_path).expanduser().resolve() / ".claude" / "logs"


def repo_conversation_dirs(repo_path):
    return _candidate_conversation_dirs(Path(repo_path).expanduser().resolve())


def _conversation_dirs(repo_path=None):
    """Compatibility wrapper for repo-specific transcript folders.

    Callers that need all sessions should walk PROJECTS_ROOT instead of relying
    on a hidden process repo.
    """
    if not repo_path:
        return []
    return repo_conversation_dirs(repo_path)


def _canonical_conversation_path(repo_path, conversation_id):
    name = conversation_id + ".jsonl"
    slug = _encode_project_slug(Path(repo_path).expanduser().resolve())
    return PROJECTS_ROOT / slug / name


def _find_session_jsonl_any_project(session_id):
    sid = str(session_id or "").strip()
    if not sid or not PROJECTS_ROOT.is_dir():
        return None
    name = sid + ".jsonl"
    try:
        project_dirs = list(PROJECTS_ROOT.iterdir())
    except OSError:
        return None
    for project_dir in project_dirs:
        try:
            cand = project_dir / name
            if cand.is_file():
                return cand
        except OSError:
            continue
    return None


def _ensure_session_jsonl_for_cwd(session_id, cwd):
    """Move a Claude JSONL into the project bucket used by `cwd`.

    `claude --resume` looks up sessions from the process cwd's project slug.
    Sessions accidentally launched from "/" can be displayed under an inferred
    repo, but resume still fails until the JSONL is rebucketed.
    """
    sid = str(session_id or "").strip()
    if not sid:
        return {"ok": False, "error": "missing_session_id"}
    try:
        dest = _canonical_conversation_path(cwd, sid)
    except (OSError, ValueError, RuntimeError) as exc:
        return {"ok": False, "error": "invalid_cwd", "message": str(exc)}
    try:
        if dest.is_file():
            return {"ok": True, "moved": False, "path": str(dest)}
    except OSError:
        return {"ok": False, "error": "stat_failed", "path": str(dest)}
    src = _find_session_jsonl_any_project(sid)
    if not src:
        return {"ok": False, "error": "session_jsonl_not_found"}
    try:
        if dest.exists():
            return {"ok": False, "error": "destination_exists", "path": str(dest)}
        dest.parent.mkdir(parents=True, exist_ok=True)
        os.rename(src, dest)
    except OSError as exc:
        return {"ok": False, "error": "rename_failed", "message": str(exc)}
    return {"ok": True, "moved": True, "from": str(src), "to": str(dest)}


def _discover_repo_paths_from_projects():
    """Best-effort repo paths inferred from Claude project-folder slugs."""
    out = []
    decoder = globals().get("_decode_project_slug")
    if not decoder or not PROJECTS_ROOT.is_dir():
        return out
    try:
        for project_dir in PROJECTS_ROOT.iterdir():
            if not project_dir.is_dir():
                continue
            try:
                decoded = decoder(project_dir.name)
            except Exception:
                decoded = None
            if decoded and decoded.is_dir():
                out.append(str(decoded.resolve()))
    except OSError:
        pass
    return out


def _known_repo_paths():
    paths = []
    try:
        for r in load_known_repos():
            p = r.get("path")
            if p:
                paths.append(str(Path(p).expanduser().resolve()))
    except Exception:
        pass
    try:
        paths.extend(_load_recent_repos())
        paths.extend(_load_custom_repos())
        paths.extend(_discover_repo_paths_from_projects())
    except Exception:
        pass
    seen = set()
    out = []
    for p in paths:
        try:
            s = str(Path(p).expanduser().resolve())
        except (OSError, ValueError, RuntimeError):
            continue
        if s not in seen and Path(s).is_dir():
            seen.add(s)
            out.append(s)
    return out


def _git_toplevel_for_existing_dir(path):
    try:
        p = Path(path).expanduser().resolve()
    except (OSError, ValueError, RuntimeError):
        return None
    if not p.is_dir():
        return None
    try:
        r = subprocess.run(
            ["git", "-C", str(p), "rev-parse", "--show-toplevel"],
            capture_output=True, text=True, timeout=3,
        )
        if r.returncode == 0 and r.stdout.strip():
            return str(Path(r.stdout.strip()).resolve())
    except (subprocess.SubprocessError, OSError):
        pass
    return None


def _has_project_marker(path):
    """Return whether ``path`` is an explicit project root.

    A project-local ``.claude/`` directory is a valid marker, but the global
    ``~/.claude/`` configuration directory is not. Treating that global
    directory as a marker makes every plain folder under the user's home look
    like a child of one giant project, so typed scratch folders never get
    registered as their own CCC workspaces.
    """
    try:
        p = Path(path).expanduser().resolve()
    except (OSError, ValueError, RuntimeError):
        return False
    try:
        if (p / ".git").exists():
            return True
        if not (p / ".claude").is_dir():
            return False
        return p != Path.home().resolve()
    except (OSError, ValueError, RuntimeError):
        return False


def _nearest_marked_repo_dir(path):
    """Return the closest existing ancestor that CCC can treat as a repo root.

    Non-git project folders are supported when they carry a `.claude/`
    marker. This matters for plain asset/project directories where sessions
    are launched from a subfolder rather than the marker-bearing root.
    """
    try:
        p = Path(path).expanduser().resolve()
    except (OSError, ValueError, RuntimeError):
        return None
    if not p.is_dir():
        return None
    for candidate in (p, *p.parents):
        try:
            if _has_project_marker(candidate):
                return str(candidate)
        except OSError:
            continue
    return None


def _plus_space_path_candidates(raw, *, cap=10):
    """Yield variants of `raw` where each space is optionally swapped for `+`.

    Defends against the URL query-string quirk: `+` decodes to a space in a
    query, so a literal `+` in a repo path arrives at the server as a space.
    When the as-given path doesn't resolve, we try `+` in each space slot to
    see if exactly one variant maps to a real/known repo.

    Cap is a safety bound: with N space positions there are 2^N variants. A
    path with more than `cap` spaces falls back to a single "all spaces → +"
    attempt instead of enumerating.
    """
    seen = set()
    if raw not in seen:
        seen.add(raw)
        yield raw
    if " " not in raw:
        return
    space_positions = [i for i, ch in enumerate(raw) if ch == " "]
    n = len(space_positions)
    if n > cap:
        alt = raw.replace(" ", "+")
        if alt not in seen:
            seen.add(alt)
            yield alt
        return
    chars0 = list(raw)
    for mask in range(1, 1 << n):
        chars = list(chars0)
        for i, pos in enumerate(space_positions):
            if mask & (1 << i):
                chars[pos] = "+"
        alt = "".join(chars)
        if alt not in seen:
            seen.add(alt)
            yield alt


def _resolve_repo_path_check(raw, *, known):
    """Return (canon_path, error_code) for a single candidate string.

    error_code is None on success. On failure it is one of "not_dir" or
    "not_allowed" so the outer logic can decide which fallback to attempt.
    """
    try:
        p = Path(raw).expanduser().resolve()
    except (OSError, ValueError, RuntimeError):
        return None, "not_dir"
    if not p.is_dir():
        return None, "not_dir"
    s = str(p)
    looks_like_repo = _has_project_marker(p)
    if s not in known and not looks_like_repo:
        return s, "not_allowed"
    return s, None


def _decode_over_url_encoded_text(value):
    """Repair a free-text value a caller wrongly URL-encoded.

    Some orchestration callers percent-encode the ``prompt`` VALUE inside a JSON
    body (JSON values are not URL-encoded), so a spawned session would receive
    ``fix%20the%20bug`` instead of ``fix the bug``. Decode ONLY when the value is
    unambiguously over-encoded: it carries no raw whitespace of its own but
    contains a percent-escape that decodes to whitespace. A genuine human prompt
    always has spaces, so this never rewrites a real prompt. Idempotent: a
    decoded value (now containing whitespace) passes straight through.
    """
    s = str(value or "")
    if "%" not in s or any(ch.isspace() for ch in s):
        return s
    try:
        decoded = urllib.parse.unquote(s)
    except Exception:
        return s
    if decoded != s and any(ch.isspace() for ch in decoded):
        return decoded
    return s


def resolve_repo_path(value):
    """Validate and canonicalize one concrete repo path.

    The sentinel "ALL" is intentionally rejected here. Aggregate scope belongs
    to aggregate endpoints, not to the repo_path field.

    Pure validator: never mutates server-side state. Bumping recent-repos is
    the API boundary's job (see require_repo_context); doing it here would
    pollute the recent list with cache-invalidation calls and other
    behind-the-scenes path normalizations.
    """
    raw = str(value or "").strip()
    if not raw:
        raise RepoContextError("repo_required", "repo_path is required")
    if raw.upper() == "ALL":
        raise RepoContextError("invalid_repo_path", "repo_path must be one real path, not ALL", path=raw)

    # Allow rule: must be in the known-repos list OR look like a real repo
    # (`.git` or `.claude` directory present). The looks-like-repo escape
    # hatch is intentional ergonomics — it lets first-time spawns into a
    # discovered folder succeed without a separate /api/repo/add round-trip.
    # The trade-off: any reachable directory with `.git` is acceptable, so
    # the gate isn't a strict allow-list. Path traversal is still bounded
    # by `Path.resolve()` above, and shell-out endpoints layer their own
    # sandboxing on top (see /api/open's REPO_ROOT-style clamps).
    known = set(_known_repo_paths())

    canon, err = _resolve_repo_path_check(raw, known=known)
    if err is None:
        return canon

    # Fallback for JSON-body over-encoding. A caller may URL-encode the
    # repo_path VALUE inside a JSON body (wrong: JSON values are not percent-
    # encoded), so /Users/.../BYM+Finie arrives as /Users/.../BYM%2BFinie. If
    # the as-given raw failed but its percent-decoded form resolves to a known
    # repo, accept that. Only fires when raw carries a literal '%' escape, so a
    # legitimate path is never altered.
    if "%" in raw:
        for variant in (urllib.parse.unquote(raw), urllib.parse.unquote_plus(raw)):
            if variant == raw:
                continue
            cand, cand_err = _resolve_repo_path_check(variant, known=known)
            if cand_err is None and cand:
                return cand

    # Fallback for query-string `+` decoding. A repo at /Users/.../BYM+Finie
    # arrives over the wire as /Users/.../BYM Finie because `+` decodes to a
    # space in a URL query. Try restoring `+` in space positions and see if
    # exactly one variant resolves to a real or known repo. Skip the raw
    # since we already tried it.
    if " " in raw:
        matches = []
        for variant in _plus_space_path_candidates(raw):
            if variant == raw:
                continue
            cand, cand_err = _resolve_repo_path_check(variant, known=known)
            if cand_err is None and cand:
                matches.append(cand)
        # Dedup while preserving order.
        matches = list(dict.fromkeys(matches))
        if len(matches) == 1:
            return matches[0]
        if len(matches) > 1:
            raise RepoContextError(
                "ambiguous_repo_path",
                "repo_path matches multiple known repos after `+`/space normalization; encode `+` as %2B",
                path=raw,
            )

    # No variant resolved. Re-raise the original error using the as-given raw.
    if err == "not_dir":
        try:
            p = Path(raw).expanduser().resolve()
            shown = str(p)
        except (OSError, ValueError, RuntimeError) as e:
            raise RepoContextError("invalid_repo_path", f"could not resolve repo_path: {e}", path=raw)
        raise RepoContextError("invalid_repo_path", f"repo_path is not a directory: {shown}", path=shown)
    # err == "not_allowed"
    if canon is None:
        canon = str(Path(raw).expanduser().resolve())
    raise RepoContextError(
        "repo_not_allowed",
        "repo_path is not known; add it through /api/repo/add first",
        path=canon,
        status=403,
    )


def _resolve_cwd_context(value):
    raw = str(value or "").strip()
    if not raw:
        raise RepoContextError("repo_required", "cwd or repo_path is required")
    try:
        cwd = Path(raw).expanduser().resolve()
    except (OSError, ValueError, RuntimeError) as e:
        raise RepoContextError("invalid_cwd", f"could not resolve cwd: {e}", path=raw)
    if not cwd.is_dir():
        raise RepoContextError("invalid_cwd", f"cwd is not a directory: {cwd}", path=str(cwd))
    if cwd.parent == cwd:
        # Filesystem root. Some sessions end up anchored here when whatever
        # spawned `claude` omitted an explicit cwd (Python/subprocess then
        # inherits the parent's cwd — "/" for a launchd daemon). Treating "/"
        # as a repo means every downstream repo_log_dir() write attempts
        # mkdir('/.claude/logs'), which always fails on macOS's read-only
        # system volume (Errno 30) — surfacing as an opaque "Launch Terminal"
        # failure instead of a clear one. Reject up front instead.
        raise RepoContextError(
            "invalid_cwd", "cwd resolved to the filesystem root", path=str(cwd)
        )
    # If `cwd` is inside a git worktree, repo_path = the toplevel (the canonical
    # repo). If `cwd` is in a non-git directory, repo_path falls back to cwd
    # itself — that's the documented edge case where repo_path == cwd. Most
    # usefully: bare scratch folders that the user wants to spawn a session
    # in. The repo_path-must-look-like-a-repo gate in resolve_repo_path()
    # still applies, so a non-git cwd has to live inside a known-repo entry
    # or have a .claude dir to pass validation.
    repo_top = _git_toplevel_for_existing_dir(cwd) or _nearest_marked_repo_dir(cwd) or str(cwd)
    return {"repo_path": resolve_repo_path(repo_top), "cwd": str(cwd)}


def repo_from_session(session_id):
    sid = str(session_id or "").strip()
    if not sid:
        raise RepoContextError("repo_required", "session_id is required to derive repo context")
    cwd = None
    try:
        cwd = find_session_cwd(sid)
    except Exception:
        cwd = None
    if not cwd:
        row_fn = globals().get("_codex_thread_row")
        if row_fn:
            try:
                row = row_fn(sid) or {}
                cwd = row.get("cwd")
            except Exception:
                cwd = None
    if not cwd:
        try:
            spawned = _spawn_registry_entry_for_session(sid) or {}
            cwd = spawned.get("cwd")
        except Exception:
            cwd = None
    if not cwd:
        raise RepoContextError("repo_required", f"could not derive repo context for session {sid}")
    try:
        return _resolve_cwd_context(cwd)
    except RepoContextError as exc:
        if exc.code != "invalid_cwd":
            raise
        try:
            eff = _infer_effective_repo(sid, literal_cwd=cwd)
        except Exception:
            eff = None
        top = eff.get("top") if isinstance(eff, dict) else None
        if top:
            return _resolve_cwd_context(top)
        raise


def require_repo_context(payload=None, query=None, *, allow_session=True):
    """Return {repo_path, cwd} or raise RepoContextError.

    This is the API boundary — every repo-scoped endpoint funnels through
    here. As a side effect, a successful resolution bumps the recent-repos
    list (so the UI's recent dropdown stays in sync with what the user is
    actually doing). resolve_repo_path() itself stays pure so internal
    callers (cache invalidation, deprecated shims) don't pollute recents.
    """
    payload = payload if isinstance(payload, dict) else {}
    query = query if isinstance(query, dict) else {}

    def pick(name):
        val = payload.get(name)
        if val not in (None, ""):
            return val
        qv = query.get(name)
        if isinstance(qv, list):
            qv = qv[0] if qv else None
        return qv

    repo_raw = pick("repo_path") or pick("repo")
    cwd_raw = pick("cwd")
    sid_raw = pick("session_id")
    if repo_raw:
        repo = resolve_repo_path(repo_raw)
        cwd = str(Path(cwd_raw).expanduser().resolve()) if cwd_raw else repo
        if cwd_raw:
            cwd_ctx = _resolve_cwd_context(cwd_raw)
            # The cwd may be a worktree whose git toplevel differs from the
            # explicit repo path. That is valid for spawn/resume style calls;
            # keep both concrete values visible to callers.
            cwd = cwd_ctx["cwd"]
        ctx = {"repo_path": repo, "cwd": cwd}
    elif cwd_raw:
        ctx = _resolve_cwd_context(cwd_raw)
    elif allow_session and sid_raw:
        ctx = repo_from_session(sid_raw)
    else:
        raise RepoContextError("repo_required", "repo_path is required for this endpoint")

    # Recent-repos bookkeeping happens here, at the boundary, not inside
    # resolve_repo_path. Internal validators (cache pop, 410 shim, etc.)
    # therefore don't move the user's recent list around behind their back.
    try:
        _record_recent_repo(ctx["repo_path"])
    except Exception:
        pass
    return ctx


def _nextjs_repo_ctx(payload=None, query=None):
    """Repo context for the localhost dev-server endpoints (status/start/stop/
    restart). Prefer explicit repo_path/cwd under the strict known-repo gate.
    Fall back to resolving the cwd from an open session_id so the localhost
    pill works for ANY engine (Codex/Gemini) or an external-volume session
    whose folder the browser can't assemble client-side — the server already
    knows the session's cwd. Uses repo_from_session directly (not
    allow_session=True) so a 15s status poll doesn't bump recent-repos."""
    try:
        return require_repo_context(payload=payload, query=query, allow_session=False)
    except RepoContextError:
        sid = None
        if isinstance(payload, dict):
            sid = payload.get("session_id")
        if not sid and isinstance(query, dict):
            v = query.get("session_id")
            sid = (v[0] if isinstance(v, list) else v) if v else None
        if not sid:
            raise
        ctx = repo_from_session(str(sid))
        if not ctx or not ctx.get("cwd"):
            raise
        return ctx


def _spawn_repo_context(cwd=None, repo_path=None):
    """Resolve spawn cwd/repo context, registering a typed folder if needed.

    Normal repo-scoped endpoints keep the stricter known-repo gate. Spawning is
    the one place where an existing folder typed into the UI should become a
    usable workspace without a separate "add repo" round trip.
    """
    payload = {"cwd": cwd, "repo_path": repo_path}
    try:
        return require_repo_context(payload, allow_session=False)
    except RepoContextError as e:
        if e.code != "repo_not_allowed":
            raise

    raw = cwd or repo_path
    if not raw:
        raise RepoContextError("repo_required", "cwd or repo_path is required")
    try:
        p = Path(str(raw)).expanduser().resolve()
    except (OSError, ValueError, RuntimeError) as err:
        raise RepoContextError("invalid_cwd", f"could not resolve cwd: {err}", path=str(raw))
    if not p.is_dir():
        raise RepoContextError("invalid_cwd", f"cwd is not a directory: {p}", path=str(p))
    try:
        resolved = _append_custom_repo(str(p))
    except ValueError as err:
        raise RepoContextError("invalid_cwd", str(err), path=str(p))
    _record_recent_repo(resolved)
    return {"repo_path": resolved, "cwd": str(p)}


