def _normalize_orchestration_spawn_engine(value):
    raw = str(value or "").strip().lower()
    if not raw:
        return "claude"
    return _ORCHESTRATION_SPAWN_ENGINE_ALIASES.get(raw)


def _clean_spawn_default_model(value):
    if value is None:
        return ""
    # Model labels can contain spaces/parentheses (Antigravity), but never
    # need embedded newlines. Collapse whitespace before persisting or
    # passing through to CLI args.
    return re.sub(r"\s+", " ", str(value)).strip()


def _codex_context_1m_enabled():
    return os.environ.get("CCC_CODEX_CONTEXT_1M", "1").lower() not in ("0", "false", "no")


def _codex_default_model():
    env_model = _clean_spawn_default_model(os.environ.get("CCC_CODEX_MODEL"))
    if env_model:
        return env_model
    return "gpt-5.5"


def _spawn_fallback_model_for_engine(engine):
    if engine == "claude":
        return os.environ.get("CCC_CLAUDE_MODEL", "claude-fable-5")
    if engine == "codex":
        return _codex_default_model()
    if engine == "gemini":
        return os.environ.get("CCC_GEMINI_MODEL", "auto")
    if engine == "cursor":
        return os.environ.get("CCC_CURSOR_MODEL", "auto")
    if engine == "antigravity":
        return os.environ.get("CCC_ANTIGRAVITY_MODEL") or _antigravity_cli_configured_model()
    if engine == "kilo":
        return os.environ.get("CCC_KILO_MODEL", "kilo/stepfun/step-3.7-flash:free")
    if engine == "hermes":
        return os.environ.get("CCC_HERMES_MODEL", "auto")
    return ""


