# Backward-compatible ID-only view used by older scripts and error payloads.
_ENGINE_KNOWN_MODELS = {
    engine: tuple(str(opt["id"]) for opt in options)
    for engine, options in _ENGINE_CURATED_MODELS.items()
}

_ENGINE_SUPPORTS_CUSTOM_MODELS = {
    "claude": True,
    "codex": False,
    "cursor": True,
    "antigravity": True,
    "kilo": True,
    "hermes": True,
}

_CODEX_PICKER_MODEL_IDS = frozenset(
    str(opt["id"]).strip().lower() for opt in _ENGINE_CURATED_MODELS["codex"]
)

_MODEL_CATALOG_CACHE = {"ts": 0.0, "data": None}
_MODEL_CATALOG_TTL_SEC = 30.0

# Known typo/guess patterns for a model id that doesn't exist -- e.g. an
# agent assuming codex model names always end in "-codex" (they don't; the
# reported case was 'gpt-5.5-codex' when the real id is just 'gpt-5.5').
_CODEX_MODEL_ALIASES = {
    "gpt-5.5-codex": "gpt-5.5",
}


def _model_catalog_key(model):
    return _clean_spawn_default_model(model).lower()


def _model_catalog_known_engines(model):
    """Return curated engines that explicitly own a model id."""
    key = _model_catalog_key(model)
    if not key:
        return set()
    return {
        engine
        for engine, options in _ENGINE_CURATED_MODELS.items()
        if any(_model_catalog_key(option.get("id")) == key for option in options)
    }


def _model_catalog_allows_model(engine, model):
    engine = _normalize_orchestration_spawn_engine(engine)
    if engine == "codex" and _model_catalog_key(model) not in _CODEX_PICKER_MODEL_IDS:
        return False
    known_engines = _model_catalog_known_engines(model)
    # Observed metadata can be stale or have been recorded before CCC learned
    # the session's real engine. Keep custom IDs, but never surface a curated
    # model in an engine picker that does not own that model.
    return not known_engines or engine in known_engines


def _model_catalog_add(catalog, engine, model, *, label=None, source="observed", **attrs):
    engine = _normalize_orchestration_spawn_engine(engine)
    if engine not in _ORCHESTRATION_SPAWN_ENGINES:
        return
    model = _clean_spawn_default_model(model)
    if not model:
        return
    if not _model_catalog_allows_model(engine, model):
        return
    bucket = catalog.setdefault(engine, {
        "default": _spawn_fallback_model_for_engine(engine),
        "supports_custom": _ENGINE_SUPPORTS_CUSTOM_MODELS.get(engine, True),
        "models": [],
        "_index": {},
    })
    key = _model_catalog_key(model)
    index = bucket.setdefault("_index", {})
    entry = index.get(key)
    if entry is None:
        entry = {
            "id": model,
            "label": _clean_spawn_default_model(label) or model,
            "sources": [],
        }
        bucket.setdefault("models", []).append(entry)
        index[key] = entry
    elif label and (not entry.get("label") or entry.get("label") == entry.get("id")):
        entry["label"] = _clean_spawn_default_model(label)
    if source and source not in entry["sources"]:
        entry["sources"].append(source)
    for key, value in attrs.items():
        if value in (None, ""):
            continue
        if key == "oneM":
            entry[key] = bool(value)
        elif key not in entry:
            entry[key] = value


def _codex_home():
    return Path(os.environ.get("CODEX_HOME") or (Path.home() / ".codex"))


def _codex_configured_model():
    path = _codex_home() / "config.toml"
    try:
        raw = path.read_text(encoding="utf-8")
    except OSError:
        return ""
    if tomllib is not None:
        try:
            data = tomllib.loads(raw)
        except tomllib.TOMLDecodeError:
            data = {}
        if isinstance(data, dict):
            return _clean_spawn_default_model(data.get("model"))
    # Python < 3.11 fallback: only read a simple top-level model = "..."
    # assignment. That is enough for Codex's current config shape.
    for line in raw.splitlines():
        m = re.match(r'^\s*model\s*=\s*["\']([^"\']+)["\']\s*(?:#.*)?$', line)
        if m:
            return _clean_spawn_default_model(m.group(1))
    return ""


def _model_records_from_json(value, *, source, skip_hidden=False):
    if isinstance(value, dict):
        rows = value.get("models")
        if rows is None:
            rows = value.get("data")
        if rows is None:
            rows = value.get("available_models")
    else:
        rows = value
    if not isinstance(rows, list):
        return []
    out = []
    for row in rows:
        if isinstance(row, str):
            model = row
            label = row
            extra = {}
        elif isinstance(row, dict):
            if skip_hidden and str(row.get("visibility") or "").lower() == "hide":
                continue
            model = (
                row.get("id") or row.get("slug") or row.get("model")
                or row.get("name") or row.get("value")
            )
            label = (
                row.get("label") or row.get("display_name")
                or row.get("displayName") or row.get("name") or model
            )
            extra = {}
            if row.get("description"):
                extra["description"] = str(row.get("description"))
            if row.get("priority") is not None:
                extra["priority"] = row.get("priority")
            levels = row.get("supported_reasoning_levels")
            if isinstance(levels, list):
                extra["reasoning_efforts"] = [
                    str(x.get("effort") if isinstance(x, dict) else x)
                    for x in levels
                    if (x.get("effort") if isinstance(x, dict) else x)
                ]
            if row.get("default_reasoning_level"):
                extra["default_reasoning_effort"] = str(row.get("default_reasoning_level"))
        else:
            continue
        model = _clean_spawn_default_model(model)
        if model:
            out.append({
                "id": model,
                "label": _clean_spawn_default_model(label) or model,
                "source": source,
                **extra,
            })
    return out


def _codex_models_cache_records():
    path = _codex_home() / "models_cache.json"
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return []
    return _model_records_from_json(data, source="codex-cache", skip_hidden=True)


def _resolve_harness_bin(engine):
    if engine == "codex":
        info = _resolve_codex_bin()
    elif engine == "claude":
        info = _resolve_claude_bin()
    else:
        return None
    if not info.get("available") or not info.get("bin"):
        return None
    return info["bin"]


def _harness_model_list_result(engine):
    """Best-effort future hook for harnesses that add JSON model discovery.

    Codex exposes its raw catalog through `codex debug models`; Claude is still
    only a free-form --model flag today. If either harness adds another
    machine-readable command, CCC starts merging it without a browser-side
    change. Failures are ignored and cached by the outer catalog builder.
    """
    engine = _normalize_orchestration_spawn_engine(engine)
    if engine not in ("codex", "claude"):
        return {"available": False, "records": []}
    bin_path = _resolve_harness_bin(engine)
    if not bin_path:
        return {"available": False, "records": []}
    candidates = []
    if engine == "codex":
        candidates = [
            [bin_path, "debug", "models"],
            [bin_path, "models", "list", "--json"],
            [bin_path, "model", "list", "--json"],
        ]
    elif engine == "claude":
        candidates = [
            [bin_path, "models", "--json"],
            [bin_path, "models", "list", "--json"],
            [bin_path, "model", "list", "--json"],
        ]
    for cmd in candidates:
        try:
            proc = subprocess.run(
                cmd,
                stdin=subprocess.DEVNULL,
                capture_output=True,
                text=True,
                timeout=4,
            )
        except (OSError, subprocess.SubprocessError):
            continue
        if proc.returncode != 0:
            continue
        text = (proc.stdout or "").strip()
        if not text:
            continue
        try:
            data = json.loads(text)
        except json.JSONDecodeError:
            continue
        rows = _model_records_from_json(data, source=f"{engine}-cli", skip_hidden=True)
        if rows:
            return {"available": True, "records": rows, "command": cmd}
    return {"available": False, "records": []}


def _harness_model_list_records(engine):
    result = _harness_model_list_result(engine)
    return result.get("records") or []


def _codex_mark_model_availability(catalog, harness_result):
    if not (harness_result or {}).get("available"):
        return
    rows = harness_result.get("records") or []
    listed = {
        _model_catalog_key(row.get("id"))
        for row in rows
        if isinstance(row, dict) and row.get("id")
    }
    if not listed:
        return
    bucket = catalog.get("codex")
    if not isinstance(bucket, dict):
        return
    bucket["availability_source"] = "codex-cli"
    bucket["availability_command"] = " ".join(harness_result.get("command") or [])
    for entry in bucket.get("models") or []:
        key = _model_catalog_key(entry.get("id"))
        available = key in listed
        entry["available"] = available
        if not available:
            entry["availability_reason"] = "Not available in this Codex CLI. Run `codex update`."
    default_key = _model_catalog_key(bucket.get("default"))
    if default_key and default_key not in listed:
        for entry in bucket.get("models") or []:
            if entry.get("available") is not False and entry.get("id"):
                bucket["default"] = entry["id"]
                bucket["default_unavailable_reason"] = (
                    "Saved Codex default is not available in this CLI."
                )
                break


def _codex_model_availability_error(model):
    model = _clean_spawn_default_model(model)
    if not model:
        return None
    try:
        result = _harness_model_list_result("codex")
    except Exception:
        return None
    if not result.get("available"):
        return None
    target = _model_catalog_key(model)
    listed = {
        _model_catalog_key(row.get("id"))
        for row in result.get("records") or []
        if isinstance(row, dict) and row.get("id")
    }
    if target not in listed:
        return f"{model} is unavailable: Not available in this Codex CLI. Run `codex update`."
    return None


def _observed_model_records():
    rows = []

    def add(engine, model, source):
        model = _clean_spawn_default_model(model)
        if model:
            rows.append({"engine": engine, "id": model, "label": model, "source": source})

    try:
        for entry in _load_session_overrides().values():
            if isinstance(entry, dict):
                add(entry.get("engine") or "claude", entry.get("model"), "session-override")
    except Exception:
        pass
    try:
        for entry in _load_spawn_registry():
            if isinstance(entry, dict):
                add(entry.get("engine") or "claude", entry.get("model"), "spawn-registry")
    except Exception:
        pass
    try:
        for entry in _codex_thread_registry_entries().values():
            if isinstance(entry, dict):
                add("codex", entry.get("model"), "codex-registry")
    except Exception:
        pass
    try:
        for entry in _spawned_sessions:
            if isinstance(entry, dict):
                add(entry.get("engine") or "claude", entry.get("model"), "live-spawn")
    except Exception:
        pass
    try:
        for meta in _conv_meta_cache.values():
            if isinstance(meta, dict):
                add(meta.get("engine") or "claude", meta.get("model"), "transcript-cache")
    except Exception:
        pass
    return rows


def _build_engine_model_catalog(force_refresh=False):
    now = time.monotonic()
    if (
        not force_refresh
        and _MODEL_CATALOG_CACHE["data"] is not None
        and now - _MODEL_CATALOG_CACHE["ts"] < _MODEL_CATALOG_TTL_SEC
    ):
        return copy.deepcopy(_MODEL_CATALOG_CACHE["data"])

    catalog = {}
    for engine in _ORCHESTRATION_SPAWN_ENGINES:
        catalog[engine] = {
            "default": _spawn_fallback_model_for_engine(engine),
            "supports_custom": _ENGINE_SUPPORTS_CUSTOM_MODELS.get(engine, True),
            "models": [],
            "_index": {},
        }
        for opt in _ENGINE_CURATED_MODELS.get(engine, ()):
            attrs = {}
            if "oneM" in opt:
                attrs["oneM"] = opt["oneM"]
            _model_catalog_add(
                catalog,
                engine,
                opt.get("id"),
                label=opt.get("label"),
                source="curated",
                **attrs,
            )

    try:
        defaults = _load_spawn_defaults()
        for engine, model in (defaults.get("models") or {}).items():
            _model_catalog_add(catalog, engine, model, source="spawn-default")
            norm = _normalize_orchestration_spawn_engine(engine)
            if norm in catalog and model and _model_catalog_allows_model(norm, model):
                catalog[norm]["default"] = _clean_spawn_default_model(model)
    except Exception:
        pass

    env_defaults = {
        "claude": os.environ.get("CCC_CLAUDE_MODEL"),
        "codex": os.environ.get("CCC_CODEX_MODEL"),
        "gemini": os.environ.get("CCC_GEMINI_MODEL"),
        "cursor": os.environ.get("CCC_CURSOR_MODEL"),
        "antigravity": os.environ.get("CCC_ANTIGRAVITY_MODEL"),
        "kilo": os.environ.get("CCC_KILO_MODEL"),
        "hermes": os.environ.get("CCC_HERMES_MODEL"),
    }
    for engine, model in env_defaults.items():
        _model_catalog_add(catalog, engine, model, source="env")

    _model_catalog_add(catalog, "codex", _codex_configured_model(), source="harness-config")
    _model_catalog_add(catalog, "antigravity", _antigravity_cli_configured_model(), source="harness-config")

    for row in _codex_models_cache_records():
        _model_catalog_add(
            catalog,
            "codex",
            row.get("id"),
            label=row.get("label"),
            source=row.get("source") or "codex-cache",
            description=row.get("description"),
            priority=row.get("priority"),
            reasoning_efforts=row.get("reasoning_efforts"),
            default_reasoning_effort=row.get("default_reasoning_effort"),
        )

    harness_results = {}
    for engine in ("claude", "codex"):
        harness_result = _harness_model_list_result(engine)
        harness_results[engine] = harness_result
        for row in harness_result.get("records") or []:
            _model_catalog_add(
                catalog,
                engine,
                row.get("id"),
                label=row.get("label"),
                source=row.get("source") or f"{engine}-cli",
                description=row.get("description"),
                priority=row.get("priority"),
                reasoning_efforts=row.get("reasoning_efforts"),
                default_reasoning_effort=row.get("default_reasoning_effort"),
            )

    _codex_mark_model_availability(catalog, harness_results.get("codex"))

    for row in _observed_model_records():
        _model_catalog_add(
            catalog,
            row.get("engine"),
            row.get("id"),
            label=row.get("label"),
            source=row.get("source") or "observed",
        )

    for bucket in catalog.values():
        bucket.pop("_index", None)
        bucket["models"] = [
            entry for entry in bucket.get("models", [])
            if entry.get("id")
        ]

    payload = {
        "catalog": catalog,
        "engines": {
            engine: [entry["id"] for entry in bucket.get("models", [])]
            for engine, bucket in catalog.items()
        },
        "enforced": [],
    }
    _MODEL_CATALOG_CACHE["ts"] = now
    _MODEL_CATALOG_CACHE["data"] = copy.deepcopy(payload)
    return payload


def _validate_codex_model(model, *, require_available=False):
    """Resolve known Codex aliases and enforce CCC's picker allowlist."""
    if not model:
        return model, None
    key = model.strip().lower()
    alias = _CODEX_MODEL_ALIASES.get(key)
    if alias:
        model = alias
    if not _model_catalog_allows_model("codex", model):
        return model, (
            f"unsupported codex model: {model!r}. Supported codex models: "
            + ", ".join(_ENGINE_KNOWN_MODELS["codex"])
        )
    if require_available:
        unavailable = _codex_model_availability_error(model)
        if unavailable:
            return model, unavailable
    return model, None


def _load_spawn_defaults():
    """Return the server-backed defaults used by new-session spawns.

    These defaults are intentionally server-side rather than localStorage so
    ccc-orchestration and other scripted callers see the same values as the UI.
    Missing file means the historical behavior: Claude + opus, Codex env/gpt,
    Cursor env/auto, and Antigravity's configured CLI model when one exists.
    """
    defaults = {
        "engine": "claude",
        "reasoning_effort": "",
        "models": {
            engine: _spawn_fallback_model_for_engine(engine)
            for engine in _ORCHESTRATION_SPAWN_ENGINES
        },
    }
    try:
        raw = json.loads(SPAWN_DEFAULTS_FILE.read_text())
    except (OSError, json.JSONDecodeError):
        return defaults
    if not isinstance(raw, dict):
        return defaults

    engine = _normalize_orchestration_spawn_engine(raw.get("engine"))
    if engine not in _ORCHESTRATION_SPAWN_ENGINES:
        engine = defaults["engine"]

    models = dict(defaults["models"])
    raw_models = raw.get("models")
    if isinstance(raw_models, dict):
        for key, value in raw_models.items():
            norm = _normalize_orchestration_spawn_engine(key)
            if norm not in _ORCHESTRATION_SPAWN_ENGINES:
                continue
            model = _clean_spawn_default_model(value)
            if len(model) <= 200:
                models[norm] = model
    for required in ("claude", "codex", "cursor", "hermes"):
        if not models.get(required):
            models[required] = defaults["models"].get(required) or _spawn_fallback_model_for_engine(required)
    reasoning_effort = str(raw.get("reasoning_effort") or raw.get("effort") or "").strip().lower()
    if reasoning_effort not in CODEX_REASONING_EFFORTS:
        reasoning_effort = ""
    return {"engine": engine, "models": models, "reasoning_effort": reasoning_effort}


def _save_spawn_defaults(config):
    if not isinstance(config, dict):
        return {"ok": False, "error": "expected JSON object"}
    current = _load_spawn_defaults()
    if "engine" in config:
        engine = _normalize_orchestration_spawn_engine(config.get("engine"))
        if engine not in _ORCHESTRATION_SPAWN_ENGINES:
            return {
                "ok": False,
                "error": f"unsupported engine: {config.get('engine')}",
                "supported_engines": list(_ORCHESTRATION_SPAWN_ENGINES),
            }
        current["engine"] = engine

    if "reasoning_effort" in config or "effort" in config:
        reasoning_effort = str((
            config.get("reasoning_effort")
            if "reasoning_effort" in config
            else config.get("effort")
        ) or "").strip().lower()
        if reasoning_effort not in CODEX_REASONING_EFFORTS:
            return {
                "ok": False,
                "error": "reasoning_effort must be low, medium, high, xhigh, or blank",
            }
        current["reasoning_effort"] = reasoning_effort

    raw_models = config.get("models")
    if raw_models is not None and not isinstance(raw_models, dict):
        return {"ok": False, "error": "models must be an object"}
    if isinstance(raw_models, dict):
        for key, value in raw_models.items():
            engine = _normalize_orchestration_spawn_engine(key)
            if engine not in _ORCHESTRATION_SPAWN_ENGINES:
                return {
                    "ok": False,
                    "error": f"unsupported model engine: {key}",
                    "supported_engines": list(_ORCHESTRATION_SPAWN_ENGINES),
                }
            model = _clean_spawn_default_model(value)
            if len(model) > 200:
                return {"ok": False, "error": f"{engine} model is too long"}
            if engine in ("claude", "codex", "cursor", "hermes") and not model:
                model = _spawn_fallback_model_for_engine(engine)
            current["models"][engine] = model

    payload = {
        "engine": current["engine"],
        "reasoning_effort": current.get("reasoning_effort", ""),
        "models": {
            engine: current["models"].get(engine, "")
            for engine in _ORCHESTRATION_SPAWN_ENGINES
        },
    }
    COMMAND_CENTER_STATE_DIR.mkdir(parents=True, exist_ok=True)
    tmp = SPAWN_DEFAULTS_FILE.with_suffix(".json.tmp")
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(payload, f, indent=2, sort_keys=True)
        f.write("\n")
    tmp.replace(SPAWN_DEFAULTS_FILE)
    return {"ok": True, **payload}


def _spawn_model_for_engine(engine, explicit_model=None):
    model = _clean_spawn_default_model(explicit_model)
    if model:
        return model
    defaults = _load_spawn_defaults()
    model = _clean_spawn_default_model((defaults.get("models") or {}).get(engine))
    if model:
        return model
    return _spawn_fallback_model_for_engine(engine)


def _spawn_request_engine_and_model(payload):
    payload = payload if isinstance(payload, dict) else {}
    defaults = _load_spawn_defaults()
    engine_raw = payload.get("engine")
    has_engine = isinstance(engine_raw, str) and bool(engine_raw.strip())
    engine = _normalize_orchestration_spawn_engine(engine_raw) if has_engine else defaults["engine"]
    if engine not in _ORCHESTRATION_SPAWN_ENGINES:
        return None, None
    model = _clean_spawn_default_model(payload.get("model"))
    if not model:
        model = _clean_spawn_default_model((defaults.get("models") or {}).get(engine))
    if not model:
        model = _spawn_fallback_model_for_engine(engine)
    return engine, model or None


def _spawn_request_reasoning_effort(payload, engine):
    """Resolve an explicit Codex effort or the persisted spawn default."""
    if engine != "codex":
        return ""
    payload = payload if isinstance(payload, dict) else {}
    if "reasoning_effort" in payload or "effort" in payload:
        value = payload.get("reasoning_effort") if "reasoning_effort" in payload else payload.get("effort")
    else:
        defaults = _load_spawn_defaults()
        value = defaults.get("reasoning_effort") or ""
    value = str(value or "").strip().lower()
    return value if value in CODEX_REASONING_EFFORTS else ""


# Archive view delegates all per-session JSONL inspection to the
# canonical _extract_tail_meta() (defined later in the file), which is
# already mtime-cached and is the same source of truth /api/sessions
# uses. That gives us has_edit / has_commit / has_push from tool-call
# events, tail_pr_number / tail_pr_url from `gh pr create`,
# last_assistant_text, pending_tool, custom_title, last_event_type —
# all without a second pass. Earlier branches of this code ran git
# status per cwd, which couldn't distinguish per-session history
# (every session in the same clone got the same answer) and missed
# has_push entirely.
_ARCHIVE_PILLS_RECENT_WINDOW = 3 * 86400

# PR state cache for the sidebar's "Ready to merge" bucket. Without this,
# every session that ever ran `gh pr create` sticks in "Ready to merge"
# forever — even after the PR is merged or closed. We cache the resolved
# state ("OPEN"/"MERGED"/"CLOSED") per PR URL with a short TTL so the
# bucket reflects reality without paying gh-network cost on every refresh.
# Keyed by full PR URL because two sessions can refer to the same PR; the
# cache is shared across them.
_PR_STATE_CACHE = {}
_PR_STATE_LOCK = threading.Lock()
_PR_STATE_TTL = 300  # 5 minutes — short enough to catch a merge, long
# enough that the dashboard's ~10s refresh cadence doesn't fan out to gh.
_PR_STATE_FAILURE_TTL = 30  # Retry gh failures soon; don't pin stale RTM rows.


def _github_pull_api_path(pr_url):
    """Return the gh-api path for a github.com PR URL, or None."""
    try:
        parsed = urllib.parse.urlparse(pr_url or "")
    except (TypeError, ValueError):
        return None
    if parsed.netloc.lower() != "github.com":
        return None
    parts = [urllib.parse.unquote(p) for p in parsed.path.split("/") if p]
    if len(parts) < 4 or parts[2] != "pull" or not parts[3].isdigit():
        return None
    owner, repo, number = parts[0], parts[1], parts[3]
    if not owner or not repo:
        return None
    return f"repos/{owner}/{repo}/pulls/{number}"


def _valid_pr_state(value):
    state = (value or "").strip().upper()
    return state if state in ("OPEN", "MERGED", "CLOSED") else None


def _get_pr_state(pr_url):
    """Resolve a PR's state via `gh pr view`, with TTL cache.

    Returns one of "OPEN" / "MERGED" / "CLOSED", or None if the lookup
    failed (gh missing, unauthed, network down, PR not found). Callers
    treat None as "still ready to merge" — we never hide a real PR
    because gh hiccupped.
    """
    if not pr_url:
        return None
    now = time.time()
    with _PR_STATE_LOCK:
        cached = _PR_STATE_CACHE.get(pr_url)
        if cached:
            ttl = cached.get("ttl", _PR_STATE_TTL)
            if (now - cached.get("at", 0)) < ttl:
                return cached.get("state")
    gh_bin = shutil.which("gh") or "gh"
    state = None
    try:
        r = subprocess.run(
            [gh_bin, "pr", "view", pr_url, "--json", "state", "-q", ".state"],
            capture_output=True, text=True, timeout=8,
        )
        if r.returncode == 0:
            state = _valid_pr_state(r.stdout)
    except (subprocess.SubprocessError, OSError):
        state = None

    # `gh pr view <url>` can be more cwd/config-sensitive than the REST API
    # path. Fall back to `gh api` so merged PRs don't linger in Ready to merge
    # just because one resolver path hiccupped.
    if state is None:
        api_path = _github_pull_api_path(pr_url)
        if api_path:
            try:
                r = subprocess.run(
                    [
                        gh_bin, "api", api_path,
                        "--jq",
                        'if .merged_at then "MERGED" elif .state == "closed" then "CLOSED" else "OPEN" end',
                    ],
                    capture_output=True, text=True, timeout=8,
                )
                if r.returncode == 0:
                    state = _valid_pr_state(r.stdout)
            except (subprocess.SubprocessError, OSError):
                state = None
    with _PR_STATE_LOCK:
        _PR_STATE_CACHE[pr_url] = {
            "state": state,
            "at": now,
            "ttl": _PR_STATE_TTL if state else _PR_STATE_FAILURE_TTL,
        }
    return state


def _prime_pr_states(pr_urls):
    """Resolve PR states for a batch of URLs in parallel, populating the
    cache so subsequent _get_pr_state() calls hit cache. Used by the
    list builders to avoid serial gh-fan-out on cold refreshes (worst
    case: cross-folder mode with dozens of unique PRs). No-op for URLs
    already in cache and within TTL.
    """
    now = time.time()
    needed = []
    seen = set()
    with _PR_STATE_LOCK:
        for url in pr_urls:
            if not url or url in seen:
                continue
            seen.add(url)
            cached = _PR_STATE_CACHE.get(url)
            ttl = cached.get("ttl", _PR_STATE_TTL) if cached else _PR_STATE_TTL
            if not cached or (now - cached.get("at", 0)) >= ttl:
                needed.append(url)
    if not needed:
        return
    # Bounded pool — gh handles concurrent reads fine, but we don't want
    # to fork 100 subprocesses if a user has been opening PRs all year.
    with ThreadPoolExecutor(max_workers=8) as ex:
        list(ex.map(_get_pr_state, needed))


def _bust_pr_state_cache(url=None):
    """Force the next _get_pr_state() to re-query gh. If url is given, only
    that URL's entry is dropped; otherwise the whole cache clears. Call after
    a merge/close action so the badge updates immediately instead of waiting
    out the TTL."""
    with _PR_STATE_LOCK:
        if url:
            _PR_STATE_CACHE.pop(url, None)
        else:
            _PR_STATE_CACHE.clear()


# Cache of session ids whose engine CLI (codex/gemini/cursor) is currently
# running, resolved by matching live process command lines against resume
# args. Claude sessions are covered by sidecar markers instead (see below) and
# are NOT included here. Rebuilt at most once per _ENGINE_LIVE_TTL seconds so
# the bulk session list (which calls _archive_session_is_live per row) does a
# single ps scan rather than one per row.
_engine_live_sids_cache = {"ts": 0.0, "sids": frozenset()}
_ENGINE_LIVE_TTL = 4.0
_codex_pool_alive_cache = {"ts": 0.0, "alive": True}


def _live_engine_session_ids():
    """Set of session ids for non-Claude engine CLIs currently running.

    One ps-backed scan per engine, cached for _ENGINE_LIVE_TTL. We only count
    sessions whose id appears in a live process's resume args (the exact-match
    signal), which is cheap and unambiguous — no cwd heuristics here, since the
    bulk list can't afford per-row disambiguation."""
    now = time.time()
    cached = _engine_live_sids_cache
    if now - cached["ts"] < _ENGINE_LIVE_TTL:
        return cached["sids"]
    sids = set()
    try:
        scanners = (
            ("codex", find_live_codex_processes),
            ("gemini", find_live_gemini_processes),
            ("cursor", find_live_cursor_processes),
        )
        for engine, scan in scanners:
            for p in scan():
                cmd = p.get("command") or ""
                # Pull any resume-arg session id out of the command line. The
                # matcher needs a candidate id, so test each whitespace token
                # that looks like a session id against the exact matcher.
                for tok in cmd.split():
                    if len(tok) >= 16 and _command_targets_engine_session(cmd, tok, engine):
                        sids.add(tok)
        for s in _spawned_sessions:
            engine = str(s.get("engine") or "claude").lower()
            if engine in ("claude", "remote-claude"):
                continue
            try:
                if _poll_spawn_entry(s) is not None:
                    continue
            except Exception:
                continue
            sid = s.get("session_id")
            if not sid:
                log = s.get("log")
                if engine == "codex":
                    sid = _extract_codex_thread_id_from_log(log)
                elif engine == "gemini":
                    sid = _extract_gemini_session_id_from_log(log)
                elif engine == "cursor":
                    sid = _extract_cursor_chat_id_from_log(log) or _cursor_session_id_for_spawn_entry(s)
            if sid:
                sids.add(sid)
    except Exception:
        # Never let liveness detection break the list; fall back to last cache.
        return cached["sids"]
    result = frozenset(sids)
    _engine_live_sids_cache["ts"] = now
    _engine_live_sids_cache["sids"] = result
    return result


# A conversation written this recently still gets the precise (file-scanning)
# liveness probe even if it's not in the cheap live-candidate set — covers
# pool-model Codex, whose rollout changes but carries no resume-arg signal.
# Codex itself treats <5min as "recently written" (session_live_status); 10min
# is a safe backstop. Older, untouched rows skip the probe entirely.
_LIVE_MTIME_WINDOW = 600

# A Claude liveness sidecar (a hook-written marker in SIDECAR_STATE_DIR) only
# proves the session is live while it is FRESH. The hooks never delete these
# markers on session end, and an interactive Claude session carries no
# resume-arg on its command line for the live-process scan to refute — so a
# stale marker would otherwise pin a long-dead session "live" indefinitely
# (observed: sessions idle for days still flagged live). Treat a marker older
# than this window as dead. Tunable: larger keeps idle-but-open sessions lit
# longer; smaller tracks active work more tightly.
_SIDECAR_LIVE_WINDOW = 1800

# How long a sticky `sidecar_status == "active"` (last-completed-tool marker,
# only cleared when the Stop hook fires) still counts as "working" in
# `_session_state_label`. Bridges the between-tools think gap — where no
# `_in_flight.json` exists yet the turn is mid-flight — without letting an
# interrupted/abandoned turn read "working" for the full liveness window. Real
# tool execution (sidecar_in_flight / pending_tool / sub-agent) counts
# regardless of this bound; this only gates the sticky `active` proxy.
_WORKING_GAP_WINDOW = 120

# CCC-174 anti-flicker: how long a LIVE session stays pinned to "waiting" after
# the underlying waiting signal transiently disappears. The three waiting
# triggers (`question_waiting`, `needs_approval`, soft-block prose) are all
# recomputed fresh every poll from flap-prone live state: the Notification
# `_needs_approval` marker is set by the hook and cleared by PostToolUse, and
# the soft-block terminal gate flips the moment a tool starts/stops between
# polls — so a session genuinely parked on the human bounces NEEDS YOU ⇄ IN
# PROGRESS with no real change. We DEMOTE-debounce only: entering "waiting" is
# always immediate (a real ask shows at once); LEAVING it is held for this
# window so a single transient poll can't flicker the section. An ended process
# (state=="ended") drops the pin instantly — you resume, not reply.
_WAITING_STICKY_WINDOW = 90  # seconds
_waiting_sticky_seen = {}    # session_id -> monotonic ts of last real "waiting"


def _stamp_session_state(c):
    """`_session_state_label` plus demote-only "waiting" hysteresis (CCC-174).

    `_session_state_label` stays a pure function (every unit test binds to it
    directly); the stickiness lives here, at the row-stamping sites that own a
    session_id and run once per poll. Returns the coarse state to stamp.

    Rules:
      - raw == "waiting"            → record now, return "waiting".
      - raw != "waiting", live, and last real "waiting" was within the window
                                    → hold "waiting" (damp the transient demotion).
      - otherwise                   → forget the session, return raw.
    """
    raw = _session_state_label(c)
    sid = c.get("session_id") or c.get("id")
    if not sid:
        return raw
    now = time.monotonic()
    if raw == "waiting":
        _waiting_sticky_seen[sid] = now
        return raw
    # A dead process is "ended" — never hold it as waiting (you resume it, you
    # do not reply to it). Drop the pin and report the real state.
    if raw == "ended" or not c.get("is_live"):
        _waiting_sticky_seen.pop(sid, None)
        return raw
    seen = _waiting_sticky_seen.get(sid)
    if seen is not None and (now - seen) < _WAITING_STICKY_WINDOW:
        return "waiting"
    _waiting_sticky_seen.pop(sid, None)
    return raw


# Short-TTL memo for the per-session liveness probe. _archive_session_is_live is
# called PER ROW by the bulk archive/live endpoints (rehydrate, live-activity,
# per-session), and each call runs uncached engine predicates
# (_is_codex/gemini/cursor_session) that hit the filesystem/DB. Under continuous
# dashboard + COO polling that became a per-row lstat storm across many
# concurrent request threads, GIL-bound — the dominant CPU cost `sample` caught
# (os_lstat / take_gil). The same session ids are re-probed every poll cycle by
# every endpoint, so a tiny TTL memo collapses those redundant probes to one per
# session per window. Liveness already lags by the serve TTL (2s) and the engine
# scan TTL (4s), so a ~2s memo introduces no staleness the callers didn't have.
_session_live_cache = {}  # sid -> (ts, bool)
_session_live_lock = threading.Lock()
try:
    _SESSION_LIVE_TTL = max(0.0, float(os.environ.get("CCC_SESSION_LIVE_TTL_SEC", "2")))
except ValueError:
    _SESSION_LIVE_TTL = 2.0


def _archive_session_is_live(session_id):
    """Memoized per-session liveness (see _archive_session_is_live_uncached)."""
    if not session_id or _SESSION_LIVE_TTL <= 0:
        return _archive_session_is_live_uncached(session_id)
    now = time.time()
    with _session_live_lock:
        hit = _session_live_cache.get(session_id)
        if hit is not None and (now - hit[0]) < _SESSION_LIVE_TTL:
            return hit[1]
    live = _archive_session_is_live_uncached(session_id)
    with _session_live_lock:
        _session_live_cache[session_id] = (time.time(), live)
        # Bound the cache: drop entries older than a few TTLs so it can't grow
        # unbounded across the full session history over a long uptime.
        if len(_session_live_cache) > 4096:
            cutoff = time.time() - (_SESSION_LIVE_TTL * 4)
            for k in [k for k, v in _session_live_cache.items() if v[0] < cutoff]:
                _session_live_cache.pop(k, None)
    return live


def _archive_session_is_live_uncached(session_id):
    """A session is "live" if any sidecar marker exists for it (Claude only),
    OR a non-Claude engine CLI (codex/gemini/cursor/antigravity) is running it.

    Claude sidecars are written by Claude Code's hooks. The hook can run
    with a non-Claude session id in scope (e.g. a Claude hook firing a
    `git commit --trailer "Co-authored-by: Cursor"` on behalf of a Cursor
    agent) — that writes a Claude-format sidecar keyed under a Cursor sid,
    polluting liveness detection. The cursor row then falsely lights up
    WIP "Shell" forever. Defense: non-Claude engines NEVER trust the
    Claude sidecar — their liveness comes solely from the live-process
    scan.
    """
    if not session_id:
        return False
    is_non_claude_engine = (
        _is_codex_session(session_id)
        or _is_cursor_session(session_id)
        or _is_gemini_session(session_id)
        or _is_antigravity_session(session_id)
        or _is_kilo_session(session_id)
    )
    if not is_non_claude_engine and SIDECAR_STATE_DIR.is_dir():
        # Only a FRESH sidecar proves liveness — a stale one is a dead session's
        # leftover marker (see _SIDECAR_LIVE_WINDOW). stat() instead of exists()
        # keeps the syscall count identical while giving us the mtime to gate on.
        now = time.time()
        try:
            for suffix in (".json", "_writes", "_in_flight.json", "_needs_approval.json"):
                try:
                    st = (SIDECAR_STATE_DIR / f"{session_id}{suffix}").stat()
                except (OSError, ValueError):
                    continue
                if (now - st.st_mtime) < _SIDECAR_LIVE_WINDOW:
                    return True
        except OSError:
            pass
    if session_id in _live_engine_session_ids():
        return True
    # Pool-model codex (Codex.app `codex app-server`) puts no session id on
    # any command line, so the resume-arg scan above misses it. A codex
    # session whose rollout was written recently (non-None codex_state) and
    # whose engine pool is up is live.
    if _is_codex_session(session_id):
        return _codex_state_fields(session_id).get("codex_state") is not None
    return False


_LIVE_ACTIVITY_FIELD_KEYS = (
    "is_live",
    "sidecar_status",
    "sidecar_has_writes",
    "sidecar_tool",
    "sidecar_file",
    "sidecar_ts",
    "sidecar_in_flight",
    "pending_tool",
    "pending_file",
    "last_event_type",
    "codex_state",
    "codex_fresh",
    "codex_state_reason",
    "codex_writer",
    "codex_desktop_attached",
    "needs_approval",
    "needs_approval_message",
    "question_waiting",
    "question_text",
    "question_header",
    "question_preamble",
    "question_options",
    "question_option_details",
)


def _discover_live_session_ids():
    """Session ids that may have live-work indicators right now.

    Cheap set union: Claude registry, engine CLI resume args, and any
    sidecar marker files on disk. Used by /api/sessions/live-activity so the
    sidebar can refresh WIP chips without re-scanning every JSONL.
    """
    sids = set()
    try:
        sids.update(_load_session_registry().keys())
    except Exception:
        pass
    try:
        sids.update(_live_engine_session_ids())
    except Exception:
        pass
    if SIDECAR_STATE_DIR.is_dir():
        # CANDIDACY GATE: only a sidecar marker FRESH within _SIDECAR_LIVE_WINDOW
        # can make a session live (_archive_session_is_live_uncached rejects
        # older ones on the same window). Sidecar files are never cleaned up, so
        # this dir accumulates one marker per session that ever ran — 300+ stale
        # markers for a handful of live sessions. Feeding the stale ones as
        # candidates makes every live-activity build re-stat hundreds of
        # guaranteed-dead sessions (4 stat()s each, every ~2s). Filter by mtime
        # HERE so the candidate set scales with ACTIVE sessions, not all-time
        # history. Correctness-preserving: a marker too old to prove liveness is
        # dropped from candidacy, never from a genuinely-live result.
        now = time.time()
        try:
            for f in SIDECAR_STATE_DIR.iterdir():
                try:
                    st = f.stat()
                except OSError:
                    continue
                if not stat.S_ISREG(st.st_mode):
                    continue
                if (now - st.st_mtime) >= _SIDECAR_LIVE_WINDOW:
                    continue  # stale marker — cannot indicate a live session
                name = f.stem
                if name.endswith("_writes"):
                    sid = name[: -len("_writes")]
                elif name.endswith("_in_flight"):
                    sid = name[: -len("_in_flight")]
                elif name.endswith("_needs_approval"):
                    sid = name[: -len("_needs_approval")]
                else:
                    sid = name
                if sid:
                    sids.add(sid)
        except OSError:
            pass
    return sids


def _live_activity_entry_for_session(session_id):
    """Sidecar-shaped activity snapshot for one session (no JSONL walk)."""
    entry = {"session_id": session_id, "is_live": _archive_session_is_live(session_id)}
    if not entry["is_live"]:
        return entry
    engine = _detect_session_engine(session_id)
    if engine == "codex":
        path = _resolve_codex_rollout_path(session_id)
        tail = _extract_codex_tail_meta(path) if path else {}
        entry.update(_codex_activity_fields_from_tail(tail, True))
        app_activity = _codex_app_server_activity_fields(session_id)
        if app_activity.get("sidecar_status") and not _codex_app_activity_superseded_by_tail(app_activity, tail):
            entry.update(app_activity)
        entry["pending_tool"] = tail.get("pending_tool")
        entry["pending_file"] = tail.get("pending_file")
        entry["last_event_type"] = tail.get("last_event_type")
        entry.update(_codex_state_fields(session_id))
    elif engine == "gemini":
        path = _resolve_gemini_chat_path(session_id)
        tail = _extract_gemini_tail_meta(path) if path else {}
        entry.update(_gemini_activity_fields_from_tail(tail, True))
        entry["pending_tool"] = tail.get("pending_tool")
        entry["pending_file"] = tail.get("pending_file")
        entry["last_event_type"] = tail.get("last_event_type")
    elif engine == "cursor":
        path = _cursor_transcript_path(session_id)
        tail = _extract_cursor_tail_meta(path) if path else {}
        entry.update(_cursor_activity_fields_from_tail(tail, True))
        entry["pending_tool"] = tail.get("pending_tool")
        entry["pending_file"] = tail.get("pending_file")
        entry["last_event_type"] = tail.get("last_event_type")
    elif engine == "antigravity":
        path = _antigravity_transcript_path(session_id)
        tail = _extract_antigravity_tail_meta(path) if path else {}
        entry.update(_antigravity_activity_fields_from_tail(tail, True))
        entry["pending_tool"] = tail.get("pending_tool")
        entry["pending_file"] = tail.get("pending_file")
        entry["last_event_type"] = tail.get("last_event_type")
    else:
        _add_sidecar_fields(entry)
    return entry


# Coalescing cache for the live-activity snapshot. /api/sessions/live-activity
# is polled by every dashboard client (browser tab + desktop app); without
# coalescing, each concurrent poll recomputed the whole snapshot, and slow polls
# made clients fire new ones before old ones finished — a pile-up that pinned a
# core on GIL/lock contention. The snapshot is inherently approximate (sidebar
# WIP chips), so serving one ≤TTL-old result to all concurrent callers is fine.
# The lock makes it single-flight: at most one build runs at a time; everyone
# else waits briefly and shares its result.
_LIVE_ACTIVITY_SNAPSHOT_TTL = 10.0
_live_activity_snapshot = {"ts": 0.0, "data": None}
_live_activity_snapshot_lock = threading.Lock()

# ── CCC self-health metrics ─────────────────────────────────────────────────
# Three cheap, in-process signals surfaced in the dashboard's bottom-left bar so
# the daemon's own health is glanceable: this process's CPU%, the wall-clock cost
# of the hot live-activity build, and a rolling count of recent server errors.
# Everything here is O(1) per update and reads nothing off disk on the hot path.
_SERVER_START_TS = time.time()

# ── Headless-resume lifecycle ledger (diagnostic only) ──────────────────────
# Append-only JSONL trace of the warm `claude -p` resume lifecycle so we can
# root-cause why warm processes die between messages and measure cache
# efficiency per resume. Pure observation — nothing here changes spawn/retire
# behavior. Off the hot path: the ledger is written only at lifecycle
# transitions (reuse/spawn/exit/retire/server_start), never per row or per poll
# iteration (the exit write is guarded to fire once via `_cleanup_done`).
_RESUME_LEDGER_FILE = COMMAND_CENTER_STATE_DIR / "resume-ledger.jsonl"
_RESUME_LEDGER_BACKUP = COMMAND_CENTER_STATE_DIR / "resume-ledger.1.jsonl"
_RESUME_LEDGER_MAX_BYTES = 5 * 1024 * 1024
_RESUME_LEDGER_LOCK = threading.Lock()
# Bounded in-memory window feeding /api/health rolling stats — so the health
# poll never reparses the file (perf gate).
_RESUME_LEDGER_WINDOW = collections.deque(maxlen=50)
# sid -> epoch of that sid's most recent exit/cold_resume, for gap computation
# without reparsing the file.
_RESUME_LAST_EPOCH = {}
# sid -> deque of that sid's recent codex_wake_* rows, so the live wake-status
# endpoint (/api/codex-wake-status) can derive the stage timeline with NO file
# scan (perf gate). Bounded per sid AND in the number of tracked sids. Mirrors
# how `_RESUME_LEDGER_WINDOW` is kept — updated only at wake transitions.
_CODEX_WAKE_EVENTS = collections.OrderedDict()
_CODEX_WAKE_MAX_SIDS = 64
_CODEX_WAKE_PER_SID = 24


def _resume_ledger_append(event, sid=None, pid=None, **fields):
    """Append one lifecycle event to the resume ledger. Never raises."""
    try:
        now = time.time()
        rec = {
            "ts": time.strftime("%Y-%m-%dT%H:%M:%S"),
            "epoch": round(now, 3),
            "event": event,
            "sid": sid,
            "pid": pid,
        }
        rec.update(fields)
        line = json.dumps(rec, default=str)
        with _RESUME_LEDGER_LOCK:
            _RESUME_LEDGER_WINDOW.append(rec)
            if event in ("exit", "cold_resume") and sid is not None:
                _RESUME_LAST_EPOCH[sid] = now
            # Feed the per-sid codex wake window (in-memory only; the endpoint
            # never touches the ledger file).
            if sid is not None and isinstance(event, str) and event.startswith("codex_wake"):
                dq = _CODEX_WAKE_EVENTS.get(sid)
                if dq is None:
                    dq = collections.deque(maxlen=_CODEX_WAKE_PER_SID)
                    _CODEX_WAKE_EVENTS[sid] = dq
                _CODEX_WAKE_EVENTS.move_to_end(sid)
                dq.append(rec)
                while len(_CODEX_WAKE_EVENTS) > _CODEX_WAKE_MAX_SIDS:
                    _CODEX_WAKE_EVENTS.popitem(last=False)
            try:
                COMMAND_CENTER_STATE_DIR.mkdir(parents=True, exist_ok=True)
                try:
                    if (_RESUME_LEDGER_FILE.exists()
                            and _RESUME_LEDGER_FILE.stat().st_size > _RESUME_LEDGER_MAX_BYTES):
                        _RESUME_LEDGER_FILE.replace(_RESUME_LEDGER_BACKUP)
                except OSError:
                    pass
                with open(_RESUME_LEDGER_FILE, "a", encoding="utf-8") as fh:
                    fh.write(line + "\n")
            except OSError:
                pass
    except Exception:
        pass


def _resume_ledger_stats():
    """Rolling stats over the in-memory window for the /api/health `resume`
    object. Reads nothing off disk. Every field tolerates an empty window."""
    empty = {
        "warm_reuse_pct": None,
        "warm_reuse_hits": 0,
        "warm_reuse_attempts": 0,
        "avg_cache_efficiency_pct": None,
        "cold_resumes_window": 0,
        "worst_cache_efficiency_pct": None,
        "avg_lifetime_s": None,
    }
    try:
        with _RESUME_LEDGER_LOCK:
            window = list(_RESUME_LEDGER_WINDOW)
        if not window:
            return empty
        reuse_hit = sum(1 for e in window if e.get("event") == "reuse_hit")
        cold = sum(1 for e in window if e.get("event") == "cold_resume")
        # A resume ATTEMPT is exactly one of: reuse_hit (reused a live warm
        # process) or cold_resume (spawned a fresh `claude --resume`). Denominator
        # is the sum of those two. `reuse_miss` is NOT counted — it is only the
        # annotation logged immediately before every cold_resume, so including it
        # double-counted each cold resume and understated warm reuse.
        attempts = reuse_hit + cold
        warm = int(round(100 * reuse_hit / attempts)) if attempts else None
        effs = [e.get("cache_efficiency_pct") for e in window
                if e.get("event") == "exit"
                and isinstance(e.get("cache_efficiency_pct"), (int, float))]
        avg_eff = round(sum(effs) / len(effs), 1) if effs else None
        worst_eff = min(effs) if effs else None
        lifetimes = [e.get("lifetime_s") for e in window
                     if e.get("event") == "exit"
                     and isinstance(e.get("lifetime_s"), (int, float))]
        avg_life = round(sum(lifetimes) / len(lifetimes), 1) if lifetimes else None
        return {
            "warm_reuse_pct": warm,
            "warm_reuse_hits": reuse_hit,
            "warm_reuse_attempts": attempts,
            "avg_cache_efficiency_pct": avg_eff,
            "cold_resumes_window": cold,
            "worst_cache_efficiency_pct": worst_eff,
            "avg_lifetime_s": avg_life,
        }
    except Exception:
        return empty


def _resume_parse_result_usage(log_path):
    """Read the tail of a stream-json resume log and pull usage/cost from the
    final `"type":"result"` event. Guarded — a missing/malformed log yields {}."""
    out = {}
    try:
        with open(log_path, "rb") as fh:
            try:
                fh.seek(0, 2)
                size = fh.tell()
                fh.seek(max(0, size - 8192))
            except OSError:
                pass
            tail = fh.read()
        text = tail.decode("utf-8", "replace")
        result_line = None
        for ln in reversed(re.split(r"[\r\n]+", text)):
            if '"type":"result"' in ln or '"type": "result"' in ln:
                result_line = ln
                break
        if not result_line:
            return out
        obj = json.loads(result_line)
        usage = obj.get("usage") or {}
        cache_read = int(usage.get("cache_read_input_tokens") or 0)
        cache_creation = int(usage.get("cache_creation_input_tokens") or 0)
        uncached = int(usage.get("input_tokens") or 0)
        out["cache_read"] = cache_read
        out["cache_creation"] = cache_creation
        out["uncached_input"] = uncached
        out["output_tokens"] = int(usage.get("output_tokens") or 0)
        out["num_turns"] = obj.get("num_turns")
        out["cost_usd"] = obj.get("total_cost_usd")
        out["terminal_reason"] = obj.get("subtype") or obj.get("result")
        out["cache_efficiency_pct"] = round(
            100 * cache_read / max(1, cache_read + cache_creation + uncached), 1)
    except Exception:
        return out
    return out


def _resume_entry_started_epoch(entry):
    """Best-effort epoch a spawn entry started at: prefer the stored epoch,
    fall back to parsing the `%Y%m%dT%H%M%S` `started` string."""
    try:
        se = entry.get("started_epoch")
        if se:
            return float(se)
        started = entry.get("started")
        if started:
            return time.mktime(time.strptime(started, "%Y%m%dT%H%M%S"))
    except Exception:
        return None
    return None

# Rolling wall-clock duration (ms) of the REAL (uncached) live-activity build.
# Cache hits aren't recorded — we only want the cost of actual work, which is the
# truest signal for the hottest endpoint. Bounded deque so memory is constant.
_live_build_ms = collections.deque(maxlen=30)
_live_build_lock = threading.Lock()


def _record_live_build_ms(ms):
    with _live_build_lock:
        _live_build_ms.append(float(ms))


def _live_build_stats():
    """{'last', 'avg', 'count'} ms over the last N real builds (None if idle)."""
    with _live_build_lock:
        vals = list(_live_build_ms)
    if not vals:
        return {"last": None, "avg": None, "count": 0}
    return {
        "last": round(vals[-1], 1),
        "avg": round(sum(vals) / len(vals), 1),
        "count": len(vals),
    }

# Rolling timestamps of recent server-side errors (500s / handler exceptions).
# A bounded ring of epoch seconds; the count is computed over a trailing window
# at read time, so we never scan service.err.log on the hot path.
_recent_error_ts = collections.deque(maxlen=200)
_recent_error_lock = threading.Lock()
_RECENT_ERROR_WINDOW_S = 15 * 60  # 15 min


def _record_server_error():
    """Bump the in-process error counter. Call wherever the server handles/logs
    a real error (500 response, handler traceback). Cheap and lock-guarded."""
    with _recent_error_lock:
        _recent_error_ts.append(time.time())


def _recent_error_count(window_s=_RECENT_ERROR_WINDOW_S):
    cutoff = time.time() - window_s
    with _recent_error_lock:
        return sum(1 for t in _recent_error_ts if t >= cutoff)

# Server CPU% sampled the same way Activity Monitor reports it: `ps -p <pid>`.
# Cached for a few seconds because the dashboard polls health frequently and a
# subprocess per poll would be exactly the kind of cost we're trying to avoid.
_server_cpu_cache = {"ts": 0.0, "pct": None}
_server_cpu_lock = threading.Lock()
_SERVER_CPU_TTL = 5.0


def _server_cpu_pct():
    """This daemon's own process CPU%, via `ps -p <pid> -o %cpu=`. Cached for
    _SERVER_CPU_TTL so frequent polls share one cheap sample. Returns float or
    None if ps is unavailable."""
    now = time.time()
    cache = _server_cpu_cache
    if cache["pct"] is not None and now - cache["ts"] < _SERVER_CPU_TTL:
        return cache["pct"]
    with _server_cpu_lock:
        now = time.time()
        if cache["pct"] is not None and now - cache["ts"] < _SERVER_CPU_TTL:
            return cache["pct"]
        pct = None
        try:
            out = subprocess.run(
                ["ps", "-p", str(os.getpid()), "-o", "%cpu="],
                capture_output=True, text=True, timeout=2,
            )
            raw = (out.stdout or "").strip()
            if raw:
                pct = round(float(raw.split()[0]), 1)
        except Exception:
            pct = None
        cache["pct"] = pct
        cache["ts"] = now
        return pct


def build_ccc_health():
    """Snapshot of CCC's own health for the dashboard bottom-left bar:
    cpu (process %), live-build latency (last/avg ms), recent error count,
    and uptime. All cheap / cached — safe to poll."""
    return {
        "cpu": _server_cpu_pct(),
        "build_ms": _live_build_stats(),
        "recent_errors": _recent_error_count(),
        "error_window_min": _RECENT_ERROR_WINDOW_S // 60,
        "uptime_s": round(time.time() - _SERVER_START_TS),
        "pid": os.getpid(),
        "resume": _resume_ledger_stats(),
    }


def _env_truthy(name, default="0"):
    return os.environ.get(name, default).lower() in ("1", "true", "yes")


def _should_prewarm_throughput_on_startup():
    return _env_truthy("CCC_PREWARM_THROUGHPUT_ON_STARTUP")


# ---------------------------------------------------------------------------
# System health (the /api/system-health endpoint + the dashboard Health panel).
#
# This is the *machine's* health, not CCC's own (build_ccc_health above):
# memory + swap pressure, sustained CPU hogs, and every Claude session rolled
# up with its whole process subtree, last-activity, and whether it's safe to
# reap. Mirrors the standalone mac-health menu-bar plugin so both render from
# the same logic.
#
# "Stale" = idle for a while, measured from the session transcript mtime (each
# turn appends to ~/.claude/projects/*/<uuid>.jsonl, so its mtime is a real
# last-activity clock that freezes when the session goes idle) — NOT process
# age, which says nothing about whether a session is still in use. A session is
# only reapable when it is headless (no TTY = no human in a terminal), idle (no
# encode/transcode child, low tree CPU), and stale. Bursty workers (whisper run
# chunk-by-chunk) and sessions blocked on one long command have a frozen
# transcript too, so they lean on the worker/CPU check, not the clock.
# ---------------------------------------------------------------------------

_SYS_PROJECTS_DIR = os.path.expanduser("~/.claude/projects")
_SYS_SESSION_UUID_RE = re.compile(r"--(?:resume|session-id|sid)\s+([0-9a-fA-F-]{36})")
_SYS_WORKER_RE = re.compile(r"\b(whisper(?:-cli)?|ffmpeg|ffprobe|HandBrakeCLI)\b", re.I)
_SYS_STALE_MIN = 120.0       # idle minutes past which a headless session is reapable
_SYS_BUSY_CPU = 30.0         # tree CPU% above which a session counts as working
_SYS_HOG_CPU = 80.0          # process CPU% to count as a sustained hog
_SYS_HOG_MIN_AGE = 2.0       # minutes alive, to skip brief compile/encode spikes
_SYS_UNIT_MB = {"K": 1 / 1024, "M": 1.0, "G": 1024.0, "T": 1024 * 1024.0}
# Absolute tool paths: the launchd daemon's PATH lacks /usr/sbin, so bare
# `sysctl`/`lsof` silently fail (FileNotFoundError -> ""). On Linux the same
# tools live elsewhere (or not at all), so resolve per platform: prefer the
# shipped macOS path when it exists, else a PATH lookup, else the bare name.
# Missing tools degrade to "" in _sys_run rather than crashing. sysctl and
# vm_stat are macOS-only; on Linux _sys_memory/_sys_cpu use /proc + os instead.
def _resolve_sys_tool(macos_path, name):
    if os.path.exists(macos_path):
        return macos_path
    return shutil.which(name) or name


_SYS_PS = _resolve_sys_tool("/bin/ps", "ps")
_SYS_LSOF = _resolve_sys_tool("/usr/sbin/lsof", "lsof")
_SYS_SYSCTL = _resolve_sys_tool("/usr/sbin/sysctl", "sysctl")
_SYS_VM_STAT = _resolve_sys_tool("/usr/bin/vm_stat", "vm_stat")
_SYS_OSASCRIPT = _resolve_sys_tool("/usr/bin/osascript", "osascript")
_SYS_GUI_APPS = (
    {
        "id": "cursor",
        "name": "Cursor.app",
        "app_name": "Cursor",
        "bundle": "Cursor.app",
    },
    {
        "id": "antigravity",
        "name": "Antigravity.app",
        "app_name": "Antigravity",
        "bundle": "Antigravity.app",
    },
    {
        "id": "codex",
        "name": "Codex.app",
        "app_name": "Codex",
        "bundle": "Codex.app",
    },
)


def _sys_run(cmd, timeout=3):
    try:
        return subprocess.run(cmd, capture_output=True, text=True, timeout=timeout).stdout
    except Exception:
        return ""


def _sys_to_mb(value, unit):
    return float(value) * _SYS_UNIT_MB.get(unit.upper(), 1.0)


def _sys_parse_etime(s):
    """ps etime (SS, MM:SS, HH:MM:SS, DD-HH:MM:SS) -> minutes."""
    days = 0
    if "-" in s:
        d, s = s.split("-", 1)
        try:
            days = int(d)
        except ValueError:
            return 0.0
    try:
        nums = [int(p) for p in s.split(":")]
    except ValueError:
        return 0.0
    if len(nums) == 1:
        h, m, sec = 0, 0, nums[0]
    elif len(nums) == 2:
        h, m, sec = 0, nums[0], nums[1]
    else:
        h, m, sec = nums[0], nums[1], nums[2]
    return days * 1440 + h * 60 + m + sec / 60.0


def _sys_memory_linux():
    """Memory + swap from /proc/meminfo (Linux). Mirrors the macOS shape so the
    same UI panel renders. 'available' uses MemAvailable, the kernel's own
    estimate of reclaimable memory."""
    info = {}
    try:
        with open("/proc/meminfo", "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                m = re.match(r"(\w+):\s+(\d+)\s*kB", line)
                if m:
                    info[m.group(1)] = int(m.group(2)) / 1024.0  # kB -> MB
    except OSError:
        return {
            "total_mb": None, "used_mb": None, "available_mb": 0,
            "compressed_mb": 0, "swap_used_mb": None, "swap_total_mb": None,
            "pressure": None,
        }
    total = info.get("MemTotal")
    available = info.get("MemAvailable", info.get("MemFree", 0))
    used = (total - available) if total else None
    swap_total = info.get("SwapTotal")
    swap_free = info.get("SwapFree")
    swap_used = (swap_total - swap_free) if (swap_total is not None and swap_free is not None) else None
    pressure = None
    if total:
        ap = available / total
        pressure = "critical" if ap < 0.05 else ("elevated" if ap < 0.20 else "ok")
    return {
        "total_mb": round(total) if total else None,
        "used_mb": round(used) if used is not None else None,
        "available_mb": round(available),
        "compressed_mb": 0,  # no direct /proc equivalent
        "swap_used_mb": round(swap_used) if swap_used is not None else None,
        "swap_total_mb": round(swap_total) if swap_total is not None else None,
        "pressure": pressure,
    }


def _sys_memory():
    """Memory + swap, matching Activity Monitor's pressure bar (kernel pressure
    level + available = free+inactive+speculative+purgeable, not top's 'used')."""
    if platform.system() != "Darwin":
        return _sys_memory_linux()
    total_mb = None
    try:
        total_mb = int(_sys_run([_SYS_SYSCTL, "-n", "hw.memsize"]).strip()) / (1024 * 1024)
    except ValueError:
        pass
    pages = {}
    for line in _sys_run([_SYS_VM_STAT]).splitlines():
        m = re.match(r"(.+?):\s+(\d+)\.?\s*$", line.strip())
        if m:
            pages[m.group(1).strip()] = int(m.group(2))
    try:
        page = int(_sys_run([_SYS_SYSCTL, "-n", "hw.pagesize"]).strip() or 16384)
    except ValueError:
        page = 16384
    mb = lambda k: pages.get(k, 0) * page / (1024 * 1024)
    available = mb("Pages free") + mb("Pages inactive") + mb("Pages speculative") + mb("Pages purgeable")
    used = (total_mb - available) if total_mb else None
    swap_used = swap_total = None
    for k, v, u in re.findall(r"(total|used|free)\s*=\s*([\d.]+)([KMGT])",
                              _sys_run([_SYS_SYSCTL, "-n", "vm.swapusage"])):
        if k == "total":
            swap_total = _sys_to_mb(v, u)
        elif k == "used":
            swap_used = _sys_to_mb(v, u)
    pressure = {"1": "ok", "2": "elevated", "4": "critical"}.get(
        _sys_run([_SYS_SYSCTL, "-n", "kern.memorystatus_vm_pressure_level"]).strip())
    if pressure is None and total_mb:
        ap = available / total_mb
        pressure = "critical" if ap < 0.05 else ("elevated" if ap < 0.20 else "ok")
    return {
        "total_mb": round(total_mb) if total_mb else None,
        "used_mb": round(used) if used is not None else None,
        "available_mb": round(available),
        "compressed_mb": round(mb("Pages occupied by compressor")),
        "swap_used_mb": round(swap_used) if swap_used is not None else None,
        "swap_total_mb": round(swap_total) if swap_total is not None else None,
        "pressure": pressure,
    }


def _sys_cpu():
    if platform.system() != "Darwin":
        # Linux: sysctl keys don't exist; use stdlib (also avoids 2 forks).
        try:
            load = list(os.getloadavg())
        except (OSError, AttributeError):
            load = [None, None, None]
        return {"load1": load[0], "load5": load[1], "load15": load[2],
                "cores": os.cpu_count()}
    cores = None
    try:
        cores = int(_sys_run([_SYS_SYSCTL, "-n", "hw.ncpu"]).strip())
    except ValueError:
        pass
    nums = re.findall(r"[\d.]+", _sys_run([_SYS_SYSCTL, "-n", "vm.loadavg"]))
    load = [float(x) for x in nums[:3]] if len(nums) >= 3 else [None, None, None]
    return {"load1": load[0], "load5": load[1], "load15": load[2], "cores": cores}


def _sys_label(cmd):
    exe = cmd.split(None, 1)[0]
    base = exe.rsplit("/", 1)[-1]
    app = re.search(r"/([^/]+)\.app/Contents/", cmd)
    if app:
        return app.group(1)
    if base == "claude":
        return "claude CLI"
    if "python" in base.lower():
        sc = re.search(r"\s([^ ]+\.py)(?:\s|$)", cmd)
        return "Python: " + sc.group(1).rsplit("/", 1)[-1] if sc else "Python"
    return base or cmd[:40]


def _sys_process_rows():
    rows = []
    for line in _sys_run([_SYS_PS, "-axo", "pid=,ppid=,rss=,pcpu=,etime=,tty=,command="]).splitlines():
        parts = line.strip().split(None, 6)
        if len(parts) < 7:
            continue
        try:
            rows.append({
                "pid": int(parts[0]),
                "ppid": int(parts[1]),
                "rss_mb": int(parts[2]) / 1024,
                "cpu": float(parts[3]),
                "etime_min": _sys_parse_etime(parts[4]),
                "tty": parts[5],
                "cmd": parts[6],
            })
        except ValueError:
            continue
    return rows


def _sys_gui_apps(rows):
    """Running GUI app-server engines, aggregated separately from session
    process trees. These are intentionally non-reapable: all conversations live
    inside the shared app process, so the only exposed control is graceful quit."""
    apps = []
    for spec in _SYS_GUI_APPS:
        marker = "/" + spec["bundle"] + "/Contents/"
        matches = [r for r in rows if marker in r.get("cmd", "")]
        if not matches:
            continue
        matches.sort(key=lambda r: r["pid"])
        main = next((r for r in matches if "/Contents/MacOS/" in r.get("cmd", "")), matches[0])
        apps.append({
            "id": spec["id"],
            "name": spec["name"],
            "app_name": spec["app_name"],
            "bundle": spec["bundle"],
            "pid": main["pid"],
            "pids": [r["pid"] for r in matches],
            "rss_mb": round(sum(r["rss_mb"] for r in matches)),
            "cpu": round(sum(r["cpu"] for r in matches), 1),
            "age_min": round(max((r["etime_min"] for r in matches), default=0.0), 1),
            "nprocs": len(matches),
            "reapable": False,
            "control": "quit-app",
            "quit_supported": platform.system() == "Darwin",
        })
    return apps


def _sys_last_activity_min(uuid, now, proj_dirs):
    """Minutes since the session transcript was last written, or None. Stats
    <proj>/<uuid>.jsonl across project dirs — no cwd-encoding assumptions."""
    if not uuid:
        return None
    target = uuid + ".jsonl"
    best = None
    for proj in proj_dirs:
        try:
            mt = os.path.getmtime(os.path.join(_SYS_PROJECTS_DIR, proj, target))
        except OSError:
            continue
        if best is None or mt > best:
            best = mt
    return ((now - best) / 60.0) if best is not None else None


def _sys_cwds(pids):
    """Batch one lsof for every session root's cwd (basename used to tell repos apart)."""
    if not pids:
        return {}
    out = _sys_run([_SYS_LSOF, "-a", "-d", "cwd", "-Fn", "-p", ",".join(map(str, pids))])
    cwds, cur = {}, None
    for line in out.splitlines():
        if line.startswith("p"):
            try:
                cur = int(line[1:])
            except ValueError:
                cur = None
        elif line.startswith("n") and cur is not None:
            cwds.setdefault(cur, line[1:])
    return cwds


def _sys_sessions(rows, now):
    by_pid = {r["pid"]: r for r in rows}
    children = {}
    for r in rows:
        children.setdefault(r["ppid"], []).append(r["pid"])

    def descendants(root):
        seen, stack = [], list(children.get(root, []))
        while stack:
            pid = stack.pop()
            seen.append(pid)
            stack.extend(children.get(pid, []))
        return seen

    try:
        proj_dirs = os.listdir(_SYS_PROJECTS_DIR)
    except OSError:
        proj_dirs = []

    # Authoritative pid -> sessionId (Claude writes ~/.claude/sessions/<pid>.json),
    # so even interactive sessions with no uuid in argv get a real session id —
    # which unlocks their real last-activity (transcript) and CCC name.
    try:
        registry = _load_session_registry()
    except Exception:
        registry = {}
    pid_to_sid, meta_by_sid = {}, {}
    for sid, data in registry.items():
        meta_by_sid[sid] = data
        try:
            pid_to_sid[int(data.get("pid"))] = sid
        except (TypeError, ValueError):
            pass
    # Names, same priority the sidebar uses: user override > registry name >
    # spawn-registry name. Loaded once, not per session.
    try:
        overrides = _load_session_name_overrides()
    except Exception:
        overrides = {}
    spawn_name_by_sid = {}
    try:
        for e in _load_spawn_registry():
            nm = str(e.get("name") or "").strip()
            if not nm:
                continue
            for key in ("session_id", "resumed_sid"):
                k = e.get(key)
                if k:
                    spawn_name_by_sid.setdefault(k, nm)
    except Exception:
        pass

    def _name_for(sid):
        if not sid:
            return None
        nm = overrides.get(sid) or (meta_by_sid.get(sid) or {}).get("name") or spawn_name_by_sid.get(sid)
        return _truncate_session_name(nm) if nm else None

    # Live WT-tracked workers are WatchTower's to release/reap, not ours —
    # surface them (wt_worker flag) but never offer them as reap targets.
    wt_pids, wt_sids = _wt_live_worker_guard()

    sessions = []
    for r in rows:
        if _sys_label(r["cmd"]) != "claude CLI":
            continue
        desc = descendants(r["pid"])
        drows = [by_pid[p] for p in desc if p in by_pid]
        tree_rss = r["rss_mb"] + sum(d["rss_mb"] for d in drows)
        tree_cpu = r["cpu"] + sum(d["cpu"] for d in drows)
        worker = next((d for d in drows if _SYS_WORKER_RE.search(d["cmd"])), None)
        interactive = bool(r["tty"]) and r["tty"] not in ("??", "?", "-", "")
        busy = bool(worker) or tree_cpu >= _SYS_BUSY_CPU
        # Registry pid->sid is authoritative; fall back to the uuid in argv.
        sid = pid_to_sid.get(r["pid"]) or \
            (m.group(1) if (m := _SYS_SESSION_UUID_RE.search(r["cmd"])) else None)
        idle_known = _sys_last_activity_min(sid, now, proj_dirs)
        idle_min = idle_known if idle_known is not None else r["etime_min"]
        wt_worker = r["pid"] in wt_pids or bool(sid and sid in wt_sids)
        sessions.append({
            "pid": r["pid"],
            "session_id": sid,
            "name": _name_for(sid),
            "entrypoint": (meta_by_sid.get(sid) or {}).get("entrypoint"),
            "age_min": round(r["etime_min"], 1),
            "idle_min": round(idle_min, 1),
            "idle_known": idle_known is not None,
            "tree_rss_mb": round(tree_rss),
            "tree_cpu": round(tree_cpu),
            "nprocs": 1 + len(desc),
            "tree_pids": [r["pid"]] + desc,
            "interactive": interactive,
            "busy": busy,
            "worker": _sys_label(worker["cmd"]) if worker else None,
            "wt_worker": wt_worker,
            "reapable": (not interactive) and (not busy) and (not wt_worker)
                        and idle_min >= _SYS_STALE_MIN,
        })

    cwds = _sys_cwds([s["pid"] for s in sessions])
    home = os.path.expanduser("~")
    for s in sessions:
        c = cwds.get(s["pid"], "")
        s["cwd"] = c
        s["cwd_short"] = "~" if c == home else (c.rsplit("/", 1)[-1] if c else "?")

    # Concurrent sessions: 2+ live processes on one session_id (e.g. a headless
    # sdk-cli + a terminal cli both on the same transcript). The data-loss path
    # is unproven (study T1), but a kill here is the riskiest move, so flag them
    # and withhold reaping — the user resolves a concurrent pair deliberately.
    sid_counts = {}
    for s in sessions:
        if s["session_id"]:
            sid_counts[s["session_id"]] = sid_counts.get(s["session_id"], 0) + 1
    for s in sessions:
        s["concurrent"] = bool(s["session_id"]) and sid_counts.get(s["session_id"], 0) >= 2
        if s["concurrent"]:
            s["reapable"] = False

    # Sort by the strength of the case to reap (strongest first), so the best
    # kill targets surface at the top and protected sessions sink:
    #   reapable (stale) > headless-but-recent > working > the one you're in.
    # Within a tier, longer-idle first, then bigger memory win.
    def _kill_rank(s):
        if s["reapable"]:
            tier = 3                                   # stale → kill candidate
        elif not s["interactive"] and not s["busy"]:
            tier = 2                                   # headless idle, not stale yet
        elif s["busy"]:
            tier = 1                                   # working → protected
        else:
            tier = 0                                   # interactive → you're in it
        return (tier, s["idle_min"], s["tree_rss_mb"])
    return sorted(sessions, key=_kill_rank, reverse=True)


def _sys_hogs(rows):
    hogs = [r for r in rows
            if r["cpu"] >= _SYS_HOG_CPU and r["etime_min"] >= _SYS_HOG_MIN_AGE]
    hogs.sort(key=lambda r: r["cpu"], reverse=True)
    return [{"pid": r["pid"], "label": _sys_label(r["cmd"]),
             "cpu": round(r["cpu"]), "etime_min": round(r["etime_min"], 1)}
            for r in hogs[:6]]


_system_health_snapshot = {"ts": 0.0, "data": None}
_system_health_lock = threading.Lock()
_SYSTEM_HEALTH_TTL = 5.0


def _build_system_health_uncached():
    now = time.time()
    rows = _sys_process_rows()
    sessions = _sys_sessions(rows, now)
    apps = _sys_gui_apps(rows)
    reap = [s for s in sessions if s["reapable"]]
    return {
        "ts": now,
        "memory": _sys_memory(),
        "cpu": _sys_cpu(),
        "hogs": _sys_hogs(rows),
        "sessions": sessions,
        "apps": apps,
        "session_totals": {
            "count": len(sessions),
            "tree_rss_mb": round(sum(s["tree_rss_mb"] for s in sessions)),
            "reapable": len(reap),
            "reapable_rss_mb": round(sum(s["tree_rss_mb"] for s in reap)),
        },
        "app_totals": {
            "count": len(apps),
            "rss_mb": round(sum(app["rss_mb"] for app in apps)),
        },
        # The reap policy, so the UI can state exactly what "stale" means
        # without hardcoding (and drifting from) these thresholds.
        "policy": {
            "stale_min": _SYS_STALE_MIN,
            "busy_cpu": _SYS_BUSY_CPU,
        },
    }


def build_system_health(force=False):
    """Machine health for the dashboard Health panel. Coalesced with a 5s TTL
    (manual cache because _ttl_memo is defined far below this point) so the
    panel's poll and any concurrent callers share one ps/lsof sweep. Pass
    force=True to bypass the cache (the reap guard needs a fresh view)."""
    snap = _system_health_snapshot
    now = time.time()
    if not force and snap["data"] is not None and now - snap["ts"] < _SYSTEM_HEALTH_TTL:
        return snap["data"]
    with _system_health_lock:
        now = time.time()
        if not force and snap["data"] is not None and now - snap["ts"] < _SYSTEM_HEALTH_TTL:
            return snap["data"]
        data = _build_system_health_uncached()
        snap["data"] = data
        snap["ts"] = now
        return data


def system_health_reap(pids):
    """SIGTERM the given PIDs, but ONLY those that belong to a currently
    reapable session tree — never an interactive or working session. Recomputes
    the snapshot fresh (cache bypassed) so the guard can't be raced against a
    stale view the client was looking at."""
    health = build_system_health(force=True)
    allowed = set()
    for s in health["sessions"]:
        if s["reapable"]:
            allowed.update(s["tree_pids"])
    want = set(int(p) for p in pids if str(p).lstrip("-").isdigit())
    to_kill = sorted(want & allowed)
    blocked = sorted(want - allowed)
    killed = []
    for pid in to_kill:
        try:
            os.kill(pid, signal.SIGTERM)
            # Attribution: a user-triggered System Health reap. Lets a later
            # `exit` (SIGTERM) row be matched to this CCC-side kill rather than
            # being misread as an external / mystery death.
            _resume_ledger_append("kill", pid=pid, source="system_health_reap")
            killed.append(pid)
        except (ProcessLookupError, PermissionError):
            pass
    # Invalidate so the next poll reflects the kill immediately.
    _system_health_snapshot["data"] = None
    return {"ok": True, "killed": killed, "blocked": blocked}


def system_health_quit_app(app_id, timeout=8):
    spec = next((s for s in _SYS_GUI_APPS if s["id"] == app_id), None)
    if not spec:
        return {"ok": False, "error": "unknown app"}
    if platform.system() != "Darwin":
        return {"ok": False, "error": "graceful app quit is only supported on macOS"}
    script = f'tell application "{spec["app_name"]}" to quit'
    try:
        proc = subprocess.run(
            [_SYS_OSASCRIPT, "-e", script],
            capture_output=True,
            text=True,
            timeout=timeout,
        )
    except subprocess.TimeoutExpired:
        _system_health_snapshot["data"] = None
        return {
            "ok": False,
            "app_id": spec["id"],
            "app_name": spec["app_name"],
            "error": "quit timed out",
        }
    _system_health_snapshot["data"] = None
    ok = proc.returncode == 0
    out = {
        "ok": ok,
        "app_id": spec["id"],
        "app_name": spec["app_name"],
        "returncode": proc.returncode,
        "hard_kill_offered": False,
    }
    if not ok:
        err = (proc.stderr or proc.stdout or "").strip()
        out["error"] = err or "quit failed"
    return out


def build_live_sessions_activity():
    """Map session_id → live-work fields for every currently-live session.

    Coalesced: concurrent / rapid polls within _LIVE_ACTIVITY_SNAPSHOT_TTL
    share a single computation. See _live_activity_snapshot."""
    snap = _live_activity_snapshot
    now = time.time()
    if snap["data"] is not None and now - snap["ts"] < _LIVE_ACTIVITY_SNAPSHOT_TTL:
        return snap["data"]
    with _live_activity_snapshot_lock:
        # Another thread may have refreshed it while we waited for the lock.
        now = time.time()
        if snap["data"] is not None and now - snap["ts"] < _LIVE_ACTIVITY_SNAPSHOT_TTL:
            return snap["data"]
        # Time the REAL build — this is the truest health signal for the hot
        # path, and the only place an actual (non-cached) build happens.
        _t0 = time.perf_counter()
        data = _build_live_sessions_activity_uncached()
        _record_live_build_ms((time.perf_counter() - _t0) * 1000.0)
        snap["data"] = data
        snap["ts"] = time.time()
        return data


def _build_live_sessions_activity_uncached():
    out = {}
    # Pool-model Codex threads (desktop app-server) never appear in the
    # resume-arg/sidecar discovery scan — union the cached sqlite candidacy
    # set (same pattern as _auto_unarchive_live_sessions, CCC-435) so a turn
    # running in Codex desktop lights up its WIP chip too.
    candidates = _discover_live_session_ids() | _codex_pool_candidate_sids()
    for sid in candidates:
        if not _archive_session_is_live(sid):
            continue
        raw = _live_activity_entry_for_session(sid)
        out[sid] = {k: raw.get(k) for k in _LIVE_ACTIVITY_FIELD_KEYS}
    return out


def _sessions_state_snapshot():
    """Cheap {session_id: {state, question_waiting, needs_approval}} for every
    currently-live session, reusing the coalesced live-activity snapshot
    (candidacy-gated, ≤1.5s old) — no per-call JSONL walk or subprocess. This
    is the source the /api/sessions/events SSE stream diffs each tick.

    `state` is the canonical four-state label via `_stamp_session_state`, so it
    carries the same CCC-174 "waiting" hysteresis the dashboard applies.
    Sessions absent from the live map are simply not present here; the SSE
    layer treats a disappearance as a transition to "ended".

    Caveat: the sidecar-shaped entry has no `last_assistant_text`, so a
    prose-only soft-block (no formal question_waiting / needs_approval flag)
    reads "idle" here. The formal human-input signals — the ones a monitor
    most cares about — are always reflected.
    """
    out = {}
    try:
        activity = build_live_sessions_activity()
    except Exception:
        return out
    for sid, fields in (activity or {}).items():
        entry = dict(fields or {})
        entry["session_id"] = sid
        try:
            state = _stamp_session_state(entry)
        except Exception:
            state = "idle" if entry.get("is_live") else "ended"
        out[sid] = {
            "state": state,
            "question_waiting": bool(entry.get("question_waiting")),
            "needs_approval": bool(entry.get("needs_approval")),
        }
    return out


def _decode_project_slug(slug):
    """Best-effort reverse of _encode_project_slug. The encoding is lossy
    (every non-alphanumeric becomes `-`), so a single slug can map to many
    candidate paths; we pick the first one that exists on disk by walking
    from `/` and absorbing as many consecutive `-`-separated parts into
    each path component as needed to find an existing dir.

    Returns a Path (existing) or None when no candidate resolves. Used by
    find_all_conversations to give a clean folder label for slugs whose
    repo has hyphens in the name (e.g. `my-finance-app`).
    """
    if not slug.startswith("-"):
        return None
    parts = slug[1:].split("-")

    def search(prefix, remaining):
        if not remaining:
            return prefix if prefix.is_dir() else None
        for k in range(1, len(remaining) + 1):
            name = "-".join(remaining[:k])
            candidate = prefix / name
            if candidate.is_dir():
                result = search(candidate, remaining[k:])
                if result is not None:
                    return result
        return None

    try:
        return search(Path("/"), parts)
    except (OSError, ValueError):
        return None


_GENERATED_HELPER_SESSION_PREFIXES = (
    "Produce a concise 4-8 word title summarizing what the user is trying to do",
    "Produce a concise 4-8 word title for the GitHub issue below",
)

_TRANSCRIPT_CONTROL_PREFIXES = (
    "<system-reminder>",
    "<command-",
    "<local-command",
    "<bash-",
)


def _is_transcript_control_text(text):
    """Return True for Claude Code bookkeeping stored as user transcript text."""
    return bool((text or "").lstrip().startswith(_TRANSCRIPT_CONTROL_PREFIXES))


def _extract_command_invocation_text(text):
    """Turn Claude Code slash-command bookkeeping into the typed command."""
    head = (text or "").lstrip()
    if not (head.startswith("<command-name>") or head.startswith("<command-message>")):
        return ""
    m = re.search(r"<command-name>([^<]+)</command-name>", head)
    cmd_name = html.unescape(m.group(1).strip()) if m else ""
    if not cmd_name:
        m2 = re.search(r"<command-message>([^<]+)</command-message>", head)
        if m2:
            raw = html.unescape(m2.group(1).strip())
            cmd_name = raw if raw.startswith("/") else ("/" + raw)
    if not cmd_name:
        return ""
    m_args = re.search(r"<command-args>([^<]*)</command-args>", head)
    cmd_args = html.unescape(m_args.group(1).strip()) if m_args else ""
    return (cmd_name + (" " + cmd_args if cmd_args else "")).strip()


def _clean_claude_goal_objective(text):
    obj = (text or "").strip()
    obj = re.sub(r"^(?:[-*]\s+)+", "", obj).strip()
    return obj


def _apply_claude_goal_command(meta, command_text):
    """Update tail metadata from a visible Claude `/goal ...` command."""
    cmd = (command_text or "").strip()
    if not cmd.lower().startswith("/goal"):
        return
    rest = cmd[len("/goal"):].strip()
    if not rest:
        return
    first, _, remainder = rest.partition(" ")
    action = first.strip().lower()
    if action in ("clear", "cancel", "reset", "remove"):
        meta["goal"] = ""
        meta["goal_status"] = ""
        return
    if action in ("pause", "paused"):
        if meta.get("goal"):
            meta["goal_status"] = "paused"
        return
    if action in ("resume", "active", "start"):
        if meta.get("goal"):
            meta["goal_status"] = "active"
        return
    if action in ("block", "blocked"):
        if meta.get("goal"):
            meta["goal_status"] = "blocked"
        return
    if action in ("complete", "completed", "done"):
        if meta.get("goal"):
            meta["goal_status"] = "complete"
        return
    objective = remainder if action in ("set", "edit") and remainder else rest
    objective = _clean_claude_goal_objective(objective)
    if objective:
        meta["goal"] = objective
        meta["goal_status"] = "active"


def _extract_user_prompt_text(ev):
    """Extract user-visible prompt text from a JSONL event.

    Claude Code records slash/local-command bookkeeping as user messages in
    the transcript. Those rows are useful for replay, but they should not be
    treated as the session's title/original ask in CCC.
    """
    if ev.get("type") != "user" or ev.get("isMeta"):
        return ""
    msg = _safe_parse_message(ev.get("message", {}))
    text = _extract_text_from_content(msg.get("content", ""))
    if _is_transcript_control_text(text):
        return ""
    return _strip_ccc_session_state_instruction(text).strip()


def _extract_queued_command_prompt(ev):
    """Extract a queued human prompt from Claude Code attachment events.

    When the user types while Claude is busy, recent Claude Code builds write
    the prompt as an attachment:

      {"type": "attachment", "attachment": {"type": "queued_command", ...}}

    Those prompts are real user-visible turns and should render in CCC's
    transcript pane. Background task notifications also use queued_command,
    so only commandMode=prompt is treated as chat input.
    """
    if ev.get("type") != "attachment":
        return None
    attachment = ev.get("attachment")
    if not isinstance(attachment, dict):
        return None
    if attachment.get("type") != "queued_command":
        return None
    if attachment.get("commandMode") != "prompt":
        return None
    prompt = attachment.get("prompt", "")
    text = _extract_text_from_content(prompt)
    if _is_transcript_control_text(text):
        return None
    images = _extract_images_from_content(prompt)
    display_text = "" if (text == "[image]" and images) else text
    display_text = _strip_ccc_session_state_instruction(display_text).strip()
    if display_text or images:
        return {"text": display_text, "images": images}
    return None


def _is_generated_helper_session(first_message):
    """Return True for CCC's own throwaway utility prompts."""
    text = (first_message or "").lstrip()
    if not text:
        return False
    if text.startswith(_GENERATED_HELPER_SESSION_PREFIXES):
        return True
    return (
        text.startswith("Use the Read tool to open this image:")
        and "Then output ONLY a single JSON line" in text[:500]
    )


def _registry_epoch_seconds(value):
    try:
        ts = float(value)
    except (TypeError, ValueError):
        return 0.0
    if ts > 10_000_000_000:
        ts = ts / 1000.0
    return ts if ts > 0 else 0.0


def _spawn_registry_entry_for_session(session_id, engine=None):
    sid = str(session_id or "").strip()
    if not sid:
        return None
    try:
        entries = _load_spawn_registry()
    except Exception:
        return None
    for entry in entries:
        if entry.get("session_id") != sid and entry.get("resumed_sid") != sid:
            continue
        if engine and entry.get("engine") != engine:
            continue
        return entry
    if engine in (None, "codex"):
        reg = _codex_thread_registry_entry(sid)
        if reg:
            shaped = _codex_thread_registry_spawn_shape(reg)
            shaped.update({
                "session_id": sid,
                "engine": "codex",
                "codex_thread_registry": True,
            })
            return shaped
    return None


def _spawn_registry_entries_by_session(engine=None):
    """Return registry entries keyed by native session id.

    Used by list builders so they do not re-read the registry once per row.
    """
    out = {}
    try:
        entries = _load_spawn_registry()
    except Exception:
        return out
    for entry in entries:
        if engine and entry.get("engine") != engine:
            continue
        for key in ("session_id", "resumed_sid"):
            sid = str(entry.get(key) or "").strip()
            if sid and sid not in out:
                out[sid] = entry
    if engine in (None, "codex"):
        for sid, entry in _codex_thread_registry_entries().items():
            if sid and sid not in out:
                shaped = _codex_thread_registry_spawn_shape(entry)
                shaped.update({
                    "session_id": sid,
                    "engine": "codex",
                    "codex_thread_registry": True,
                })
                out[sid] = shaped
    return out


def _tail_meta_spawn_named(tail_meta):
    """True when Claude's transcript still reflects its launch --name."""
    custom_title = str((tail_meta or {}).get("custom_title") or "").strip()
    agent_name = str((tail_meta or {}).get("agent_name") or "").strip()
    return bool(custom_title and agent_name and custom_title == agent_name)


def _live_registry_conversation_row(
    session_id,
    meta,
    *,
    folder_path=None,
    folder_label=None,
    name_overrides=None,
    archived_set=None,
    trashed_set=None,
    pinned_rank=None,
    repo_pins=None,
    resolve_worktree_dirty=True,
):
    """Build a row for a live Claude session whose JSONL does not exist yet."""
    sid = str(session_id or "").strip()
    if not sid:
        return None
    cwd = str((meta or {}).get("cwd") or "").strip()
    natural_folder_path = folder_path or (_find_git_root(cwd) if cwd else "") or cwd
    natural_folder_label = folder_label or (
        _resolve_dir_case(natural_folder_path) if natural_folder_path else "Live session"
    )
    row_folder_path = natural_folder_path
    row_folder_label = natural_folder_label
    pinned_repo = False
    pin_target = (repo_pins or {}).get(sid)
    if pin_target and pin_target != row_folder_path:
        try:
            if Path(pin_target).is_dir():
                row_folder_path = pin_target
                row_folder_label = Path(pin_target).name
                pinned_repo = True
        except OSError:
            pass

    overrides = name_overrides or {}
    spawn_entry = _spawn_registry_entry_for_session(sid, engine="claude") or {}
    spawn_prompt = _strip_ccc_session_state_instruction(
        spawn_entry.get("command_summary") or ""
    ).strip()
    spawn_name = str(spawn_entry.get("name") or "").strip()
    parent_session_id = str(spawn_entry.get("parent_session_id") or "").strip()
    display_name = (
        overrides.get(sid)
        or (meta or {}).get("name")
        or spawn_name
        or (f"Session in {natural_folder_label}" if natural_folder_label and natural_folder_label not in ("Live session",) else f"Live session {sid[:8]}")
    )
    spawn_named = bool(spawn_name and display_name == spawn_name and not overrides.get(sid))
    mtime = (
        _registry_epoch_seconds((meta or {}).get("updatedAt"))
        or _registry_epoch_seconds((meta or {}).get("startedAt"))
        or time.time()
    )
    branch = _git_branch_for_cwd(cwd)
    cwd_is_worktree = bool(cwd and (Path(cwd) / ".git").is_file())
    row = {
        "id": sid,
        "session_id": sid,
        "jsonl_path": "",
        "slug": _encode_project_slug(row_folder_path) if row_folder_path else "live-session",
        "folder_label": row_folder_label,
        "folder_path": row_folder_path,
        "pinned_repo": pinned_repo,
        "source": "interactive",
        "engine": "claude",
        "timestamp": "",
        "session_cwd": cwd,
        "session_cwd_exists": bool(cwd and Path(cwd).is_dir()),
        "session_cwd_is_worktree": cwd_is_worktree,
        "mtime": mtime,
        "modified": mtime,
        "modified_human": time.strftime("%Y-%m-%d %H:%M", time.localtime(mtime)),
        "size": 0,
        "first_message": _prompt_fragment(spawn_prompt, 200) if spawn_prompt else "",
        "last_prompt": _prompt_fragment(spawn_prompt, 200) if spawn_prompt else "",
        "ai_title": None,
        "branch": branch,
        "git_branch": branch,
        "effective_branch": branch,
        "effective_kind": "worktree" if cwd_is_worktree else None,
        "display_name": display_name,
        "spawn_named": spawn_named,
        "name_overridden": bool(overrides.get(sid)),
        "archived": sid in (archived_set or set()),
        "trashed": sid in (trashed_set or set()),
        "recently_unarchived": _is_recently_unarchived(sid),
        "verified": False,
        "pinned": sid in (pinned_rank or {}),
        "pin_rank": (pinned_rank or {}).get(sid),
        "worktree_dirty": (
            _worktree_dirty_cached(cwd, mtime) if resolve_worktree_dirty and cwd else False
        ),
        "has_commit": False,
        "has_push": False,
        "has_edit": False,
        "tail_pr_number": None,
        "tail_pr_url": None,
        "pr_state": None,
        "is_live": True,
        "spawn_pid": (meta or {}).get("pid"),
        "last_assistant_text": "",
        "last_event_type": None,
        "pending_tool": None,
        "pending_file": None,
        "sidecar_status": None,
        "sidecar_has_writes": False,
        "sidecar_tool": None,
        "sidecar_file": None,
        "sidecar_ts": 0,
        "sidecar_in_flight": False,
        "needs_approval": False,
        "needs_approval_message": "",
        "question_waiting": False,
        "question_text": "",
        "question_header": "",
        "question_preamble": "",
        "question_options": [],
        "question_option_details": [],
        "parent_session_id": parent_session_id,
    }
    try:
        _add_sidecar_fields(row)
    except Exception:
        pass
    return row


def find_all_conversations(
    limit_per_folder=None,
    resolve_pr_states=True,
    resolve_effective=True,
    resolve_worktree_dirty=True,
    only_jsonl_paths=None,
):
    """Walk ~/.claude/projects/ for every subdir and return a flat list of
    conversation metadata across every folder you've ever Claude-Code'd in.

    Powers the multi-repo conversation archive: read-only browse of every
    JSONL on disk, regardless of whether a CCC server is currently running
    for that folder. Slow on cold scan (proportional to total JSONL count),
    so callers should expect ~seconds latency the first time. No caching
    layer in v1 — add later if it bites.

    Each entry:
        {session_id, jsonl_path, slug, folder_label, folder_path,
         mtime, size, first_message, git_branch}

    Folder resolution: known-repo paths from recent + custom files give a
    real label; unknown slugs fall back to a best-effort decode (replace
    `-` with `/` and verify) or just the raw slug.

    only_jsonl_paths: incremental mode (W84). When set (absolute path
    strings), build rows ONLY for those Claude transcripts — skip every
    other file, the registry-only augmentation, and the non-Claude engine
    finders. Callers merge the result into a cached full row set
    (_archive_merge_incremental_rows); rows for sources skipped here are
    carried over from that cache.
    """
    _only_dirs = None
    if only_jsonl_paths is not None:
        only_jsonl_paths = {str(p) for p in only_jsonl_paths}
        _only_dirs = {os.path.dirname(p) for p in only_jsonl_paths}
    projects_root = Path.home() / ".claude" / "projects"
    projects_root_exists = projects_root.is_dir()

    # Build slug → repo_path map for label resolution.
    known_by_slug = {}
    try:
        for repo in (_load_recent_repos() + _load_custom_repos()):
            try:
                known_by_slug[_encode_project_slug(repo)] = repo
            except Exception:
                pass
    except Exception:
        pass

    # Global state files keyed by session_id alone — same source of truth
    # the active-repo session list reads. Merging them in here lets the
    # archive view show user renames and route archived sessions into the
    # Archived bucket without a server-per-repo.
    try:
        name_overrides = _load_session_name_overrides()
    except Exception:
        name_overrides = {}
    try:
        archived_set, trashed_set = _load_conversation_lifecycle_sets()
    except Exception:
        archived_set, trashed_set = set(), set()
    try:
        pinned_list = _load_pinned_conversations()
    except Exception:
        pinned_list = []
    pinned_rank = _pinned_rank_map(pinned_list)
    try:
        repo_pins = _load_repo_pins()
    except Exception:
        repo_pins = {}
    spawn_registry_by_sid = _spawn_registry_entries_by_session(engine="claude")

    # Liveness gate, built once. The cheap "could be live right now" set —
    # Claude registry (one cached `ps`), engine resume-arg scan, sidecar marker
    # files — instead of running _archive_session_is_live (which scans every
    # Gemini/Codex file to classify the engine) for all ~1000 archive rows.
    # Below, only sessions in this set or written within _LIVE_MTIME_WINDOW get
    # the precise probe; the vast majority of rows are old and untouched and
    # resolve to not-live for free. This is the dominant cost of the build.
    try:
        live_candidates = _discover_live_session_ids()
    except Exception:
        live_candidates = set()

    out = []
    seen_session_ids = set()
    _now = time.time()

    project_dirs = []
    if projects_root_exists:
        try:
            project_dirs = list(projects_root.iterdir())
        except OSError:
            project_dirs = []

    for project_dir in project_dirs:
        if _only_dirs is not None and str(project_dir) not in _only_dirs:
            continue
        if not project_dir.is_dir():
            continue
        slug = project_dir.name

        repo_path = known_by_slug.get(slug)
        if repo_path:
            folder_label = _resolve_dir_case(repo_path)
            folder_path = repo_path
        else:
            decoded = _decode_project_slug(slug)
            if decoded:
                folder_label = _resolve_dir_case(str(decoded)) or slug
                folder_path = str(decoded)
            else:
                folder_label = _slug_to_label(slug)
                folder_path = slug

        # If this is a worktree dir (<parent>-wt-<name>), normalise
        # folder_label to the parent repo name so sessions group under
        # the parent, and stash the worktree suffix for the UI badge.
        _wt_worktree_label = None
        _wt_idx = folder_label.find("-wt-")
        if _wt_idx > 0:
            _wt_worktree_label = folder_label[_wt_idx + 4:]  # e.g. "gemini"
            folder_label = folder_label[:_wt_idx]             # e.g. "claude-command-center"

        try:
            jsonls = []
            for f in project_dir.iterdir():
                if only_jsonl_paths is not None and str(f) not in only_jsonl_paths:
                    continue
                if f.is_file() and f.name.endswith(".jsonl"):
                    try:
                        jsonls.append((f, f.stat()))
                    except OSError:
                        continue
        except OSError:
            continue

        jsonls.sort(key=lambda pair: pair[1].st_mtime, reverse=True)
        if limit_per_folder:
            jsonls = jsonls[:limit_per_folder]

        for f, stat in jsonls:
            session_id = f.stem
            if session_id in seen_session_ids:
                continue
            seen_session_ids.add(session_id)

            first_message = None
            timestamp = None
            git_branch = None
            session_cwd = None
            # Head-parse cache: the first ~20 lines (first_message / launch
            # branch / timestamp / cwd) never change after the session starts,
            # but this loop re-opened and re-JSON-parsed every transcript on
            # every poll — ~1274 file opens + json.loads per call, the dominant
            # warm cost once the tail-meta cache is hit. Cache by (mtime_ns,
            # size) just like _extract_tail_meta; archived transcripts resolve
            # for free. Reuse the already-stat'd `stat` — no extra syscall.
            _head_key = (stat.st_mtime_ns, stat.st_size)
            _hc = _conv_head_cache.get(str(f))
            if _hc is not None and _hc[0] == _head_key:
                first_message, git_branch, timestamp, session_cwd = _hc[1]
            else:
                try:
                    with open(f, "r") as fh:
                        for i, line in enumerate(fh):
                            if i >= 20:
                                break
                            line = line.strip()
                            if not line:
                                continue
                            try:
                                ev = json.loads(line)
                            except json.JSONDecodeError:
                                continue
                            if not first_message:
                                text = _extract_user_prompt_text(ev)
                                if text:
                                    first_message = text
                            if not git_branch:
                                git_branch = ev.get("gitBranch") or ev.get("git_branch")
                            if not timestamp:
                                timestamp = ev.get("timestamp")
                            if not session_cwd:
                                session_cwd = ev.get("cwd")
                            if first_message and git_branch and timestamp and session_cwd:
                                break
                except (OSError, UnicodeDecodeError):
                    pass
                _conv_head_cache[str(f)] = (
                    _head_key,
                    (first_message, git_branch, timestamp, session_cwd),
                )

            if _is_generated_helper_session(first_message):
                continue
            # Skip _resolve_session_cwd here — this is a cross-project
            # bulk scan, and the relocation walk per stale-cwd row hangs
            # /api/conversations/all on cold cache. Resolution still
            # happens lazily via find_session_cwd / find_conversations
            # (per-repo, cached) when the UI actually needs the cwd.

            # Reuse _extract_tail_meta — same source of truth /api/sessions
            # uses, mtime-cached. Pulls per-session signals from JSONL
            # tool-use events: has_edit (Edit/Write/NotebookEdit), has_commit
            # (`git commit` Bash), has_push (`git push` Bash), tail_pr_number
            # / tail_pr_url (`gh pr create` URL). It also records whether a
            # session ever used `cd <path>` / `git -C <path>`, which lets the
            # archive skip effective-repo inference for the common no-drift
            # case instead of walking tool paths for every recent transcript.
            try:
                tail_meta = _extract_tail_meta(f) or {}
            except Exception:
                tail_meta = {}

            # Tool-call inference — match what extract_session_workspace
            # does for active sessions. The JSONL's first-event cwd /
            # gitBranch reflect where the session was *launched*, but the
            # user often `cd`s into a worktree partway through, so the
            # branch chip would show "main" even when Claude has been
            # editing in `feat/foo` for hours. _infer_effective_repo walks
            # the session's tool-call paths and finds the dominant git
            # repo; it's mtime-cached internally so the cost amortizes.
            #
            # Recency gate: cold sessions older than the pills window have
            # static cwd/branch — the user can't have cd'd into a worktree
            # since "now" if the JSONL hasn't been touched in days. Skipping
            # inference there is the difference between a 1s and a 25s cold
            # scan on a ~1k-session archive (each call shells out to git
            # 1-4 times for rev-parse / branch / upstream / ahead-behind).
            effective_cwd = session_cwd or folder_path or ""
            effective_branch = git_branch
            effective_kind = None
            is_recent_for_inference = (
                (_now - stat.st_mtime) < _ARCHIVE_PILLS_RECENT_WINDOW
            )
            try:
                # Pass the already-stat'd mtime so the function can hit
                # its cache without re-walking PROJECTS_ROOT for every
                # session (otherwise 936 × 68 = ~63k stat calls per batch).
                eff = _infer_effective_repo(
                    session_id,
                    literal_cwd=session_cwd or folder_path,
                    jsonl_mtime=stat.st_mtime,
                ) if (
                    resolve_effective
                    and is_recent_for_inference
                    and tail_meta.get("has_external_cd")
                ) else None
            except Exception:
                eff = None
            if eff and eff.get("top"):
                effective_cwd = eff["top"]
                if eff.get("branch"):
                    effective_branch = eff["branch"]
                effective_kind = eff.get("kind")  # 'worktree' / 'clone' / 'other'

            # Worktree detection: prefer the inferred kind when available;
            # fall back to path-shape heuristics on the resolved cwd. Path
            # heuristics catch worktrees the user picked manually that
            # don't match `_infer_effective_repo`'s "dominant repo" rule.
            cwd_is_worktree = (
                effective_kind == "worktree"
                or "/.worktrees/" in effective_cwd
                or "/.claude/worktrees/" in effective_cwd
                or "-wt-" in Path(effective_cwd).name
                or Path(effective_cwd).parent.name.endswith("-wt")
            )

            # Per-row folder bucket. A user pin moves the row to a different
            # repo group without touching the transcript or fudging the
            # underlying session_cwd / branch / pills (those still reflect
            # reality). Pin is honored only when the target dir still
            # exists; stale pins fall back to the natural repo.
            row_folder_path = folder_path
            row_folder_label = folder_label
            pinned_repo = False
            pin_target = repo_pins.get(session_id)
            if pin_target and pin_target != folder_path:
                try:
                    if Path(pin_target).is_dir():
                        row_folder_path = pin_target
                        row_folder_label = Path(pin_target).name
                        pinned_repo = True
                except OSError:
                    pass

            spawn_named = _tail_meta_spawn_named(tail_meta)
            # Pick up any /rename done in the terminal — Claude Code writes
            # those as `custom-title` events with the new name, same shape
            # as our spawn-time titles. Old logic only honored custom_title
            # when it equaled agent_name (spawn_named), so a user /rename
            # diverged from agent_name and got dropped — matches Claude
            # Desktop behavior to take any custom_title verbatim.
            display_name = (
                name_overrides.get(session_id)
                or tail_meta.get("custom_title")
                or tail_meta.get("agent_name")
                or tail_meta.get("ai_title")
                or None
            )
            has_edit = bool(tail_meta.get("has_edit"))
            has_commit = bool(tail_meta.get("has_commit"))
            has_push = bool(tail_meta.get("has_push"))
            pr_number = tail_meta.get("tail_pr_number")
            pr_url = tail_meta.get("tail_pr_url")
            # worktree_dirty is a current-state signal (uncommitted edits
            # right now), not a per-session one. Use the cached probe
            # against the effective worktree, same as /api/sessions does.
            # last-meaningful activity (fallback to file mtime) — gates both the
            # worktree probe and the liveness probe to recently-active rows.
            _last_ts = tail_meta.get("last_meaningful_ts") or stat.st_mtime
            worktree_dirty = False
            try:
                # Only probe last-meaningful-ts'd sessions to keep this
                # cheap; old archive rows rarely need this state.
                if resolve_worktree_dirty and (_now - _last_ts) < (3 * 86400) and effective_cwd:
                    worktree_dirty = _worktree_dirty_cached(effective_cwd, _last_ts)
            except Exception:
                worktree_dirty = False
            # Only plausibly-live sessions get the precise (Gemini/Codex
            # file-scanning) liveness probe; stale rows are not live for free.
            if session_id in live_candidates or (_now - _last_ts) < _LIVE_MTIME_WINDOW:
                is_live = _archive_session_is_live(session_id)
            else:
                is_live = False

            # Sidecar overlay (Round 3): for live sessions, merge in the
            # sidecar's snapshot of "what is the agent doing right now"
            # — tool name, file, in-flight flag, needs-approval marker.
            # Cheap (one or two file reads per live session) and unlocks
            # the live-tool pill / sending pulse / needs-approval signal
            # on archive rows for free, since the existing renderer reads
            # these exact fields.
            sidecar_fields = {
                "sidecar_status": None,
                "sidecar_has_writes": False,
                "sidecar_tool": None,
                "sidecar_file": None,
                "sidecar_ts": 0,
                "sidecar_in_flight": False,
                "needs_approval": False,
                "needs_approval_message": "",
                "question_waiting": False,
                "question_text": "",
                "question_header": "",
                "question_preamble": "",
                "question_options": [],
                "question_option_details": [],
            }
            if is_live:
                _entry = {"session_id": session_id, "is_live": True}
                try:
                    _add_sidecar_fields(_entry)
                    for k in sidecar_fields:
                        if k in _entry:
                            sidecar_fields[k] = _entry[k]
                except Exception:
                    pass

            # Use transcript activity for the row timestamp. The JSONL file
            # can be rewritten later by metadata-only entries such as
            # custom-title updates; those should not make an old session look
            # active again in the archive list.
            row_mtime = tail_meta.get("last_meaningful_ts") or stat.st_mtime
            model = tail_meta.get("model") or ""
            latest_tok = tail_meta.get("latest_input_tokens") or 0
            if "[1m]" in model.lower() or latest_tok > 200_000:
                ctx_limit = 1_000_000
            else:
                ctx_limit = 200_000
            spawn_entry = spawn_registry_by_sid.get(session_id) or {}
            parent_session_id = str(spawn_entry.get("parent_session_id") or "").strip()
            if not parent_session_id:
                parent_session_id = _parent_session_id_from_return_address_text(first_message)
            out.append({
                "session_id": session_id,
                "source": "interactive",
                "engine": "claude",
                "jsonl_path": str(f),
                "slug": slug,
                "folder_label": row_folder_label,
                "folder_path": row_folder_path,
                "pinned_repo": pinned_repo,
                # Surface the inferred effective cwd / branch — these are
                # what the renderer's branch chip + worktree leaf read,
                # and they reflect where Claude actually edited (after
                # any `cd` into a worktree), not the launch values.
                "session_cwd": effective_cwd,
                "session_cwd_is_worktree": cwd_is_worktree,
                # Both keys carry the same recency timestamp. The per-repo
                # /api/sessions builder emits "modified"; this archive builder
                # historically emitted only "mtime". Clients fall back across
                # both (c.modified || c.mtime), but emitting both keeps the two
                # payload shapes identical so a consumer reading either field
                # never silently gets null.
                "mtime": row_mtime,
                "modified": row_mtime,
                "size": stat.st_size,
                "first_message": first_message[:200] if first_message else None,
                "ai_title": (tail_meta.get("ai_title") or None),
                # Both keys: `branch`/`git_branch` is the JSONL's literal
                # gitBranch (what the row defaults to when no inference);
                # `effective_branch`/`effective_kind` carry the tool-call
                # inference. The renderer prefers effective_branch and
                # uses effective_kind === 'worktree' to decide the
                # 🌿 leaf — without these the leaf never shows for
                # archive rows whose session was launched in a clone but
                # edited a sibling worktree.
                "branch": effective_branch,
                "git_branch": effective_branch,
                "effective_branch": effective_branch,
                "effective_kind": effective_kind,
                "display_name": display_name,
                "spawn_named": spawn_named,
                "name_overridden": bool(name_overrides.get(session_id)),
                "archived": session_id in archived_set,
                "trashed": session_id in trashed_set,
                "recently_unarchived": _is_recently_unarchived(session_id),
                "pinned": session_id in pinned_rank,
                "pin_rank": pinned_rank.get(session_id),
                # State pills + PR# + live flag — sourced from _extract_tail_meta
                # (per-session JSONL tool-use scan) plus a cached current-
                # state probe for worktree_dirty.
                "worktree_dirty": worktree_dirty,
                "has_commit": has_commit,
                "has_push": has_push,
                "has_edit": has_edit,
                "tail_pr_number": pr_number,
                "tail_pr_url": pr_url,
                # Resolved PR state ("OPEN" / "MERGED" / "CLOSED" / None).
                # Filled in below via a parallel prime pass so we don't
                # serially fan out to gh on cold-cache refreshes. None
                # means gh failed and the row stays visible to be safe.
                "pr_state": None,
                "is_live": is_live,
                # When the session lives in a sibling worktree dir (e.g.
                # "claude-command-center-wt-gemini"), folder_label is
                # normalised to the parent repo name and this field carries
                # the suffix so the UI can render a "wt-gemini" badge.
                "worktree_label": _wt_worktree_label,
                # Last assistant text — passed through so anyone re-enabling
                # the subtitle in archive can see it. Currently hidden via
                # _hideAskHtml flag in the UI shaper.
                "last_assistant_text": tail_meta.get("last_assistant_text") or "",
                # Attention API: the soft-block detector + ?state= filter read
                # these terminal-vs-working signals. All already computed by
                # _extract_tail_meta above, so surfacing them is free (no extra
                # parse / no subprocess). Without them the cross-repo attention
                # feed can't tell a paused-for-question session from a working
                # one whose sub-agent is still running.
                "last_event_type": tail_meta.get("last_event_type"),
                "pending_tool": tail_meta.get("pending_tool"),
                "pending_file": tail_meta.get("pending_file"),
                "subagent_in_flight_count": tail_meta.get("subagent_in_flight_count", 0),
                "session_state": _parse_session_state(tail_meta.get("last_assistant_text")),
                "goal": tail_meta.get("goal") or "",
                "goal_status": tail_meta.get("goal_status") or "",
                "parent_session_id": parent_session_id,
                # Context % badge — same fields as find_conversations so
                # archive rows can render sidebar usage without opening the
                # session pane.
                "model": model,
                "latest_input_tokens": latest_tok,
                "live_context_tokens": tail_meta.get("live_context_tokens") or 0,
                "live_context_limit": tail_meta.get("live_context_limit") or 0,
                "live_context_percent": tail_meta.get("live_context_percent") or 0,
                "context_limit": ctx_limit,
                **_token_optimizer_quality_for_session(session_id),
                # Sidecar overlay — only meaningful when is_live; cold
                # rows get safe defaults that suppress the live pill.
                **sidecar_fields,
            })

    # Incremental mode: rows for everything below (registry-only sessions,
    # non-Claude engines, remote) are carried over from the cached snapshot
    # by the merging caller; regenerating them here would replace rich cached
    # rows with partial ones. Overlays (pins, WT names, lanes) are reapplied
    # at serve time by _rehydrate_archive_cached_rows.
    if only_jsonl_paths is not None:
        if resolve_pr_states:
            _prime_pr_states(r.get("tail_pr_url") for r in out)
            for r in out:
                url = r.get("tail_pr_url")
                if url:
                    r["pr_state"] = _get_pr_state(url)
        _apply_pinned_conversation_fields(out, pinned_list)
        _apply_watchtower_worker_display_names(out)
        _apply_session_lane_overrides(out)
        return out

    # Claude can have a live process registry entry before it has written
    # a project JSONL. Surface those registry-only sessions so UUID search
    # and active-session discovery do not silently miss them.
    try:
        for sid, meta in _load_session_registry().items():
            if sid in seen_session_ids:
                continue
            row = _live_registry_conversation_row(
                sid,
                meta,
                name_overrides=name_overrides,
                archived_set=archived_set,
                trashed_set=trashed_set,
                pinned_rank=pinned_rank,
                repo_pins=repo_pins,
                resolve_worktree_dirty=resolve_worktree_dirty,
            )
            if row:
                out.append(row)
                seen_session_ids.add(sid)
    except Exception:
        pass

    # Add Codex threads to the archive too. They live in ~/.codex/state_*.sqlite
    # instead of ~/.claude/projects, but the row shape below matches the archive
    # renderer's existing Claude session rows.
    try:
        out.extend(find_codex_conversations(
            include_old=True,
            repo_only=False,
            limit=limit_per_folder,
            resolve_pr_states=resolve_pr_states,
            resolve_worktree_dirty=resolve_worktree_dirty,
        ))
    except Exception:
        pass

    # Add Gemini sessions to the archive too. They live in ~/.gemini/tmp/
    # and have their own JSON format, but find_gemini_conversations returns
    # rows compatible with the archive renderer.
    try:
        out.extend(find_gemini_conversations(
            include_old=True,
            repo_only=False,
            limit=limit_per_folder,
            resolve_pr_states=resolve_pr_states,
            resolve_worktree_dirty=resolve_worktree_dirty,
        ))
    except Exception:
        pass

    # Add Cursor agent transcripts from ~/.cursor/projects.
    try:
        out.extend(find_cursor_conversations(
            include_old=True,
            repo_only=False,
            limit=limit_per_folder,
            resolve_pr_states=resolve_pr_states,
            resolve_worktree_dirty=resolve_worktree_dirty,
        ))
    except Exception:
        pass

    # Add Antigravity sessions to the archive. Antigravity stores JSONL
    # transcripts under ~/.gemini/antigravity/brain/<uuid>/.
    try:
        out.extend(find_antigravity_conversations(
            include_old=True,
            repo_only=False,
            limit=limit_per_folder,
            resolve_pr_states=resolve_pr_states,
            resolve_worktree_dirty=resolve_worktree_dirty,
        ))
    except Exception:
        pass
    try:
        out.extend(find_kilo_conversations(
            include_old=True,
            repo_only=False,
            limit=limit_per_folder,
            resolve_pr_states=resolve_pr_states,
            resolve_worktree_dirty=resolve_worktree_dirty,
        ))
    except Exception:
        pass
    try:
        out.extend(find_hermes_conversations(
            include_old=True,
            repo_only=False,
            limit=limit_per_folder,
            resolve_pr_states=resolve_pr_states,
            resolve_worktree_dirty=resolve_worktree_dirty,
        ))
    except Exception:
        pass
    try:
        out.extend(_find_remote_sessions(limit=limit_per_folder))
    except Exception:
        pass

    if resolve_pr_states:
        # Parallel-resolve PR states for every row that recorded a PR URL.
        # Hits the in-process cache on warm refreshes; bounded thread pool
        # keeps the cold path under ~half a second even for hundreds of PRs.
        _prime_pr_states(r.get("tail_pr_url") for r in out)
        for r in out:
            url = r.get("tail_pr_url")
            if url:
                r["pr_state"] = _get_pr_state(url)
    _apply_pinned_conversation_fields(out, pinned_list)
    out.sort(key=lambda r: r["mtime"], reverse=True)
    _sort_pinned_conversations_first(out, pinned_list)
    # CCC-505: the cross-repo archive (this function) skipped the WT overlay
    # that find_all_sessions applies, so a dormant session whose display_name
    # was clipped at self-rename time (e.g. "CCC#496: ...sc…") never got the
    # unclipped rest attached — it just looked permanently truncated here.
    _apply_watchtower_worker_display_names(out)
    _apply_session_lane_overrides(out)
    return out


_ARCHIVE_RESPONSE_CACHE_SCHEMA_VERSION = 5
_ARCHIVE_RESPONSE_CACHE_FILE = COMMAND_CENTER_STATE_DIR / "archive-conversations-cache.json"
# The all-repos archive payload can be several MB on machines with years of
# agent history. Refreshing it every 30 seconds keeps the Python server in a
# near-permanent scan/JSON cycle and starves click-to-open requests. Keep the
# default conservative for freshness, but make it tunable for power users.
try:
    _ARCHIVE_RESPONSE_CACHE_FRESH_TTL = max(
        30.0,
        float(os.environ.get("CCC_ARCHIVE_CACHE_TTL_SEC", "300")),
    )
except ValueError:
    _ARCHIVE_RESPONSE_CACHE_FRESH_TTL = 300.0
_ARCHIVE_RESPONSE_CACHE_LOCK = threading.Lock()
_ARCHIVE_RESPONSE_CACHE_LOADED = False
_ARCHIVE_RESPONSE_CACHE = {}
_ARCHIVE_RESPONSE_REFRESHING = set()


def _archive_response_cache_key(
    *,
    include_prs=False,
    resolve_pr_states=False,
    resolve_effective=False,
    resolve_worktree_dirty=False,
):
    return (
        f"include_prs={int(bool(include_prs))};"
        f"resolve_prs={int(bool(resolve_pr_states))};"
        f"resolve_effective={int(bool(resolve_effective))};"
        f"resolve_worktrees={int(bool(resolve_worktree_dirty))}"
    )


def _load_archive_response_cache():
    global _ARCHIVE_RESPONSE_CACHE_LOADED
    with _ARCHIVE_RESPONSE_CACHE_LOCK:
        if _ARCHIVE_RESPONSE_CACHE_LOADED:
            return
        _ARCHIVE_RESPONSE_CACHE_LOADED = True
    try:
        with _ARCHIVE_RESPONSE_CACHE_FILE.open("r") as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError, ValueError):
        return
    if not isinstance(data, dict):
        return
    if data.get("schema_version") != _ARCHIVE_RESPONSE_CACHE_SCHEMA_VERSION:
        return
    entries = data.get("entries")
    if not isinstance(entries, dict):
        return
    keep = {}
    for key, entry in entries.items():
        if not isinstance(key, str) or not isinstance(entry, dict):
            continue
        if not isinstance(entry.get("conversations"), list):
            continue
        keep[key] = {
            "cached_at": float(entry.get("cached_at") or 0),
            "conversations": entry.get("conversations") or [],
            "signature": entry.get("signature") or None,
        }
    if keep:
        with _ARCHIVE_RESPONSE_CACHE_LOCK:
            _ARCHIVE_RESPONSE_CACHE.update(keep)


def _save_archive_response_cache():
    with _ARCHIVE_RESPONSE_CACHE_LOCK:
        snapshot = {
            "schema_version": _ARCHIVE_RESPONSE_CACHE_SCHEMA_VERSION,
            "entries": dict(_ARCHIVE_RESPONSE_CACHE),
        }
    try:
        _ARCHIVE_RESPONSE_CACHE_FILE.parent.mkdir(parents=True, exist_ok=True)
        tmp = _ARCHIVE_RESPONSE_CACHE_FILE.with_suffix(".json.tmp")
        with tmp.open("w") as f:
            json.dump(snapshot, f)
        tmp.replace(_ARCHIVE_RESPONSE_CACHE_FILE)
    except OSError as e:
        print(f"  [archive-cache] save failed: {e}")


def _archive_response_cache_get(key):
    _load_archive_response_cache()
    with _ARCHIVE_RESPONSE_CACHE_LOCK:
        entry = _ARCHIVE_RESPONSE_CACHE.get(key)
        if not entry:
            return None
        return {
            "cached_at": float(entry.get("cached_at") or 0),
            "conversations": [dict(r) for r in (entry.get("conversations") or []) if isinstance(r, dict)],
            "signature": entry.get("signature") or None,
        }


def _archive_response_cache_signature(key):
    """Signature of the persisted entry for `key`, without copying its rows
    (the full getter deep-copies every conversation dict — too heavy for a
    per-poll predicate)."""
    _load_archive_response_cache()
    with _ARCHIVE_RESPONSE_CACHE_LOCK:
        entry = _ARCHIVE_RESPONSE_CACHE.get(key)
        return (entry or {}).get("signature") or None


def _archive_response_cache_put(key, conversations, signature=None):
    rows = [dict(r) for r in (conversations or []) if isinstance(r, dict)]
    with _ARCHIVE_RESPONSE_CACHE_LOCK:
        _ARCHIVE_RESPONSE_CACHE[key] = {
            "cached_at": time.time(),
            "conversations": rows,
            "signature": signature,
        }
    _save_archive_response_cache()


def _archive_response_cache_is_stale(entry):
    return (time.time() - float(entry.get("cached_at") or 0)) > _ARCHIVE_RESPONSE_CACHE_FRESH_TTL


def _archive_response_refreshing(key):
    with _ARCHIVE_RESPONSE_CACHE_LOCK:
        return key in _ARCHIVE_RESPONSE_REFRESHING


def _archive_response_refresh_begin(key):
    with _ARCHIVE_RESPONSE_CACHE_LOCK:
        if key in _ARCHIVE_RESPONSE_REFRESHING:
            return False
        _ARCHIVE_RESPONSE_REFRESHING.add(key)
        return True


def _archive_response_refresh_end(key):
    with _ARCHIVE_RESPONSE_CACHE_LOCK:
        _ARCHIVE_RESPONSE_REFRESHING.discard(key)


# Per-cache-key build locks. The ?all=1 endpoints (dashboard + COO board poll
# them) had no single-flight: on a cold/changed cache, every concurrent poll
# kicked off its own O(all-sessions) _build_archive_conversations. N parallel
# full rebuilds pinned every core, GIL-starved click-to-open, and a 14s request
# wedged the server (ignored SIGTERM, had to be kill -9'd). The lock makes the
# rebuild single-flight: the first caller builds, the rest wait briefly and
# share the freshly-cached payload instead of stampeding the CPU.
_ARCHIVE_BUILD_LOCKS = {}
_ARCHIVE_BUILD_LOCKS_GUARD = threading.Lock()


def _archive_build_lock(key):
    with _ARCHIVE_BUILD_LOCKS_GUARD:
        lk = _ARCHIVE_BUILD_LOCKS.get(key)
        if lk is None:
            lk = threading.Lock()
            _ARCHIVE_BUILD_LOCKS[key] = lk
        return lk


# TTL-memoized wrapper around the corpus fingerprint. The fingerprint is a
# stat-only walk of the WHOLE transcript corpus (thousands of files), but it is
# GLOBAL — identical for every archive cache key. Without memoization each
# cache key's background refresh (dashboard + COO board + every filter/sort
# combo poll distinct keys) re-walked the entire corpus independently, so N
# concurrently-refreshing keys meant N full-corpus scandir passes every serve
# TTL. That O(keys × all-files) scandir per window is the sustained CPU burn
# `sample` caught across the `refresh` threads. Caching the signature for a
# short window collapses it to ONE walk per window shared by all keys. The TTL
# stays within the serve cache's existing staleness tolerance, so it introduces
# no correctness window the serve path didn't already have.
try:
    _ARCHIVE_SIG_TTL = max(0.0, float(os.environ.get("CCC_ARCHIVE_SIG_TTL_SEC", "2")))
except ValueError:
    _ARCHIVE_SIG_TTL = 2.0
_archive_sig_cache = {"ts": 0.0, "sig": None}
_archive_sig_lock = threading.Lock()

# Per-signature stat maps, retained from the signature walk (which already
# stats every transcript — this just stops discarding the result). Keyed by
# the signature hash, value is ({jsonl_path: (mtime_ns, size)}, {extra: mtime}).
# Two remembered signatures ⇒ an exact file-level diff of what changed between
# them, which is what lets _archive_compute_rows re-parse ONLY the touched
# transcripts instead of rebuilding all ~1000+ rows on every corpus change.
# Small LRU: entries are ~100KB each; live corpora produce a new signature
# every few seconds and only the cached response entries' signatures matter.
_ARCHIVE_STATMAP_BY_SIG = {}
_ARCHIVE_STATMAP_MAX = 16
# A delta larger than this falls back to the full rebuild — the incremental
# path exists for the steady-state "a handful of sessions wrote" case, not to
# re-implement the builder for bulk changes (restores, migrations, first run).
try:
    _ARCHIVE_INCR_MAX_FILES = max(0, int(os.environ.get("CCC_ARCHIVE_INCR_MAX_FILES", "200")))
except ValueError:
    _ARCHIVE_INCR_MAX_FILES = 200


def _archive_corpus_signature():
    """Corpus fingerprint, memoized for _ARCHIVE_SIG_TTL so concurrent per-key
    refreshes share one full-corpus walk instead of each re-scanning it."""
    if _ARCHIVE_SIG_TTL > 0:
        now = time.time()
        with _archive_sig_lock:
            c = _archive_sig_cache
            if c["sig"] is not None and (now - c["ts"]) < _ARCHIVE_SIG_TTL:
                return c["sig"]
    sig, files, extras = _archive_corpus_signature_parts()
    with _archive_sig_lock:
        if _ARCHIVE_SIG_TTL > 0:
            _archive_sig_cache["ts"] = time.time()
            _archive_sig_cache["sig"] = sig
        _ARCHIVE_STATMAP_BY_SIG.pop(sig, None)
        _ARCHIVE_STATMAP_BY_SIG[sig] = (files, extras)
        while len(_ARCHIVE_STATMAP_BY_SIG) > _ARCHIVE_STATMAP_MAX:
            _ARCHIVE_STATMAP_BY_SIG.pop(next(iter(_ARCHIVE_STATMAP_BY_SIG)))
    return sig


def _archive_signature_delta(old_sig, new_sig):
    """File-level diff between two remembered corpus signatures.

    Returns (changed_paths, removed_paths) — changed covers added AND edited
    Claude transcripts — or None when a full rebuild is required: unknown
    signature (restart, LRU eviction), a non-Claude engine source changed
    (those are dir-granularity in the signature, so no file diff exists), or
    the delta is too large to be worth the incremental path.
    """
    if not old_sig or not new_sig or old_sig == new_sig:
        return None
    with _archive_sig_lock:
        old = _ARCHIVE_STATMAP_BY_SIG.get(old_sig)
        new = _ARCHIVE_STATMAP_BY_SIG.get(new_sig)
    if not old or not new:
        return None
    old_files, old_extras = old
    new_files, new_extras = new
    if old_extras != new_extras:
        return None
    changed = [p for p, st in new_files.items() if old_files.get(p) != st]
    removed = [p for p in old_files if p not in new_files]
    if not changed and not removed:
        return None
    if _ARCHIVE_INCR_MAX_FILES <= 0 or len(changed) > _ARCHIVE_INCR_MAX_FILES:
        return None
    return changed, removed


def _archive_merge_incremental_rows(cached_rows, fresh_rows, removed_paths):
    """Merge freshly-built rows for changed transcripts into the cached row
    set: replace by session id (falling back to jsonl path), drop rows whose
    transcript was removed, append genuinely new sessions. Ordering is not
    this function's job — _rehydrate_archive_cached_rows re-sorts by mtime
    and re-applies pinned-first on every serve.
    """
    removed = set(removed_paths or [])
    fresh_by_key = {}
    for r in fresh_rows or []:
        if not isinstance(r, dict):
            continue
        k = r.get("session_id") or r.get("id") or r.get("jsonl_path")
        if k:
            fresh_by_key[k] = r
    out = []
    for raw in cached_rows or []:
        if not isinstance(raw, dict):
            continue
        jp = raw.get("jsonl_path")
        if jp and jp in removed:
            continue
        k = raw.get("session_id") or raw.get("id") or jp
        if k and k in fresh_by_key:
            out.append(fresh_by_key.pop(k))
            continue
        out.append(raw)
    out.extend(fresh_by_key.values())
    return out


def _archive_corpus_signature_uncached():
    """Signature hash only — see _archive_corpus_signature_parts."""
    return _archive_corpus_signature_parts()[0]


def _archive_corpus_signature_parts():
    """Cheap stat-only fingerprint of the conversation corpus on disk.

    No JSON parse, no subprocess, no per-row liveness probe — just the
    (mtime_ns, size) of every Claude transcript plus the mtime of the engine
    transcript roots and CCC state dirs that feed archive rows. Two identical
    signatures ⇒ nothing the archive build reads has changed, so the persisted
    response payload can be served as-is without an O(all-sessions) rebuild.

    A new/edited/removed transcript flips a file's mtime (and the dir mtime),
    so the signature changes and the cache invalidates immediately — no TTL
    staleness window for the dominant Claude corpus. Engine sources beyond
    ~/.claude/projects are covered at directory granularity (their root mtime
    changes when sessions are added/removed); in-place edits there fall back to
    the build cache's own (mtime,size) gating on the next signature change.

    Deliberately EXCLUDES fast-changing live state (sidecar markers, the spawned
    registry): those mutate on every poll while a session is live, so folding
    them in would bust the build cache constantly and pin the CPU. Live state is
    not part of the expensive build — it is layered back on by
    _rehydrate_archive_cached_rows and coalesced by the serve cache, so it does
    not need to gate the transcript-parse cache.
    """
    parts = []
    files = {}
    extras_map = {}
    projects_root = Path.home() / ".claude" / "projects"
    try:
        dir_paths = sorted(
            e.path for e in os.scandir(projects_root) if e.is_dir()
        )
    except OSError:
        dir_paths = []
    for d in dir_paths:
        try:
            with os.scandir(d) as it:
                for e in it:
                    if not e.name.endswith(".jsonl"):
                        continue
                    try:
                        st = e.stat()
                    except OSError:
                        continue
                    parts.append(f"{e.path}|{st.st_mtime_ns}|{st.st_size}")
                    files[e.path] = (st.st_mtime_ns, st.st_size)
        except OSError:
            continue
    # Fold in dir-level mtimes of sibling engine transcript stores so adds /
    # removes / renames there also bust the cache. stat() only — cheap. These
    # are transcript corpora (not live state), so they are safe to gate on.
    for extra in (
        Path.home() / ".codex" / "sessions",
        Path.home() / ".cursor" / "projects",
        Path.home() / ".gemini" / "antigravity" / "brain",
        Path.home() / ".hermes" / "state.db",
    ):
        try:
            mt = os.stat(extra).st_mtime_ns
        except OSError:
            continue
        parts.append(f"{extra}|{mt}")
        extras_map[str(extra)] = mt
    parts.sort()
    h = hashlib.sha1()
    for p in parts:
        h.update(p.encode("utf-8", "replace"))
        h.update(b"\n")
    h.update(str(len(parts)).encode())
    return h.hexdigest(), files, extras_map


# Short-TTL coalescing cache for the fully-rehydrated ?all=1 payload. The
# dashboard AND the COO board both poll these endpoints; without coalescing,
# every concurrent poll re-ran _rehydrate_archive_cached_rows — whose dominant
# cost is the per-live-session _archive_session_is_live probe (engine
# classification scans, ~25ms each). Under real polling those probes serialized
# on the GIL and held the endpoint at 1-2s + a sustained CPU burn. Same fix and
# rationale as _live_activity_snapshot's 1.5s window: serve one ≤TTL-old
# rehydrated snapshot to all concurrent callers. Transcript-derived fields
# (state / ended_blocked / question from JSONL) are signature-gated and stay
# fresh on any real change; only process-liveness/sidecar lag, by ≤TTL.
try:
    _ARCHIVE_SERVE_TTL = max(0.0, float(os.environ.get("CCC_ARCHIVE_SERVE_TTL_SEC", "2")))
except ValueError:
    _ARCHIVE_SERVE_TTL = 2.0
_archive_serve_cache = {}      # key -> {"ts", "rows"}
_archive_serve_lock = threading.Lock()
_archive_serve_refreshing = set()  # keys with a background refresh in flight
_archive_serve_generation = 0


def _archive_serve_cache_store(key, rows, generation):
    """Store rows only if no lifecycle mutation invalidated their build."""
    with _archive_serve_lock:
        if generation != _archive_serve_generation:
            return False
        _archive_serve_cache[key] = {"ts": time.time(), "rows": rows}
        return True


def _clear_archive_serve_cache():
    global _archive_serve_generation
    with _archive_serve_lock:
        _archive_serve_cache.clear()
        _archive_serve_generation += 1


# Coalescing cache for the spawned-session list on the ?all=1 hot path.
# list_spawned_sessions() runs best-effort desktop-visibility/registry side
# effects per spawned entry (_spawn_session_id_from_entry), so a box with a
# dozen+ spawned agents spends ~1-2s in it — per request, uncoalesced. After the
# archive build was cached this became the dominant cost of /api/{sessions,
# conversations}?all=1, which the dashboard AND COO board poll. Coalesce it on
# the same short window as the serve cache: the side effects still fire (at most
# once per window) and concurrent polls share one result.
_archive_spawned_cache = {"ts": 0.0, "data": None}
_archive_spawned_lock = threading.Lock()
_archive_spawned_refreshing = False


def _archive_spawned_refresh():
    global _archive_spawned_refreshing
    try:
        data = list_spawned_sessions()
        with _archive_spawned_lock:
            _archive_spawned_cache["ts"] = time.time()
            _archive_spawned_cache["data"] = data
    except Exception as e:
        print(f"  [spawned-cache] refresh failed: {e}")
    finally:
        with _archive_spawned_lock:
            _archive_spawned_refreshing = False


def _archive_spawned_coalesced():
    """Spawned-session list for the ?all=1 hot path, stale-while-revalidate.

    list_spawned_sessions() costs ~1-2s on a box with a dozen+ spawned agents
    (best-effort desktop-visibility side effects per entry), so blocking the
    request on it — even coalesced — leaves one unlucky poll per window stalled.
    Instead: serve the last known list immediately and refresh in the background
    when it goes stale. The request path never pays the cost (after a one-time
    cold build); the side effects run off-thread; staleness is ≤ the serve TTL
    plus one refresh. Spawned sessions appear/finish slowly, so this is safe.
    """
    global _archive_spawned_refreshing
    if _ARCHIVE_SERVE_TTL <= 0:
        return list_spawned_sessions()
    start_refresh = False
    with _archive_spawned_lock:
        data = _archive_spawned_cache["data"]
        age = time.time() - _archive_spawned_cache["ts"]
        if data is None:
            # A cold spawned-session scan can be the slowest part of all=1:
            # each retained spawn may need process and transcript discovery.
            # Serve an empty snapshot for this first poll and populate the
            # cache off-thread; the next poll receives the full list.
            if not _archive_spawned_refreshing:
                _archive_spawned_refreshing = True
                start_refresh = True
        else:
            if age >= _ARCHIVE_SERVE_TTL and not _archive_spawned_refreshing:
                _archive_spawned_refreshing = True
                threading.Thread(target=_archive_spawned_refresh, daemon=True).start()
            return [dict(r) for r in data]
    if not start_refresh:
        return []
    refresh_thread = threading.Thread(target=_archive_spawned_refresh, daemon=True)
    refresh_thread.start()
    # Preserve the prior first-response shape when discovery is genuinely
    # cheap, without letting a slow registry/transcript walk own the request.
    refresh_thread.join(timeout=0.05)
    with _archive_spawned_lock:
        data = _archive_spawned_cache["data"]
    return [dict(r) for r in (data or [])]


def _archive_all_rows_cached(cache_options):
    """Archive rows for an ?all=1 request, served from the persisted response
    cache when the on-disk corpus is unchanged.

    Three tiers, cheapest first:
      1. Coalescing serve cache: a fully-rehydrated snapshot ≤_ARCHIVE_SERVE_TTL
         old for the same corpus signature → return a copy immediately, so
         concurrent dashboard/COO polls share one rehydrate instead of each
         re-probing liveness.
      2. Signature-matched response cache: rehydrate the persisted rows (cheap —
         refresh only fast-changing live/sidecar/name/pin state, same transform
         /api/conversations/all's stale-serve uses) with NO O(all-sessions)
         rebuild.
      3. Miss / changed corpus: rebuild once under a per-key lock so concurrent
         pollers don't stampede the CPU (the bug that wedged the server),
         persist with the new signature, return raw build rows (identical shape
         to today's direct-build response).

    Returns (rows, from_cache: bool). from_cache is False only when tier 3 ran.
    """
    key = _archive_response_cache_key(**cache_options)
    return _archive_serve_rows(key, cache_options)


def _stamp_archive_state(rows):
    """Stamp the single-source-of-truth coarse `state` + `ended_blocked` onto
    every archive row, IN PLACE.

    Same stamp /api/sessions applies via _apply_session_query_params, lifted into
    the snapshot itself so it is cache-safe: it lands in the stale-while-revalidate
    serve cache and the persisted-rows cold serve, so /api/conversations?all=1
    (which has no post-serve projection pass) carries `state`/`ended_blocked` on
    every warm hit, not just on a cold build. Pure string/flag work on fields
    already merged onto the row — no subprocess, no transcript parse — so it is
    safe to run at build/rehydrate time on all rows. Additive: touches only the
    two keys.
    """
    for r in rows or []:
        if isinstance(r, dict):
            r["state"] = _stamp_session_state(r)
            r["ended_blocked"] = _session_ended_blocked(r)
    return rows


def _stamp_archive_goals(rows):
    """Stamp the current codex `/goal` objective + status onto codex rows, IN
    PLACE, at serve time.

    Goal lives in ~/.codex/goals_1.sqlite — outside the transcript corpus
    signature and not re-layered by _rehydrate_archive_cached_rows — so a goal
    set or cleared after the persisted build would never reach the row without
    this pass. ONE batched, cached snapshot read (no per-row DB work), so it is
    cache-safe to run on every warm serve, exactly like _stamp_archive_state.
    Additive: only touches `goal`/`goal_status`, and only on codex rows.
    """
    snap = _codex_goals_snapshot()
    for r in rows or []:
        if not isinstance(r, dict) or r.get("engine") != "codex":
            continue
        sid = r.get("session_id") or r.get("id")
        g = snap.get(sid) if sid else None
        if g:
            r["goal"] = g.get("objective") or ""
            r["goal_status"] = g.get("status") or ""
        else:
            r["goal"] = ""
            r["goal_status"] = ""
    return rows


def _archive_compute_rows(key, cache_options, serve_generation=None):
    """Produce archive rows under the per-key build lock (single-flight).

    Signature-gated: unchanged transcript corpus → rehydrate the persisted rows
    (cheap, refreshes only live/sidecar state); changed → rebuild, reusing the
    per-(mtime,size) parse cache so only the touched sessions re-parse. Updates
    both the persisted response cache and the in-memory serve snapshot.
    Returns (rows, from_cache).
    """
    if serve_generation is None:
        with _archive_serve_lock:
            serve_generation = _archive_serve_generation
    sig = _archive_corpus_signature()
    lock = _archive_build_lock(key)
    with lock:
        entry = _archive_response_cache_get(key)
        if entry and entry.get("signature") == sig:
            rows = _rehydrate_archive_cached_rows(entry.get("conversations") or [])
            from_cache = True
        else:
            rows = None
            # Incremental tier: the corpus changed, but if we know exactly
            # WHICH transcripts changed (both signatures' stat maps are still
            # in memory) re-parse only those and merge into the cached rows.
            # This is what keeps a brand-new session's list/search visibility
            # at "one refresh" instead of "one full O(all-rows) rebuild"
            # (~12s warm, 60-95s live under GIL contention — measured, W84).
            # include_prs entries are excluded: their row set carries a
            # list-level open-PR overlay the delta build can't reproduce.
            if entry and not cache_options.get("include_prs"):
                delta = _archive_signature_delta(entry.get("signature"), sig)
                if delta is not None:
                    changed, removed = delta
                    try:
                        fresh = find_all_conversations(
                            resolve_pr_states=cache_options.get("resolve_pr_states", False),
                            resolve_effective=cache_options.get("resolve_effective", False),
                            resolve_worktree_dirty=cache_options.get("resolve_worktree_dirty", False),
                            only_jsonl_paths=set(changed),
                        ) if changed else []
                        merged = _archive_merge_incremental_rows(
                            entry.get("conversations") or [], fresh, removed,
                        )
                        _archive_response_cache_put(key, merged, signature=sig)
                        _save_conv_meta_cache()
                        rows = _rehydrate_archive_cached_rows(merged)
                        from_cache = True
                    except Exception as e:
                        print(f"  [archive-cache] incremental refresh failed, rebuilding: {e}")
                        rows = None
            if rows is None:
                rows = _build_archive_conversations(**cache_options)
                _archive_response_cache_put(key, rows, signature=sig)
                _save_conv_meta_cache()
                from_cache = False
    _stamp_archive_state(rows)  # cache-safe: stamp lives in the served snapshot
    _stamp_archive_goals(rows)  # cache-safe: codex goal layered on at serve time
    _apply_watchtower_worker_display_names(rows)  # cache-safe: refresh WT ticket badge
    if _ARCHIVE_SERVE_TTL > 0:
        _archive_serve_cache_store(key, rows, serve_generation)
    return rows, from_cache


def _archive_serve_refresh(key, cache_options, serve_generation):
    global _archive_serve_refreshing
    try:
        _archive_compute_rows(key, cache_options, serve_generation)
    except Exception as e:
        print(f"  [archive-serve] background refresh failed: {e}")
    finally:
        with _archive_serve_lock:
            _archive_serve_refreshing.discard(key)


def _archive_refresh_is_cheap(key, cache_options):
    """True when refreshing this key now would take the fast path in
    _archive_compute_rows: corpus signature unchanged (rehydrate-only) or a
    known-small transcript delta (incremental merge). Both are sub-second;
    everything else means a full O(all-rows) rebuild that must stay off the
    request path. Signature is memoized (TTL) and the cache probe is an
    in-memory dict read, so this predicate is cheap enough per poll.
    """
    try:
        entry_sig = _archive_response_cache_signature(key)
        if not entry_sig:
            return False
        sig = _archive_corpus_signature()
        if entry_sig == sig:
            return True
        if cache_options.get("include_prs"):
            return False
        return _archive_signature_delta(entry_sig, sig) is not None
    except Exception:
        return False


def _archive_serve_rows(key, cache_options):
    """Archive rows for an ?all=1 request, stale-while-revalidate.

    The endpoint is polled continuously by the dashboard AND the COO board, and
    in a live environment a session is almost always writing its JSONL — so the
    corpus signature changes on nearly every poll. Blocking each poll on the
    signature-gated rebuild (~1-2s, GIL-bound) is exactly the sustained CPU
    drain we are killing. Instead:

      - fresh snapshot (< serve TTL) → return a copy immediately;
      - stale snapshot → return it immediately AND kick a single background
        refresh (the request never pays the rebuild);
      - no snapshot yet (cold) → build once synchronously.

    Same shape and tolerance as _live_activity_snapshot and the sibling
    /api/conversations/all?stale_ok serve: transcript-derived fields
    (state/ended_blocked/question) and live state lag by at most the serve TTL
    plus one background refresh. The signature still gates the actual rebuild, so
    a changed corpus re-parses only the touched sessions.

    Returns (rows, from_cache). from_cache is False only on the cold build.
    """
    global _archive_serve_refreshing
    if _ARCHIVE_SERVE_TTL <= 0:
        return _archive_compute_rows(key, cache_options)
    now = time.time()
    with _archive_serve_lock:
        serve_generation = _archive_serve_generation
        sc = _archive_serve_cache.get(key)
        if sc is not None:
            rows = [dict(r) for r in sc.get("rows") or []]
            stale = (now - sc.get("ts", 0)) >= _ARCHIVE_SERVE_TTL
            if stale and key not in _archive_serve_refreshing:
                _archive_serve_refreshing.add(key)
                spawn = True
            else:
                spawn = False
        else:
            rows = None
            spawn = False
    if rows is not None:
        if spawn:
            # W84: when the refresh is predictably cheap — corpus unchanged
            # (rehydrate-only) or a known-small file delta (incremental tier)
            # — run it synchronously so a transcript that landed since the
            # last snapshot is IN this poll's response, not the next one's.
            # A 60s-cadence dashboard poll otherwise always trails reality by
            # a full poll cycle even after the rebuild itself got cheap. The
            # slow cases (unknown signature, engine-source change, bulk delta
            # → full rebuild) keep the stale-serve + background refresh.
            if _archive_refresh_is_cheap(key, cache_options):
                try:
                    return _archive_compute_rows(key, cache_options, serve_generation)
                except Exception as e:
                    print(f"  [archive-serve] sync refresh failed, serving stale: {e}")
                finally:
                    with _archive_serve_lock:
                        _archive_serve_refreshing.discard(key)
                return rows, True
            threading.Thread(
                target=_archive_serve_refresh,
                args=(key, cache_options, serve_generation),
                daemon=True,
            ).start()
        return rows, True
    # Cold (e.g. just after a restart): the in-memory serve snapshot is empty.
    # Rather than block this first caller on a full rebuild (~20-30s cold), serve
    # the persisted response payload from the last run (rehydrated for fresh
    # live state) and rebuild in the background. Only a truly first-ever run with
    # no persisted cache builds synchronously.
    entry = _archive_response_cache_get(key)
    if entry and entry.get("conversations"):
        rows = _rehydrate_archive_cached_rows(entry.get("conversations") or [])
        _stamp_archive_state(rows)  # cache-safe: stamp lives in the served snapshot
        _stamp_archive_goals(rows)  # cache-safe: codex goal layered on at serve time
        _apply_watchtower_worker_display_names(rows)  # cache-safe: refresh WT ticket badge
        stored = _archive_serve_cache_store(key, rows, serve_generation)
        with _archive_serve_lock:
            if stored and key not in _archive_serve_refreshing:
                _archive_serve_refreshing.add(key)
                spawn = True
            else:
                spawn = False
        if spawn:
            threading.Thread(
                target=_archive_serve_refresh,
                args=(key, cache_options, serve_generation),
                daemon=True,
            ).start()
        return [dict(r) for r in rows], True
    # Nothing persisted yet — build once synchronously.
    return _archive_compute_rows(key, cache_options, serve_generation)


_ARCHIVE_SIDECAR_DEFAULTS = {
    "sidecar_status": None,
    "sidecar_has_writes": False,
    "sidecar_tool": None,
    "sidecar_file": None,
    "sidecar_ts": 0,
    "sidecar_in_flight": False,
    "needs_approval": False,
    "needs_approval_message": "",
    "question_waiting": False,
    "question_text": "",
    "question_header": "",
    "question_preamble": "",
    "question_options": [],
    "question_option_details": [],
}


def _rehydrate_archive_cached_rows(rows):
    """Apply fast-changing state to cached archive rows before responding."""
    try:
        name_overrides = _load_session_name_overrides()
    except Exception:
        name_overrides = {}
    try:
        archived_set, trashed_set = _load_conversation_lifecycle_sets()
    except Exception:
        archived_set, trashed_set = set(), set()
    try:
        verified_set = set(_load_verified_conversations())
    except Exception:
        verified_set = set()
    try:
        pinned_list = _load_pinned_conversations()
    except Exception:
        pinned_list = []
    pinned_rank = _pinned_rank_map(pinned_list)
    try:
        spawn_registry_by_sid = _spawn_registry_entries_by_session()
    except Exception:
        spawn_registry_by_sid = {}

    # Same liveness gate as the build path. This rehydrate runs on EVERY
    # stale-cache serve — the path the dashboard hits on each load — so an
    # ungated per-row _archive_session_is_live (which scans every Gemini/Codex
    # file to classify the engine) for all ~1000 rows was the real recurring
    # "10s to load" even when the response cache was warm. Probe only the cheap
    # live-candidate set + recently-written rows; the rest are not live for free.
    try:
        live_candidates = _discover_live_session_ids()
    except Exception:
        live_candidates = set()
    _now_rehydrate = time.time()

    hydrated = []
    for raw in rows or []:
        if not isinstance(raw, dict):
            continue
        row = dict(raw)
        sid = row.get("session_id") or row.get("id")
        if sid:
            override = name_overrides.get(sid)
            if override:
                row["display_name"] = override
                row["name_overridden"] = True
            else:
                # Keep whatever display_name the parser already derived
                # (which, for dormant sessions, includes any custom-title
                # event the user wrote via `/rename` in Claude Code OR the
                # rename_session() write-through to the JSONL). Previously
                # we set display_name=None for interactive sessions without
                # a side-car override — that wiped the JSONL-derived rename
                # on every fetch and the client fell back to the AI title.
                # Don't lose user intent recorded in the JSONL.
                row["name_overridden"] = False

            row["archived"] = sid in archived_set
            row["trashed"] = sid in trashed_set
            row["recently_unarchived"] = _is_recently_unarchived(sid, _now_rehydrate)
            row["verified"] = sid in verified_set
            row["pinned"] = sid in pinned_rank
            row["pin_rank"] = pinned_rank.get(sid)
            spawn_parent_id = str(
                (spawn_registry_by_sid.get(sid) or {}).get("parent_session_id") or ""
            ).strip()
            if not spawn_parent_id:
                spawn_parent_id = _parent_session_id_from_return_address_text(
                    row.get("first_message")
                )
            if not spawn_parent_id and sid in spawn_registry_by_sid and row.get("jsonl_path"):
                spawn_parent_id = _parent_session_id_from_transcript_return_address(
                    row.get("jsonl_path")
                )
            if spawn_parent_id:
                row["parent_session_id"] = spawn_parent_id
            else:
                row.setdefault("parent_session_id", "")

            row_ts = row.get("mtime") or row.get("modified") or 0
            if sid in live_candidates or (_now_rehydrate - row_ts) < _LIVE_MTIME_WINDOW:
                is_live = _archive_session_is_live(sid)
            else:
                is_live = False
            row["is_live"] = is_live
            for k, v in _ARCHIVE_SIDECAR_DEFAULTS.items():
                row[k] = copy.deepcopy(v)
            if is_live:
                live_row = {"session_id": sid, "is_live": True}
                try:
                    _add_sidecar_fields(live_row)
                    for k in _ARCHIVE_SIDECAR_DEFAULTS:
                        if k in live_row:
                            row[k] = live_row[k]
                except Exception:
                    pass
        hydrated.append(row)

    _apply_pinned_conversation_fields(hydrated, pinned_list)
    hydrated.sort(key=lambda r: r.get("mtime") or r.get("modified") or 0, reverse=True)
    _sort_pinned_conversations_first(hydrated, pinned_list)
    _apply_session_lane_overrides(hydrated)
    _stamp_archive_state(hydrated)
    # Layer the current codex goal on every rehydrate (one batched, cached read)
    # so the stale_ok serve the dashboard polls reflects goal set/clear without
    # waiting for a full transcript-signature rebuild.
    _stamp_archive_goals(hydrated)
    # Same reasoning for WT ticket badges: without this, a session that closes
    # a new ticket only gets its display_name refreshed on the next full
    # transcript-signature rebuild, not on every cache-hit serve.
    _apply_watchtower_worker_display_names(hydrated)
    return hydrated


def _archive_cached_payload(key):
    entry = _archive_response_cache_get(key)
    if not entry:
        return None
    rows = _rehydrate_archive_cached_rows(entry.get("conversations") or [])
    return {
        "conversations": rows,
        "count": len(rows),
        "cached": True,
        "stale": _archive_response_cache_is_stale(entry),
        "refreshing": _archive_response_refreshing(key),
        "cached_at": entry.get("cached_at") or 0,
    }


def _build_archive_conversations(
    *,
    include_prs=False,
    resolve_pr_states=False,
    resolve_effective=False,
    resolve_worktree_dirty=False,
    progress_step=None,
):
    def progress(key, **kwargs):
        if progress_step:
            progress_step(key, **kwargs)

    progress("folders",     state="running")
    progress("transcripts", state="running")
    progress("infer",       state="running")
    progress("worktrees",   state="running")
    progress("codex",       state="running")
    progress("cursor",      state="running")
    progress("antigravity", state="running")
    progress("hermes",      state="running")
    raw_convs = find_all_conversations(
        resolve_pr_states=resolve_pr_states,
        resolve_effective=resolve_effective,
        resolve_worktree_dirty=resolve_worktree_dirty,
    )
    count = len(raw_convs or [])
    progress("folders",     state="done")
    progress("transcripts", state="done", count=count, total=count, detail=f"{count} conversations parsed.")
    if resolve_effective:
        progress("infer",       state="done")
    else:
        progress("infer",       state="skipped", detail="Deferred until archive rows are visible.")
    if resolve_worktree_dirty:
        progress("worktrees",   state="done")
    else:
        progress("worktrees",   state="skipped", detail="Deferred until archive rows are visible.")
    progress("codex",       state="done")
    progress("cursor",      state="done")
    progress("antigravity", state="done")
    progress("hermes",      state="done")
    if include_prs:
        progress("pr_states",   state="running", detail="gh pr view per known PR URL.")
        convs = conversations_with_open_prs(raw_convs)
        progress("pr_states",   state="done")
    else:
        convs = raw_convs
        progress("pr_states",   state="skipped", detail="Deferred until archive rows are visible.")
    progress("issues",      state="skipped", detail="Loaded by /api/issues/all.")
    progress("group_chats", state="skipped", detail="Loaded by /api/group-chats/archived.")
    _stamp_archive_state(convs)
    return convs


def archive_window_since_epoch(window: str, now: float | None = None) -> float | None:
    """Translate the public archive window into a server-side time bound."""
    seconds = {"1d": 24 * 60 * 60, "7d": 7 * 24 * 60 * 60}.get(window)
    if seconds is None:
        return None
    return (time.time() if now is None else now) - seconds


def _archive_refresh_response_cache_async(key, options):
    if not _archive_response_refresh_begin(key):
        return False

    def refresh():
        try:
            # Signature BEFORE the build: files that change mid-build make the
            # entry conservatively stale (next refresh re-checks), never
            # wrongly fresh. Persisting without a signature disabled the
            # sig-match/incremental fast paths for this key entirely.
            sig = _archive_corpus_signature()
            convs = _build_archive_conversations(**options)
            _archive_response_cache_put(key, convs, signature=sig)
            _save_conv_meta_cache()
        except Exception as e:
            print(f"  [archive-cache] background refresh failed: {e}")
        finally:
            _archive_response_refresh_end(key)

    threading.Thread(target=refresh, daemon=True).start()
    return True


def load_known_repos():
    """Auto-detect projects for the picker by scanning $HOME.

    Returns one entry per direct child of $HOME that looks like a project —
    either a git repo (`.git/`) or a Claude workspace (`.claude/`). Skips
    dotfile dirs themselves so the list stays clean. Sorted alphabetically.
    Falls back to cwd when nothing is found so the picker is never empty.
    """
    home = Path.home()
    repos = []
    try:
        for entry in sorted(home.iterdir(), key=lambda p: p.name.lower()):
            if not entry.is_dir() or entry.name.startswith("."):
                continue
            is_git = (entry / ".git").is_dir()
            is_claude = (entry / ".claude").is_dir()
            if not (is_git or is_claude):
                continue
            repos.append({"path": str(entry.resolve()), "label": entry.name})
    except OSError:
        pass
    if not repos:
        cwd = Path.cwd().resolve()
        repos.append({"path": str(cwd), "label": cwd.name})
    # Merge in user-picked repos (folders outside $HOME, or nested ones the scan
    # missed). Label with parent dir when it disambiguates a duplicate name.
    scanned_paths = {r["path"] for r in repos}
    scanned_labels = {r["label"] for r in repos}
    for custom_path in _load_custom_repos():
        if custom_path in scanned_paths:
            continue
        name = Path(custom_path).name
        if name in scanned_labels:
            label = f"{name} ({Path(custom_path).parent.name})"
        else:
            label = name
        repos.append({"path": custom_path, "label": label})
    # Re-order: recently-used repos first (in recency order), then the rest
    # in the original alphabetical order. The picker modal uses this ordering
    # to group a "Recent" section above the long list.
    recent = _load_recent_repos()
    if recent:
        by_path = {r["path"]: r for r in repos}
        ordered = []
        seen = set()
        for p in recent:
            if p in by_path and p not in seen:
                ordered.append(by_path[p])
                seen.add(p)
        for r in repos:
            if r["path"] not in seen:
                ordered.append(r)
        repos = ordered
    return repos


def _which(cmd):
    """Return the absolute path of `cmd` on PATH, or None. shutil-free so the
    file stays stdlib-only without importing shutil at module top."""
    import shutil
    return shutil.which(cmd)


def _iter_common_cli_candidates(cmd):
    """Yield common user-install locations that launchd often omits from PATH."""
    home = Path.home()
    fixed = [
        Path("/opt/homebrew/bin") / cmd,
        Path("/usr/local/bin") / cmd,
        home / ".local" / "bin" / cmd,
        home / ".npm-global" / "bin" / cmd,
        home / "Library" / "pnpm" / cmd,
        home / ".volta" / "bin" / cmd,
        home / ".bun" / "bin" / cmd,
        home / ".asdf" / "shims" / cmd,
        home / ".nodenv" / "shims" / cmd,
        home / ".local" / "share" / "mise" / "shims" / cmd,
    ]
    seen = set()
    for p in fixed:
        s = str(p)
        if s not in seen:
            seen.add(s)
            yield p
    glob_roots = [
        (home / ".nvm" / "versions" / "node", f"*/bin/{cmd}"),
        (home / ".fnm" / "node-versions", f"*/installation/bin/{cmd}"),
    ]
    for root, pattern in glob_roots:
        if not root.is_dir():
            continue
        try:
            paths = sorted(root.glob(pattern), reverse=True)
        except OSError:
            continue
        for p in paths:
            s = str(p)
            if s not in seen:
                seen.add(s)
                yield p
    try:
        hidden_bin_paths = sorted(home.glob(f".*/bin/{cmd}"), reverse=True)
    except OSError:
        hidden_bin_paths = []
    for p in hidden_bin_paths:
        s = str(p)
        if s not in seen:
            seen.add(s)
            yield p


def _resolve_claude_bin():
    """Locate a usable Claude Code CLI binary.

    LaunchAgents inherit a sparse PATH, so relying only on Popen(["claude", ...])
    produces opaque FileNotFoundError failures even when an interactive shell can
    run Claude. CCC_CLAUDE_BIN is the explicit escape hatch; common user-install
    locations cover Homebrew, npm/nvm/fnm, Volta, asdf, mise, and similar setups.
    """
    env_bin = (os.environ.get("CCC_CLAUDE_BIN") or "").strip()
    if env_bin:
        expanded = os.path.expanduser(env_bin)
        if os.path.isfile(expanded) and os.access(expanded, os.X_OK):
            return {"available": True, "bin": expanded, "source": "env"}
        return {
            "available": False,
            "bin": None,
            "code": "claude_unavailable",
            "reason": f"CCC_CLAUDE_BIN is set to {env_bin!r} but it isn't an executable file",
        }
    which_bin = shutil.which("claude")
    if which_bin:
        return {"available": True, "bin": which_bin, "source": "path"}
    for candidate in _iter_common_cli_candidates("claude"):
        if candidate.is_file() and os.access(candidate, os.X_OK):
            return {"available": True, "bin": str(candidate), "source": "candidate"}
    return {
        "available": False,
        "bin": None,
        "code": "claude_unavailable",
        "reason": "Claude Code CLI not found. Install Claude Code or set CCC_CLAUDE_BIN.",
    }


# ── In-app update: version check + self-update ─────────────────────────────
# The UI pings /api/version/check on load; if the local __version__ is behind
# the latest GitHub release tag, it shows a "Update available" pill. Clicking
# the pill posts to /api/self-update, which runs
#     git fetch origin && git reset --hard origin/main
# in the install directory (pre-flight checked for local mods + branch=main),
# writes the response, and then os.execvp's the server back onto itself so
# the new code is running.
_VERSION_CHECK_CACHE = {"ts": 0.0, "data": None}
_VERSION_CHECK_TTL = 6 * 60 * 60  # 6h — GitHub unauth limit is 60/h/IP


def _install_dir():
    """Dir containing server.py — this is the git clone we'd update."""
    return Path(__file__).resolve().parent


def _ccc_last_updated_iso():
    """ISO-8601 timestamp of the most recent change to this install.

    Prefers `git log -1 --format=%cI HEAD` so a fresh `git pull` (or
    self-update) reflects immediately, even when no source file mtime
    changed. Falls back to server.py mtime when git is unavailable
    (e.g. zip install). Returns "" on total failure.
    """
    try:
        out = subprocess.check_output(
            ["git", "-C", str(_install_dir()), "log", "-1", "--format=%cI", "HEAD"],
            stderr=subprocess.DEVNULL,
            timeout=2,
        ).decode("utf-8", "replace").strip()
        if out:
            return out
    except Exception:
        pass
    try:
        import datetime as _dt
        ts = Path(__file__).resolve().stat().st_mtime
        return _dt.datetime.fromtimestamp(ts).astimezone().isoformat()
    except Exception:
        return ""


def _strip_v(tag):
    if not tag:
        return ""
    return tag[1:] if tag.startswith(("v", "V")) else tag


def _semver_tuple(s):
    """Coerce 'X.Y.Z' → (X, Y, Z). Non-numeric chunks → 0. Trailing '-rc1' etc
    is stripped. Used only for the 'is the local behind?' comparison."""
    parts = (s or "").split("-", 1)[0].split(".")
    out = []
    for p in parts[:3]:
        try:
            out.append(int(p))
        except ValueError:
            out.append(0)
    while len(out) < 3:
        out.append(0)
    return tuple(out)


def _fetch_latest_release():
    """Hit GitHub's latest-release endpoint. Returns dict or raises on failure.
    Stdlib-only — urllib.request. Short timeout so we never hang the UI."""
    url = "https://api.github.com/repos/amirfish1/claude-command-center/releases/latest"
    req = urllib.request.Request(url, headers={
        "User-Agent": f"claude-command-center/{__version__}",
        "Accept": "application/vnd.github+json",
    })
    with urllib.request.urlopen(req, timeout=5) as resp:
        return json.loads(resp.read().decode("utf-8"))


def _version_check(force=False):
    """Return {ok, current, latest, behind, changelog_url} for the UI.
    Caches for 6h to stay well under GitHub's unauthenticated rate limit.
    Never raises — network / parse errors come back as {ok:false, error}."""
    now = time.time()
    if not force and _VERSION_CHECK_CACHE["data"] and (now - _VERSION_CHECK_CACHE["ts"]) < _VERSION_CHECK_TTL:
        return _VERSION_CHECK_CACHE["data"]
    try:
        rel = _fetch_latest_release()
    except Exception as e:
        # 404 (no releases yet), network error, timeout, JSON error — all
        # handled identically: surface to the client, keep the server up.
        data = {"ok": False, "current": __version__, "error": str(e)}
        _VERSION_CHECK_CACHE["data"] = data
        _VERSION_CHECK_CACHE["ts"] = now
        return data
    latest = _strip_v(rel.get("tag_name") or "")
    current = __version__
    behind = _semver_tuple(current) < _semver_tuple(latest) if latest else False
    changelog_url = (
        f"https://github.com/amirfish1/claude-command-center/compare/"
        f"v{current}...v{latest}"
    ) if behind else (rel.get("html_url") or "")
    data = {
        "ok": True,
        "current": current,
        "latest": latest,
        "behind": behind,
        "changelog_url": changelog_url,
    }
    _VERSION_CHECK_CACHE["data"] = data
    _VERSION_CHECK_CACHE["ts"] = now
    return data


def _git(args, cwd, timeout=10):
    """Run `git <args>` in cwd. Returns (rc, stdout, stderr) — stderr trimmed."""
    try:
        r = subprocess.run(
            ["git"] + list(args),
            cwd=str(cwd),
            capture_output=True,
            text=True,
            timeout=timeout,
        )
        return r.returncode, r.stdout, (r.stderr or "").strip()
    except FileNotFoundError:
        return 127, "", "git not found on PATH"
    except subprocess.TimeoutExpired:
        return 124, "", f"git {' '.join(args)} timed out"


def _self_update():
    """Run the pre-flight + pull. Returns a response dict; the caller is
    responsible for writing it to the client BEFORE the restart fires."""
    d = _install_dir()
    if not (d / ".git").exists():
        return {"ok": False, "error": "not a git clone", "install_dir": str(d)}
    rc, out, err = _git(["status", "--porcelain"], d)
    if rc != 0:
        return {"ok": False, "error": f"git status failed: {err or 'rc={}'.format(rc)}"}
    if out.strip():
        paths = [ln[3:] for ln in out.splitlines() if len(ln) > 3]
        return {"ok": False, "error": "local changes present", "paths": paths}
    rc, branch, err = _git(["rev-parse", "--abbrev-ref", "HEAD"], d)
    if rc != 0:
        return {"ok": False, "error": f"git rev-parse failed: {err or 'rc={}'.format(rc)}"}
    branch = branch.strip()
    if branch != "main":
        return {"ok": False, "error": f"on branch {branch!r}, not main"}
    rc, _, err = _git(["fetch", "origin", "--quiet"], d, timeout=30)
    if rc != 0:
        return {"ok": False, "error": f"git fetch failed: {err or 'rc={}'.format(rc)}"}
    rc, _, err = _git(["reset", "--hard", "origin/main", "--quiet"], d)
    if rc != 0:
        return {"ok": False, "error": f"git reset failed: {err or 'rc={}'.format(rc)}"}
    rc, sha, _ = _git(["rev-parse", "HEAD"], d)
    # Bust the 6h cache so the post-restart UI reads fresh latest/current.
    _VERSION_CHECK_CACHE["ts"] = 0.0
    _VERSION_CHECK_CACHE["data"] = None
    return {"ok": True, "new_sha": (sha or "").strip()}


# ── In-app bug reporting ───────────────────────────────────────────────
# The UI surfaces a "Report a bug" link in the topbar that opens a small
# modal (title + description + auto-collected context). On submit, the
# client posts to /api/bug-report; the handler shells out to `gh issue
# create` against amirfish1/claude-command-center. If `gh` isn't
# available we return the rendered markdown so the UI can offer a
# copy-to-clipboard fallback for manual filing.
_BUG_REPORT_REPO = "amirfish1/claude-command-center"
# Screenshot support (macOS only): the modal can capture an area screenshot
# via `screencapture -i`, which is then committed to a dedicated public
# branch (`bug-screenshots`) of this repo so the issue body can render the
# image inline via raw.githubusercontent.com. If the push fails (random OSS
# user without write access) we keep the local copy and tell the user to
# drag-drop manually. The local save ALWAYS happens first so the image is
# never lost regardless of upload outcome.
_BUG_SCREENSHOT_DIR = Path.home() / ".claude" / "command-center" / "bug-screenshots"
_BUG_SCREENSHOT_WT = Path.home() / ".claude" / "command-center" / "bug-screenshots-wt"
_BUG_SCREENSHOT_BRANCH = "bug-screenshots"


def _build_bug_report_body(description, ccc_version, user_agent, session_id,
                           screenshot_url=None, screenshot_local_path=None):
    """Render the GitHub issue body (markdown). Pure — no I/O — so it's
    cheap to also return on the failure path for clipboard fallback.

    Screenshot rendering: if `screenshot_url` is given we embed it as an
    inline image (the happy path — image was pushed to the bug-screenshots
    branch). Otherwise if `screenshot_local_path` is given we surface the
    local path with a drag-drop instruction so the user can manually
    attach it to the issue after it's filed."""
    lines = [
        "## Description",
        "",
        description.strip(),
        "",
    ]
    if screenshot_url:
        lines += [
            "## Screenshot",
            "",
            f"![screenshot]({screenshot_url})",
            "",
        ]
    elif screenshot_local_path:
        lines += [
            "## Screenshot",
            "",
            f"📎 Saved locally at `{screenshot_local_path}`. After this issue "
            "opens, drag the file into a comment to attach it.",
            "",
        ]
    lines += [
        "## Context",
        "",
        "| Field | Value |",
        "|---|---|",
        f"| **CCC version** | `{ccc_version or '-'}` |",
        f"| **Session** | `{session_id or '-'}` |",
        f"| **User agent** | `{user_agent or '-'}` |",
        "",
        "_Reported via the in-app Report a bug feature._",
    ]
    return "\n".join(lines)


def _resolve_screencapture_bin():
    """Locate the macOS `screencapture` binary.

    On every Mac the binary lives at /usr/sbin/screencapture, but /usr/sbin
    is missing from PATH when CCC is launched outside a login shell (e.g.
    by launchd, or by Claude Code itself). Prefer the absolute path; fall
    back to PATH lookup for non-standard installs.

    Returns the absolute path string, or None if the binary truly isn't
    on the system.
    """
    fixed = "/usr/sbin/screencapture"
    if os.path.isfile(fixed) and os.access(fixed, os.X_OK):
        return fixed
    return shutil.which("screencapture")


def _capture_screenshot_native(timeout=120):
    """Trigger the macOS area-screenshot picker (`screencapture -i`) and
    return the resulting PNG as base64. Blocks until the user finishes
    drawing the rectangle, presses Esc to cancel, or `timeout` elapses.

    Returns one of:
      {ok: True,  image_b64: "...", mime: "image/png", path: "/tmp/..."}
      {ok: False, cancelled: True}                  — user pressed Esc
      {ok: False, error: "..."}                     — non-mac, timeout, etc.

    macOS-only: `screencapture` is a shipped system tool. On other OSes we
    return an explanatory error so the UI can hide / explain the feature.
    """
    if platform.system() != "Darwin":
        _log_macos_only("screenshots")
        return {"ok": False, "error": "Screenshots are macOS-only."}
    screencapture_bin = _resolve_screencapture_bin()
    if not screencapture_bin:
        # Should be unreachable on a real Mac (`/usr/sbin/screencapture` is
        # shipped with the OS), but surface a friendly error if a stripped
        # install or a hardened sandbox really is missing it.
        return {"ok": False, "error": "`screencapture` not found - is this a full macOS install?"}
    # NamedTemporaryFile(delete=False) so screencapture (a separate process)
    # can write to the path; we reap it ourselves once we've base64-encoded.
    tmp = tempfile.NamedTemporaryFile(prefix="ccc-bug-", suffix=".png", delete=False)
    tmp_path = tmp.name
    tmp.close()
    try:
        # `-i` is interactive: shows the crosshair / area-selector overlay.
        # `-x` suppresses the camera-shutter sound so this isn't disruptive
        # in a quiet office. The user draws an area; on Esc the file is left
        # zero-bytes and screencapture exits 0.
        try:
            proc = subprocess.run(
                [screencapture_bin, "-i", "-x", tmp_path],
                capture_output=True, text=True, timeout=timeout,
            )
        except subprocess.TimeoutExpired:
            return {"ok": False, "error": f"screencapture timed out after {timeout}s"}
        if proc.returncode != 0:
            err = (proc.stderr or proc.stdout or "").strip()[:200]
            return {"ok": False, "error": err or f"screencapture exited {proc.returncode}"}
        try:
            data = Path(tmp_path).read_bytes()
        except OSError as e:
            return {"ok": False, "error": f"could not read capture: {e}"}
        # Esc / cancel leaves a zero-byte file behind. Treat as cancellation.
        if not data:
            return {"ok": False, "cancelled": True}
        return {
            "ok": True,
            "image_b64": base64.b64encode(data).decode("ascii"),
            "mime": "image/png",
            "path": tmp_path,
            "bytes": len(data),
        }
    finally:
        # The client got the bytes inline; the temp file is no longer
        # needed. Best-effort cleanup so /tmp doesn't fill up over time.
        try:
            os.unlink(tmp_path)
        except OSError:
            pass


def _save_screenshot_locally(image_b64):
    """Decode `image_b64` and write to ~/.claude/command-center/bug-screenshots/.
    Returns the absolute path on success, or raises ValueError on bad input.
    Called on the bug-report submission path BEFORE the upload attempt so
    the screenshot survives even if everything else fails."""
    try:
        raw = base64.b64decode(image_b64, validate=True)
    except (ValueError, TypeError) as e:
        raise ValueError(f"invalid base64: {e}") from e
    if not raw:
        raise ValueError("empty screenshot")
    _BUG_SCREENSHOT_DIR.mkdir(parents=True, exist_ok=True)
    # Filename: timestamp + short random suffix so back-to-back submissions
    # in the same second don't collide.
    fname = f"bug-{datetime.now().strftime('%Y%m%d-%H%M%S')}-{os.urandom(3).hex()}.png"
    out = _BUG_SCREENSHOT_DIR / fname
    out.write_bytes(raw)
    return str(out)


def _github_owner_repo_from_url(url):
    # Match git@github.com:owner/repo(.git) and https://github.com/owner/repo(.git).
    m = re.match(r"^git@github\.com:([^/]+)/([^/]+?)(?:\.git)?$", url)
    if not m:
        m = re.match(r"^https?://github\.com/([^/]+)/([^/]+?)(?:\.git)?/?$", url)
    if not m:
        return None
    return (m.group(1), m.group(2))


def _origin_owner_repo():
    """Return (owner, repo) parsed from the install dir's `origin` remote, or
    None if the dir isn't a clone or the URL doesn't look like GitHub.
    Used to build the raw.githubusercontent.com URL for embedded screenshots
    AND to derive the push URL for the bug-screenshots branch."""
    rc, out, _ = _git(["remote", "get-url", "origin"], _install_dir())
    if rc != 0:
        return None
    return _github_owner_repo_from_url(out.strip())


_GITHUB_OWNER_LOGIN_CACHE = {"ts": 0.0, "owners": set()}
_GITHUB_OWNER_LOGIN_TTL = 300.0


def _github_owner_login_candidates():
    """GitHub owners considered "mine" for all-repo issue/PR feeds.

    Prefer explicit configuration and the authenticated `gh` login. Fall back
    to this install's origin owner so OSS/source installs still get a narrow
    feed without hardcoding a username in the public repo.
    """
    now = time.time()
    cached = _GITHUB_OWNER_LOGIN_CACHE.get("owners") or set()
    if cached and (now - float(_GITHUB_OWNER_LOGIN_CACHE.get("ts") or 0)) < _GITHUB_OWNER_LOGIN_TTL:
        return set(cached)
    owners = set()
    raw_env = os.environ.get("CCC_GITHUB_OWNERS") or os.environ.get("CCC_GITHUB_OWNER") or ""
    for part in raw_env.replace(";", ",").split(","):
        p = part.strip().lower()
        if p:
            owners.add(p)
    try:
        r = subprocess.run(
            ["gh", "api", "user", "--jq", ".login"],
            capture_output=True,
            text=True,
            timeout=5,
        )
        if r.returncode == 0 and r.stdout.strip():
            owners.add(r.stdout.strip().lower())
    except (OSError, subprocess.SubprocessError):
        pass
    origin = _origin_owner_repo()
    if origin and origin[0]:
        owners.add(str(origin[0]).lower())
    _GITHUB_OWNER_LOGIN_CACHE["owners"] = set(owners)
    _GITHUB_OWNER_LOGIN_CACHE["ts"] = now
    return owners


def _github_repo_owner_for_path(repo_path):
    """Return the GitHub origin owner for a local repo path, or ''."""
    try:
        p = Path(repo_path).expanduser().resolve()
    except (OSError, ValueError, RuntimeError):
        return ""
    if not p.is_dir():
        return ""
    rc, out, _ = _git(["remote", "get-url", "origin"], p, timeout=3)
    if rc != 0:
        return ""
    parsed = _github_owner_repo_from_url(out.strip())
    return (parsed[0] if parsed else "") or ""


def _push_screenshot_to_branch(local_path, commit_subject):
    """Copy `local_path` into the bug-screenshots scratch worktree, commit,
    and push. Returns one of:
      {ok: True,  raw_url: "https://raw.githubusercontent.com/.../<file>"}
      {ok: False, error: "..."}

    The scratch worktree at ~/.claude/command-center/bug-screenshots-wt/
    is reused across runs. On first run the `bug-screenshots` branch
    doesn't exist on origin so we create it as an orphan (no parent
    commits — keeps it clean of main's history)."""
    install = _install_dir()
    rc, origin_url, err = _git(["remote", "get-url", "origin"], install)
    if rc != 0:
        return {"ok": False, "error": f"no origin remote: {err or 'rc={}'.format(rc)}"}
    origin_url = origin_url.strip()
    owner_repo = _origin_owner_repo()
    if not owner_repo:
        return {"ok": False, "error": f"origin URL not recognised as GitHub: {origin_url}"}
    owner, repo = owner_repo

    wt = _BUG_SCREENSHOT_WT
    # Always rebuild the scratch dir if it isn't a healthy git clone — this
    # keeps the logic dead-simple and avoids subtle stuck-state bugs (e.g.
    # half-applied orphan switch from a prior crashed run). The cost is one
    # extra `git init` + fetch per submission, which is negligible.
    if not (wt / ".git").is_dir():
        shutil.rmtree(wt, ignore_errors=True)
        wt.mkdir(parents=True, exist_ok=True)
        rc, _, err = _git(["init", "--quiet", "-b", "main"], wt)
        if rc != 0:
            # Older git without -b flag — retry without it.
            shutil.rmtree(wt, ignore_errors=True)
            wt.mkdir(parents=True, exist_ok=True)
            rc, _, err = _git(["init", "--quiet"], wt)
            if rc != 0:
                return {"ok": False, "error": f"git init failed: {err}"}
        rc, _, err = _git(["remote", "add", "origin", origin_url], wt)
        if rc != 0:
            return {"ok": False, "error": f"git remote add failed: {err}"}

    # Try to fetch the existing bug-screenshots branch. If origin doesn't
    # have it yet (first push ever), we'll create it as an orphan below.
    rc, _, fetch_err = _git(
        ["fetch", "origin", _BUG_SCREENSHOT_BRANCH, "--quiet"], wt, timeout=30,
    )
    branch_on_origin = (rc == 0)

    if branch_on_origin:
        # Hard-reset to remote so we don't accumulate junk commits locally
        # when the user submits multiple bug reports.
        rc, _, err = _git(
            ["checkout", "-B", _BUG_SCREENSHOT_BRANCH,
             f"origin/{_BUG_SCREENSHOT_BRANCH}", "--quiet"], wt,
        )
        if rc != 0:
            return {"ok": False, "error": f"checkout bug-screenshots failed: {err}"}
    else:
        # First-ever push: create the branch as an orphan so its history is
        # independent from main. Wipe any tracked files left over from a
        # previous half-baked run (`git switch --orphan` doesn't touch the
        # working tree).
        rc, _, err = _git(["switch", "--orphan", _BUG_SCREENSHOT_BRANCH], wt)
        if rc != 0:
            # `git switch` requires git 2.23+. On ancient git fall back to
            # the symbolic-ref + rm-cached dance.
            rc, _, err = _git(
                ["symbolic-ref", "HEAD", f"refs/heads/{_BUG_SCREENSHOT_BRANCH}"], wt,
            )
            if rc != 0:
                return {"ok": False, "error": f"orphan branch create failed: {err}"}
            # Drop any stale index entries so the orphan starts empty.
            _git(["rm", "-rf", "--cached", "--quiet", "."], wt)
        # Clean the working tree of any leftover files (other than .git).
        for entry in wt.iterdir():
            if entry.name == ".git":
                continue
            try:
                if entry.is_dir():
                    shutil.rmtree(entry)
                else:
                    entry.unlink()
            except OSError:
                pass

    # Configure local user/email for the commit so this works on a fresh
    # box without ~/.gitconfig user.email set. Safe scope: --local only
    # touches this scratch dir's .git/config, never global config.
    _git(["config", "--local", "user.name", "Command Center"], wt)
    _git(["config", "--local", "user.email", "ccc-bug-report@localhost"], wt)

    # Copy the screenshot in under its basename and stage it explicitly —
    # never `git add -A`, both because of the multi-agent rule and because
    # we want to be defensive about anything else lingering in the WT.
    fname = Path(local_path).name
    dest = wt / fname
    try:
        shutil.copy2(local_path, dest)
    except OSError as e:
        return {"ok": False, "error": f"copy failed: {e}"}

    rc, _, err = _git(["add", fname], wt)
    if rc != 0:
        return {"ok": False, "error": f"git add failed: {err}"}

    # Cap the commit subject so a pathological title doesn't push the
    # commit message over GitHub's display limits.
    subject = (commit_subject or "screenshot").strip()
    if len(subject) > 100:
        subject = subject[:100].rstrip() + "…"
    rc, _, err = _git(
        ["commit", "-m", f"add screenshot: {subject}", "--quiet"], wt,
    )
    if rc != 0:
        return {"ok": False, "error": f"git commit failed: {err}"}

    rc, _, err = _git(
        ["push", "-u", "origin", _BUG_SCREENSHOT_BRANCH, "--quiet"], wt, timeout=30,
    )
    if rc != 0:
        return {"ok": False, "error": f"git push failed: {err[:300] if err else 'rc={}'.format(rc)}"}

    raw_url = (
        f"https://raw.githubusercontent.com/{owner}/{repo}/"
        f"{_BUG_SCREENSHOT_BRANCH}/{urllib.parse.quote(fname)}"
    )
    return {"ok": True, "raw_url": raw_url, "filename": fname}


def _bug_log(msg):
    """Single-line stderr logger for the bug-report flow. Useful when the
    push succeeds silently but the user-side render looks off — easier to
    grep `[bug-report]` in the server console than to hunt timestamps."""
    print(f"[bug-report] {msg}", file=sys.stderr, flush=True)


def _create_bug_report_issue(payload):
    """Validate the payload, build a GitHub issue, file it via `gh`.

    Returns one of:
      {ok: True,  url: ".../issues/N", number: N,
       screenshot_needs_manual?: True, screenshot_path?: "<abs>"}
      {ok: False, error: "...",  markdown: "..."}   # gh missing / failed
      {ok: False, error: "..."}                     # validation failure
    The `markdown` key on the failure path lets the client offer a
    copy-to-clipboard fallback so the user can file it manually.

    Optional `screenshot_b64` field: PNG bytes (base64, no data: prefix).
    Always saved locally first; then we try to push to the bug-screenshots
    branch for inline rendering. On push failure the issue body falls back
    to the local path + drag-drop instructions, and the response carries
    `screenshot_needs_manual=true` so the client can `open -R` the file
    and surface the issue URL for manual attachment.
    """
    # The modal collapsed Title+Description into a single Details field, so
    # we derive the issue title from the first non-empty line. We still
    # accept an explicit `title` from older clients / programmatic callers.
    description = (payload.get("description") or "").strip()
    if not description:
        return {"ok": False, "error": "details are required"}
    title = (payload.get("title") or "").strip()
    if not title:
        for line in description.splitlines():
            candidate = line.strip()
            if candidate:
                title = candidate
                break
    if not title:
        # Should be unreachable because `description` is non-empty above,
        # but guard anyway so we never ship an empty title to gh.
        return {"ok": False, "error": "details are required"}
    # Cap title at a friendly length so the GitHub issue list stays readable.
    # GitHub itself accepts 256 chars; 120 keeps things tidy.
    if len(title) > 120:
        title = title[:120].rstrip() + "…"

    ccc_version = (payload.get("ccc_version") or "").strip() or __version__
    user_agent = (payload.get("user_agent") or "").strip()
    session_id = (payload.get("session_id") or "").strip()

    # ── Screenshot pre-flight ──
    # Save first (always), then try to push, then build the body. The
    # `screenshot_*` locals stay None when no image was supplied so the
    # body builder skips the screenshot section entirely.
    screenshot_b64 = (payload.get("screenshot_b64") or "").strip()
    screenshot_local_path = None
    screenshot_url = None
    screenshot_needs_manual = False
    if screenshot_b64:
        try:
            screenshot_local_path = _save_screenshot_locally(screenshot_b64)
            _bug_log(f"screenshot saved locally at {screenshot_local_path}")
        except ValueError as e:
            # Bad base64 isn't fatal — we just skip the screenshot section
            # so the bug report itself still gets filed. Log loudly so the
            # client-side bug is findable.
            _bug_log(f"screenshot decode failed, skipping: {e}")
            screenshot_local_path = None
        if screenshot_local_path:
            push = _push_screenshot_to_branch(screenshot_local_path, title)
            if push.get("ok"):
                screenshot_url = push["raw_url"]
                _bug_log(f"screenshot pushed: {screenshot_url}")
            else:
                screenshot_needs_manual = True
                _bug_log(f"screenshot push failed, using local fallback: {push.get('error')}")

    body = _build_bug_report_body(
        description, ccc_version, user_agent, session_id,
        screenshot_url=screenshot_url,
        screenshot_local_path=screenshot_local_path if screenshot_needs_manual else None,
    )
    fallback_md = f"## {title}\n\n{body}"

    if not _which("gh"):
        return {
            "ok": False,
            "error": "gh CLI not found on PATH - copy the markdown and file the issue manually.",
            "markdown": fallback_md,
            "repo_url": f"https://github.com/{_BUG_REPORT_REPO}/issues/new",
            "screenshot_path": screenshot_local_path,
        }

    try:
        # `gh issue create` prints the issue URL on stdout when it succeeds.
        # We pipe body via --body-file=- so we don't have to worry about
        # arbitrary user input being interpreted by the shell — there is
        # no shell (subprocess.run with a list).
        proc = subprocess.run(
            ["gh", "issue", "create",
             "-R", _BUG_REPORT_REPO,
             "--label", "bug",
             "--title", title,
             "--body-file", "-"],
            input=body,
            capture_output=True, text=True, timeout=20,
        )
    except subprocess.TimeoutExpired:
        return {"ok": False, "error": "gh issue create timed out", "markdown": fallback_md,
                "screenshot_path": screenshot_local_path}
    except (OSError, subprocess.SubprocessError) as e:
        return {"ok": False, "error": f"gh failed to launch: {e}", "markdown": fallback_md,
                "screenshot_path": screenshot_local_path}

    if proc.returncode != 0:
        err = (proc.stderr or proc.stdout or "").strip()[:400]
        return {
            "ok": False,
            "error": err or f"gh issue create exited {proc.returncode}",
            "markdown": fallback_md,
            "repo_url": f"https://github.com/{_BUG_REPORT_REPO}/issues/new",
            "screenshot_path": screenshot_local_path,
        }

    url = (proc.stdout or "").strip().splitlines()[-1] if proc.stdout else ""
    number = None
    m = re.search(r"/issues/(\d+)", url)
    if m:
        number = int(m.group(1))
    result = {"ok": True, "url": url, "number": number}
    if screenshot_needs_manual and screenshot_local_path:
        result["screenshot_needs_manual"] = True
        result["screenshot_path"] = screenshot_local_path
    return result


def _reveal_bug_screenshot(path_str):
    """Reveal `path_str` in Finder via `open -R`. Sandbox-clamped to the
    bug-screenshots dir so this can't be abused to reveal arbitrary files.
    Used by the manual-attach fallback after the issue is filed."""
    if platform.system() != "Darwin":
        _log_macos_only("revealFile")
        return {"ok": False, "error": "macOS-only"}
    if not path_str:
        return {"ok": False, "error": "missing path"}
    try:
        rp = Path(path_str).expanduser().resolve(strict=False)
        root = _BUG_SCREENSHOT_DIR.resolve()
    except OSError as e:
        return {"ok": False, "error": str(e)}
    if not (str(rp).startswith(str(root) + os.sep) or rp == root):
        return {"ok": False, "error": "path outside bug-screenshots sandbox"}
    if not rp.exists():
        return {"ok": False, "error": "file not found", "path": str(rp)}
    try:
        subprocess.Popen(["open", "-R", str(rp)])
        return {"ok": True, "path": str(rp)}
    except OSError as e:
        return {"ok": False, "error": str(e)}


# ── Page annotations ───────────────────────────────────────────────────
# Local-only notes created from the browser overlay. Each annotation stores
# the user's note plus enough page/element/viewport anchors for a later agent
# to reopen the page and inspect the same visual area.

_LONE_SURROGATE_RE = re.compile("[{}-{}]".format(chr(0xD800), chr(0xDFFF)))


def _strip_lone_surrogates(s):
    """Remove unpaired UTF-16 surrogate code points (U+D800..U+DFFF).

    JS strings are UTF-16; the browser's clipboard / pasted-image / selection
    APIs can leave a lone high or low surrogate in the payload sent to
    /api/annotations (or any other text field). Python stores those as-is
    in `str`, but `json.dumps` happily serialises them, and the Anthropic
    API rejects the resulting request with
        "API Error: 400 The request body is not valid JSON:
         no low surrogate in string: line 1 column N (char N)"
    Strip the unpaired code points at the boundary so downstream injection
    paths can never feed broken UTF-16 into the API. Paired surrogates
    (i.e. real astral-plane chars like emoji) are already collapsed into
    a single Python code point above U+FFFF and do not match this regex.
    """
    if not s:
        return s
    return _LONE_SURROGATE_RE.sub("", s)


def _annotation_text(value, max_len=4000):
    s = "" if value is None else str(value)
    s = _strip_lone_surrogates(s).replace("\x00", "").strip()
    if len(s) > max_len:
        return s[:max_len].rstrip() + "…"
    return s


def _annotation_number(value, default=0.0):
    try:
        n = float(value)
    except (TypeError, ValueError):
        return default
    if n != n or n in (float("inf"), float("-inf")):
        return default
    if n < -1000000 or n > 1000000:
        return default
    return round(n, 2)


def _annotation_rect(value):
    raw = value if isinstance(value, dict) else {}
    return {
        "x": _annotation_number(raw.get("x")),
        "y": _annotation_number(raw.get("y")),
        "width": max(0.0, _annotation_number(raw.get("width"))),
        "height": max(0.0, _annotation_number(raw.get("height"))),
    }


def _annotation_screen(value):
    raw = value if isinstance(value, dict) else {}
    screen = _annotation_rect(raw)
    screen["estimated"] = bool(raw.get("estimated"))
    screen["window_screen_x"] = _annotation_number(raw.get("window_screen_x"))
    screen["window_screen_y"] = _annotation_number(raw.get("window_screen_y"))
    screen["outer_width"] = max(0.0, _annotation_number(raw.get("outer_width")))
    screen["outer_height"] = max(0.0, _annotation_number(raw.get("outer_height")))
    screen["chrome_border_x"] = max(0.0, _annotation_number(raw.get("chrome_border_x")))
    screen["chrome_offset_y"] = max(0.0, _annotation_number(raw.get("chrome_offset_y")))
    screen["device_pixel_ratio"] = max(1.0, min(4.0, _annotation_number(raw.get("device_pixel_ratio"), 1.0)))
    return screen


def _annotation_element(value):
    raw = value if isinstance(value, dict) else {}
    return {
        "tag": _annotation_text(raw.get("tag"), 64).lower(),
        "id": _annotation_text(raw.get("id"), 256),
        "role": _annotation_text(raw.get("role"), 128),
        "selector": _annotation_text(raw.get("selector"), 400),
        "href": _annotation_text(raw.get("href"), 400),
        "text": _annotation_text(raw.get("text"), 200),
    }


def _load_annotations():
    try:
        data = json.loads(ANNOTATIONS_FILE.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, ValueError):
        return []
    if isinstance(data, dict):
        data = data.get("annotations", [])
    if not isinstance(data, list):
        return []
    return [item for item in data if isinstance(item, dict)]


def _write_annotations(items):
    ANNOTATIONS_FILE.parent.mkdir(parents=True, exist_ok=True)
    tmp = ANNOTATIONS_FILE.with_suffix(".json.tmp")
    tmp.write_text(
        json.dumps({"annotations": items}, indent=2, sort_keys=True) + "\n",
        encoding="utf-8",
    )
    os.replace(tmp, ANNOTATIONS_FILE)


def _frontmost_window_bounds_for_capture():
    """Return the frontmost macOS window's on-screen bounds (points), or None.

    `id of window` (needed for `screencapture -l <id>`) stopped resolving
    reliably on recent macOS versions for many apps -- not just Electron/
    WebView ones. It fails the same way (AppleEvent -1728) even for a plain
    Terminal.app window that is definitely open and frontmost (OPS-63).
    `position`/`size` of the window remain readable via System Events, so
    capture by absolute screen rect instead of by window id.
    """
    if platform.system() != "Darwin":
        return None
    script = r'''
tell application "System Events"
  tell (first application process whose frontmost is true)
    if (count of windows) is 0 then return ""
    set w to window 1
    set {px, py} to position of w
    set {sw, sh} to size of w
    return (px as string) & "," & (py as string) & "," & (sw as string) & "," & (sh as string)
  end tell
end tell
'''
    # The System Events query races the Window Server around annotate time
    # (the user just clicked something) and can transiently return a stale
    # frontmost app or empty output -- OPS-63 follow-up. A couple of quick
    # retries clears most of these without needing a user-visible fallback.
    last_err = None
    for attempt in range(3):
        if attempt:
            time.sleep(0.15)
        try:
            proc = subprocess.run(
                ["osascript", "-e", script],
                capture_output=True,
                text=True,
                timeout=4,
            )
        except (OSError, subprocess.SubprocessError) as e:
            last_err = f"osascript failed: {e}"
            continue
        if proc.returncode != 0:
            last_err = (proc.stderr or "").strip()[:200] or f"osascript exited {proc.returncode}"
            continue
        out = (proc.stdout or "").strip()
        parts = out.split(",")
        if len(parts) != 4:
            last_err = f"unexpected osascript output: {out[:100]!r}"
            continue
        try:
            x, y, width, height = (float(p) for p in parts)
        except ValueError:
            last_err = f"non-numeric osascript output: {out[:100]!r}"
            continue
        if width <= 0 or height <= 0:
            last_err = f"zero-size window ({width}x{height})"
            continue
        return {"x": x, "y": y, "width": width, "height": height}
    if last_err:
        print(f"[annotation-capture] frontmost window bounds failed after retries: {last_err}", file=sys.stderr, flush=True)
    return None


def _capture_annotation_window_crop(screen, viewport_crop, annotation_id):
    """Capture the front window's real on-screen bounds and crop directly to
    the viewport-relative region via `screencapture -R`.

    More reliable than guessing global screen coordinates from the browser
    (the browser's own screen-position estimate can be off enough to
    produce a rect that doesn't intersect any display -- OPS-63).
    """
    if platform.system() != "Darwin":
        return None, "window capture is macOS-only"
    screencapture_bin = _resolve_screencapture_bin()
    if not screencapture_bin:
        return None, "screencapture not found"
    bounds = _frontmost_window_bounds_for_capture()
    if not bounds:
        return None, "could not resolve front window"
    crop = _annotation_rect(viewport_crop)
    if crop["width"] < 3 or crop["height"] < 3:
        return None, "crop region too small"
    screen = screen if isinstance(screen, dict) else {}
    border_x = max(0.0, _annotation_number(screen.get("chrome_border_x")))
    chrome_y = max(0.0, _annotation_number(screen.get("chrome_offset_y")))
    x = int(round(bounds["x"] + crop["x"] + border_x))
    y = int(round(bounds["y"] + crop["y"] + chrome_y))
    width = int(round(crop["width"]))
    height = int(round(crop["height"]))
    if width < 3 or height < 3:
        return None, "crop region too small"
    ANNOTATION_SCREENSHOT_DIR.mkdir(parents=True, exist_ok=True)
    out = ANNOTATION_SCREENSHOT_DIR / f"{annotation_id}.png"
    try:
        proc = subprocess.run(
            [screencapture_bin, "-x", "-R", f"{x},{y},{width},{height}", str(out)],
            capture_output=True,
            text=True,
            timeout=8,
        )
    except (OSError, subprocess.SubprocessError) as e:
        return None, f"window screencapture failed: {e}"
    if proc.returncode != 0:
        err = (proc.stderr or proc.stdout or "").strip()[:300]
        try:
            out.unlink(missing_ok=True)
        except OSError:
            pass
        hint = err or f"window screencapture exited {proc.returncode}"
        low = hint.lower()
        if "intersect" in low or "display" in low or "could not create" in low:
            # Window was offscreen/minimized/on another Space, or the process
            # lacks Screen Recording permission — both yield a non-actionable
            # macOS stderr. Surface the fix so the agent (or its user) can act.
            hint += (
                " (bring the CCC browser window fully on-screen - not minimized "
                "or on another Space - and grant Screen Recording permission to "
                "your terminal/Claude Code in System Settings → Privacy & Security)"
            )
        return None, hint
    try:
        if not out.is_file() or out.stat().st_size <= 0:
            return None, "window screencapture produced no image"
    except OSError:
        return None, "window screencapture file missing"
    return str(out), None


def _capture_annotation_screen_rect(screen_rect, annotation_id):
    """Best-effort non-interactive capture of the selected screen rect.

    Browser APIs can only estimate the viewport-to-screen transform. If that
    estimate is off, the annotation still has URL/selector/rect/text anchors;
    the screenshot path is an optional convenience.

    Returns (path, error_message).
    """
    if platform.system() != "Darwin":
        return None, "screen-region capture is macOS-only"
    screencapture_bin = _resolve_screencapture_bin()
    if not screencapture_bin:
        return None, "screencapture not found"
    rect = _annotation_rect(screen_rect)
    x = int(round(rect["x"]))
    y = int(round(rect["y"]))
    w = int(round(rect["width"]))
    h = int(round(rect["height"]))
    if w < 3 or h < 3 or w > 10000 or h > 10000:
        return None, "screen region too small"
    if x < -10000 or y < -10000 or x > 100000 or y > 100000:
        return None, "screen region out of bounds"
    ANNOTATION_SCREENSHOT_DIR.mkdir(parents=True, exist_ok=True)
    out = ANNOTATION_SCREENSHOT_DIR / f"{annotation_id}.png"
    try:
        proc = subprocess.run(
            [screencapture_bin, "-x", "-R", f"{x},{y},{w},{h}", str(out)],
            capture_output=True,
            text=True,
            timeout=8,
        )
    except (OSError, subprocess.SubprocessError) as e:
        return None, f"screencapture failed: {e}"
    if proc.returncode != 0:
        err = (proc.stderr or proc.stdout or "").strip()[:300]
        try:
            out.unlink(missing_ok=True)
        except OSError:
            pass
        hint = err or f"screencapture exited {proc.returncode}"
        if "could not create" in hint.lower() or proc.returncode == 1:
            hint += " (capture failed; check Screen Recording permission, window focus, or region bounds)"
        return None, hint
    try:
        if out.stat().st_size <= 0:
            out.unlink(missing_ok=True)
            return None, "screencapture produced an empty file"
    except OSError:
        return None, "screencapture file missing"
    return str(out), None


def _capture_annotation_screenshot_native(payload, annotation_id):
    """Try window crop, then estimated screen rect. Returns (path, error)."""
    errors = []
    screen = payload.get("screen") if isinstance(payload.get("screen"), dict) else {}
    viewport = payload.get("viewport_crop")
    if isinstance(viewport, dict):
        path, err = _capture_annotation_window_crop(screen, viewport, annotation_id)
        if path:
            return path, None
        if err:
            errors.append(err)
    path, err = _capture_annotation_screen_rect(screen, annotation_id)
    if path:
        return path, None
    if err:
        errors.append(err)
    return None, "; ".join(errors) if errors else "screenshot capture failed"


def _save_annotation_screenshot_b64(image_b64, annotation_id):
    try:
        raw = base64.b64decode(str(image_b64 or ""), validate=True)
    except (ValueError, TypeError) as e:
        raise ValueError(f"invalid base64: {e}") from e
    if not raw:
        raise ValueError("empty screenshot")
    if len(raw) > 25 * 1024 * 1024:
        raise ValueError("screenshot too large")
    ANNOTATION_SCREENSHOT_DIR.mkdir(parents=True, exist_ok=True)
    out = ANNOTATION_SCREENSHOT_DIR / f"{annotation_id}.png"
    out.write_bytes(raw)
    return str(out)


def _minimize_front_window_for_capture():
    if platform.system() != "Darwin":
        return None
    script = r'''
tell application "System Events"
  set frontProc to first application process whose frontmost is true
  set frontPid to unix id of frontProc
  set frontName to name of frontProc
  set actionTaken to "none"
  try
    if (count of windows of frontProc) > 0 then
      set value of attribute "AXMinimized" of window 1 of frontProc to true
      set actionTaken to "window"
    end if
  on error
    try
      set visible of frontProc to false
      set actionTaken to "app"
    end try
  end try
  return (frontPid as text) & tab & frontName & tab & actionTaken
end tell
'''
    try:
        proc = subprocess.run(
            ["osascript", "-e", script],
            capture_output=True,
            text=True,
            timeout=4,
        )
    except (OSError, subprocess.SubprocessError):
        return None
    if proc.returncode != 0:
        return None
    parts = (proc.stdout or "").strip().split("\t")
    if len(parts) < 3:
        return None
    return {"pid": parts[0], "name": parts[1], "action": parts[2]}


def _restore_window_after_capture(window_info):
    if platform.system() != "Darwin" or not window_info:
        return
    pid = str(window_info.get("pid") or "").strip()
    if not pid.isdigit():
        return
    script = f'''
tell application "System Events"
  set targetProc to first application process whose unix id is {pid}
  set visible of targetProc to true
  try
    repeat with w in windows of targetProc
      try
        if (value of attribute "AXMinimized" of w) is true then
          set value of attribute "AXMinimized" of w to false
        end if
      end try
    end repeat
  end try
  set frontmost of targetProc to true
end tell
'''
    try:
        subprocess.run(
            ["osascript", "-e", script],
            capture_output=True,
            text=True,
            timeout=4,
        )
    except (OSError, subprocess.SubprocessError):
        pass


def capture_annotation_screen(minimize=True):
    window_info = _minimize_front_window_for_capture() if minimize else None
    if window_info:
        time.sleep(0.25)
    result = _capture_screenshot_native()
    _restore_window_after_capture(window_info)
    if window_info:
        result["window_action"] = window_info.get("action")
        result["window_app"] = window_info.get("name")
    return result


def list_annotations(limit=100):
    try:
        limit = int(limit or 100)
    except (TypeError, ValueError):
        limit = 100
    limit = max(1, min(limit, 500))
    with _ANNOTATIONS_LOCK:
        items = _load_annotations()
    return {"ok": True, "annotations": list(reversed(items[-limit:])), "count": len(items)}


def create_annotation(payload):
    if not isinstance(payload, dict):
        return {"ok": False, "error": "expected JSON object"}
    note = _annotation_text(payload.get("note"), 2000)
    if not note:
        return {"ok": False, "error": "note is required"}
    created_at = datetime.now(tz=timezone.utc).isoformat()
    annotation_id = f"ann-{datetime.now().strftime('%Y%m%d-%H%M%S')}-{os.urandom(3).hex()}"
    screen = _annotation_screen(payload.get("screen"))
    annotation = {
        "id": annotation_id,
        "created_at": created_at,
        "note": note,
        "url": _annotation_text(payload.get("url"), 1000),
        "title": _annotation_text(payload.get("title"), 200),
        "session_id": _annotation_text(payload.get("session_id"), 160),
        "repo_path": _annotation_text(payload.get("repo_path"), 500),
        "rect": _annotation_rect(payload.get("rect")),
        "screen": screen,
        "element": _annotation_element(payload.get("element")),
        "source": _annotation_text(payload.get("source"), 80) or "browser-page",
    }
    screenshot_b64 = _annotation_text(payload.get("screenshot_b64"), 40 * 1024 * 1024)
    screenshot_warning = None
    if screenshot_b64:
        try:
            annotation["screenshot_path"] = _save_annotation_screenshot_b64(
                screenshot_b64, annotation_id
            )
        except ValueError as e:
            screenshot_warning = str(e)
    if not annotation.get("screenshot_path") and payload.get("capture_screen", True):
        screenshot_path, capture_err = _capture_annotation_screenshot_native(
            payload, annotation_id
        )
        if screenshot_path:
            annotation["screenshot_path"] = screenshot_path
        elif capture_err:
            screenshot_warning = capture_err
    if screenshot_warning and not annotation.get("screenshot_path"):
        annotation["screenshot_warning"] = screenshot_warning
    with _ANNOTATIONS_LOCK:
        items = _load_annotations()
        items.append(annotation)
        # Keep the file bounded. The newest annotations are usually the only
        # relevant ones for active agent handoff.
        if len(items) > 500:
            items = items[-500:]
        _write_annotations(items)
    result = {"ok": True, "annotation": annotation}
    if screenshot_warning and not annotation.get("screenshot_path"):
        result["screenshot_warning"] = screenshot_warning
    return result


def _normalize_annotation_queue_name(value):
    text = str(value or "").strip().lower()
    text = re.sub(r"[\s_-]+", " ", text)
    return text


def _annotation_queue_submission_key(text, meta, project):
    """Return a stable key for one in-flight annotation queue submission."""
    meta = meta if isinstance(meta, dict) else {}
    fields = {
        "annotation_id": str(meta.get("annotation_id") or meta.get("id") or ""),
        "note": str(meta.get("note") or ""),
        "url": str(meta.get("url") or ""),
        "title": str(meta.get("title") or ""),
        "selector": str(meta.get("selector") or ""),
        "screenshot_path": str(meta.get("screenshot_path") or ""),
        "repo_path": str(meta.get("repo_path") or ""),
        "source": str(meta.get("source") or ""),
        "lane": str(meta.get("lane") or ""),
        "project": str(project or meta.get("project") or ""),
        "text": text,
    }
    return hashlib.sha256(json.dumps(fields, sort_keys=True, ensure_ascii=False).encode("utf-8")).hexdigest()


def _find_annotation_ux_queue_session(queue_name=ANNOTATION_UX_FIXES_QUEUE_NAME):
    """Find the newest Claude session in the CCC repo with the queue name."""
    repo_path = resolve_repo_path(str(CCC_ROOT))
    target = _normalize_annotation_queue_name(queue_name)
    matches = []
    try:
        live_sids = set(_load_session_registry().keys())
        rows = find_conversations(repo_path, include_old=True, live_sids=live_sids)
    except Exception:
        rows = []
    for row in rows:
        sid = row.get("session_id") or row.get("id")
        if not sid:
            continue
        names = [
            row.get("display_name"),
            row.get("ai_title"),
        ]
        if row.get("spawn_named"):
            names.append(row.get("display_name"))
        if any(_normalize_annotation_queue_name(name) == target for name in names if name):
            matches.append(row)
    if not matches:
        return None
    matches.sort(
        key=lambda row: (
            1 if row.get("is_live") else 0,
            float(row.get("last_interacted") or row.get("modified") or row.get("mtime") or 0),
        ),
        reverse=True,
    )
    return matches[0]


def enqueue_annotation_ux_fixes_queue(
    text, queue_name=ANNOTATION_UX_FIXES_QUEUE_NAME, engine="claude", meta=None, inject=False, project=""
):
    """Append annotation context to the durable, numbered UX-fixes queue.

    By default this no longer interrupts any session: it records a numbered
    ``open`` item that survives across sessions and that any session can later
    *claim* when it is free (see ``ux_fixes_queue``). This is the anti-
    interruption behaviour — captures stop derailing long-running work.

    Pass ``inject=True`` to additionally fall back to the legacy behaviour of
    injecting into / spawning the named ``queue_name`` session.
    """
    text = _annotation_text(text, 24000)
    if not text:
        return {"ok": False, "error": "missing text", "status": 400}

    # Require an actionable anchor. A note alone gives a fix-worker nothing to
    # locate, so it blocks the ticket and the queue silts up (CCC-396..402). An
    # anchor is at least one of: a CSS selector, a screenshot path, or a URL.
    _meta_for_anchor = meta if isinstance(meta, dict) else {}
    _has_anchor = bool(
        str(_meta_for_anchor.get("selector") or "").strip()
        or str(_meta_for_anchor.get("screenshot_path") or "").strip()
        or str(_meta_for_anchor.get("url") or "").strip()
    )
    if not _has_anchor:
        return {
            "ok": False,
            "error": "Annotation needs an element, screenshot, or URL before it can go to the fix queue",
            "status": 400,
        }

    repo_path = resolve_repo_path(str(CCC_ROOT))

    # Durable record first — this is the source of truth a human refers to by
    # number and a second session can see. Never interrupts anyone.
    meta = meta if isinstance(meta, dict) else {}
    # Only default repo_path to the CCC repo for CCC-origin captures. A product
    # source (e.g. "bym") that omits repo_path must NOT be clobbered to CCC_ROOT,
    # or repo-path-wins project routing misfiles the item as CCC.
    _src = str(meta.get("source") or "ccc").lower()
    _repo_path = str(meta.get("repo_path") or "")
    if not _repo_path and _src in ("", "ccc"):
        _repo_path = CCC_ROOT
    _url = str(meta.get("url") or "")
    # An annotation's page title is often a generic browser label (for example
    # "problem"). When it points at a GitHub Issue, prefer the issue's actual
    # title so the WatchTower ticket is identifiable in CCC and its queue.
    _title = github_issue_title(_url) or str(meta.get("title") or "")
    _submission_key = _annotation_queue_submission_key(text, meta, project)
    with _ANNOTATION_QUEUE_SUBMISSIONS_LOCK:
        if _submission_key in _ANNOTATION_QUEUE_SUBMISSIONS_IN_FLIGHT:
            return {
                "ok": False,
                "error": "This annotation is already being submitted",
                "status": 409,
            }
        _ANNOTATION_QUEUE_SUBMISSIONS_IN_FLIGHT.add(_submission_key)
    try:
        item = _q.enqueue(
            note=meta.get("note") or text,
            text=text,
            source=str(meta.get("source") or "ccc"),
            annotation_id=str(meta.get("annotation_id") or meta.get("id") or ""),
            url=_url,
            title=_title,
            selector=str(meta.get("selector") or ""),
            screenshot_path=str(meta.get("screenshot_path") or ""),
            repo_path=_repo_path,
            lane=str(meta.get("lane") or "normal"),
            project=str(project or meta.get("project") or ""),
        )
    except Exception as e:  # never lose a capture to a queue error
        item = None
        queue_error = str(e)
    else:
        queue_error = None
    finally:
        with _ANNOTATION_QUEUE_SUBMISSIONS_LOCK:
            _ANNOTATION_QUEUE_SUBMISSIONS_IN_FLIGHT.discard(_submission_key)

    # Dispatch NOW (nudge a live worker, else spawn) + log the decision so a
    # captured ticket is handled immediately and the activity log explains the
    # outcome instead of going silent after ENQUEUE. Best-effort.
    if item and _WT_WORKERS_AVAILABLE and _wt_workers is not None:
        try:
            _wt_workers.dispatch_after_enqueue(
                str(item.get("project") or ""), str(item.get("ref") or ""))
        except Exception:
            pass

    if not inject:
        if item:
            return {
                "ok": True,
                "action": "queued",
                "number": item.get("number"),
                "queue_name": queue_name,
                "repo_path": repo_path,
                "item": item,
            }
        return {"ok": False, "action": "queue", "error": queue_error or "enqueue failed"}

    existing = _find_annotation_ux_queue_session(queue_name)
    if existing:
        sid = existing.get("session_id") or existing.get("id")
        injected = _inject_text_into_session(sid, text)
        if injected.get("ok"):
            _record_interaction(sid)
            return {
                "ok": True,
                "action": "injected",
                "queue_name": queue_name,
                "session_id": sid,
                "repo_path": repo_path,
                "inject": injected,
            }
        return {
            "ok": False,
            "action": "inject",
            "queue_name": queue_name,
            "session_id": sid,
            "repo_path": repo_path,
            "error": injected.get("error") or "inject failed",
            "inject": injected,
        }

    if engine == "antigravity":
        spawned = spawn_session_antigravity(text, name=queue_name, repo_path=repo_path)
    elif engine == "gemini":
        spawned = spawn_session_gemini(text, name=queue_name, repo_path=repo_path)
    elif engine == "kilo":
        spawned = spawn_session_kilo(text, name=queue_name, repo_path=repo_path)
    elif engine == "cursor":
        spawned = spawn_session_cursor(text, name=queue_name, repo_path=repo_path)
    else:
        spawned = spawn_session(text, name=queue_name, repo_path=repo_path)
        
    if not spawned.get("ok"):
        out = {
            "ok": False,
            "action": "spawn",
            "queue_name": queue_name,
            "repo_path": repo_path,
            "error": spawned.get("error") or "spawn failed",
            "spawn": spawned,
        }
        if spawned.get("code") == "claude_unavailable":
            out["status"] = 503
        return out

    sid = None
    log_path = spawned.get("log")
    if log_path:
        sid = _morning_resolve_session_id_from_log(log_path, max_wait_s=8.0)
    if sid:
        try:
            _save_session_name_override(sid, queue_name)
        except OSError:
            pass
        _record_interaction(sid)

    return {
        "ok": True,
        "action": "spawned",
        "queue_name": queue_name,
        "session_id": sid,
        "repo_path": repo_path,
        "pid": spawned.get("pid"),
        "spawn": spawned,
    }


def _schedule_restart(delay=0.5):
    """Arm an os.execvp() that replaces this process with a fresh
    `python server.py` after `delay` seconds. Called AFTER the HTTP response
    is flushed so the client sees {ok:true} before the socket dies."""
    def _go():
        try:
            sys.stdout.flush()
            sys.stderr.flush()
        except Exception:
            pass
        os.execvp(sys.executable, [sys.executable, str(Path(__file__).resolve())])
    t = threading.Timer(delay, _go)
    t.daemon = True
    t.start()


def _load_network_config():
    """Read persisted network config from NETWORK_CONFIG_FILE.

    Returns a dict with the three keys we care about, defaults filled in:
      {"bind_host": str|None, "allowed_origins": [str], "trust_tailnet": bool}
    Missing file or malformed JSON returns the empty default — same-origin
    behaviour falls back to env vars + loopback, which is the safe baseline.
    """
    default = {"bind_host": None, "allowed_origins": [], "trust_tailnet": False}
    try:
        raw = json.loads(NETWORK_CONFIG_FILE.read_text())
    except (OSError, json.JSONDecodeError):
        return default
    if not isinstance(raw, dict):
        return default
    bind_host = raw.get("bind_host")
    if not isinstance(bind_host, str) or not bind_host.strip():
        bind_host = None
    raw_origins = raw.get("allowed_origins") or []
    origins = []
    if isinstance(raw_origins, list):
        for item in raw_origins:
            if isinstance(item, str) and item.strip():
                origins.append(item.strip())
    return {
        "bind_host": bind_host.strip() if bind_host else None,
        "allowed_origins": origins,
        "trust_tailnet": bool(raw.get("trust_tailnet")),
    }


def _save_network_config(config):
    """Persist `config` to NETWORK_CONFIG_FILE. Only the three known keys are
    written — the function silently drops anything else so a bad POST body
    can't smuggle extra fields onto disk."""
    bind_host = config.get("bind_host")
    if bind_host is not None:
        bind_host = str(bind_host).strip() or None
    raw_origins = config.get("allowed_origins") or []
    origins = []
    if isinstance(raw_origins, list):
        for item in raw_origins:
            if isinstance(item, str) and item.strip():
                origins.append(item.strip())
    payload = {
        "bind_host": bind_host,
        "allowed_origins": origins,
        "trust_tailnet": bool(config.get("trust_tailnet")),
    }
    COMMAND_CENTER_STATE_DIR.mkdir(parents=True, exist_ok=True)
    NETWORK_CONFIG_FILE.write_text(json.dumps(payload, indent=2))
    return payload


# Car Mode key names -> the env var each maps to when we launch the voice agent.
_CAR_MODE_KEYS = {
    "anthropic_api_key": "ANTHROPIC_API_KEY",
    "deepgram_api_key": "DEEPGRAM_API_KEY",
}


def _load_car_mode_config():
    """Read stored Car Mode API keys. Missing/malformed file -> empty dict (the
    keys then fall back to os.environ / ccc-voice/.env at launch)."""
    try:
        raw = json.loads(CAR_MODE_CONFIG_FILE.read_text())
    except (OSError, json.JSONDecodeError):
        return {}
    if not isinstance(raw, dict):
        return {}
    out = {}
    for key in _CAR_MODE_KEYS:
        val = raw.get(key)
        if isinstance(val, str) and val.strip():
            out[key] = val.strip()
    return out


def _save_car_mode_config(config):
    """Persist only the known Car Mode keys (never smuggle extra fields to disk).
    An empty string clears that key. Returns the set of key names now stored."""
    existing = _load_car_mode_config()
    for key in _CAR_MODE_KEYS:
        if key not in (config or {}):
            continue  # not in this request -> leave as-is
        val = config.get(key)
        if isinstance(val, str) and val.strip():
            existing[key] = val.strip()
        else:
            existing.pop(key, None)  # blank -> clear
    COMMAND_CENTER_STATE_DIR.mkdir(parents=True, exist_ok=True)
    tmp = CAR_MODE_CONFIG_FILE.with_suffix(".json.tmp")
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(existing, f, indent=2, sort_keys=True)
        f.write("\n")
    tmp.replace(CAR_MODE_CONFIG_FILE)
    try:
        os.chmod(CAR_MODE_CONFIG_FILE, 0o600)  # keys are secrets — owner-only
    except OSError:
        pass
    return set(existing.keys())


def _car_mode_effective_keys():
    """Which Car Mode keys are available from EITHER stored config or the
    environment. Returns {"anthropic": bool, "deepgram": bool}. Never returns the
    values themselves. The launcher also honours ccc-voice/.env, so a user with
    keys only in that file still works — this just drives the UI's capability copy."""
    cfg = _load_car_mode_config()
    return {
        "anthropic": bool(cfg.get("anthropic_api_key") or os.environ.get("ANTHROPIC_API_KEY")),
        "deepgram": bool(cfg.get("deepgram_api_key") or os.environ.get("DEEPGRAM_API_KEY")),
    }


def _car_mode_status_mode(keys):
    """Map available keys -> capability mode string (see /api/car-mode/status)."""
    if not keys["anthropic"]:
        return "unavailable_no_anthropic"
    if not keys["deepgram"]:
        return "degraded_no_deepgram"  # dispatcher works, but no STT/TTS -> no hands-free voice
    return "voice"


def _detect_tailnet_origins(port):
    """Return ({available, running, hostname, ips, origins}) describing the
    local Tailscale node, or `available=False` when the CLI is missing.

    Origins are built from the magic-DNS hostname plus each tailscale IP, on
    HTTP at the supplied port — what a phone on the tailnet would see in its
    Origin header when hitting CCC. Never raises; any error path returns
    `available=False`/`running=False` so callers can degrade gracefully.
    """
    blank = {"available": False, "running": False, "hostname": "", "ips": [], "origins": []}
    try:
        proc = subprocess.run(
            ["tailscale", "status", "--json"],
            capture_output=True, text=True, timeout=4,
        )
    except (FileNotFoundError, subprocess.TimeoutExpired, OSError):
        return blank
    if proc.returncode != 0 or not proc.stdout.strip():
        return {**blank, "available": True}
    try:
        data = json.loads(proc.stdout)
    except json.JSONDecodeError:
        return {**blank, "available": True}
    self_node = data.get("Self") or {}
    hostname = (self_node.get("DNSName") or "").rstrip(".")
    raw_ips = self_node.get("TailscaleIPs") or data.get("TailscaleIPs") or []
    ips = [ip for ip in raw_ips if isinstance(ip, str)]
    backend = (data.get("BackendState") or "").strip()
    running = backend.lower() == "running"
    origins = []
    if hostname:
        origins.append(f"http://{hostname}:{port}")
    for ip in ips:
        if ":" in ip:  # IPv6 needs brackets in the URL
            origins.append(f"http://[{ip}]:{port}")
        else:
            origins.append(f"http://{ip}:{port}")
    return {
        "available": True,
        "running": running,
        "hostname": hostname,
        "ips": ips,
        "origins": origins,
    }


def _resolve_runtime_network(port):
    """Merge env vars, persisted config, and Tailscale auto-detect into the
    final {bind_host, allowed_origins[]} the server should use this run.

    Priority:
      bind_host: env CCC_BIND_HOST > config.bind_host > "127.0.0.1"
      allowed_origins: union of env CCC_ALLOWED_ORIGIN, config.allowed_origins,
        and detected tailnet origins (when trust_tailnet is on)
      trust_tailnet: env CCC_TRUST_TAILNET in {"1","true","yes","on"}
        OR config.trust_tailnet
    Returns (bind_host, allowed_origins, info) where `info` summarizes which
    layers contributed — purely for the startup banner and the GET endpoint.
    """
    config = _load_network_config()
    env_bind = os.environ.get("CCC_BIND_HOST", "").strip()
    bind_host = env_bind or (config["bind_host"] or "127.0.0.1")

    # Ephemeral verification servers (CCC_EPHEMERAL=1) must never expose the
    # network: force loopback regardless of CCC_BIND_HOST or config. Ad-hoc
    # snapshot/QA servers inherit the primary session's env, which previously
    # leaked a 0.0.0.0 bind onto the LAN (OPS-30/36/38/39). Pairs with the
    # write_port_file() CCC_EPHEMERAL skip so they also can't clobber port.txt.
    if os.environ.get("CCC_EPHEMERAL"):
        if env_bind and env_bind not in ("127.0.0.1", "localhost"):
            print(f"   CCC_EPHEMERAL set: ignoring CCC_BIND_HOST={env_bind}, forcing 127.0.0.1")
        bind_host = "127.0.0.1"
        env_bind = ""

    env_trust = os.environ.get("CCC_TRUST_TAILNET", "").strip().lower() in ("1", "true", "yes", "on")
    trust_tailnet = env_trust or config["trust_tailnet"]

    env_origins = [o.strip() for o in os.environ.get("CCC_ALLOWED_ORIGIN", "").split(",") if o.strip()]
    origins = []
    seen = set()
    for src in (env_origins, config["allowed_origins"]):
        for o in src:
            if o not in seen:
                seen.add(o)
                origins.append(o)
    tailnet_info = _detect_tailnet_origins(port) if trust_tailnet else {"available": False, "running": False, "hostname": "", "ips": [], "origins": []}
    if trust_tailnet:
        for o in tailnet_info["origins"]:
            if o not in seen:
                seen.add(o)
                origins.append(o)

    info = {
        "bind_host": bind_host,
        "allowed_origins": origins,
        "trust_tailnet": trust_tailnet,
        "env_overrides": {
            "bind_host": bool(env_bind),
            "trust_tailnet": env_trust,
            "allowed_origins": bool(env_origins),
        },
        "tailnet": tailnet_info,
        "config_file_origins": list(config["allowed_origins"]),
        "config_file_bind_host": config["bind_host"],
        "config_file_trust_tailnet": config["trust_tailnet"],
        "port": port,
    }
    return bind_host, origins, info


# Cache the healthcheck — it walks ~/.claude/projects and shells out to `gh`,
# both of which are slow (multi-hundred-ms on a populated machine). The UI hits
# this endpoint on every page load; without a cache it dominated the network
# critical path. TTL is short so a failing dep still recovers within ~30s.
_HEALTHCHECK_CACHE = {"ts": 0.0, "data": None}
_HEALTHCHECK_TTL_SEC = 30.0
_HEALTHCHECK_CACHE_LOCK = threading.Lock()

# Separate longer cache for the `gh auth status` subprocess. Even after the
# outer healthcheck cache expires, this avoids re-shelling out for 5 minutes.
_GH_AUTH_CACHE = {"ts": 0.0, "check": None}
_GH_AUTH_TTL_SEC = 300.0


def _gh_auth_check_cached(gh_path):
    now = time.monotonic()
    if _GH_AUTH_CACHE["check"] is not None and now - _GH_AUTH_CACHE["ts"] < _GH_AUTH_TTL_SEC:
        return _GH_AUTH_CACHE["check"]
    try:
        r = subprocess.run(
            ["gh", "auth", "status"],
            capture_output=True, text=True, timeout=5,
        )
        if r.returncode != 0:
            check = {
                "id": "gh_cli",
                "label": "GitHub CLI",
                "status": "warn",
                "message": "`gh` installed but not authenticated",
                "hint": "Run `gh auth login` in your terminal, then refresh.",
            }
        else:
            user = ""
            m = re.search(r"account\s+(\S+)", r.stderr or r.stdout or "")
            if m:
                user = m.group(1)
            check = {
                "id": "gh_cli",
                "label": "GitHub CLI",
                "status": "ok",
                "message": f"Authenticated{f' as @{user}' if user else ''}",
            }
    except (subprocess.SubprocessError, OSError) as e:
        check = {
            "id": "gh_cli",
            "label": "GitHub CLI",
            "status": "error",
            "message": f"`gh auth status` failed: {e}",
            "hint": "Check `gh` install. Run `gh auth status` manually for details.",
        }
    _GH_AUTH_CACHE["ts"] = now
    _GH_AUTH_CACHE["check"] = check
    return check


def _run_healthcheck():
    """Probe every external dependency and surface a structured diagnosis.

    Each check returns:
      - status: "ok" / "warn" / "error"
      - message: human-readable one-liner
      - hint: actionable next step (only present on warn/error)

    The UI renders a setup banner that lists only the failing checks.
    Empty UI without explanation is the worst first-run experience.
    """
    now = time.monotonic()
    cached = _HEALTHCHECK_CACHE["data"]
    if cached is not None and now - _HEALTHCHECK_CACHE["ts"] < _HEALTHCHECK_TTL_SEC:
        return cached
    # A cold dashboard boot can issue several healthcheck requests together.
    # Serialize the expensive filesystem/subprocess probe and recheck after
    # waiting so that only the first caller performs it.
    with _HEALTHCHECK_CACHE_LOCK:
        now = time.monotonic()
        cached = _HEALTHCHECK_CACHE["data"]
        if cached is not None and now - _HEALTHCHECK_CACHE["ts"] < _HEALTHCHECK_TTL_SEC:
            return cached
        out = _build_healthcheck()
        _HEALTHCHECK_CACHE["ts"] = now
        _HEALTHCHECK_CACHE["data"] = out
        return out


def _build_healthcheck():
    out = {"checks": []}

    # ── claude CLI ────────────────────────────────────────────────────
    claude_info = _resolve_claude_bin()
    projects_dir = Path.home() / ".claude" / "projects"
    if not claude_info.get("available"):
        out["checks"].append({
            "id": "claude_cli",
            "label": "Claude Code CLI",
            "status": "error",
            "message": "Claude Code CLI not found",
            "hint": claude_info.get("reason") or "Install Claude Code: https://docs.claude.com/en/docs/claude-code",
        })
    elif not projects_dir.is_dir():
        out["checks"].append({
            "id": "claude_cli",
            "label": "Claude Code CLI",
            "status": "warn",
            "message": "`claude` installed but no sessions yet",
            "hint": "Run `claude` once in any repo to generate session data, then refresh.",
        })
    else:
        try:
            session_files = [p for p in projects_dir.rglob("*.jsonl")]
            n = len(session_files)
        except OSError:
            n = 0
        out["checks"].append({
            "id": "claude_cli",
            "label": "Claude Code CLI",
            "status": "ok",
            "message": f"Found {n} session file{'s' if n != 1 else ''} on disk",
        })

    # ── gh CLI ────────────────────────────────────────────────────────
    gh_path = _which("gh")
    if not gh_path:
        out["checks"].append({
            "id": "gh_cli",
            "label": "GitHub CLI",
            "status": "warn",
            "message": "`gh` not found on PATH (issue board disabled)",
            "hint": "Install: `brew install gh`  (or see https://cli.github.com/)",
        })
    else:
        out["checks"].append(_gh_auth_check_cached(gh_path))

    # ── Repo list state ───────────────────────────────────────────────
    try:
        repo_count = len(load_known_repos())
    except Exception:
        repo_count = 0
    out["checks"].append({
        "id": "repo_list",
        "label": "Known repos",
        "status": "ok" if repo_count else "warn",
        "message": (
            f"{repo_count} repo{'s' if repo_count != 1 else ''} available"
            if repo_count else
            "No repo folders discovered yet"
        ),
        "hint": None if repo_count else "Add a repo from the repo picker.",
    })

    # Overall summary: worst status wins.
    statuses = [c["status"] for c in out["checks"]]
    if "error" in statuses:
        out["overall"] = "error"
    elif "warn" in statuses:
        out["overall"] = "warn"
    else:
        out["overall"] = "ok"
    return out


STATIC_DIR = CCC_ROOT / "static"
MORNING_STATIC_DIR = STATIC_DIR / "morning"

# ── Optional Morning view plugin ──────────────────────────────────────────
# The Morning view (goals/strategic/tactical/braindump) is highly opinionated
# to one user's workflow. Files (morning.py, morning_store.py, static/morning/,
# scripts/ingest_apple_notes.py, ingesters/) are gitignored and may not be
# present — we detect both the import success AND the user's opt-in env var
# before enabling routes.
#
# CI guarantees nothing in the core depends on these — the smoke test boots
# the server with NO morning files present and asserts startup succeeds.
try:
    import morning  # noqa: F401  — used inside route handlers
    _MORNING_IMPORTABLE = True
except ImportError:
    morning = None
    _MORNING_IMPORTABLE = False
MORNING_ENABLED = (
    _MORNING_IMPORTABLE
    and os.environ.get("CCC_ENABLE_MORNING", "").strip().lower() in ("1", "true", "yes", "on")
)

PORT = int(os.environ.get("PORT", 8090))
# Slow-request threshold (ms). Requests taking at least this long get a single
# [SLOW] line on stdout; everything faster stays silent. Tune via CCC_SLOW_REQ_MS.
try:
    SLOW_REQ_MS = float(os.environ.get("CCC_SLOW_REQ_MS", "500"))
except (TypeError, ValueError):
    SLOW_REQ_MS = 500.0
# Set in main() after _resolve_runtime_network. Module-level so functions
# called at runtime can reach it without threading the value through every
# call site.
BIND_HOST = "127.0.0.1"
# Optional title-prefix noise stripper. Comma-separated prefixes.
# Empty by default; set `CCC_TITLE_STRIP=ACME,FOO` to strip `[ACME ...]` and `[FOO ...]` from titles.
TITLE_STRIP_PREFIXES = [p for p in os.environ.get("CCC_TITLE_STRIP", "").split(",") if p]

# Same-origin allowlist extension. Origins listed here are accepted on top of
# the loopback defaults (localhost / 127.0.0.1 / [::1]) so the UI can be
# reached from another device on a trusted network (Tailscale, VPN). Three
# layers feed this list at startup, all merged into the final ALLOWED_ORIGINS:
#   1. CCC_ALLOWED_ORIGIN env var — comma-separated full origins
#   2. ~/.claude/command-center/network.json `allowed_origins` field
#   3. Tailscale auto-detect when `trust_tailnet` is on (config or env)
# Format: scheme://host[:port], e.g. `http://my-mac.tailnet.ts.net:8090`.
# The server has no auth, so every entry here is a peer that can run commands
# as you — see SECURITY.md. Mutated by `_resolve_runtime_network` in main().
ALLOWED_ORIGINS = [o.strip() for o in os.environ.get("CCC_ALLOWED_ORIGIN", "").split(",") if o.strip()]
# Populated in main() once the file + env + tailnet layers are merged. The
# GET /api/network-config handler returns this verbatim so the UI can show
# the user exactly what's trusted on this run, including which env vars
# are pinning values they can't override from the UI.
RUNTIME_NETWORK_INFO = None

# Optional org-tagger for multi-tenant apps. Set CCC_ORG_PATTERNS as
# `Label1:pat1a|pat1b;Label2:pat2`. The server scans each GitHub issue body
# for the patterns and tags the card with `org: "Label1"`, letting the UI
# group backlog by org. Leave unset and every issue is tagged `org: null`.
_org_spec = os.environ.get("CCC_ORG_PATTERNS", "")
ORG_PATTERNS = []
for chunk in _org_spec.split(";"):
    if ":" not in chunk:
        continue
    label, pats = chunk.split(":", 1)
    label = label.strip()
    alts = [p.strip() for p in pats.split("|") if p.strip()]
    if label and alts:
        try:
            ORG_PATTERNS.append((label, re.compile("|".join(alts), re.IGNORECASE)))
        except re.error:
            pass


def _detect_issue_org(body):
    """Return the first matching org label for an issue body, or None."""
    if not body or not ORG_PATTERNS:
        return None
    for label, rx in ORG_PATTERNS:
        if rx.search(body):
            return label
    return None


_TITLE_STRIP_RE = re.compile(
    r"^\s*\[(?:" + "|".join(re.escape(p) for p in TITLE_STRIP_PREFIXES) + r")[^\]]*\]\s*"
) if TITLE_STRIP_PREFIXES else None


def _strip_title_prefix(title):
    if not title or not _TITLE_STRIP_RE:
        return title
    return _TITLE_STRIP_RE.sub("", title)


# ── Flow work-item state ─────────────────────────────────────────────────
def _flow_display_path(path):
    try:
        p = Path(path).expanduser().resolve(strict=False)
        home = Path.home().resolve(strict=False)
        rel = p.relative_to(home)
        return "~/" + str(rel)
    except (OSError, RuntimeError, ValueError):
        return str(path)


def _flow_slug(value, fallback="item", max_len=48):
    s = re.sub(r"[^A-Za-z0-9._-]+", "-", str(value or "").strip()).strip("-._")
    if not s:
        s = fallback
    return s[:max_len]


def _flow_field_key(label):
    s = re.sub(r"[^a-z0-9]+", "_", str(label or "").strip().lower()).strip("_")
    aliases = {
        "target": "target_date",
        "date": "target_date",
        "due": "target_date",
        "due_date": "target_date",
        "color": "color_seed",
    }
    return aliases.get(s, s)


def _flow_node_id(kind, repo_path=None, object_id=None):
    kind = (kind or "").strip().lower()
    if kind == "repo":
        repo = resolve_repo_path(repo_path)
        return f"repo:{repo}"
    if kind == "object":
        oid = _flow_slug(object_id, fallback="object", max_len=96)
        return f"object:{oid}"
    raise ValueError("kind must be repo or object")


def _flow_state_path(kind, repo_path=None, object_id=None):
    kind = (kind or "").strip().lower()
    if kind == "repo":
        repo = resolve_repo_path(repo_path)
        leaf = _flow_slug(Path(repo).name, fallback="repo", max_len=44)
        digest = hashlib.sha1(repo.encode("utf-8")).hexdigest()[:12]
        return FLOW_STATE_DIR / "repos" / f"{leaf}-{digest}.md"
    if kind == "object":
        oid = _flow_slug(object_id, fallback="object", max_len=96)
        return FLOW_STATE_DIR / "objects" / f"{oid}.md"
    raise ValueError("kind must be repo or object")


def _flow_parse_fields(content):
    fields = {k: "" for k in _FLOW_FIELD_LABELS}
    fields["status"] = "Active"
    fields["color_seed"] = "auto"
    in_fields = False
    for line in str(content or "").splitlines():
        if re.match(r"^##\s+Flow fields\s*$", line.strip(), re.IGNORECASE):
            in_fields = True
            continue
        if in_fields and re.match(r"^##\s+", line):
            break
        if not in_fields:
            continue
        if not line.strip().startswith("|"):
            continue
        cells = [c.strip() for c in line.strip().strip("|").split("|")]
        if len(cells) < 2:
            continue
        if re.fullmatch(r":?-{3,}:?", cells[0] or ""):
            continue
        key = _flow_field_key(cells[0])
        if key in fields and cells[0].lower() != "field":
            fields[key] = cells[1]
    return fields


def _flow_managed_block(name, body):
    return (
        f"<!-- ccc:auto:start {name} -->\n"
        f"{str(body or '').rstrip()}\n"
        f"<!-- ccc:auto:end {name} -->"
    )


def _flow_replace_managed_block(content, name, body):
    block = _flow_managed_block(name, body)
    pattern = re.compile(
        r"<!--\s*ccc:auto:start\s+" + re.escape(name) + r"\s*-->"
        r"[\s\S]*?"
        r"<!--\s*ccc:auto:end\s+" + re.escape(name) + r"\s*-->",
        re.IGNORECASE,
    )
    if pattern.search(content or ""):
        return pattern.sub(block, content, count=1)
    return str(content or "").rstrip() + "\n\n" + block + "\n"


def _flow_table_cell(value):
    s = str(value or "").replace("\r", " ").replace("\n", " ").strip()
    s = s.replace("|", "\\|")
    return s or "-"


def _flow_item_done(item):
    if bool(item.get("done")):
        return True
    status = str(item.get("status") or "").strip().lower()
    return status in {"done", "completed", "complete", "archived", "verified", "closed"}


def _flow_current_work_block(items):
    rows = [
        "## Current work",
        "",
        "| Item | Status | Session | Updated | Notes |",
        "|---|---|---|---|---|",
    ]
    clean = [it for it in (items or []) if isinstance(it, dict) and (it.get("title") or it.get("item"))]
    if not clean:
        rows.append("| No visible child work yet. | - | - | - | - |")
    for it in clean:
        rows.append(
            "| "
            + " | ".join([
                _flow_table_cell(it.get("title") or it.get("item")),
                _flow_table_cell(it.get("status")),
                _flow_table_cell(it.get("session") or it.get("session_id")),
                _flow_table_cell(it.get("updated")),
                _flow_table_cell(it.get("notes")),
            ])
            + " |"
        )
    return "\n".join(rows)


def _flow_open_items_block(items):
    lines = ["## Open items", ""]
    open_items = [it for it in (items or []) if isinstance(it, dict) and not _flow_item_done(it)]
    if not open_items:
        lines.append("- None detected yet.")
    for it in open_items:
        title = _flow_table_cell(it.get("title") or it.get("item"))
        status = _flow_table_cell(it.get("status"))
        lines.append(f"- {title}" + (f" ({status})" if status != "-" else ""))
    return "\n".join(lines)


def _flow_completed_block(items):
    lines = ["## Completed", ""]
    done_items = [it for it in (items or []) if isinstance(it, dict) and _flow_item_done(it)]
    if not done_items:
        lines.append("- None detected yet.")
    for it in done_items:
        title = _flow_table_cell(it.get("title") or it.get("item"))
        status = _flow_table_cell(it.get("status"))
        lines.append(f"- {title}" + (f" ({status})" if status != "-" else ""))
    return "\n".join(lines)


def _flow_template(kind, title, repo_path=None, object_id=None):
    title = (str(title or "").strip()
             or (Path(str(repo_path)).name if repo_path else "")
             or str(object_id or "").strip()
             or "Flow work item")
    fields = [
        "| Field | Value |",
        "|---|---|",
        "| Status | Active |",
        "| Goal |  |",
        "| Target date |  |",
        "| ETA |  |",
        "| Owner |  |",
        "| Color seed | auto |",
    ]
    meta = []
    if kind == "repo" and repo_path:
        meta.append(f"Repo path: `{repo_path}`")
    if kind == "object" and object_id:
        meta.append(f"Object id: `{object_id}`")
    now = datetime.now().astimezone().strftime("%Y-%m-%d %H:%M:%S %Z")
    parts = [
        f"# {title}",
        "",
        "## Flow fields",
        "",
        "\n".join(fields),
        "",
    ]
    if meta:
        parts.extend(["## Identity", "", "\n".join(meta), ""])
    parts.extend([
        "## Summary",
        "",
        "Write the current state here.",
        "",
        _flow_managed_block("status-table", _flow_current_work_block([])),
        "",
        _flow_managed_block("open-items", _flow_open_items_block([])),
        "",
        _flow_managed_block("completed", _flow_completed_block([])),
        "",
        "## Manual notes",
        "",
        f"Created by CCC Flow on {now}.",
        "",
    ])
    return "\n".join(parts)


def _flow_read_index():
    try:
        data = json.loads(FLOW_INDEX_FILE.read_text(encoding="utf-8"))
    except (OSError, UnicodeDecodeError, json.JSONDecodeError):
        data = {}
    nodes = data.get("nodes") if isinstance(data, dict) else None
    return nodes if isinstance(nodes, dict) else {}


def _flow_write_index(nodes):
    FLOW_STATE_DIR.mkdir(parents=True, exist_ok=True)
    tmp = FLOW_INDEX_FILE.with_suffix(".json.tmp")
    tmp.write_text(
        json.dumps({"schema": 1, "nodes": nodes}, indent=2, sort_keys=True) + "\n",
        encoding="utf-8",
    )
    os.replace(tmp, FLOW_INDEX_FILE)


def _flow_index_upsert(entry):
    with _FLOW_INDEX_LOCK:
        nodes = _flow_read_index()
        nodes[entry["node_id"]] = {
            "kind": entry.get("kind") or "",
            "repo_path": entry.get("repo_path") or "",
            "object_id": entry.get("object_id") or "",
            "title": entry.get("title") or "",
            "path": entry.get("path") or "",
            "updated_at": time.time(),
        }
        _flow_write_index(nodes)


def _flow_response_for_path(entry, path):
    try:
        content = path.read_text(encoding="utf-8", errors="replace")
        mtime = path.stat().st_mtime
    except OSError as exc:
        return {"ok": False, "error": str(exc)}, 500
    fields = _flow_parse_fields(content)
    return {
        "ok": True,
        "kind": entry.get("kind") or "",
        "node_id": entry["node_id"],
        "title": entry.get("title") or "",
        "repo_path": entry.get("repo_path") or "",
        "object_id": entry.get("object_id") or "",
        "path": str(path),
        "state_path": _flow_display_path(path),
        "content": content,
        "mtime": mtime,
        "fields": fields,
    }, 200


def _flow_entry_from_payload(payload):
    payload = payload or {}
    kind = str(payload.get("kind") or "").strip().lower()
    repo_path = str(payload.get("repo_path") or "").strip()
    object_id = str(payload.get("object_id") or "").strip()
    title = str(payload.get("title") or "").strip()
    node_id = _flow_node_id(kind, repo_path=repo_path, object_id=object_id)
    if kind == "repo":
        repo_path = resolve_repo_path(repo_path)
        if not title:
            title = Path(repo_path).name
    elif kind == "object":
        object_id = _flow_slug(object_id, fallback="object", max_len=96)
        if not title:
            title = object_id
    path = _flow_state_path(kind, repo_path=repo_path, object_id=object_id)
    return {
        "kind": kind,
        "node_id": node_id,
        "repo_path": repo_path,
        "object_id": object_id,
        "title": title,
        "path": str(path),
    }, path


def _flow_load_node_payload(payload, create=False):
    try:
        entry, path = _flow_entry_from_payload(payload)
    except (RepoContextError, ValueError) as exc:
        status = exc.status if isinstance(exc, RepoContextError) else 400
        return {"ok": False, "error": str(exc)}, status
    if not _path_is_within(path, FLOW_STATE_DIR):
        return {"ok": False, "error": "invalid flow state path"}, 403
    if not path.exists():
        if not create:
            return {"ok": False, "error": "not found", "path": str(path)}, 404
        try:
            path.parent.mkdir(parents=True, exist_ok=True)
            content = _flow_template(
                entry["kind"],
                entry.get("title"),
                repo_path=entry.get("repo_path"),
                object_id=entry.get("object_id"),
            )
            tmp = path.with_suffix(path.suffix + ".tmp")
            tmp.write_text(content, encoding="utf-8")
            os.replace(tmp, path)
        except OSError as exc:
            return {"ok": False, "error": f"could not create flow file: {exc}"}, 500
    _flow_index_upsert(entry)
    return _flow_response_for_path(entry, path)


def _flow_save_node_payload(payload):
    try:
        entry, path = _flow_entry_from_payload(payload)
    except (RepoContextError, ValueError) as exc:
        status = exc.status if isinstance(exc, RepoContextError) else 400
        return {"ok": False, "error": str(exc)}, status
    if not _path_is_within(path, FLOW_STATE_DIR):
        return {"ok": False, "error": "invalid flow state path"}, 403
    content = payload.get("content")
    if not isinstance(content, str):
        return {"ok": False, "error": "content must be a string"}, 400
    if len(content.encode("utf-8", errors="replace")) > 1024 * 1024:
        return {"ok": False, "error": "content too large"}, 413
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        if path.exists() and not payload.get("overwrite"):
            current_mtime = path.stat().st_mtime
            expected = payload.get("mtime")
            if expected is not None:
                try:
                    expected_f = float(expected)
                except (TypeError, ValueError):
                    expected_f = 0.0
                if expected_f and abs(current_mtime - expected_f) > 0.001:
                    return {
                        "ok": False,
                        "error": "flow file changed on disk",
                        "mtime": current_mtime,
                    }, 409
        tmp = path.with_suffix(path.suffix + ".tmp")
        tmp.write_text(content, encoding="utf-8")
        os.replace(tmp, path)
    except OSError as exc:
        return {"ok": False, "error": str(exc)}, 500
    _flow_index_upsert(entry)
    return _flow_response_for_path(entry, path)


def _flow_refresh_node_payload(payload):
    result, status = _flow_load_node_payload(payload, create=True)
    if not result.get("ok"):
        return result, status
    content = result.get("content") or ""
    items = payload.get("items") or []
    if not isinstance(items, list):
        items = []
    content = _flow_replace_managed_block(content, "status-table", _flow_current_work_block(items))
    content = _flow_replace_managed_block(content, "open-items", _flow_open_items_block(items))
    content = _flow_replace_managed_block(content, "completed", _flow_completed_block(items))
    save_payload = dict(payload)
    save_payload["content"] = content
    save_payload["mtime"] = result.get("mtime")
    save_payload["overwrite"] = True
    refreshed, refresh_status = _flow_save_node_payload(save_payload)
    if refreshed.get("ok"):
        refreshed["derived"] = {
            "active_session_count": len([it for it in items if isinstance(it, dict) and not _flow_item_done(it)]),
            "completed_count": len([it for it in items if isinstance(it, dict) and _flow_item_done(it)]),
            "open_item_count": len([it for it in items if isinstance(it, dict) and not _flow_item_done(it)]),
        }
    return refreshed, refresh_status


def _flow_index_payload():
    entries = []
    with _FLOW_INDEX_LOCK:
        nodes = _flow_read_index()
    for node_id, entry in sorted(nodes.items()):
        if not isinstance(entry, dict):
            continue
        path = Path(entry.get("path") or "")
        if not path.is_file() or not _path_is_within(path, FLOW_STATE_DIR):
            continue
        try:
            content = path.read_text(encoding="utf-8", errors="replace")
            mtime = path.stat().st_mtime
        except OSError:
            continue
        entries.append({
            "node_id": node_id,
            "kind": entry.get("kind") or "",
            "repo_path": entry.get("repo_path") or "",
            "object_id": entry.get("object_id") or "",
            "title": entry.get("title") or "",
            "path": str(path),
            "state_path": _flow_display_path(path),
            "mtime": mtime,
            "fields": _flow_parse_fields(content),
        })
    return {"ok": True, "entries": entries, "count": len(entries)}

# Sidecar state (written by hooks)
SIDECAR_STATE_DIR = Path.home() / ".claude" / "command-center" / "live-state"
HOOK_SCRIPTS_DIR = Path.home() / ".claude" / "command-center" / "hooks"
HOOK_MARKER = "command-center/hooks/"
CCC_HOOK_SCRIPT_NAMES = ("pre-tool-use.py", "post-tool-use.py", "notification.py", "stop.py")
# Legacy marker (pre-rename) — kept so ensure_hooks_installed can detect old
# entries in ~/.claude/settings.json and rewrite them to the new path.
HOOK_MARKER_LEGACY = "log-viewer/hooks/"


def _hook_python_executable():
    """Absolute Python executable for Claude Code hook commands."""
    system_python = "/usr/bin/python3"
    if sys.platform == "darwin" and os.access(system_python, os.X_OK):
        return system_python
    exe = sys.executable or ""
    if exe and not os.path.isabs(exe):
        exe = shutil.which(exe) or exe
    if not exe:
        exe = shutil.which("python3") or shutil.which("python") or "python3"
    return exe


def _hook_script_command(script_path):
    return f"{shlex.quote(_hook_python_executable())} {shlex.quote(str(script_path))}"


def _ccc_hook_command(script_name):
    return _hook_script_command(HOOK_SCRIPTS_DIR / script_name)


def _normalize_ccc_hook_command(command):
    """Return a PATH-independent command for CCC hook script entries."""
    if not isinstance(command, str):
        return command, False
    rewritten = command.replace(HOOK_MARKER_LEGACY, HOOK_MARKER)
    for script_name in CCC_HOOK_SCRIPT_NAMES:
        if script_name in rewritten and HOOK_MARKER in rewritten:
            normalized = _ccc_hook_command(script_name)
            return normalized, normalized != command
    return rewritten, rewritten != command

