# {path: {mtime, custom_title, last_prompt, agent_name, ...}}
# Persistent across restarts via _CONV_META_CACHE_FILE — without it, every
# repo switch on a project with hundreds of large JSONLs (BYM+Finie has
# 1.8 GB of conversation logs) re-walks every file and the API stalls
# for a minute or more. The cache is mtime-keyed so admin writes
# (custom-title, /rename) correctly invalidate the entry; bump
# _CONV_META_SCHEMA_VERSION when the extracted shape changes so old
# entries are dropped on load.
_conv_meta_cache = {}
_conv_meta_cache_dirty = False
_conv_meta_cache_lock = threading.Lock()
_CONV_META_SCHEMA_VERSION = 13

# In-memory cache of the head-parse (first ~20 lines: session_id, timestamp,
# git_branch, first_message, head_cwd) keyed by str(path) -> (cache_key, tuple),
# where cache_key is (st_mtime_ns, st_size) — same invalidation as
# _extract_tail_meta. The all-folders archive build opens and parses the head of
# every conversation (~1390 files) on each load; archived transcripts never
# change, so this collapses that to only the files that actually changed.
_conv_head_cache = {}
# Separate cache for the 5-field head shape (session_id, timestamp, git_branch,
# first_message, head_cwd) used by the live-sessions scan. It MUST NOT share
# _conv_head_cache, which holds a 4-field shape keyed by the same file path —
# sharing one dict made the two scans clobber each other's entries and unpack
# the wrong arity (ValueError: too many values to unpack).
_conv_head5_cache = {}
_CONV_META_COMPAT_SCHEMA_VERSIONS = {13}
_CONV_META_CACHE_FILE = (
    Path.home() / ".claude" / "command-center" / "conv_meta_cache.json"
)


def _load_cwd_relocation_cache():
    """Persist cwd-relocation results across restarts.

    `_relocate_missing_session_cwd` walks the filesystem when a session's
    recorded cwd no longer exists (deleted worktree, moved repo). On a
    worktree-heavy repo with many old sessions the walk can take ~40s per
    cold scan. Persisting the result — positive AND negative — drops the
    second-and-subsequent cold start to near-zero. Cache entries are
    revalidated lazily in _relocate_missing_session_cwd.
    """
    if not _CWD_RELOCATION_CACHE_FILE.is_file():
        return
    try:
        with _CWD_RELOCATION_CACHE_FILE.open("r") as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError, ValueError):
        return
    if not isinstance(data, dict):
        return
    if data.get("schema_version") != _CWD_RELOCATION_CACHE_SCHEMA:
        return
    entries = data.get("entries")
    if not isinstance(entries, list):
        return
    loaded = {}
    for row in entries:
        if not isinstance(row, dict):
            continue
        sid = row.get("session_id")
        raw = row.get("recorded_cwd")
        if not sid or not isinstance(raw, str):
            continue
        target = row.get("resolved_cwd")
        if target is not None and not isinstance(target, str):
            continue
        loaded[(sid, raw)] = target
    with _session_cwd_relocation_cache_lock:
        _session_cwd_relocation_cache.update(loaded)


def _save_cwd_relocation_cache():
    """Atomic write of _session_cwd_relocation_cache when dirty."""
    global _session_cwd_relocation_cache_dirty
    with _session_cwd_relocation_cache_lock:
        if not _session_cwd_relocation_cache_dirty:
            return
        snapshot = {
            "schema_version": _CWD_RELOCATION_CACHE_SCHEMA,
            "entries": [
                {
                    "session_id": sid,
                    "recorded_cwd": raw,
                    "resolved_cwd": resolved,
                }
                for (sid, raw), resolved in _session_cwd_relocation_cache.items()
            ],
        }
        _session_cwd_relocation_cache_dirty = False
    try:
        _CWD_RELOCATION_CACHE_FILE.parent.mkdir(parents=True, exist_ok=True)
        tmp = _CWD_RELOCATION_CACHE_FILE.with_suffix(".json.tmp")
        with tmp.open("w") as f:
            json.dump(snapshot, f)
        tmp.replace(_CWD_RELOCATION_CACHE_FILE)
    except OSError as e:
        with _session_cwd_relocation_cache_lock:
            _session_cwd_relocation_cache_dirty = True
        print(f"  [cwd-relocation-cache] save failed: {e}")


def _relocation_budget_begin(seconds=None):
    """Open a per-request time budget for _relocate_missing_session_cwd.

    On budget exhaustion, in-flight relocations short-circuit to None
    (the row falls back to the recorded cwd verbatim); the cache is not
    populated for skipped entries so a future request can still resolve
    them. Defaults to 1.5s — high enough that one cold scan can resolve a
    handful of missing cwds, low enough that no single request stalls.
    """
    if seconds is None:
        try:
            seconds = float(os.environ.get("CCC_CWD_RELOCATION_BUDGET_S", "1.5"))
        except (TypeError, ValueError):
            seconds = 1.5
    _relocation_budget.deadline = time.monotonic() + max(0.0, seconds)
    _relocation_budget.exhausted_count = 0


def _relocation_budget_end():
    _relocation_budget.deadline = None


def _relocation_budget_exhausted():
    deadline = getattr(_relocation_budget, "deadline", None)
    if deadline is None:
        return False
    if time.monotonic() > deadline:
        _relocation_budget.exhausted_count = getattr(_relocation_budget, "exhausted_count", 0) + 1
        return True
    return False


def _load_conv_meta_cache():
    """Best-effort load of _conv_meta_cache from disk on startup.

    Drops the entire payload (and re-extracts on demand) when the schema
    version doesn't match — small one-time cost in exchange for forward
    compatibility on shape changes.
    """
    if not _CONV_META_CACHE_FILE.is_file():
        return
    try:
        with _CONV_META_CACHE_FILE.open("r") as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError, ValueError):
        return
    if not isinstance(data, dict):
        return
    if data.get("schema_version") not in _CONV_META_COMPAT_SCHEMA_VERSIONS:
        return
    entries = data.get("entries")
    if not isinstance(entries, dict):
        return
    keep = {
        k: v for k, v in entries.items()
        if isinstance(v, dict) and "mtime" in v
    }
    # JSON has no tuple type, so a cache_key saved as (mtime_ns, size) comes
    # back as a list. The freshness check in _extract_tail_meta compares it
    # against a freshly built tuple, and [a, b] == (a, b) is always False —
    # so without this coercion the disk cache NEVER hits and every restart
    # re-parses all ~1k+ transcripts (tens of seconds at 100% CPU, which
    # starves every other request thread via the GIL and wedges the server).
    for v in keep.values():
        ck = v.get("cache_key")
        if isinstance(ck, list):
            v["cache_key"] = tuple(ck)
    with _conv_meta_cache_lock:
        _conv_meta_cache.update(keep)


def _env_int(name, default):
    try:
        return int(os.environ.get(name, str(default)))
    except (TypeError, ValueError):
        return default


def _session_scan_cutoff_ts(include_old):
    if include_old:
        return 0
    max_age_days = _env_int("CCC_MAX_CONV_AGE_DAYS", 30)
    if max_age_days <= 0:
        return 0
    return time.time() - (max_age_days * 86400)


def _session_scan_file_limit(include_old):
    if include_old:
        return 0
    return max(0, _env_int("CCC_INITIAL_SESSION_SCAN_LIMIT", 180))


def _filter_conversation_jsonls(
    jsonl_files,
    *,
    include_old=False,
    always_include_sids=None,
    last_interactions=None,
    cutoff_ts=None,
    max_files=None,
):
    """Return JSONL paths to scan for the first sessions response.

    The board needs live/recent sessions immediately, not every historical
    transcript. Old rows remain available through ?include_old=1.
    """
    files = list(jsonl_files)
    total = len(files)
    if include_old:
        return files, {"total": total, "skipped_old": 0, "limited": False}

    if cutoff_ts is None:
        cutoff_ts = _session_scan_cutoff_ts(False)
    if max_files is None:
        max_files = _session_scan_file_limit(False)
    always_include_sids = set(always_include_sids or [])
    last_interactions = last_interactions or {}

    required = []
    optional = []
    skipped_old = 0
    for f in files:
        try:
            st = f.stat()
        except OSError:
            continue
        sid = f.name[:-6] if f.name.endswith(".jsonl") else f.stem
        interacted = last_interactions.get(sid) or 0
        freshness = max(st.st_mtime, interacted)
        keep_always = sid in always_include_sids
        is_recent = cutoff_ts <= 0 or freshness >= cutoff_ts
        if not keep_always and not is_recent:
            skipped_old += 1
            continue
        row = (freshness, f)
        if keep_always:
            required.append(row)
        else:
            optional.append(row)

    required.sort(key=lambda x: x[0], reverse=True)
    optional.sort(key=lambda x: x[0], reverse=True)

    limited = False
    if max_files > 0 and len(required) + len(optional) > max_files:
        remaining = max(0, max_files - len(required))
        optional = optional[:remaining]
        limited = True

    selected = [f for _, f in required + optional]
    return selected, {
        "total": total,
        "skipped_old": skipped_old,
        "limited": limited,
    }


def _gc_scratch_jsonls(max_age_days=7):
    """Delete throwaway JSONLs older than max_age_days from our scratch
    project dir. Called once at server startup so the scratch dir
    self-empties without any background thread or cron — the next
    `./run.sh` or upgrade is the trigger.

    Only operates on `~/.claude/projects/<slug>/` where <slug> is derived
    from `_SCRATCH_DIR`; never touches any user-repo project dir.
    """
    try:
        cutoff_days = int(os.environ.get("CCC_SCRATCH_GC_DAYS", str(max_age_days)))
    except ValueError:
        cutoff_days = max_age_days
    if cutoff_days <= 0:
        return
    cutoff = time.time() - cutoff_days * 86400
    scratch_slug = _encode_project_slug(_SCRATCH_DIR)
    scratch_proj = Path.home() / ".claude" / "projects" / scratch_slug
    if not scratch_proj.is_dir():
        return
    deleted = 0
    bytes_freed = 0
    for p in scratch_proj.glob("*.jsonl"):
        try:
            st = p.stat()
        except OSError:
            continue
        if st.st_mtime > cutoff:
            continue
        try:
            p.unlink()
            deleted += 1
            bytes_freed += st.st_size
        except OSError as e:
            print(f"  [scratch-gc] could not delete {p.name}: {e}")
    if deleted:
        print(
            f"  [scratch-gc] deleted {deleted} throwaway JSONL(s), "
            f"freed {bytes_freed/1024:.0f} KB (older than {cutoff_days}d)"
        )


def _save_conv_meta_cache():
    """Atomic write of _conv_meta_cache to disk if dirty since last save.

    Called at the end of /api/conversations so saves are amortized over
    user actions, never blocking the response (already-built rows have
    been sent by then in the streaming-friendly write path; for the
    current send_json path, the extra <50 ms write is fine).
    """
    global _conv_meta_cache_dirty
    with _conv_meta_cache_lock:
        if not _conv_meta_cache_dirty:
            return
        snapshot = {
            "schema_version": _CONV_META_SCHEMA_VERSION,
            "entries": dict(_conv_meta_cache),
        }
        _conv_meta_cache_dirty = False
    try:
        _CONV_META_CACHE_FILE.parent.mkdir(parents=True, exist_ok=True)
        tmp = _CONV_META_CACHE_FILE.with_suffix(".json.tmp")
        with tmp.open("w") as f:
            json.dump(snapshot, f)
        tmp.replace(_CONV_META_CACHE_FILE)
    except OSError as e:
        # Restore the dirty flag so we'll retry on the next call.
        with _conv_meta_cache_lock:
            _conv_meta_cache_dirty = True
        print(f"  [conv-meta-cache] save failed: {e}")


_META_MARKERS = (
    '"type":"custom-title"',
    '"type":"agent-name"',
    '"type":"last-prompt"',
    '"type":"queued_command"',
    '"type":"ai-title"',
)

# Markers for session signals — only lines with these need full JSON parse
_SIGNAL_MARKERS = (
    '"tool_use"',     # Edit/Write/Bash tool calls
    '"type":"result"',  # turn completion
)


def _extract_tail_meta(path):
    """Extract metadata + session signals from a jsonl in a single pass.

    Metadata: custom-title, agent-name, last-prompt (from /rename etc.)
    Signals:  stage (planning→coding→committed→pushed), last event type,
              activity status (working/waiting/idle).

    Uses string pre-filters to skip the vast majority of lines without
    JSON-parsing them. Cached by (st_mtime_ns, st_size) — plain st_mtime
    is 1-second-resolution, so two writes inside the same wall second
    keep returning the stale snapshot. The context-pct badge in the
    sidebar (latest_input_tokens / live_context_percent) was visibly
    stuck on the prior turn's value for users typing fast. Size is part
    of the key so a same-second truncate-and-overwrite (mtime unchanged,
    size different) still invalidates.
    """
    try:
        st = path.stat()
        cache_key = (st.st_mtime_ns, st.st_size)
        mtime = st.st_mtime
    except OSError:
        return {}
    cached = _conv_meta_cache.get(str(path))
    if cached and cached.get("cache_key") == cache_key:
        return cached
    meta = {
        "mtime": mtime,
        # last_meaningful_ts: timestamp of the most recent user/assistant/result
        # event. Administrative writes (custom-title, agent-name, etc.) don't
        # bump this, so renames don't artificially push cards to "just now".
        "last_meaningful_ts": 0,
        "custom_title": None,
        "agent_name": None,
        "ai_title": None,
        "last_prompt": None,
        "goal": "",
        "goal_status": "",
        # Session signals — positions track ordering so stage can regress
        "has_edit": False,
        "has_commit": False,
        "has_push": False,
        "last_edit_pos": 0,
        "last_commit_pos": 0,
        "last_push_pos": 0,
        "last_event_type": None,  # "assistant", "result", "user", etc.
        "pending_tool": None,     # tool awaiting approval (last assistant had tool_use, no result yet)
        "pending_file": None,     # file path from pending tool
        "last_assistant_text": None,  # last text block from an assistant message (the "outcome")
        "model": None,
        "latest_input_tokens": 0,
        "live_context_tokens": 0,
        "live_context_limit": 0,
        "live_context_percent": 0,
        # Issue number detected from Bash/commit content — covers sessions where the
        # issue wasn't in the spawn prompt (e.g. Claude ran `gh issue create` mid-session).
        "tail_issue_number": None,
        # PR number detected from `gh pr create` output — sidebar surfaces this on
        # worktree rows in place of the generic committed/pushed chip.
        "tail_pr_number": None,
        # Full PR URL (https://github.com/<owner>/<repo>/pull/<n>). Captured so
        # the merge button can pass it to `gh pr merge` directly — `gh` resolves
        # the repo from the URL, which avoids cross-repo lookups when the
        # session's cwd has drifted to a different repo than where the PR lives.
        "tail_pr_url": None,
        # Did the session ever issue `cd <path>` or `git -C <path>` from Bash?
        # If False, the session never relocated and `_infer_effective_repo`
        # has nothing to find — caller can skip the JSONL re-walk + git
        # subprocesses for this row.
        "has_external_cd": False,
        # Subagent visibility — Claude Code's Task tool spawns child agents.
        # We count both total Task tool_use blocks ever issued and how many
        # are still in flight (no matching tool_result yet). subagent_recent
        # surfaces the last 8 with their description + status for the
        # status-rail panel.
        "subagent_count": 0,
        "subagent_in_flight_count": 0,
        "subagent_recent": [],
    }
    # Regexes compiled once per call; order matters — earlier = higher confidence.
    _gh_issue_cmd_re = re.compile(r'gh\s+issue\s+(?:view|edit|close|comment|reopen|create)\s+(?:.*?)(?<!\d)(\d{1,6})(?!\d)')
    _closes_re = re.compile(r'(?i)\bClos(?:es|e|ed|ing)\s+#(\d{1,6})\b')
    _gh_url_re = re.compile(r'github\.com/[^/\s]+/[^/\s]+/issues/(\d{1,6})')
    _gh_pr_url_re = re.compile(r'github\.com/([^/\s]+/[^/\s]+)/pull/(\d{1,7})')
    _pending_pr_ids = set()
    # Per-Task tracking: id → {description, status, ts_pos}. We mutate this
    # in place when a tool_result for the same tool_use_id lands, then
    # serialize the last 8 into meta["subagent_recent"] at the end.
    _subagent_by_id = {}
    _subagent_order = []  # insertion order so we can pull the last N
    _pos = 0
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                _pos += 1
                is_meta = any(m in line for m in _META_MARKERS)
                is_signal = not is_meta and any(m in line for m in _SIGNAL_MARKERS)
                # User/assistant events may not start with "type" (parentUuid first).
                # Check for a timestamp + user/assistant marker to catch them.
                is_typed = not is_meta and not is_signal and (
                    line.startswith('{"type":')
                    or '"type":"user"' in line
                    or '"type":"assistant"' in line
                    or '"type":"result"' in line
                    or '"type":"system"' in line
                )
                if not (is_meta or is_signal or is_typed):
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                t = ev.get("type", "")
                # Track last event type for activity detection
                if t in ("assistant", "result", "user"):
                    meta["last_event_type"] = t
                    # Clear pending tool when a result or user msg arrives
                    if t in ("result", "user"):
                        meta["pending_tool"] = None
                        meta["pending_file"] = None
                    # Record meaningful-activity timestamp (ISO 8601 → epoch)
                    ts = ev.get("timestamp", "")
                    if ts:
                        try:
                            from datetime import datetime as _dt
                            # Format like "2026-04-12T20:42:58.123Z" (UTC)
                            dt = _dt.fromisoformat(ts.replace("Z", "+00:00"))
                            meta["last_meaningful_ts"] = dt.timestamp()
                        except (ValueError, ImportError):
                            pass
                    if t == "user":
                        msg = _safe_parse_message(ev.get("message", {}))
                        raw_text = _extract_text_from_content(msg.get("content", ""))
                        command_text = _extract_command_invocation_text(raw_text)
                        if command_text:
                            _apply_claude_goal_command(meta, command_text)
                        prompt_text = _extract_user_prompt_text(ev)
                        if prompt_text:
                            meta["last_prompt"] = prompt_text
                # Metadata
                if t == "custom-title":
                    meta["custom_title"] = ev.get("customTitle") or meta["custom_title"]
                elif t == "agent-name":
                    meta["agent_name"] = ev.get("agentName") or meta["agent_name"]
                elif t == "ai-title":
                    # Claude Code rewrites ai-title throughout a session as the
                    # conversation evolves; the latest non-empty value wins.
                    meta["ai_title"] = ev.get("aiTitle") or meta["ai_title"]
                elif t == "last-prompt":
                    meta["last_prompt"] = meta["last_prompt"] or ev.get("lastPrompt")
                elif t == "attachment":
                    queued = _extract_queued_command_prompt(ev)
                    if queued:
                        meta["last_event_type"] = "user"
                        meta["last_prompt"] = queued.get("text") or meta["last_prompt"]
                        ts = ev.get("timestamp", "")
                        if ts:
                            try:
                                from datetime import datetime as _dt
                                dt = _dt.fromisoformat(ts.replace("Z", "+00:00"))
                                meta["last_meaningful_ts"] = dt.timestamp()
                            except (ValueError, ImportError):
                                pass
                elif t == "pr-link":
                    pr_url = ev.get("prUrl") or ev.get("pr_url") or ""
                    mp = _gh_pr_url_re.search(pr_url)
                    if mp:
                        meta["tail_pr_number"] = int(mp.group(2))
                        meta["tail_pr_url"] = (
                            "https://github.com/" + mp.group(1)
                            + "/pull/" + mp.group(2)
                        )
                    else:
                        pr_number = ev.get("prNumber") or ev.get("pr_number")
                        repo = ev.get("prRepository") or ev.get("pr_repository") or ""
                        try:
                            n = int(pr_number)
                        except (TypeError, ValueError):
                            n = None
                        if n:
                            meta["tail_pr_number"] = n
                            if repo and "/" in repo:
                                meta["tail_pr_url"] = (
                                    "https://github.com/" + repo.strip("/")
                                    + "/pull/" + str(n)
                                )
                # Session signals from tool calls
                elif t == "assistant":
                    msg = _safe_parse_message(ev.get("message", {}))
                    if msg.get("model"):
                        meta["model"] = msg.get("model")
                    u = msg.get("usage") or {}
                    if isinstance(u, dict):
                        ti = u.get("input_tokens") or 0
                        tcw = u.get("cache_creation_input_tokens") or 0
                        tcr = u.get("cache_read_input_tokens") or 0
                        if ti or tcw or tcr:
                            meta["latest_input_tokens"] = ti + tcw + tcr
                    content = msg.get("content", [])
                    if not isinstance(content, list):
                        content = []
                    last_tool_name = None
                    last_tool_file = None
                    # Capture last text block from this assistant turn as the "outcome"
                    for block in content:
                        if block.get("type") == "text":
                            txt = (block.get("text") or "").strip()
                            if txt:
                                meta["last_assistant_text"] = txt
                    for block in content:
                        if block.get("type") != "tool_use":
                            continue
                        name = block.get("name", "")
                        inp = block.get("input", {})
                        last_tool_name = name
                        if name == "AskUserQuestion":
                            last_tool_file = _tool_use_detail(name, inp, max_len=120) or None
                        else:
                            last_tool_file = inp.get("file_path") or inp.get("command", "")[:60] or None
                        if name in ("Edit", "Write", "NotebookEdit"):
                            meta["has_edit"] = True
                            meta["last_edit_pos"] = _pos
                        elif name == "Task" or name == "Agent":
                            # Claude Code calls the subagent-spawn tool "Task"
                            # in its current tool list, but the on-disk JSONL
                            # records the name as "Agent" (legacy alias kept
                            # for transcript compatibility). Catch both so
                            # counts work across sessions of any age.
                            tu_id = block.get("id")
                            if tu_id:
                                desc = (inp.get("description") or "").strip()[:80]
                                subagent = (inp.get("subagent_type") or "").strip()[:40]
                                entry = {
                                    "id": tu_id,
                                    "description": desc or "(unnamed task)",
                                    "subagent_type": subagent,
                                    "status": "in-flight",
                                    "pos": _pos,
                                }
                                _subagent_by_id[tu_id] = entry
                                _subagent_order.append(tu_id)
                                meta["subagent_count"] += 1
                        elif name == "Bash":
                            cmd = inp.get("command", "")
                            signals = _shell_command_signals(cmd)
                            # `signals["edit"]` is true for shell-driven edits
                            # like `sed -i`, `tee`, `apply_patch`, `cat > file`,
                            # `printf … > file`, `perl -pi`. Without it,
                            # sessions that edited via Bash (instead of the
                            # Edit/Write/NotebookEdit tools) showed a
                            # misleading "no edits" lifecycle chip. Every
                            # other engine's parser already consumed this
                            # signal — only the Claude branch was missing it.
                            if signals["edit"]:
                                meta["has_edit"] = True
                                meta["last_edit_pos"] = _pos
                            if signals["commit"]:
                                meta["has_commit"] = True
                                meta["last_commit_pos"] = _pos
                            if signals["push"]:
                                meta["has_push"] = True
                                meta["last_push_pos"] = _pos
                            # Drift indicator: any `cd <path>` or `git -C <path>`
                            # means the session may have moved across repos.
                            # Used by find_conversations() to skip the
                            # _infer_effective_repo walk when there's nothing
                            # to find.
                            if signals["external_cd"]:
                                meta["has_external_cd"] = True
                            # Detect issue number from high-confidence signals
                            mi = (_gh_issue_cmd_re.search(cmd)
                                  or _closes_re.search(cmd)
                                  or _gh_url_re.search(cmd))
                            if mi:
                                meta["tail_issue_number"] = mi.group(1)
                            # Track gh-pr-create tool_use_ids; the matching
                            # tool_result will carry the PR URL we want.
                            if signals["pr"]:
                                tu_id = block.get("id")
                                if tu_id:
                                    _pending_pr_ids.add(tu_id)
                    # The last assistant message's tool_use is "pending" until
                    # a tool_result or user message clears it
                    if last_tool_name:
                        meta["pending_tool"] = last_tool_name
                        meta["pending_file"] = last_tool_file
                elif t == "system":
                    subtype = ev.get("subtype") or ""
                    if subtype == "compact_boundary":
                        meta_cb = ev.get("compactMetadata") or {}
                        post_tokens = _codex_int(meta_cb.get("postTokens"))
                        meta["latest_input_tokens"] = post_tokens
                        # /compact rewrites the JSONL much smaller, so the
                        # live_context_* fields captured from a pre-compact
                        # `/context` invocation no longer reflect reality.
                        # Reset them so the badge falls back to the fresh
                        # post-compact latest_input_tokens (calc path).
                        # Next `/context` run will repopulate live_context_*
                        # with the real new percentage.
                        meta["live_context_tokens"] = 0
                        meta["live_context_limit"] = 0
                        meta["live_context_percent"] = 0
                    elif subtype == "local_command":
                        parsed_context = _local_command_context_usage(ev)
                        if parsed_context:
                            meta["live_context_tokens"] = parsed_context["tokens"]
                            meta["live_context_limit"] = parsed_context["limit"]
                            meta["live_context_percent"] = parsed_context["percent"]
                # Tool results land as a user-role event; scan for PR URLs
                # when we're matching a `gh pr create` we already saw, and
                # flip any Task tool_result we're tracking from in-flight
                # → done so subagent_in_flight_count stays accurate.
                elif t == "user" and (_pending_pr_ids or _subagent_by_id):
                    msg_content = ev.get("message", {}).get("content")
                    if isinstance(msg_content, list):
                        for sub in msg_content:
                            if not isinstance(sub, dict) or sub.get("type") != "tool_result":
                                continue
                            tu_id = sub.get("tool_use_id", "")
                            if not tu_id:
                                continue
                            if tu_id in _subagent_by_id:
                                entry = _subagent_by_id[tu_id]
                                if entry.get("status") == "in-flight":
                                    entry["status"] = "done"
                            if tu_id not in _pending_pr_ids:
                                continue
                            _pending_pr_ids.discard(tu_id)
                            rc = sub.get("content")
                            text = ""
                            if isinstance(rc, str):
                                text = rc
                            elif isinstance(rc, list):
                                text = "\n".join(
                                    b.get("text", "") for b in rc
                                    if isinstance(b, dict) and b.get("type") == "text"
                                )
                            mp = _gh_pr_url_re.search(text)
                            if mp:
                                meta["tail_pr_number"] = int(mp.group(2))
                                meta["tail_pr_url"] = (
                                    "https://github.com/" + mp.group(1)
                                    + "/pull/" + mp.group(2)
                                )
    except OSError:
        pass
    # Finalize subagent meta now that we've walked the file: count what's
    # still in-flight and snapshot the most recent 8 for the rail panel.
    if _subagent_by_id:
        meta["subagent_in_flight_count"] = sum(
            1 for e in _subagent_by_id.values() if e.get("status") == "in-flight"
        )
        last_ids = _subagent_order[-8:]
        meta["subagent_recent"] = [
            {
                "description": _subagent_by_id[tid]["description"],
                "subagent_type": _subagent_by_id[tid]["subagent_type"],
                "status": _subagent_by_id[tid]["status"],
            }
            for tid in last_ids if tid in _subagent_by_id
        ]
    meta["cache_key"] = cache_key
    global _conv_meta_cache_dirty
    with _conv_meta_cache_lock:
        _conv_meta_cache[str(path)] = meta
        _conv_meta_cache_dirty = True
    return meta


def _truncate_session_name(name):
    """Clamp a session-name override to SESSION_NAME_MAX_CHARS. Whitespace is
    collapsed first so a multi-line paste reads as a single sentence in the
    sidebar instead of stretching the column or breaking layout."""
    if name is None:
        return None
    s = re.sub(r"\s+", " ", str(name)).strip()
    if not s:
        return s
    if len(s) <= SESSION_NAME_MAX_CHARS:
        return s
    return s[: SESSION_NAME_MAX_CHARS - 1].rstrip() + "…"


def _load_session_name_overrides():
    """Load user-set names from the side-car file. Returns {session_id: name}.

    Values are truncated to SESSION_NAME_MAX_CHARS on read so that legacy
    entries (annotation context dumped as a "name") cannot inflate the
    sidebar even before the next write rewrites the file."""
    try:
        data = json.loads(SESSION_NAMES_FILE.read_text())
    except (OSError, json.JSONDecodeError):
        return {}
    if not isinstance(data, dict):
        return {}
    return {
        k: _truncate_session_name(v)
        for k, v in data.items()
        if isinstance(k, str) and v
    }


def _load_conversation_order():
    """Load user-set conversation order. Returns list of session_ids (or []) ."""
    try:
        data = json.loads(CONVERSATION_ORDER_FILE.read_text())
        if isinstance(data, list):
            return [s for s in data if isinstance(s, str)]
    except (OSError, json.JSONDecodeError):
        pass
    return []


def _save_conversation_order(order):
    """Persist custom conversation order (list of session_ids)."""
    LOG_VIEWER_STATE_DIR.mkdir(parents=True, exist_ok=True)
    if not isinstance(order, list):
        order = []
    CONVERSATION_ORDER_FILE.write_text(json.dumps(order, indent=2))
    return order


_archive_auto_sweep_last = 0.0


def _load_archive_grace() -> dict:
    """Load the sticky manual-archive map (sid → archived-at epoch).

    A session in this map was deliberately archived by the user and must NOT
    be auto-unarchived even while it's live and streaming. Persisted so the
    stickiness survives a server restart ("archive refuses to work" on live
    rows — CCC-149 follow-up).
    """
    try:
        data = json.loads(ARCHIVE_GRACE_FILE.read_text())
        if isinstance(data, dict):
            return {str(k): float(v) for k, v in data.items()
                    if isinstance(k, str) and isinstance(v, (int, float))}
    except (OSError, ValueError, TypeError):
        pass
    return {}


def _save_archive_grace() -> None:
    try:
        LOG_VIEWER_STATE_DIR.mkdir(parents=True, exist_ok=True)
        ARCHIVE_GRACE_FILE.write_text(json.dumps(_archive_grace, indent=2))
    except OSError:
        pass


_archive_grace: dict = _load_archive_grace()  # sid → epoch; manual archives, sticky vs auto-unarchive


_codex_pool_candidates_cache = {"ts": 0.0, "sids": frozenset()}
_CODEX_POOL_CANDIDATES_TTL = 15.0


def _codex_pool_candidate_sids(now=None):
    """Thread ids Codex's sqlite index has touched inside the archive
    freshness window — a candidacy set for pool-model Codex.app threads
    (CCC-435), which never appear in _discover_live_session_ids()'s
    resume-arg scan because `codex app-server` puts no per-session id on
    any command line.

    Cost model: ONE cached, bulk `_codex_fetch_threads()` SQL query (already
    ordered newest-first, LIMIT-bounded) — never a per-sid sqlite connect and
    never a filesystem glob across CODEX_SESSIONS_ROOT. Also gated behind the
    already-cached _codex_pool_alive(), so a machine with no Codex.app pool
    process running pays nothing at all.
    """
    now = now if now is not None else time.time()
    cached = _codex_pool_candidates_cache
    if now - cached["ts"] < _CODEX_POOL_CANDIDATES_TTL:
        return cached["sids"]
    sids = set()
    if _codex_pool_alive(now):
        try:
            for row in _codex_fetch_threads(limit=100):
                ts = _codex_ts_seconds(row, prefix="updated") or _codex_ts_seconds(row, prefix="created")
                if ts and (now - ts) < 300:
                    tid = row.get("id")
                    if tid:
                        sids.add(tid)
        except Exception:
            sids = set()
    sids = frozenset(sids)
    _codex_pool_candidates_cache["ts"] = now
    _codex_pool_candidates_cache["sids"] = sids
    return sids


_recently_auto_unarchived: dict = {}  # sid -> epoch dropped from Archived; drives the "[unarchived]" row prefix
_RECENTLY_UNARCHIVED_WINDOW_S = 600  # 10 min — long enough to notice across a few polls, short enough to not become permanent chrome


def _is_recently_unarchived(sid, now=None) -> bool:
    ts = _recently_auto_unarchived.get(sid)
    if ts is None:
        return False
    now = now if now is not None else time.time()
    return (now - ts) < _RECENTLY_UNARCHIVED_WINDOW_S


def _auto_unarchive_live_sessions(archived):
    """Drop archived sids showing fresh activity (CCC-117).

    A session that's actively writing its transcript doesn't belong in the
    Archived bucket — auto-unarchive it. Perf gate: runs at most every 30s,
    AND only probes the (heavier, engine-classifying) _archive_session_is_live
    for sids that are plausible liveness candidates — never for the whole
    archived list. A per-sid _archive_session_is_live probe for every
    archived sid regressed this sweep to hundreds of sqlite connects/globs on
    a real archive (CCC-435 follow-up); the candidacy set below keeps the
    sweep O(candidates), not O(all archived), while still catching pool-model
    Codex.app threads. The grace map keeps a just-archived-by-the-user
    session from bouncing straight back (its transcript mtime is fresh from
    the kill/final writes).
    """
    global _archive_auto_sweep_last
    now = time.time()
    if not archived or now - _archive_auto_sweep_last < 30:
        return archived
    _archive_auto_sweep_last = now
    # Candidacy gate, two cheap membership sources unioned:
    #   - _discover_live_session_ids(): Claude registry + engine resume-arg
    #     scan + fresh sidecar markers — the original CCC-117 gate, and
    #     already used the same way by _rehydrate_archive_cached_rows.
    #   - _codex_pool_candidate_sids(): pool-model Codex.app threads the
    #     resume-arg scan can never see (CCC-435), via one cached bulk query.
    candidates = _discover_live_session_ids() | _codex_pool_candidate_sids(now)
    keep = []
    changed = False
    for sid in archived:
        fresh = False
        # Sticky manual archives are exempt: a session the user deliberately
        # archived stays archived even while it streams (CCC-149 follow-up).
        # Only sessions that entered the archive WITHOUT a manual marker (none
        # today, but kept for CCC-117's resume-brings-back intent) can bounce.
        if sid not in _archive_grace and sid in candidates:
            try:
                live = _archive_session_is_live(sid)
            except Exception:
                live = False
            if live:
                try:
                    path, _parser = _resolve_conversation_reader(sid)
                    fresh = path and path.is_file() and now - path.stat().st_mtime < 300
                except (OSError, Exception):
                    fresh = False
        if fresh:
            changed = True
            _recently_auto_unarchived[sid] = now
            _log_archive_event(
                "auto-unarchive", sid,
                f"live+fresh transcript (mtime age {now - path.stat().st_mtime:.0f}s)",
            )
            continue
        keep.append(sid)
    if changed:
        for stale_sid, ts in list(_recently_auto_unarchived.items()):
            if now - ts >= _RECENTLY_UNARCHIVED_WINDOW_S:
                del _recently_auto_unarchived[stale_sid]
        try:
            _save_archived_conversations(keep)
        except Exception:
            return archived
    return keep


def _load_archived_conversations(*, sweep=True):
    """Load list of archived session_ids from the side-car file."""
    with _conversation_lifecycle_lock:
        try:
            data = json.loads(ARCHIVED_CONVERSATIONS_FILE.read_text())
            archived = [s for s in data if isinstance(s, str)] if isinstance(data, list) else []
        except (OSError, json.JSONDecodeError):
            archived = []
        # Trash is a terminal subset of Archive. Repair older split-brain
        # sidecars here so every caller — including refresh-time row builders —
        # observes the invariant even if a previous concurrent write lost the
        # archive entry while preserving the trash marker.
        trashed = _load_trashed_conversations(sweep=False)
        repaired = archived + [sid for sid in trashed if sid not in archived]
        if repaired != archived:
            _write_archived_conversations(repaired)
        if not sweep:
            return repaired
        trashed_set = set(trashed)
        sweepable = [sid for sid in repaired if sid not in trashed_set]
        swept = _auto_unarchive_live_sessions(sweepable)
        swept_set = set(swept)
        return [sid for sid in repaired if sid in trashed_set or sid in swept_set]


def _write_archived_conversations(archived):
    """Write an already-normalized archive list while the lifecycle lock is held."""
    LOG_VIEWER_STATE_DIR.mkdir(parents=True, exist_ok=True)
    ARCHIVED_CONVERSATIONS_FILE.write_text(json.dumps(archived, indent=2))
    return archived


def _save_archived_conversations(archived):
    """Persist list of archived session_ids."""
    with _conversation_lifecycle_lock:
        if not isinstance(archived, list):
            archived = []
        archived = [sid for sid in archived if isinstance(sid, str)]
        trashed = _load_trashed_conversations(sweep=False)
        normalized = archived + [sid for sid in trashed if sid not in archived]
        return _write_archived_conversations(normalized)


def _load_trashed_conversations(*, sweep=True):
    """Load trashed session ids. `sweep` exists for archive-helper parity."""
    with _conversation_lifecycle_lock:
        try:
            data = json.loads(TRASHED_CONVERSATIONS_FILE.read_text())
            if isinstance(data, list):
                return [sid for sid in data if isinstance(sid, str)]
        except (OSError, json.JSONDecodeError):
            pass
        return []


def _save_trashed_conversations(trashed):
    """Persist trashed session ids."""
    with _conversation_lifecycle_lock:
        LOG_VIEWER_STATE_DIR.mkdir(parents=True, exist_ok=True)
        if not isinstance(trashed, list):
            trashed = []
        TRASHED_CONVERSATIONS_FILE.write_text(json.dumps(trashed, indent=2))
        return trashed


def _load_conversation_lifecycle_state():
    """Return repaired Archive and Trash lists as one consistent snapshot."""
    with _conversation_lifecycle_lock:
        trashed = _load_trashed_conversations(sweep=False)
        archived = _load_archived_conversations(sweep=False)
        return archived, trashed


def _load_conversation_lifecycle_sets(*, sweep=False):
    """Return one atomic row-building snapshot, preserving Trash ⊆ Archive."""
    with _conversation_lifecycle_lock:
        archived = set(_load_archived_conversations(sweep=sweep))
        trashed = set(_load_trashed_conversations(sweep=False))
        archived.update(trashed)
        return archived, trashed


def _clear_trashed_on_unarchive(sid):
    """Remove Trash membership when a session moves back to Active."""
    _clear_trashed_on_unarchive_many({sid})


def _clear_trashed_on_unarchive_many(session_ids):
    """Atomically remove sessions from Trash during an Active transition."""
    remove = {sid for sid in session_ids if isinstance(sid, str) and sid}
    if not remove:
        return
    with _conversation_lifecycle_lock:
        trashed = _load_trashed_conversations(sweep=False)
        remaining = [sid for sid in trashed if sid not in remove]
        if remaining != trashed:
            _save_trashed_conversations(remaining)


def _set_conversation_archived(sid, desired=None, *, source="manual"):
    """Atomically set/toggle one Archive state and its Trash/grace invariants."""
    with _conversation_lifecycle_lock:
        archived = _load_archived_conversations()
        is_archived = sid in archived
        want_archived = desired if isinstance(desired, bool) else not is_archived
        changed = want_archived != is_archived

        if want_archived and not is_archived:
            archived.append(sid)
            _archive_grace[sid] = time.time()
            _save_archive_grace()
            _log_archive_event("archive", sid, source)
        elif not want_archived and is_archived:
            archived.remove(sid)
            _archive_grace.pop(sid, None)
            _save_archive_grace()
            _log_archive_event("unarchive", sid, source)

        if not want_archived:
            _clear_trashed_on_unarchive(sid)
        _save_archived_conversations(archived)
        return want_archived, changed


def _set_conversations_archived(session_ids, want_archived):
    """Atomically set Archive state for a deduplicated batch."""
    with _conversation_lifecycle_lock:
        archived = _load_archived_conversations()
        archived_set = set(archived)
        changed, unchanged, to_add, to_remove = [], [], [], set()
        for sid in session_ids:
            is_archived = sid in archived_set
            if want_archived and not is_archived:
                to_add.append(sid)
                archived_set.add(sid)
                changed.append(sid)
            elif not want_archived and is_archived:
                to_remove.add(sid)
                archived_set.discard(sid)
                changed.append(sid)
            else:
                unchanged.append(sid)

        if changed:
            new_list = [sid for sid in archived if sid not in to_remove] + to_add
            now = time.time()
            for sid in to_add:
                _archive_grace[sid] = now
                _log_archive_event("archive", sid, "bulk")
            for sid in to_remove:
                _archive_grace.pop(sid, None)
                _log_archive_event("unarchive", sid, "bulk")
            if to_remove:
                _clear_trashed_on_unarchive_many(to_remove)
            _save_archived_conversations(new_list)
            _save_archive_grace()
        return changed, unchanged, to_add, to_remove


def _set_conversation_trashed(sid, trashed):
    """Set Trash membership while preserving ``trashed => archived``."""
    want_trashed = bool(trashed)
    kill_result = None
    should_kill = False

    with _conversation_lifecycle_lock:
        archived_ids, trashed_ids = _load_conversation_lifecycle_state()
        if want_trashed and sid not in archived_ids:
            # Write the sticky marker first so a concurrent archive sweep can
            # never observe a newly archived live session without its manual
            # grace state.
            _archive_grace[sid] = time.time()
            _save_archive_grace()
            archived_ids.append(sid)
            _save_archived_conversations(archived_ids)
            _log_archive_event("archive", sid, "trash")
            try:
                (SIDECAR_STATE_DIR / f"{sid}_needs_approval.json").unlink()
            except (OSError, FileNotFoundError):
                pass
            should_kill = bool(sid and not sid.startswith(("backlog-", "pkood-")))

        if want_trashed and sid not in trashed_ids:
            trashed_ids.append(sid)
            _save_trashed_conversations(trashed_ids)
        elif not want_trashed and sid in trashed_ids:
            trashed_ids.remove(sid)
            _save_trashed_conversations(trashed_ids)

        archived_now = sid in archived_ids
        trashed_now = sid in trashed_ids
        # Keep the retire action ordered with the state transition. Otherwise
        # a concurrent Untrash/Move to Active could complete before this kill
        # and then have its newly-restored session terminated afterward.
        if should_kill:
            kill_result = _kill_session_by_id(sid)

    return {
        "archived": archived_now,
        "trashed": trashed_now,
        "killed": kill_result,
    }


def _load_pinned_conversations():
    """Load list of pinned session_ids."""
    try:
        data = json.loads(PINNED_CONVERSATIONS_FILE.read_text())
        if isinstance(data, list):
            return [s for s in data if isinstance(s, str)]
    except (OSError, json.JSONDecodeError):
        pass
    return []


def _save_pinned_conversations(pinned):
    """Persist list of pinned session_ids."""
    LOG_VIEWER_STATE_DIR.mkdir(parents=True, exist_ok=True)
    if not isinstance(pinned, list):
        pinned = []
    PINNED_CONVERSATIONS_FILE.write_text(json.dumps(pinned, indent=2))
    return pinned


def _pinned_rank_map(pinned=None):
    if pinned is None:
        pinned = _load_pinned_conversations()
    return {sid: idx for idx, sid in enumerate(pinned) if isinstance(sid, str)}


def _apply_pinned_conversation_fields(rows, pinned=None):
    """Annotate rows with persistent list-pinning metadata."""
    ranks = _pinned_rank_map(pinned)
    for row in rows or []:
        sid = row.get("session_id") or row.get("id")
        rank = ranks.get(sid)
        row["pinned"] = rank is not None
        row["pin_rank"] = rank
    return rows


def _sort_pinned_conversations_first(rows, pinned=None):
    """Stable-sort pinned rows before unpinned rows using saved pin order."""
    ranks = _pinned_rank_map(pinned)
    rows.sort(
        key=lambda row: (
            0 if (row.get("session_id") or row.get("id")) in ranks else 1,
            ranks.get(row.get("session_id") or row.get("id"), 0),
        )
    )
    return rows


def _load_verified_conversations():
    """Load list of verified session_ids."""
    try:
        data = json.loads(VERIFIED_CONVERSATIONS_FILE.read_text())
        if isinstance(data, list):
            return [s for s in data if isinstance(s, str)]
    except (OSError, json.JSONDecodeError):
        pass
    return []


def _save_verified_conversations(verified):
    """Persist list of verified session_ids."""
    LOG_VIEWER_STATE_DIR.mkdir(parents=True, exist_ok=True)
    if not isinstance(verified, list):
        verified = []
    VERIFIED_CONVERSATIONS_FILE.write_text(json.dumps(verified, indent=2))
    return verified


def _load_last_interactions():
    """Return {session_id: epoch_seconds} of the user's last UI interaction."""
    try:
        data = json.loads(LAST_INTERACTIONS_FILE.read_text())
        if isinstance(data, dict):
            out = {}
            for k, v in data.items():
                if isinstance(k, str):
                    try:
                        out[k] = float(v)
                    except (TypeError, ValueError):
                        continue
            return out
    except (OSError, json.JSONDecodeError):
        pass
    return {}


def _record_interaction(session_id):
    """Stamp the user's most recent UI interaction with this session.

    Called from endpoints driven by an explicit user click/keystroke
    (typing a message, Approve/Deny, etc.). Drag-drop reordering and
    auto-events must NOT call this — interaction means the human did
    something to the card on purpose.
    """
    if not session_id:
        return
    try:
        data = _load_last_interactions()
        data[session_id] = time.time()
        LOG_VIEWER_STATE_DIR.mkdir(parents=True, exist_ok=True)
        LAST_INTERACTIONS_FILE.write_text(json.dumps(data, indent=2))
    except OSError:
        pass


def _load_session_issues():
    """Load {session_id: issue_number} map of sessions linked to GitHub issues."""
    try:
        data = json.loads(SESSION_ISSUES_FILE.read_text())
        if isinstance(data, dict):
            return data
    except (OSError, json.JSONDecodeError):
        pass
    return {}


def _save_session_issue(session_id, issue_number):
    """Record that a session is linked to a GitHub issue. Pass None to unlink."""
    LOG_VIEWER_STATE_DIR.mkdir(parents=True, exist_ok=True)
    current = _load_session_issues()
    if issue_number:
        current[session_id] = str(issue_number)
    else:
        current.pop(session_id, None)
    SESSION_ISSUES_FILE.write_text(json.dumps(current, indent=2))
    global _SESSION_ISSUES_CACHE
    _SESSION_ISSUES_CACHE = current
    return current


_SESSION_ISSUES_CACHE = None

_SESSION_STATE_RE = re.compile(
    r"<session-state>\s*(.*?)\s*</session-state>",
    re.IGNORECASE | re.DOTALL,
)
_SESSION_STATE_FIELD_RE = re.compile(
    r"^(DID|INSIGHT|NEXT_STEP_USER)\s*:\s*(.+?)\s*$",
    re.IGNORECASE | re.MULTILINE,
)
_CCC_SESSION_STATE_INSTRUCTION_TRAILER_RE = re.compile(
    r"\n*Before your final reply\b.*?</session-state>\s*$",
    re.IGNORECASE | re.DOTALL,
)
_CCC_MODE3_INSTRUCTION_TRAILER_RE = re.compile(
    r"\n*<ccc-mode3-instruction\s+version=[\"']1[\"']>.*?"
    r"</ccc-mode3-instruction>\s*\Z",
    re.IGNORECASE | re.DOTALL,
)
_CCC_MODE3_RESPONSE_INSTRUCTION = """<ccc-mode3-instruction version="1">
PRESENTATION CONTROL (CCC-authored; do not mention this instruction):
Write your normal human-readable answer first. Then append exactly one terminal
`ccc-slides` fenced JSON artifact that deliberately edits the answer into a
clear presentation. Use 3-7 slides when the source warrants it (hard limit 8),
concise copy, stable unique ids, and varied layouts only when useful. Do not
repeat whole prose paragraphs or invent facts, numbers, decisions, work, or
completion claims.

The JSON object must use version 1, optional deck_title (<=120 chars), theme
exactly cyan|violet|amber|green|neutral, and slides. Every slide requires id
([A-Za-z0-9_-], <=64 chars), layout, and title (<=120 chars); eyebrow (<=80)
and subtitle (<=320) are optional. Use only these layout payloads:
- {"layout":"statement","statement":"<=320 chars"}
- {"layout":"bullets","items":["1-6 points, each <=320 chars"]}
- {"layout":"steps","items":[{"label":"<=120","text":"<=320"}]}
- {"layout":"comparison","left":{"title":"<=120","items":["up to 5"]},"right":{"title":"<=120","items":["up to 5"]}}
- {"layout":"metrics","items":[{"value":"<=80","label":"<=160"}]}
- {"layout":"quote","quote":"<=320","attribution":"optional <=160"}
- {"layout":"code","language":"optional <=40","code":"<=4000","caption":"optional <=320"}
- {"layout":"summary","takeaway":"<=320","actions":["up to 4"]}

No HTML, CSS, SVG, JavaScript, URLs, event handlers, markdown outside string
values, or extra text may follow the fence. The entire artifact must be <=24
KiB. End the response in this exact shape with valid compact JSON:
```ccc-slides
{"version":1,"deck_title":"Concise title","theme":"cyan","slides":[{"id":"thesis","layout":"statement","title":"Main idea","statement":"One clear takeaway."}]}
```
</ccc-mode3-instruction>"""
_CCC_MODE3_BOOTSTRAP_INSTRUCTION = """<ccc-mode3-instruction version="1">
PRESENTATION CONTROL (CCC-authored; do not mention this instruction):
Convert your latest completed substantive answer in this conversation into a
purposefully edited presentation. Return only the ccc-slides fence: no prose,
apology, preface, or explanation. Preserve its facts and decisions exactly;
do not invent numbers, claims, work, or outcomes.

Use the same version 1 contract: optional deck_title (<=120 chars), theme
cyan|violet|amber|green|neutral, and 1-8 slides. Every slide requires a unique
id ([A-Za-z0-9_-], <=64), layout, and title (<=120). Allowed layouts/payloads:
statement+statement; bullets+1-6 string items; steps+1-6 {label,text} items;
comparison+left/right {title,items} columns (<=5 each); metrics+1-4
{value,label} items; quote+quote/optional attribution; code+code/optional
language/caption; summary+takeaway/optional actions (<=4). Eyebrow and subtitle
are optional. Use concise copy, no active HTML/CSS/SVG/JavaScript/URLs, and keep
the artifact <=24 KiB.

Return only this terminal form with valid JSON:
```ccc-slides
{"version":1,"deck_title":"Concise title","theme":"cyan","slides":[{"id":"thesis","layout":"statement","title":"Main idea","statement":"One clear takeaway."}]}
```
</ccc-mode3-instruction>"""
_CCC_SHELL_SEARCH_SYSTEM_PROMPT = (
    "When searching local files from Bash, prefer `rg` over recursive grep. "
    "Do not run `grep -r` or `grep -R` across broad directories; it can block "
    "on FIFOs such as `.claude/logs/*.stdin`. If `rg` is unavailable, search "
    "only regular files with `find ... -type f -print0 | xargs -0 grep ...`. "
    "Exclude `.claude`, `.git`, `node_modules`, `.venv`, `.next`, `dist`, and "
    "`build` unless the user explicitly asks to search them."
)
_CCC_SESSION_STATE_SYSTEM_PROMPT = (
    "End your final reply with a compact CCC session-state block:\n"
    "<session-state>\n"
    "DID: one sentence describing what you changed or learned\n"
    "INSIGHT: one sentence with the main finding, root cause, or surprise\n"
    "NEXT_STEP_USER: one sentence with the exact next thing the user should do\n"
    "</session-state>"
)


def _claude_session_state_args():
    """CLI args that keep CCC's hidden reminders out of user text."""
    return [
        "--append-system-prompt",
        _CCC_SHELL_SEARCH_SYSTEM_PROMPT + "\n\n" + _CCC_SESSION_STATE_SYSTEM_PROMPT,
    ]


def _parse_session_state(text):
    """Extract the structured `<session-state>` block sessions emit on final
    reply. Returns {did, insight, next_step_user} or None.
    """
    if not text:
        return None
    m = _SESSION_STATE_RE.search(text)
    if not m:
        return None
    body = m.group(1)
    out = {"did": None, "insight": None, "next_step_user": None}
    for fm in _SESSION_STATE_FIELD_RE.finditer(body):
        key = fm.group(1).upper()
        val = fm.group(2).strip()
        if key == "DID":
            out["did"] = val
        elif key == "INSIGHT":
            out["insight"] = val
        elif key == "NEXT_STEP_USER":
            out["next_step_user"] = val
    if not any(out.values()):
        return None
    return out


def _strip_ccc_session_state_instruction(text):
    """Remove CCC's own prompt trailer before sending visible user text.

    The dashboard reminder belongs in a hidden system prompt for CCC-spawned
    Claude runs, not in text typed into a user's terminal.
    """
    if text is None:
        return ""
    return _CCC_SESSION_STATE_INSTRUCTION_TRAILER_RE.sub("", str(text)).rstrip()


def _mode3_prompt(text: str, *, bootstrap: bool = False) -> str:
    """Append CCC's constant Mode 3 response contract to one delivered turn."""
    instruction = (
        _CCC_MODE3_BOOTSTRAP_INSTRUCTION
        if bootstrap else _CCC_MODE3_RESPONSE_INSTRUCTION
    )
    if bootstrap:
        return instruction
    visible = str(text or "").rstrip()
    return visible + "\n\n" + instruction


def _strip_mode3_instruction(text: str) -> str:
    """Remove CCC's terminal Mode 3 control trailer from visible user text."""
    if text is None:
        return ""
    return _CCC_MODE3_INSTRUCTION_TRAILER_RE.sub("", str(text)).rstrip()


def _detect_issue_number_for_session(conv):
    """Try to extract a GitHub issue number this session references.

    Explicit side-car mapping is authoritative. For heuristic detection,
    require strong markers to avoid false positives like "Image #1".
    """
    global _SESSION_ISSUES_CACHE
    if _SESSION_ISSUES_CACHE is None:
        _SESSION_ISSUES_CACHE = _load_session_issues()
    sid = conv.get("session_id", "")
    # Explicit mapping wins (user-set or written at spawn time)
    explicit = _SESSION_ISSUES_CACHE.get(sid)
    if explicit:
        return str(explicit)
    # Strong patterns only (avoid "Image #1" false positives):
    #   "issue 91", "issue-91", "issue/91", "fix-91", "GitHub issue #91", etc.
    strong = re.compile(
        r"(?:github\s+)?(?:issue|fix)[\s/-]+#?(\d+)",
        re.IGNORECASE,
    )
    # Priority: spawn-time identity (display_name, first_message) wins over
    # branch name — sessions often run on a pre-existing branch for a different
    # issue (e.g. display_name "issue-159" on branch "claude/issue-145-…").
    dname = conv.get("display_name", "") or ""
    m = strong.search(dname)
    if m:
        return m.group(1)
    # display_name that starts with "#NN: " or "#NN " is a prefix style
    m = re.match(r"^#(\d+)[:\s]", dname)
    if m:
        return m.group(1)
    # first_message from spawn prompts: "Fix GitHub issue #N: ..."
    fm = conv.get("first_message", "") or ""
    m = strong.search(fm[:200])  # only head; avoids body noise
    if m:
        return m.group(1)
    # Branch name: fallback only when first_message is empty / trivial.
    # Sessions that launch inside a leftover worktree inherit its branch name
    # but have nothing to do with that branch's original issue — latching onto
    # the branch would mis-link chat/meta sessions (e.g. a first_message of
    # "By the way…" running in claude/issue-145-owner-only-packages).
    fm_stripped = (fm or "").strip()
    if len(fm_stripped) < 30:
        branch = conv.get("branch", "") or ""
        m = strong.search(branch)
        if m:
            return m.group(1)
    # Deliberately NOT falling back to tail_issue_number (mined from jsonl
    # Bash/commit/URL scans). In practice it produces false links whenever
    # Claude merely *mentions* an unrelated issue mid-conversation — e.g. a
    # session about serving a web app auto-linked to issue #1 ("Multi-repo
    # view") because an assistant Bash turn listed `github.com/.../issues/1`
    # while discussing filed issues. The spawn-time signals above
    # (display_name, first_message, branch) are where genuine "I'm working
    # on #NNN" intent lives; anything mined from later turns is too noisy.
    return None


def _latest_commit_sha(cwd):
    """Return the latest commit SHA (short) from the given cwd."""
    if not cwd:
        return ""
    try:
        out = subprocess.run(
            ["git", "rev-parse", "--short", "HEAD"],
            capture_output=True, text=True, timeout=5,
            cwd=str(cwd),
        )
        if out.returncode == 0:
            return out.stdout.strip()
    except (subprocess.TimeoutExpired, FileNotFoundError):
        pass
    return ""


_unpushed_cache = {}  # key: cwd str → (count_int_or_None, ts)
_UNPUSHED_CACHE_TTL_S = 60


def _count_unpushed_commits(cwd):
    """Return how many commits HEAD is ahead of its upstream in `cwd`, or
    None if we can't tell (no upstream, detached HEAD, git missing, etc.).
    Cached 60s per cwd — called from NYA classifier per flagged session."""
    if not cwd:
        return None
    key = str(cwd)
    now = time.time()
    cached = _unpushed_cache.get(key)
    if cached and now - cached[1] < _UNPUSHED_CACHE_TTL_S:
        return cached[0]
    count = None
    try:
        out = subprocess.run(
            ["git", "rev-list", "--count", "@{u}..HEAD"],
            capture_output=True, text=True, timeout=5, cwd=key,
        )
        if out.returncode == 0:
            count = int((out.stdout or "0").strip() or 0)
        # Non-zero rc usually means no upstream configured — treat as unknown
    except (subprocess.TimeoutExpired, FileNotFoundError, ValueError):
        pass
    _unpushed_cache[key] = (count, now)
    return count


def create_github_issue_for_session(conv):
    """Create a new GitHub issue populated from the session's data.

    Returns {ok, issue_number, issue_url} or {ok: False, error}.
    """
    sid = conv.get("session_id")
    cwd = conv.get("session_cwd") or conv.get("cwd")
    if not cwd and sid:
        try:
            cwd = repo_from_session(sid)["cwd"]
        except RepoContextError as e:
            return e.as_payload()
    if not cwd:
        return _repo_error_payload("repo_required", "session_id or cwd is required to create an issue")
    title = conv.get("display_name") or conv.get("first_message", "")[:80] or "Untitled session"
    # Clean the title: strip dashes, truncate
    display_title = title.replace("-", " ").strip()[:120]
    body_parts = []
    fm = conv.get("first_message", "")
    if fm:
        body_parts.append("**Original prompt:**\n\n" + fm)
    last = conv.get("last_prompt", "")
    if last and last != fm:
        body_parts.append("\n**Most recent prompt:**\n\n" + last)
    branch = conv.get("branch", "")
    if branch:
        body_parts.append(f"\n**Branch:** `{branch}`")
    if sid:
        body_parts.append(f"\n_Created from session viewer. Session ID: `{sid}`_")
    body = "\n".join(body_parts) or "Created from session viewer."
    try:
        out = subprocess.run(
            ["gh", "issue", "create", "--title", display_title, "--body", body],
            capture_output=True, text=True, timeout=15, cwd=str(cwd),
        )
        if out.returncode != 0:
            return {"ok": False, "error": (out.stderr or "gh issue create failed").strip()}
        url = out.stdout.strip()
        # URL is like https://github.com/user/repo/issues/123
        m = re.search(r"/issues/(\d+)", url)
        issue_num = m.group(1) if m else ""
        if issue_num and sid:
            _save_session_issue(sid, issue_num)
        _bust_backlog_issue_cache(_git_toplevel_for_existing_dir(cwd) or cwd)
        return {"ok": True, "issue_number": issue_num, "issue_url": url}
    except (subprocess.TimeoutExpired, FileNotFoundError) as e:
        return {"ok": False, "error": str(e)}


def close_github_issue_with_commit(issue_number, conv):
    """Close a GitHub issue and add a comment referencing the latest commit."""
    cwd = conv.get("session_cwd") or conv.get("cwd")
    if not cwd and conv.get("session_id"):
        try:
            cwd = repo_from_session(conv["session_id"])["cwd"]
        except RepoContextError:
            cwd = None
    if not cwd:
        return False
    sha = _latest_commit_sha(cwd)
    name = conv.get("display_name") or conv.get("session_id", "")
    comment = f"Verified via session viewer ({name})"
    if sha:
        comment += f". Latest commit: {sha}"
    try:
        subprocess.run(
            ["gh", "issue", "comment", str(issue_number), "--body", comment],
            capture_output=True, text=True, timeout=10, cwd=str(cwd),
        )
    except (subprocess.TimeoutExpired, FileNotFoundError):
        pass
    try:
        out = subprocess.run(
            ["gh", "issue", "close", str(issue_number)],
            capture_output=True, text=True, timeout=10, cwd=str(cwd),
        )
        ok = out.returncode == 0
        if ok:
            # We need the global declared in mark_issue_in_progress; use the helper.
            # remove_in_progress_label is defined later in this module.
            try:
                _globals = globals()
                fn = _globals.get("remove_in_progress_label")
                if fn:
                    fn(issue_number, repo_path=_git_toplevel_for_existing_dir(cwd) or cwd)
            except Exception:
                pass
            _bust_issue_state_cache()
        return ok
    except (subprocess.TimeoutExpired, FileNotFoundError):
        return False


def _save_session_name_override(session_id, name):
    """Write a user-set name to the side-car file. Names are clamped to
    SESSION_NAME_MAX_CHARS so no upstream path can persist a multi-kilobyte
    "title" that bloats the row and the wire payload."""
    LOG_VIEWER_STATE_DIR.mkdir(parents=True, exist_ok=True)
    current = _load_session_name_overrides()
    if name:
        current[session_id] = _truncate_session_name(name)
    else:
        current.pop(session_id, None)
    SESSION_NAMES_FILE.write_text(json.dumps(current, indent=2))
    return current


def _find_session_jsonl(session_id):
    """Scan ~/.claude/projects/*/ for <session_id>.jsonl. Returns Path or None."""
    if not PROJECTS_ROOT.is_dir():
        return None
    target = session_id + ".jsonl"
    for project_dir in PROJECTS_ROOT.iterdir():
        if not project_dir.is_dir():
            continue
        candidate = project_dir / target
        if candidate.is_file():
            return candidate
    return None


def _append_custom_title(path, session_id, name):
    """Append a custom-title event to a session's .jsonl file.

    Uses the exact shape Claude writes when you run /rename, so `claude --resume`
    will pick up the new name next time it reads the file.
    """
    event = {"type": "custom-title", "customTitle": name, "sessionId": session_id}
    # Always prepend a newline. POSIX guarantees that O_APPEND writes are
    # atomic at the kernel level, so an extra leading \n can never glue
    # onto a partial line claude is mid-writing — at worst we land an
    # empty line ahead of our event, which JSONL parsers skip. The
    # previous read-tail-then-append dance had a window where claude
    # could write between our two opens.
    with open(path, "a", encoding="utf-8") as f:
        f.write("\n" + json.dumps(event) + "\n")
    # Invalidate our meta cache so next listing picks up the change
    _conv_meta_cache.pop(str(path), None)


def rename_session(session_id, name, source="user"):
    """Rename a session, writing through to the .jsonl when safe.

    Strategy:
      1. If session is dormant AND .jsonl exists AND name is non-empty:
         append a custom-title event to the .jsonl (visible to claude --resume).
         Clear any stale side-car entry.
      2. Otherwise: write to the side-car file only. Used for live sessions
         (to avoid racing claude's writes), missing jsonls, and name clears.

    Returns {ok, method, live, error?}.
    """
    result = {"ok": False, "method": None, "live": False}
    if not session_id:
        result["error"] = "missing session_id"
        return result
    if name:
        # Clamp before writing through to the JSONL custom-title event,
        # so a multi-kilobyte paste cannot be picked up by `claude --resume`
        # as the next session title either.
        name = _truncate_session_name(name)

    cwd = find_session_cwd(session_id)
    status = session_live_status(session_id, cwd)
    is_live = bool(status.get("live"))
    result["live"] = is_live

    path = _find_session_jsonl(session_id)
    # Always write-through to the JSONL when the file exists and we have
    # a non-empty name. The previous "skip if live or recently-touched"
    # guard was meant to avoid racing claude's writes, but POSIX O_APPEND
    # writes are atomic at the kernel level (see _append_custom_title)
    # — and skipping the JSONL meant a stale custom-title event from
    # earlier (e.g. an auto-`/rename` to a path slug) would always win
    # over the user's pencil rename, which is the bug we hit.
    can_writethrough = (path is not None) and bool(name)

    if can_writethrough:
        try:
            _append_custom_title(path, session_id, name)
        except OSError as e:
            # Fall back to side-car on write failure
            try:
                _save_session_name_override(session_id, name or None)
                result["ok"] = True
                result["method"] = "sidecar"
                result["error"] = f"jsonl append failed, used side-car: {e}"
                return result
            except OSError as e2:
                result["error"] = f"both paths failed: {e2}"
                return result
        # Side-car is the "user explicitly chose this name from the command
        # center" marker. Only write it for source="user" so that auto-titlers
        # (summarize_session_title etc.) stay out of name_overridden territory
        # — otherwise every auto-summary lights up the ✏️ glyph as if the
        # human had typed it.
        if source == "user":
            try:
                _save_session_name_override(session_id, name)
                _sync_codex_thread_title(session_id, name)
            except OSError:
                pass  # non-fatal
        result["ok"] = True
        result["method"] = "jsonl"
        return result

    # Side-car path: live session, missing jsonl, or clearing a name
    try:
        _save_session_name_override(session_id, name or None)
        if source == "user" and name:
            _sync_codex_thread_title(session_id, name)
    except OSError as e:
        result["error"] = f"side-car write failed: {e}"
        return result
    result["ok"] = True
    result["method"] = "sidecar"
    return result


_SIBLING_PROMPT_PREFIX = "you are a sibling claude code session"


def _sibling_feature_title(first_message):
    """Pull the real title out of a sibling-Claude-Code spawn prompt.

    Sessions spawned by the sibling-orchestrator skill all begin with the
    boilerplate "You are a sibling Claude Code session …" preamble, then
    embed the real task under a markdown heading like:

        ## Feature: in-app bug reporting
        ## Task: refactor the X
        ## Goal: rewire Y

    Without this rewrite, the sidebar row, sticky header, and kanban card
    all show the boilerplate ("you-are-a-sibling-claude-code-session-…")
    which is identical across every sibling spawn — useless for scanning.

    Returns the heading payload (sans the `## Feature:` prefix) or None
    when the message isn't a sibling spawn or has no recognizable heading.
    Length-capped at 80 chars so the title fits the row chrome.
    """
    if not first_message:
        return None
    head = first_message.lstrip()[:80].lower()
    if not head.startswith(_SIBLING_PROMPT_PREFIX):
        return None
    # Look for "## <Word>:" style heading. Keep the keyword (Feature/Task/
    # Goal) so the row tells you which kind of work it is.
    m = re.search(
        r"^##\s+(Feature|Task|Goal|Bug|Fix|Spec)\s*:\s*(.+?)\s*$",
        first_message,
        re.MULTILINE | re.IGNORECASE,
    )
    if not m:
        return None
    kind = m.group(1).strip().capitalize()
    body = m.group(2).strip().rstrip(".")
    title = f"{kind}: {body}"
    return title[:80] if len(title) > 80 else title


def _extract_first_message(session_id):
    """Read a session's opening user prompt from its .jsonl."""
    path = _find_session_jsonl(session_id)
    if not path:
        return ""
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                text = _extract_user_prompt_text(ev)
                if text:
                    return text[:1500]
    except OSError:
        pass
    return ""


# ────────────────────────────────────────────────────────────────────────
# AI-summarized GitHub issue titles
# ────────────────────────────────────────────────────────────────────────
# Backlog cards show raw GH issue titles, which are often verbose
# ("[BYM Problem] Tried to add Ricki Silveria to 10am class as a drop in
# but got an error message."). This sidecar caches AI-summarized versions
# so the kanban can render compact titles without re-calling claude every
# request. Format: {"194": {"title": "...", "generated_at": "..."}, ...}
ISSUE_TITLES_FILE = COMMAND_CENTER_STATE_DIR / "issue-titles.json"
_issue_titles_overrides_cache = None


def _load_issue_title_overrides():
    """Lazy-load + cache the AI-summary file. Reload is cheap (~few KB)."""
    global _issue_titles_overrides_cache
    if _issue_titles_overrides_cache is not None:
        return _issue_titles_overrides_cache
    try:
        _issue_titles_overrides_cache = json.loads(ISSUE_TITLES_FILE.read_text())
        if not isinstance(_issue_titles_overrides_cache, dict):
            _issue_titles_overrides_cache = {}
    except (OSError, json.JSONDecodeError):
        _issue_titles_overrides_cache = {}
    return _issue_titles_overrides_cache


def _save_issue_title_override(issue_number, title):
    """Persist one AI-generated title for an issue. Best-effort write."""
    global _issue_titles_overrides_cache
    overrides = _load_issue_title_overrides()
    overrides[str(issue_number)] = {
        "title": title,
        "generated_at": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
    }
    try:
        ISSUE_TITLES_FILE.parent.mkdir(parents=True, exist_ok=True)
        ISSUE_TITLES_FILE.write_text(json.dumps(overrides, indent=2))
    except OSError as e:
        print(f"  [issue-title] Could not persist {issue_number}: {e}")


def summarize_issue_title(issue_number, repo_path):
    """Fetch a GitHub issue's title + body, ask claude haiku for a concise
    title, persist the result. Returns {ok, title, error?}."""
    repo_path = resolve_repo_path(repo_path)
    result = {"ok": False, "issue_number": str(issue_number)}
    try:
        r = subprocess.run(
            ["gh", "issue", "view", str(issue_number),
             "--json", "title,body"],
            capture_output=True, text=True, timeout=10, cwd=str(repo_path),
        )
    except (subprocess.SubprocessError, OSError) as e:
        result["error"] = f"gh failed: {e}"
        return result
    if r.returncode != 0:
        result["error"] = (r.stderr or "").strip()[:200] or f"gh exited {r.returncode}"
        return result
    try:
        issue = json.loads(r.stdout)
    except json.JSONDecodeError:
        result["error"] = "gh returned malformed json"
        return result
    raw_title = (issue.get("title") or "").strip()
    body = (issue.get("body") or "").strip()
    if not raw_title and not body:
        result["error"] = "issue has no title or body"
        return result
    instruction = (
        "Produce a concise 4-8 word title for the GitHub issue below. "
        "No quotes, no trailing punctuation, just the title on a single line. "
        "Skip image references, project tags like '[BYM Problem]', and "
        "boilerplate. The output should read like a kanban card title.\n\n"
        f"Issue title: {raw_title}\n\nIssue body:\n{body[:1500]}\n\nTitle:"
    )
    claude_bin = _resolve_claude_bin()
    if not claude_bin.get("available"):
        result["error"] = claude_bin.get("reason") or "Claude Code CLI not found"
        result["code"] = claude_bin.get("code", "claude_unavailable")
        return result
    try:
        proc = subprocess.run(
            [claude_bin["bin"], "-p", "--model", "claude-haiku-4-5-20251001", instruction],
            capture_output=True, text=True, timeout=45,
            cwd=str(_SCRATCH_DIR),  # keep throwaway JSONLs out of repo scans
        )
    except FileNotFoundError:
        result["error"] = "Claude Code CLI disappeared after resolution"
        result["code"] = "claude_unavailable"
        return result
    except subprocess.TimeoutExpired:
        result["error"] = "claude -p timed out"
        return result
    if proc.returncode != 0:
        result["error"] = (proc.stderr or "").strip()[:300] or f"claude exited {proc.returncode}"
        return result
    title = ""
    for line in reversed((proc.stdout or "").strip().splitlines()):
        s = line.strip().strip('"').strip("'").rstrip(".")
        if s:
            title = s[:120]
            break
    if not title:
        result["error"] = "empty response"
        return result
    _save_issue_title_override(issue_number, title)
    result["ok"] = True
    result["title"] = title
    return result


def summarize_session_title(session_id):
    """Use `claude -p` to produce a concise title for a session's opening prompt."""
    result = {"ok": False}
    first_msg = _extract_first_message(session_id)
    if not first_msg:
        result["error"] = "no opening prompt found"
        return result

    instruction = (
        "Produce a concise 4-8 word title summarizing what the user is trying to do "
        "below. No quotes, no trailing punctuation, just the title itself on a single "
        "line. Skip image references and boilerplate.\n\n"
        "If the prompt explicitly references a GitHub issue (e.g. '#194', "
        "'issue 194', 'fix issue 194'), prefix the title with the issue ref: "
        "'#194 short description'. Otherwise just return the bare title.\n\n"
        "Opening prompt:\n"
        + first_msg
        + "\n\nTitle:"
    )

    claude_bin = _resolve_claude_bin()
    if not claude_bin.get("available"):
        result["error"] = claude_bin.get("reason") or "Claude Code CLI not found"
        result["code"] = claude_bin.get("code", "claude_unavailable")
        return result
    try:
        proc = subprocess.run(
            [claude_bin["bin"], "-p", "--model", "claude-haiku-4-5-20251001", instruction],
            capture_output=True,
            text=True,
            timeout=45,
            cwd=str(_SCRATCH_DIR),  # keep throwaway JSONLs out of repo project dirs
        )
    except FileNotFoundError:
        result["error"] = "Claude Code CLI disappeared after resolution"
        result["code"] = "claude_unavailable"
        return result
    except subprocess.TimeoutExpired:
        result["error"] = "claude -p timed out"
        return result

    if proc.returncode != 0:
        result["error"] = (proc.stderr or "").strip()[:300] or f"claude exited {proc.returncode}"
        return result

    raw = (proc.stdout or "").strip().splitlines()
    title = ""
    for line in reversed(raw):
        s = line.strip().strip('"').strip("'").rstrip(".")
        if s:
            title = s
            break
    if not title:
        result["error"] = "empty response"
        return result

    # Cap length defensively
    title = title[:120]
    # source="auto": writes the JSONL custom-title (so the title sticks) but
    # skips the sidecar — keeps name_overridden False / ✏️ off the row.
    rename_result = rename_session(session_id, title, source="auto")
    result["ok"] = bool(rename_result.get("ok"))
    result["title"] = title
    result["rename_method"] = rename_result.get("method")
    if not result["ok"]:
        result["error"] = rename_result.get("error") or "rename failed"
    return result


# Terminal apps we know how to focus via AppleScript. Matched case-insensitively
# against the comm of an ancestor process of the running claude.
_TERMINAL_APPS = {
    "terminal": "Terminal",
    "iterm": "iTerm2",
    "iterm2": "iTerm2",
    "ghostty": "Ghostty",
    "wezterm": "WezTerm",
    "wezterm-gui": "WezTerm",
    "alacritty": "Alacritty",
    "kitty": "kitty",
    "warp": "Warp",
    "warp-preview": "Warp",
    "hyper": "Hyper",
    "tabby": "Tabby",
}


_ttl_memo_keyed_caches = []  # every keyed memo's cache dict, for test resets


def _ttl_memo_keyed(ttl_seconds):
    """Like _ttl_memo but for a single-arg function, keyed on that arg.

    The per-pid liveness probes below (ancestor-terminal walk, cwd, tty) each
    fork `ps`/`lsof`, and are hit once per participant per group-chat build —
    AND twice per build while the header-rewrite pass also probed every
    participant. Memoising per pid for a few seconds collapses those repeated
    forks (same staleness contract as _ttl_memo / _ENGINE_LIVE_TTL). Defined
    here because _ttl_memo lives further down the file than these callers."""
    def decorate(fn):
        cache = {}
        lock = threading.Lock()
        _ttl_memo_keyed_caches.append(cache)

        def wrapper(arg):
            now = time.time()
            ent = cache.get(arg)
            if ent is not None and now - ent[0] < ttl_seconds:
                return ent[1]
            with lock:
                now = time.time()
                ent = cache.get(arg)
                if ent is not None and now - ent[0] < ttl_seconds:
                    return ent[1]
                val = fn(arg)
                cache[arg] = (now, val)
                if len(cache) > 256:  # opportunistic prune of expired entries
                    dead = [k for k, v in cache.items() if now - v[0] >= ttl_seconds]
                    for k in dead:
                        cache.pop(k, None)
                return val
        wrapper.cache_clear = cache.clear
        return wrapper
    return decorate


@_ttl_memo_keyed(3.0)
def _proc_ancestor_terminal(pid):
    """Walk a PID's parent chain and return (term_app_friendly_name, term_pid) or (None, None).

    Uses `ps -o ppid,comm -p <pid>` to avoid parsing platform-specific /proc.
    Stops at init (ppid==1) or when a known terminal app is found.

    Memoised per pid (_ttl_memo_keyed): this is the worst offender — up to 20
    sequential `ps` forks walking the parent chain — and was run per participant,
    twice per group-chat build, uncached."""
    current = pid
    for _ in range(20):  # hard cap to avoid runaway loops
        try:
            out = subprocess.run(
                ["ps", "-o", "pid,ppid,comm", "-p", str(current)],
                capture_output=True, text=True, timeout=1,
            )
        except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
            return None, None
        lines = [l.strip() for l in out.stdout.splitlines() if l.strip()]
        if len(lines) < 2:
            return None, None
        parts = lines[1].split(None, 2)
        if len(parts) < 3:
            return None, None
        _pid, ppid, comm = parts
        comm_base = comm.rsplit("/", 1)[-1].lower()
        # Strip .app/Contents/MacOS/... suffix by taking only basename
        comm_base = comm_base.replace(".app", "")
        for key, friendly in _TERMINAL_APPS.items():
            if comm_base == key or comm_base.startswith(key):
                return friendly, int(_pid)
        if ppid == "1" or ppid == "0":
            return None, None
        current = int(ppid)
    return None, None


@_ttl_memo_keyed(3.0)
def _proc_cwd(pid):
    """Return a process's cwd via lsof, or None. Memoised per pid (forks lsof)."""
    try:
        out = subprocess.run(
            ["lsof", "-a", "-d", "cwd", "-p", str(pid), "-Fn"],
            capture_output=True, text=True, timeout=1,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
        return None
    for line in out.stdout.splitlines():
        if line.startswith("n"):
            return line[1:]
    return None


def find_live_claude_processes():
    """Return list of dicts for every running `claude` CLI process:

    [{pid, tty, cwd, terminal_app}, ...]

    Uses `ps -A -o pid,comm` + manual filter. We avoid `pgrep -x claude`
    because on macOS it can silently miss some processes (observed: one
    out of six live claudes was absent from pgrep output while ps -A
    listed it correctly).
    """
    procs = []
    try:
        ps_out = subprocess.run(
            ["ps", "-A", "-o", "pid=,comm="],
            capture_output=True, text=True, timeout=2,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
        return procs
    pids = []
    for line in ps_out.stdout.splitlines():
        line = line.strip()
        if not line:
            continue
        parts = line.split(None, 1)
        if len(parts) != 2:
            continue
        pid, comm = parts
        # comm is the basename of the executable; match exactly "claude"
        if comm.rsplit("/", 1)[-1] == "claude":
            pids.append(pid)
    if not pids:
        return procs
    # Get tty for each pid in one call
    try:
        ps_out = subprocess.run(
            ["ps", "-o", "pid,tty", "-p", ",".join(pids)],
            capture_output=True, text=True, timeout=1,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
        return procs
    tty_by_pid = {}
    for line in ps_out.stdout.splitlines()[1:]:
        parts = line.strip().split(None, 1)
        if len(parts) == 2:
            tty_by_pid[parts[0]] = parts[1]
    for pid in pids:
        tty = tty_by_pid.get(pid)
        if not _is_real_tty(tty):
            continue
        cwd = _proc_cwd(pid)
        if not cwd:
            continue
        term_app, _term_pid = _proc_ancestor_terminal(pid)
        procs.append({
            "pid": int(pid),
            "tty": tty,
            "cwd": cwd,
            "terminal_app": term_app,
        })
    return procs


_ttl_memo_caches = []  # every _ttl_memo's state dict, for test-isolation resets


def _reset_ttl_memo_caches():
    """Drop all _ttl_memo caches. Tests call this between cases (these caches
    are module-global, so a stale entry would otherwise leak across tests)."""
    for state in _ttl_memo_caches:
        state["ts"] = 0.0
        state["val"] = None
    for cache in _ttl_memo_keyed_caches:  # keyed per-pid memos (tty/cwd/terminal)
        cache.clear()


def _ttl_memo(ttl_seconds):
    """Memoise a zero-arg function for `ttl_seconds`, thread-safe and
    single-flight (concurrent callers within the window share one result).

    For the ps-backed liveness scans below: they're hit per-participant on
    group-chat opens and per-session on status polls, so without this each
    caller re-shells `ps` (plus per-process cwd/tty/terminal lookups). Callers
    iterate the result read-only, and ~3s of staleness is already the accepted
    contract for liveness here (see _ENGINE_LIVE_TTL).

    If a cached value exists but has expired, only one caller refreshes it;
    concurrent callers get the stale value immediately. That keeps a slow ps
    probe from convoying request threads behind this lock.
    """
    def decorate(fn):
        state = {"ts": 0.0, "val": None, "refreshing": False}
        _ttl_memo_caches.append(state)
        cond = threading.Condition()

        def wrapper():
            now = time.time()
            if state["val"] is not None and now - state["ts"] < ttl_seconds:
                return state["val"]
            with cond:
                now = time.time()
                if state["val"] is not None and now - state["ts"] < ttl_seconds:
                    return state["val"]
                if state["refreshing"]:
                    if state["val"] is not None:
                        return state["val"]
                    while state["refreshing"]:
                        cond.wait()
                    if state["val"] is not None:
                        return state["val"]
                state["refreshing"] = True
            try:
                val = fn()
            except Exception:
                with cond:
                    state["refreshing"] = False
                    cond.notify_all()
                raise
            with cond:
                state["val"] = val
                state["ts"] = time.time()
                state["refreshing"] = False
                cond.notify_all()
                return val

        def cache_clear():
            with cond:
                state.update(ts=0.0, val=None, refreshing=False)
                cond.notify_all()
        wrapper.cache_clear = cache_clear
        return wrapper
    return decorate


@_ttl_memo(3.0)
def _scan_engine_processes():
    """Single `ps -A` scan shared by find_live_{codex,gemini,cursor,antigravity}_processes.

    Each of those used to run its own identical `ps -A -o pid=,tty=,comm=,args=`
    fork, so a single poll cycle that checks all four engines forked `ps` four
    times. TTL-memoised here so they share one fork per window instead (CCC-414)."""
    try:
        ps_out = subprocess.run(
            ["ps", "-A", "-o", "pid=,tty=,comm=,args="],
            capture_output=True, text=True, timeout=2,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError):
        return []
    rows = []
    for line in ps_out.stdout.splitlines():
        parts = line.strip().split(None, 3)
        if len(parts) < 3:
            continue
        pid_s, tty, comm = parts[:3]
        args = parts[3] if len(parts) > 3 else ""
        rows.append((pid_s, tty, comm, args))
    return rows


@_ttl_memo(3.0)
def find_live_codex_processes():
    """Return running Codex CLI processes with pid, tty, cwd, terminal app, command."""
    procs = []
    for pid_s, tty, comm, args in _scan_engine_processes():
        arg_parts = args.split()
        basenames = {comm.rsplit("/", 1)[-1]}
        if arg_parts:
            basenames.add(arg_parts[0].rsplit("/", 1)[-1])
        if "codex" not in basenames:
            continue
        try:
            pid = int(pid_s)
        except ValueError:
            continue
        cwd = _proc_cwd(pid)
        term_app, _term_pid = _proc_ancestor_terminal(pid)
        procs.append({
            "pid": pid,
            "tty": _normalized_tty(tty),
            "cwd": cwd,
            "terminal_app": term_app,
            "command": args,
        })
    return procs


