def _codex_recovery_is_silent_turn(recovery):
    return isinstance(recovery, dict) and recovery.get("trigger") == "silent-turn"


def _codex_recovery_event_kind(recovery, suffix):
    prefix = (
        "turn_recovery"
        if _codex_recovery_is_silent_turn(recovery)
        else "compaction_recovery"
    )
    return f"{prefix}_{suffix}"


def _codex_recovery_activity_text(recovery):
    if _codex_recovery_is_silent_turn(recovery):
        return "Recovering stalled Codex turn"
    return "Recovering after compaction"


def _codex_telemetry_append(event, **fields):
    rec = {
        "ts": time.time(),
        "event": str(event or "codex_event"),
    }
    rec.update({k: v for k, v in fields.items() if v is not None})
    try:
        CODEX_TELEMETRY_FILE.parent.mkdir(parents=True, exist_ok=True)
        with CODEX_TELEMETRY_FILE.open("a", encoding="utf-8") as f:
            f.write(json.dumps(rec, sort_keys=True, default=str) + "\n")
    except OSError:
        pass


def _codex_elapsed_ms(start):
    try:
        return round((time.monotonic() - float(start)) * 1000.0, 1)
    except (TypeError, ValueError):
        return None


def _codex_telemetry_register_turn(thread_id, turn_id, *, path, started_at_monotonic=None, **fields):
    if not turn_id:
        return
    rec = {
        "thread_id": str(thread_id or ""),
        "turn_id": str(turn_id),
        "path": str(path or "codex"),
        "started_at_monotonic": float(started_at_monotonic or time.monotonic()),
    }
    for key in ("transport", "model", "cwd"):
        if fields.get(key) is not None:
            rec[key] = fields[key]
    _CODEX_TELEMETRY_TURNS[str(turn_id)] = rec


def _codex_telemetry_note_notification(method, params, thread_id, turn_id):
    if not turn_id:
        return
    rec = _CODEX_TELEMETRY_TURNS.get(str(turn_id))
    if not rec:
        return
    latency_ms = _codex_elapsed_ms(rec.get("started_at_monotonic"))
    common = {
        "thread_id": thread_id or rec.get("thread_id"),
        "turn_id": str(turn_id),
        "path": rec.get("path"),
        "transport": rec.get("transport"),
        "model": rec.get("model"),
        "cwd": rec.get("cwd"),
        "latency_ms": latency_ms,
        "method": method,
    }
    if not rec.get("first_notification_seen"):
        rec["first_notification_seen"] = True
        _codex_telemetry_append("codex_turn_first_notification", **common)
    if method == "item/agentMessage/delta" and not rec.get("first_visible_output_seen"):
        rec["first_visible_output_seen"] = True
        _codex_telemetry_append("codex_turn_first_visible_output", **common)
    if method == "thread/tokenUsage/updated":
        usage = params.get("tokenUsage") or params.get("token_usage") or params.get("usage")
        if isinstance(usage, dict):
            rec["token_usage"] = usage
    if method == "turn/completed":
        _codex_telemetry_append(
            "codex_turn_complete",
            **common,
            token_usage=rec.get("token_usage"),
        )
        _CODEX_TELEMETRY_TURNS.pop(str(turn_id), None)


def _codex_thread_registry_now():
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")


def _codex_thread_registry_empty():
    return {
        "schema_version": _CODEX_THREAD_REGISTRY_SCHEMA,
        "authoritative": False,
        "source": "ccc-wt-codex-reconciliation",
        "updated_at": _codex_thread_registry_now(),
        "threads": {},
    }


def _load_codex_thread_registry():
    try:
        with CODEX_THREAD_REGISTRY_FILE.open("r", encoding="utf-8") as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        return _codex_thread_registry_empty()
    if not isinstance(data, dict):
        return _codex_thread_registry_empty()
    if not isinstance(data.get("threads"), dict):
        data["threads"] = {}
    data["schema_version"] = _CODEX_THREAD_REGISTRY_SCHEMA
    data["authoritative"] = False
    data.setdefault("source", "ccc-wt-codex-reconciliation")
    return data


def _save_codex_thread_registry(data):
    data["schema_version"] = _CODEX_THREAD_REGISTRY_SCHEMA
    data["authoritative"] = False
    data["source"] = "ccc-wt-codex-reconciliation"
    data["updated_at"] = _codex_thread_registry_now()
    CODEX_THREAD_REGISTRY_FILE.parent.mkdir(parents=True, exist_ok=True)
    tmp = CODEX_THREAD_REGISTRY_FILE.with_suffix(CODEX_THREAD_REGISTRY_FILE.suffix + ".tmp")
    with tmp.open("w", encoding="utf-8") as f:
        json.dump(data, f, indent=2, sort_keys=True)
    tmp.replace(CODEX_THREAD_REGISTRY_FILE)


class _CodexThreadRegistryLock:
    def __init__(self):
        self._fh = None

    def __enter__(self):
        lock_path = CODEX_THREAD_REGISTRY_FILE.with_suffix(CODEX_THREAD_REGISTRY_FILE.suffix + ".lock")
        lock_path.parent.mkdir(parents=True, exist_ok=True)
        self._fh = lock_path.open("a+")
        fcntl.flock(self._fh.fileno(), fcntl.LOCK_EX)
        return self

    def __exit__(self, *_exc):
        if self._fh is not None:
            try:
                fcntl.flock(self._fh.fileno(), fcntl.LOCK_UN)
            finally:
                self._fh.close()


def _codex_thread_registry_merge_nested(dst, src):
    if not isinstance(src, dict):
        return dst
    out = dict(dst or {})
    for key, value in src.items():
        if value is None or value == "":
            continue
        out[key] = value
    return out


def _codex_thread_registry_merge_record(existing, fields, now):
    rec = dict(existing or {})
    rec.setdefault("created_at", now)
    rec["updated_at"] = now
    rec["thread_id"] = fields.get("thread_id") or rec.get("thread_id")
    rec["engine"] = "codex"
    source = fields.get("source")
    sources = [str(s) for s in rec.get("sources") or [] if s]
    if source and str(source) not in sources:
        sources.append(str(source))
    if sources:
        rec["sources"] = sources
    visibility = fields.get("visibility")
    if visibility and _CODEX_THREAD_VISIBILITY_RANK.get(str(visibility), 0) >= _CODEX_THREAD_VISIBILITY_RANK.get(str(rec.get("visibility") or "unknown"), 0):
        rec["visibility"] = str(visibility)
    owner = fields.get("transport_owner")
    if owner and _CODEX_THREAD_OWNER_RANK.get(str(owner), 0) >= _CODEX_THREAD_OWNER_RANK.get(str(rec.get("transport_owner") or ""), 0):
        rec["transport_owner"] = str(owner)
    for key in (
        "cwd",
        "repo_path",
        "transport",
        "title",
        "name",
        "parent_session_id",
        "report_to",
        "model",
        "reasoning_effort",
        "worker_id",
        "queue",
        "ref",
    ):
        value = fields.get(key)
        if value is not None and value != "":
            rec[key] = value
    for key in ("ccc", "wt"):
        value = fields.get(key)
        if isinstance(value, dict):
            nested = _codex_thread_registry_merge_nested(rec.get(key), value)
            if nested:
                rec[key] = nested
    return rec


def _codex_thread_registry_upsert(thread_id, **fields):
    sid = str(thread_id or "").strip()
    if not sid:
        return None
    fields["thread_id"] = sid
    try:
        with _CodexThreadRegistryLock():
            data = _load_codex_thread_registry()
            threads = data.setdefault("threads", {})
            now = _codex_thread_registry_now()
            existing = threads.get(sid) if isinstance(threads.get(sid), dict) else {}
            rec = _codex_thread_registry_merge_record(existing, fields, now)
            threads[sid] = rec
            _save_codex_thread_registry(data)
            return rec
    except OSError:
        return None


def _codex_thread_registry_entries():
    try:
        threads = _load_codex_thread_registry().get("threads") or {}
    except Exception:
        return {}
    return {
        str(sid): dict(rec)
        for sid, rec in threads.items()
        if sid and isinstance(rec, dict)
    }


def _codex_thread_registry_entry(thread_id):
    return _codex_thread_registry_entries().get(str(thread_id or "").strip())


def _codex_thread_registry_spawn_shape(entry):
    if not isinstance(entry, dict):
        return {}
    ccc = entry.get("ccc") if isinstance(entry.get("ccc"), dict) else {}
    wt = entry.get("wt") if isinstance(entry.get("wt"), dict) else {}
    return {
        "pid": ccc.get("spawn_id") or entry.get("worker_id") or wt.get("worker_id") or "",
        "alive": False,
        "log": ccc.get("log") or wt.get("log") or "",
        "cwd": entry.get("cwd") or "",
        "repo_path": entry.get("repo_path") or entry.get("cwd") or "",
        "spawned_at": ccc.get("spawned_at") or wt.get("started_at") or entry.get("created_at") or "",
        "prompt": ccc.get("prompt") or "",
        "model": entry.get("model") or "",
        "parent_session_id": entry.get("parent_session_id") or "",
        "worker_id": entry.get("worker_id") or wt.get("worker_id") or "",
        "queue": entry.get("queue") or wt.get("queue") or "",
        "ref": entry.get("ref") or wt.get("ref") or "",
        "visibility": entry.get("visibility") or "",
        "transport_owner": entry.get("transport_owner") or "",
    }


def _codex_app_server_state_payload_unlocked():
    threads = {}
    for sid, state in (_CODEX_APP_SERVER_THREAD_STATE or {}).items():
        if not sid or not isinstance(state, dict):
            continue
        public = {}
        for key in (
            "thread_id",
            "status",
            "active_flags",
            "thread_needs_approval",
            "event_seq",
            "last_event",
            "last_event_at",
            "last_activity_at",
            "last_turn_id",
            "active_turn_id",
            "last_completed_turn_id",
            "token_usage",
            "thread_settings",
            "pending_approval_request",
            "active_item",
            "last_item",
            "recent_items",
            "coordination_events",
            "compaction_recovery",
        ):
            if key in state:
                public[key] = state[key]
        threads[str(sid)] = public
    return {
        "schema_version": _CODEX_APP_SERVER_STATE_SCHEMA,
        "authoritative": False,
        "source": "codex-app-server-notifications",
        "updated_at": time.time(),
        "transport": _codex_app_server_transport_kind(),
        "threads": threads,
    }


def _save_codex_app_server_state_unlocked():
    """Persist compact last-known Codex app-server state for UI/diagnostics.

    This is intentionally not the durable transcript. Consumers must treat
    Codex rollout/session files as authoritative history and use this only for
    live status, telemetry, and coordination hints.
    """
    try:
        CODEX_APP_SERVER_STATE_FILE.parent.mkdir(parents=True, exist_ok=True)
        tmp = CODEX_APP_SERVER_STATE_FILE.with_suffix(".json.tmp")
        with tmp.open("w") as f:
            json.dump(_codex_app_server_state_payload_unlocked(), f, indent=2, sort_keys=True)
        tmp.replace(CODEX_APP_SERVER_STATE_FILE)
    except OSError:
        pass


def _codex_managed_app_server_socket_path():
    raw = os.environ.get("CCC_CODEX_APP_SERVER_SOCKET")
    if raw:
        return Path(os.path.expanduser(raw))
    return Path.home() / ".codex" / "app-server-control" / "app-server-control.sock"


def _codex_managed_app_server_enabled():
    return os.environ.get("CCC_CODEX_MANAGED_APP_SERVER", "1").lower() not in ("0", "false", "no")


class _CodexAppServerTransport:
    def __init__(self, kind, *, proc=None, sock=None):
        self.kind = kind
        self.proc = proc
        self.sock = sock
        self._send_lock = threading.Lock()

    def alive(self):
        if self.kind == "stdio":
            return self.proc is not None and self.proc.poll() is None
        return self.sock is not None

    def send_json(self, payload):
        data = json.dumps(payload)
        with self._send_lock:
            if self.kind == "stdio":
                self.proc.stdin.write(data + "\n")
                self.proc.stdin.flush()
            else:
                _websocket_send_text(self.sock, data)

    def close(self):
        if self.sock is not None:
            try:
                self.sock.close()
            except OSError:
                pass
            self.sock = None
        if self.proc is not None and self.proc.poll() is None:
            try:
                self.proc.terminate()
            except OSError:
                pass


def _read_exact(sock, n):
    chunks = []
    remaining = n
    while remaining > 0:
        chunk = sock.recv(remaining)
        if not chunk:
            raise OSError("socket closed")
        chunks.append(chunk)
        remaining -= len(chunk)
    return b"".join(chunks)


def _websocket_send_frame(sock, opcode, payload=b"", *, mask=True):
    payload = payload or b""
    first = 0x80 | (opcode & 0x0F)
    length = len(payload)
    if length <= 125:
        header = bytes([first, (0x80 if mask else 0) | length])
    elif length <= 0xFFFF:
        header = bytes([first, (0x80 if mask else 0) | 126]) + length.to_bytes(2, "big")
    else:
        header = bytes([first, (0x80 if mask else 0) | 127]) + length.to_bytes(8, "big")
    if not mask:
        sock.sendall(header + payload)
        return
    key = os.urandom(4)
    masked = bytes(b ^ key[i % 4] for i, b in enumerate(payload))
    sock.sendall(header + key + masked)


def _websocket_send_text(sock, text):
    _websocket_send_frame(sock, 0x1, str(text).encode("utf-8"), mask=True)


def _websocket_recv_text(sock):
    fragments = []
    while True:
        first, second = _read_exact(sock, 2)
        fin = bool(first & 0x80)
        opcode = first & 0x0F
        masked = bool(second & 0x80)
        length = second & 0x7F
        if length == 126:
            length = int.from_bytes(_read_exact(sock, 2), "big")
        elif length == 127:
            length = int.from_bytes(_read_exact(sock, 8), "big")
        mask_key = _read_exact(sock, 4) if masked else b""
        payload = _read_exact(sock, length) if length else b""
        if masked and payload:
            payload = bytes(b ^ mask_key[i % 4] for i, b in enumerate(payload))
        if opcode == 0x8:
            raise OSError("websocket closed")
        if opcode == 0x9:
            _websocket_send_frame(sock, 0xA, payload, mask=True)
            continue
        if opcode == 0xA:
            continue
        if opcode == 0x1:
            fragments = [payload]
        elif opcode == 0x0:
            fragments.append(payload)
        else:
            continue
        if fin:
            return b"".join(fragments).decode("utf-8", "replace")


def _connect_codex_managed_app_server(path):
    sock = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
    sock.settimeout(10)
    try:
        sock.connect(str(path))
        key = base64.b64encode(os.urandom(16)).decode("ascii")
        request = (
            "GET / HTTP/1.1\r\n"
            "Host: localhost\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            f"Sec-WebSocket-Key: {key}\r\n"
            "Sec-WebSocket-Version: 13\r\n"
            "\r\n"
        )
        sock.sendall(request.encode("ascii"))
        response = b""
        while b"\r\n\r\n" not in response and len(response) < 16384:
            chunk = sock.recv(4096)
            if not chunk:
                raise OSError("managed app-server closed during websocket handshake")
            response += chunk
        header = response.split(b"\r\n\r\n", 1)[0].decode("iso-8859-1", "replace")
        lines = header.split("\r\n")
        if not lines or " 101 " not in f" {lines[0]} ":
            raise OSError("managed app-server did not accept websocket upgrade")
        accept = ""
        for line in lines[1:]:
            name, _, value = line.partition(":")
            if name.lower() == "sec-websocket-accept":
                accept = value.strip()
                break
        expected = base64.b64encode(hashlib.sha1(
            (key + "258EAFA5-E914-47DA-95CA-C5AB0DC85B11").encode("ascii")
        ).digest()).decode("ascii")
        if accept and accept != expected:
            raise OSError("managed app-server websocket accept key mismatch")
        sock.settimeout(None)
        return _CodexAppServerTransport("managed-unix", sock=sock)
    except Exception:
        try:
            sock.close()
        except OSError:
            pass
        raise


def _resolve_codex_bin():
    """Locate a usable Codex CLI binary.

    Priority order:
      1. $CCC_CODEX_BIN (env override) — if set and executable.
      2. `shutil.which("codex")` — picks up Homebrew / Cargo / npm-global.
      3. /Applications/Codex.app/Contents/Resources/codex (macOS Codex
         desktop app's bundled CLI).

    Returns a dict so the caller and the availability endpoint can share
    one shape:
      {available: True,  bin: "<abs path>", source: "env|path|bundle"}
      {available: False, reason: "<human readable>", bin: None}
    """
    env_bin = os.environ.get("CCC_CODEX_BIN")
    if env_bin:
        if os.path.isfile(env_bin) and os.access(env_bin, os.X_OK):
            return {"available": True, "bin": env_bin, "source": "env"}
        return {
            "available": False,
            "bin": None,
            "code": "codex_unavailable",
            "reason": f"CCC_CODEX_BIN is set to {env_bin!r} but it isn't an executable file",
        }
    which_bin = shutil.which("codex")
    if which_bin:
        return {"available": True, "bin": which_bin, "source": "path"}
    if os.path.isfile(CODEX_APP_BUNDLE_PATH) and os.access(CODEX_APP_BUNDLE_PATH, os.X_OK):
        return {"available": True, "bin": CODEX_APP_BUNDLE_PATH, "source": "bundle"}
    return {
        "available": False,
        "bin": None,
        "code": "codex_unavailable",
        "reason": (
            "Codex CLI not found. Install Codex.app, "
            "`npm i -g @openai/codex`, or set CCC_CODEX_BIN."
        ),
    }


def _codex_notification_thread_id(method, params):
    for key in ("threadId", "thread_id", "conversationId", "conversation_id"):
        value = params.get(key) if isinstance(params, dict) else None
        if value:
            return str(value)
    thread = params.get("thread") if isinstance(params, dict) else None
    if isinstance(thread, dict) and thread.get("id"):
        return str(thread["id"])
    turn_id = _codex_notification_turn_id(method, params)
    if turn_id:
        return _CODEX_APP_SERVER_TURN_THREAD.get(turn_id)
    return None


def _codex_notification_turn_id(method, params):
    for key in ("turnId", "turn_id", "expectedTurnId"):
        value = params.get(key) if isinstance(params, dict) else None
        if value:
            return str(value)
    turn = params.get("turn") if isinstance(params, dict) else None
    if isinstance(turn, dict) and turn.get("id"):
        return str(turn["id"])
    item = params.get("item") if isinstance(params, dict) else None
    if isinstance(item, dict):
        for key in ("turnId", "turn_id"):
            if item.get(key):
                return str(item[key])
    return None


def _codex_app_server_request_thread_id(method, params):
    return _codex_notification_thread_id(method, params)


def _codex_app_server_request_turn_id(method, params):
    return _codex_notification_turn_id(method, params)


def _codex_app_server_flag_token(value):
    text = str(value or "").strip()
    if not text:
        return ""
    text = re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", text)
    return re.sub(r"[^a-zA-Z0-9]+", "_", text).strip("_").lower()


def _codex_app_server_flags_need_approval(flags):
    if not isinstance(flags, (list, tuple, set)):
        flags = [flags] if flags else []
    tokens = {_codex_app_server_flag_token(flag) for flag in flags if flag}
    return bool(tokens & {
        "waiting_on_approval",
        "waiting_for_approval",
        "approval_required",
        "approval_requested",
        "needs_approval",
        "requires_approval",
        "permission_required",
        "waiting_on_permission",
    })


def _codex_app_server_status_fields(status_obj):
    if isinstance(status_obj, dict):
        status = status_obj.get("type") or status_obj.get("status") or status_obj.get("state")
        flags = (
            status_obj.get("activeFlags")
            or status_obj.get("active_flags")
            or status_obj.get("flags")
            or []
        )
    else:
        status = status_obj
        flags = []
    if not isinstance(flags, list):
        flags = [flags] if flags else []
    return {
        "status": str(status or ""),
        "active_flags": [str(flag) for flag in flags if flag],
        "thread_needs_approval": _codex_app_server_flags_need_approval(flags),
    }


def _codex_app_server_thread_needs_approval(state):
    if not isinstance(state, dict):
        return False
    if state.get("thread_needs_approval"):
        return True
    return _codex_app_server_flags_need_approval(state.get("active_flags") or [])


def _codex_app_server_thread_approval_message(state):
    if not isinstance(state, dict):
        return "Codex is waiting for approval"
    last_item = state.get("last_item") if isinstance(state.get("last_item"), dict) else {}
    command = (last_item or {}).get("command")
    if command:
        return _codex_app_server_trim_text(
            f"Codex is waiting for approval after: {_shell_command_activity_label(command, max_len=200)}",
            240,
        )
    return "Codex is waiting for approval"


def _codex_app_server_record_thread(thread_id, thread):
    if not thread_id or not isinstance(thread, dict):
        return
    status_fields = _codex_app_server_status_fields(thread.get("status"))
    status = status_fields.get("status")
    state = _CODEX_APP_SERVER_THREAD_STATE.setdefault(thread_id, {})
    previous_turn_id = str(
        state.get("active_turn_id") or state.get("last_turn_id") or ""
    )
    if status:
        state["status"] = status
    state["active_flags"] = status_fields.get("active_flags") or []
    state["thread_needs_approval"] = bool(status_fields.get("thread_needs_approval"))
    state["thread_id"] = thread_id
    state["last_event_at"] = time.time()
    turns = thread.get("turns") or []
    active = _codex_latest_active_turn(thread)
    if active and active.get("id"):
        turn_id = str(active["id"])
        state["active_turn_id"] = turn_id
        state["last_turn_id"] = turn_id
        # A thread/read after CCC restarts is observation, not progress. Keep
        # the persisted activity timestamp when it rediscovers the same turn;
        # otherwise every watcher reconciliation would make a silent turn look
        # newly active and it could sleep forever.
        if previous_turn_id != turn_id or not state.get("last_activity_at"):
            state["last_activity_at"] = state["last_event_at"]
        _CODEX_APP_SERVER_TURN_THREAD[turn_id] = thread_id
    elif str(status or "").lower() == "idle":
        state.pop("active_turn_id", None)
        state.pop("active_writer", None)
        state["thread_needs_approval"] = False
        state["active_flags"] = []
    for turn in turns:
        if isinstance(turn, dict) and turn.get("id"):
            _CODEX_APP_SERVER_TURN_THREAD[str(turn["id"])] = thread_id


def _codex_app_server_trim_text(value, limit=_CODEX_APP_SERVER_ITEM_TEXT_MAX):
    text = value if isinstance(value, str) else ("" if value is None else str(value))
    text = text.strip()
    if len(text) > limit:
        return text[:limit] + "..."
    return text


def _codex_app_server_json_preview(value, limit=240):
    if value in (None, "", [], {}):
        return ""
    if isinstance(value, str):
        return _codex_app_server_trim_text(value, limit)
    try:
        text = json.dumps(value, sort_keys=True, default=str)
    except (TypeError, ValueError):
        text = str(value)
    return _codex_app_server_trim_text(text, limit)


def _codex_app_server_item_id(item, params=None):
    params = params if isinstance(params, dict) else {}
    for value in (params.get("itemId"), params.get("item_id")):
        if value:
            return str(value)
    if isinstance(item, dict):
        for key in ("id", "call_id", "callId"):
            if item.get(key):
                return str(item[key])
    return ""


def _codex_app_server_file_change_detail(changes):
    if not isinstance(changes, list):
        return ""
    parts = []
    for change in changes[:6]:
        if not isinstance(change, dict):
            continue
        path = change.get("path") or change.get("move_path") or ""
        kind = change.get("kind")
        if isinstance(kind, dict):
            kind = kind.get("type")
        kind = str(kind or "update")
        if path:
            parts.append(f"{kind} {path}")
    if len(changes) > 6:
        parts.append(f"+{len(changes) - 6} more")
    return ", ".join(parts)


def _codex_app_server_command_text(command):
    if isinstance(command, list):
        try:
            return shlex.join([str(part) for part in command])
        except Exception:
            return " ".join(str(part) for part in command)
    return "" if command is None else str(command)


def _codex_app_server_file_changes_preview(changes):
    if isinstance(changes, list):
        return _codex_app_server_file_change_detail(changes)
    if not isinstance(changes, dict):
        return ""
    parts = []
    items = list(changes.items())
    for path, change in items[:6]:
        kind = "update"
        if isinstance(change, dict):
            raw_kind = change.get("type") or change.get("kind")
            if isinstance(raw_kind, dict):
                raw_kind = raw_kind.get("type")
            if raw_kind:
                kind = str(raw_kind)
        parts.append(f"{kind} {path}")
    if len(items) > 6:
        parts.append(f"+{len(items) - 6} more")
    return ", ".join(parts)


_CODEX_APP_SERVER_APPROVAL_ITEM_TYPES = {
    "commandExecution",
    "fileChange",
    "mcpToolCall",
    "dynamicToolCall",
    "collabAgentToolCall",
    "permissions",
}
_CODEX_APP_SERVER_COMMAND_APPROVAL_METHODS = {
    "item/commandExecution/requestApproval",
    "execCommandApproval",
}
_CODEX_APP_SERVER_FILE_APPROVAL_METHODS = {
    "item/fileChange/requestApproval",
    "applyPatchApproval",
}
_CODEX_APP_SERVER_PERMISSION_APPROVAL_METHODS = {
    "item/permissions/requestApproval",
}
_CODEX_APP_SERVER_APPROVAL_REQUEST_METHODS = (
    _CODEX_APP_SERVER_COMMAND_APPROVAL_METHODS
    | _CODEX_APP_SERVER_FILE_APPROVAL_METHODS
    | _CODEX_APP_SERVER_PERMISSION_APPROVAL_METHODS
)
_CODEX_APP_SERVER_APPROVAL_STATUSES = {
    "approval_required",
    "approval_requested",
    "awaiting_approval",
    "blocked_on_approval",
    "needs_approval",
    "pending_approval",
    "permission_required",
    "permission_requested",
    "requires_approval",
    "requires_permission",
    "waiting_for_approval",
    "waiting_for_permission",
}
_CODEX_APP_SERVER_APPROVAL_BOOL_KEYS = (
    "approvalRequired",
    "approval_required",
    "requiresApproval",
    "requires_approval",
    "needsApproval",
    "needs_approval",
    "permissionRequired",
    "permission_required",
)
_CODEX_APP_SERVER_APPROVAL_MESSAGE_KEYS = (
    "approvalMessage",
    "approval_message",
    "approvalPrompt",
    "approval_prompt",
    "permissionMessage",
    "permission_message",
    "justification",
    "message",
    "prompt",
    "reason",
)


def _codex_app_server_status_text(value):
    if isinstance(value, dict):
        for key in ("type", "status", "state", "name"):
            if value.get(key):
                return str(value[key])
        return ""
    return str(value or "")


def _codex_app_server_status_token(value):
    text = _codex_app_server_status_text(value).strip()
    if not text:
        return ""
    text = re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", text)
    return re.sub(r"[^a-zA-Z0-9]+", "_", text).strip("_").lower()


def _codex_app_server_truthy_approval_flag(value):
    if isinstance(value, bool):
        return value
    if value is None:
        return False
    if isinstance(value, (int, float)):
        return value != 0
    text = str(value).strip().lower()
    if text in ("", "0", "false", "no", "none", "null", "off"):
        return False
    return True


def _codex_app_server_approval_dicts(item, params=None):
    params = params if isinstance(params, dict) else {}
    for obj in (item, params):
        if not isinstance(obj, dict):
            continue
        yield obj
        for key in ("approval", "permission", "permissions", "confirmation", "sandbox"):
            child = obj.get(key)
            if isinstance(child, dict):
                yield child


def _codex_app_server_item_needs_approval(item, params=None):
    if not isinstance(item, dict):
        item = {}
    params = params if isinstance(params, dict) else {}
    typ = str(item.get("type") or params.get("itemType") or params.get("item_type") or "")
    if typ not in _CODEX_APP_SERVER_APPROVAL_ITEM_TYPES:
        return False
    status = item.get("status") if "status" in item else params.get("status")
    if _codex_app_server_status_token(status) in _CODEX_APP_SERVER_APPROVAL_STATUSES:
        return True
    for obj in _codex_app_server_approval_dicts(item, params):
        for key in _CODEX_APP_SERVER_APPROVAL_BOOL_KEYS:
            if key in obj and _codex_app_server_truthy_approval_flag(obj.get(key)):
                return True
        for key in ("status", "state", "type"):
            if _codex_app_server_status_token(obj.get(key)) in _CODEX_APP_SERVER_APPROVAL_STATUSES:
                return True
    actions = []
    for obj in (item, params):
        if not isinstance(obj, dict):
            continue
        for key in ("commandActions", "actions", "availableActions", "approvalActions"):
            value = obj.get(key)
            if isinstance(value, list):
                actions.extend(value)
    for action in actions:
        if isinstance(action, dict):
            text = " ".join(
                str(action.get(key) or "")
                for key in ("id", "type", "kind", "name", "label")
            ).lower()
        else:
            text = str(action or "").lower()
        if any(marker in text for marker in ("approval", "approve", "permission", "allow command", "deny")):
            return True
    return False


def _codex_app_server_approval_message(item, params=None, fallback=""):
    if not isinstance(item, dict):
        item = {}
    params = params if isinstance(params, dict) else {}
    for obj in _codex_app_server_approval_dicts(item, params):
        for key in _CODEX_APP_SERVER_APPROVAL_MESSAGE_KEYS:
            value = obj.get(key)
            if isinstance(value, str) and value.strip():
                return _codex_app_server_trim_text(value, 240)
    command = item.get("command") or params.get("command")
    if command:
        label = _shell_command_activity_label(command, max_len=220)
        return _codex_app_server_trim_text(f"Approval required for: {label}", 240)
    return _codex_app_server_trim_text(fallback or "Codex is waiting for approval", 240)


def _codex_app_server_item_summary(item, params=None, *, in_flight=None, now=None):
    """Compact a Codex app-server ThreadItem into CCC live-activity fields.

    App-server notifications are faster than rollout JSONL flushes and include
    rich non-JSONL item types. This summary is intentionally small: it drives
    live status UI only; persisted Codex rollout remains the durable transcript.
    """
    if not isinstance(item, dict):
        item = {}
    params = params if isinstance(params, dict) else {}
    typ = str(item.get("type") or params.get("itemType") or params.get("item_type") or "")
    status = item.get("status") or params.get("status") or ""
    item_id = _codex_app_server_item_id(item, params)
    needs_approval = _codex_app_server_item_needs_approval(item, params)
    if in_flight is None:
        in_flight = _codex_app_server_status_token(status) in ("", "inprogress", "in_progress", "running", "pending")
    if needs_approval:
        in_flight = True
    ts_ms = params.get("startedAtMs") or params.get("completedAtMs") or params.get("timestampMs")
    try:
        ts = float(ts_ms) / 1000.0 if ts_ms else float(now if now is not None else time.time())
    except (TypeError, ValueError):
        ts = float(now if now is not None else time.time())

    tool = ""
    detail = ""
    command = ""
    output = ""
    is_error = False

    if typ == "commandExecution":
        tool = "Bash"
        command = item.get("command") or ""
        detail = _shell_command_activity_label(command, max_len=240) if command else ""
        output = item.get("aggregatedOutput") or ""
        is_error = str(status or "").lower() in ("failed", "declined") or item.get("exitCode") not in (None, 0)
    elif typ == "fileChange":
        tool = "apply_patch"
        detail = _codex_app_server_file_change_detail(item.get("changes"))
        output = item.get("output") or ""
        is_error = str(status or "").lower() in ("failed", "declined")
    elif typ == "mcpToolCall":
        tool_name = item.get("tool") or "mcpToolCall"
        server = item.get("server") or ""
        tool = f"{server}.{tool_name}" if server else str(tool_name)
        detail = _codex_app_server_json_preview(item.get("arguments"))
        result = item.get("result")
        output = _codex_app_server_json_preview(result, limit=600)
        is_error = bool(item.get("error")) or str(status or "").lower() in ("failed", "errored")
    elif typ == "dynamicToolCall":
        tool_name = item.get("tool") or "dynamicToolCall"
        namespace = item.get("namespace") or ""
        tool = f"{namespace}.{tool_name}" if namespace else str(tool_name)
        detail = _codex_app_server_json_preview(item.get("arguments"))
        output = _codex_app_server_json_preview(item.get("contentItems"), limit=600)
        is_error = item.get("success") is False or str(status or "").lower() in ("failed", "errored")
    elif typ == "collabAgentToolCall":
        tool = item.get("tool") or "collabAgent"
        detail = _codex_app_server_json_preview(item.get("input") or item.get("arguments"))
        state = item.get("state") if isinstance(item.get("state"), dict) else {}
        output = _codex_app_server_trim_text(state.get("message") or "", 600)
        is_error = str((state.get("status") if state else status) or "").lower() in ("failed", "errored", "notfound")
    elif typ == "webSearch":
        tool = "WebSearch"
        detail = _codex_app_server_json_preview(item.get("action") or item.get("query"))
    elif typ == "imageView":
        tool = "view_image"
        detail = item.get("path") or item.get("url") or item.get("imageUrl") or ""
    elif typ == "imageGeneration":
        tool = "image_gen"
        detail = item.get("prompt") or item.get("description") or ""
    elif typ == "subAgentActivity":
        tool = "Task"
        detail = item.get("message") or item.get("title") or item.get("description") or ""
    elif typ == "agentMessage":
        detail = item.get("text") or ""
    elif typ == "plan":
        tool = "Plan"
        detail = item.get("text") or ""
    elif typ == "reasoning":
        tool = "Thinking"
        summary = item.get("summary") if isinstance(item.get("summary"), list) else []
        detail = " ".join(str(x) for x in summary if x)[:240]
    elif typ:
        tool = typ
        detail = _codex_app_server_json_preview(item)

    summary = {
        "id": item_id,
        "type": typ,
        "tool": _codex_app_server_trim_text(tool, 120),
        "detail": _codex_app_server_trim_text(detail, 240),
        "status": _codex_app_server_status_text(status) or ("approvalRequired" if needs_approval else ("inProgress" if in_flight else "completed")),
        "in_flight": bool(in_flight),
        "ts": ts,
        "updated_at": float(now if now is not None else time.time()),
    }
    if command:
        summary["command"] = _codex_app_server_trim_text(command)
    if output:
        summary["output"] = _codex_app_server_trim_text(output, 600)
    if is_error:
        summary["is_error"] = True
    if needs_approval:
        summary["needs_approval"] = True
        summary["approval_message"] = _codex_app_server_approval_message(item, params, fallback=detail or output)
    return summary


def _codex_app_server_latest_active_item(state):
    active = state.get("active_items") if isinstance(state, dict) else None
    if not isinstance(active, dict) or not active:
        return None
    items = [v for v in active.values() if isinstance(v, dict)]
    if not items:
        return None
    return max(items, key=lambda x: float(x.get("updated_at") or x.get("ts") or 0))


def _codex_app_server_pending_approval_item(state):
    if not isinstance(state, dict):
        return None
    candidates = []
    pending = state.get("pending_approval_request") if isinstance(state.get("pending_approval_request"), dict) else None
    if pending:
        candidates.append(pending)
    active_item = state.get("active_item") if isinstance(state.get("active_item"), dict) else None
    if active_item:
        candidates.append(active_item)
    active_items = state.get("active_items") if isinstance(state.get("active_items"), dict) else {}
    for item in active_items.values():
        if isinstance(item, dict):
            candidates.append(item)
    if state.get("active_turn_id") or str(state.get("status") or "").lower() == "active":
        last_item = state.get("last_item") if isinstance(state.get("last_item"), dict) else None
        if last_item:
            candidates.append(last_item)
    seen = set()
    deduped = []
    for item in candidates:
        key = item.get("id") or id(item)
        if key in seen:
            continue
        seen.add(key)
        deduped.append(item)
    deduped.sort(key=lambda x: float(x.get("updated_at") or x.get("ts") or 0), reverse=True)
    for item in deduped:
        if item.get("needs_approval"):
            return item
    return None


def _codex_app_server_push_recent_item(state, item):
    if not isinstance(state, dict) or not isinstance(item, dict):
        return
    recent = state.setdefault("recent_items", [])
    if not isinstance(recent, list):
        recent = []
        state["recent_items"] = recent
    item_id = item.get("id")
    if item_id:
        recent[:] = [x for x in recent if not (isinstance(x, dict) and x.get("id") == item_id)]
    recent.append(dict(item))
    del recent[:-_CODEX_APP_SERVER_RECENT_ITEM_MAX]


def _codex_app_server_record_item_notification(state, method, params, now):
    item = params.get("item") if isinstance(params.get("item"), dict) else {}
    item_id = _codex_app_server_item_id(item, params)
    active = state.setdefault("active_items", {})
    if not isinstance(active, dict):
        active = {}
        state["active_items"] = active

    if method == "item/started":
        summary = _codex_app_server_item_summary(item, params, in_flight=True, now=now)
        if item_id:
            active[item_id] = summary
        state["active_item"] = summary
        state["last_item"] = summary
        return

    if method == "item/completed":
        summary = _codex_app_server_item_summary(item, params, in_flight=False, now=now)
        if item_id and isinstance(active.get(item_id), dict):
            merged = dict(active[item_id])
            merged.update({k: v for k, v in summary.items() if v not in (None, "", [], {})})
            summary = merged
        if item_id:
            active.pop(item_id, None)
        _codex_app_server_push_recent_item(state, summary)
        state["last_item"] = summary
        latest = _codex_app_server_latest_active_item(state)
        if latest:
            state["active_item"] = latest
        else:
            state.pop("active_item", None)
        return

    if method in ("item/commandExecution/outputDelta", "item/fileChange/outputDelta"):
        delta = params.get("delta") or ""
        if not item_id:
            return
        current = active.get(item_id)
        if not isinstance(current, dict):
            item_type = "fileChange" if method == "item/fileChange/outputDelta" else "commandExecution"
            current = _codex_app_server_item_summary(
                {"id": item_id, "type": item_type, "status": "inProgress"},
                params,
                in_flight=True,
                now=now,
            )
            active[item_id] = current
        current["output"] = _codex_app_server_trim_text((current.get("output") or "") + str(delta), 600)
        current["updated_at"] = now
        state["active_item"] = current
        state["last_item"] = current
        return

    if method == "item/fileChange/patchUpdated":
        changes = params.get("changes")
        if not item_id:
            return
        current = active.get(item_id)
        if not isinstance(current, dict):
            current = _codex_app_server_item_summary(
                {"id": item_id, "type": "fileChange", "status": "inProgress", "changes": changes},
                params,
                in_flight=True,
                now=now,
            )
            active[item_id] = current
        current["detail"] = _codex_app_server_file_change_detail(changes)
        current["updated_at"] = now
        state["active_item"] = current
        state["last_item"] = current


def _codex_compaction_recovery_note_notification_unlocked(
    state, method, params, turn_id, now
):
    """Update the durable post-compaction recovery latch from one notification."""
    item = params.get("item") if isinstance(params.get("item"), dict) else {}
    item_type = str(
        item.get("type") or params.get("itemType") or params.get("item_type") or ""
    )
    recovery = state.get("compaction_recovery")

    if item_type == "contextCompaction" and method in ("item/started", "item/completed"):
        episode_id = _codex_app_server_item_id(item, params)
        if not episode_id and isinstance(recovery, dict) and (
            recovery.get("compaction_in_flight")
            and str(recovery.get("compaction_turn_id") or "") == str(turn_id or "")
        ):
            episode_id = recovery.get("episode_id")
        episode_id = episode_id or f"compaction-{turn_id or int(float(now) * 1000)}"
        if not isinstance(recovery, dict) or recovery.get("episode_id") != episode_id:
            recovery = {
                "episode_id": episode_id,
                "trigger": "compaction",
                "compaction_turn_id": str(turn_id or state.get("active_turn_id") or ""),
                "compacted_at": float(now),
                "last_progress_at": float(now),
                "status": "waiting",
                "attempts": 0,
                "next_attempt_at": float(now) + _CODEX_COMPACTION_RECOVERY_GRACE_S,
                "reason": "Waiting for Codex to continue after compaction",
                "compaction_in_flight": method == "item/started",
                "saw_agent_output": False,
            }
            state["compaction_recovery"] = recovery
            _codex_coordination_event_unlocked(
                state,
                "compaction_recovery_armed",
                detail="Watching for Codex to continue after compaction",
                now=now,
            )
        else:
            recovery["compaction_in_flight"] = method == "item/started"
            recovery["last_progress_at"] = float(now)
        return

    if not isinstance(recovery, dict):
        return
    if str(recovery.get("status") or "") in _CODEX_COMPACTION_RECOVERY_TERMINAL:
        return

    if method == "turn/started":
        if turn_id and str(turn_id) != str(recovery.get("compaction_turn_id") or ""):
            recovery["status"] = "recovering"
            recovery["recovery_turn_id"] = str(turn_id)
            recovery["last_progress_at"] = float(now)
            recovery["reason"] = (
                "Codex continued after the turn went silent"
                if _codex_recovery_is_silent_turn(recovery)
                else "Codex continued after compaction"
            )
            recovery["saw_agent_output"] = False
        return

    if method == "item/agentMessage/delta":
        if str(params.get("delta") or "").strip():
            recovery["saw_agent_output"] = True
            recovery["last_progress_at"] = float(now)
        return

    if method in ("item/started", "item/completed"):
        recovery["last_progress_at"] = float(now)
        if item_type == "agentMessage" and str(item.get("text") or "").strip():
            recovery["saw_agent_output"] = True
        return

    if method.startswith("item/"):
        recovery["last_progress_at"] = float(now)
        return

    if method == "turn/completed":
        relevant_turns = {
            str(recovery.get("compaction_turn_id") or ""),
            str(recovery.get("recovery_turn_id") or ""),
        }
        if turn_id and str(turn_id) not in relevant_turns:
            return
        turn = params.get("turn") if isinstance(params.get("turn"), dict) else {}
        completion_status = _codex_app_server_status_token(
            turn.get("status") or params.get("status")
        )
        interrupted = completion_status in {
            "aborted", "cancelled", "canceled", "failed", "interrupted"
        }
        if recovery.get("saw_agent_output") and not interrupted:
            recovery["status"] = "recovered"
            recovery["reason"] = (
                "Codex produced a final reply after recovering a silent turn"
                if _codex_recovery_is_silent_turn(recovery)
                else "Codex produced a final reply after compaction"
            )
            recovery["recovered_at"] = float(now)
            _codex_coordination_event_unlocked(
                state,
                _codex_recovery_event_kind(recovery, "recovered"),
                detail=recovery["reason"],
                now=now,
            )
        elif int(recovery.get("attempts") or 0) >= _CODEX_COMPACTION_RECOVERY_MAX_ATTEMPTS:
            recovery["status"] = "exhausted"
            recovery["reason"] = (
                "Silent-turn recovery ended without a final reply"
                if _codex_recovery_is_silent_turn(recovery)
                else "Compaction recovery ended without a final reply"
            )
            _codex_coordination_event_unlocked(
                state,
                _codex_recovery_event_kind(recovery, "exhausted"),
                detail=recovery["reason"],
                now=now,
            )
        else:
            recovery["status"] = "waiting"
            recovery["last_progress_at"] = float(now)
            recovery["next_attempt_at"] = float(now) + _CODEX_COMPACTION_RECOVERY_GRACE_S
            recovery["reason"] = (
                "Codex went idle after silent-turn recovery without a final reply"
                if _codex_recovery_is_silent_turn(recovery)
                else "Codex went idle after compaction without a final reply"
            )


def _codex_app_server_approval_request_summary(request_id, method, params, now):
    if not isinstance(params, dict):
        params = {}
    raw_request_id = request_id
    request_id = str(request_id or "").strip()
    approval_id = params.get("approvalId") or params.get("approval_id") or ""
    item_id = (
        params.get("itemId")
        or params.get("item_id")
        or params.get("callId")
        or params.get("call_id")
        or approval_id
        or request_id
    )
    turn_id = _codex_app_server_request_turn_id(method, params) or ""
    try:
        ts = float(params.get("startedAtMs") or 0) / 1000.0
    except (TypeError, ValueError):
        ts = 0.0
    if not ts:
        ts = float(now or time.time())

    tool = "Approval"
    typ = "approval"
    detail = ""
    command = ""
    message = str(params.get("reason") or "").strip()
    can_approve = False

    if method in _CODEX_APP_SERVER_COMMAND_APPROVAL_METHODS:
        typ = "commandExecution"
        tool = "Bash"
        command = _codex_app_server_command_text(params.get("command"))
        detail = _shell_command_activity_label(command, max_len=240) if command else ""
        message = message or (f"Approve command: {detail}" if detail else "Codex is waiting for command approval")
        can_approve = True
    elif method in _CODEX_APP_SERVER_FILE_APPROVAL_METHODS:
        typ = "fileChange"
        tool = "apply_patch"
        detail = (
            _codex_app_server_file_changes_preview(params.get("changes"))
            or _codex_app_server_file_changes_preview(params.get("fileChanges"))
            or str(params.get("grantRoot") or "").strip()
        )
        if params.get("grantRoot") and not message:
            message = f"Approve file writes under {params.get('grantRoot')}"
        message = message or (f"Approve file changes: {detail}" if detail else "Codex is waiting for file-change approval")
        can_approve = True
    elif method in _CODEX_APP_SERVER_PERMISSION_APPROVAL_METHODS:
        typ = "permissions"
        tool = "Permissions"
        permissions = params.get("permissions")
        detail = (
            str(params.get("cwd") or "").strip()
            or _codex_app_server_json_preview(permissions)
        )
        message = message or "Codex is requesting additional permissions"
        can_approve = isinstance(permissions, dict)
    else:
        return None

    summary = {
        "id": str(item_id or request_id),
        "type": typ,
        "tool": tool,
        "detail": _codex_app_server_trim_text(detail, 240),
        "status": "waiting_for_approval",
        "in_flight": True,
        "needs_approval": True,
        "approval_message": _codex_app_server_trim_text(message, 240),
        "request_id": request_id,
        "request_id_raw": raw_request_id,
        "approval_method": method,
        "item_id": str(item_id or ""),
        "turn_id": str(turn_id or ""),
        "approval_id": str(approval_id or ""),
        "can_approve": bool(can_approve),
        "ts": ts,
        "updated_at": float(now or time.time()),
    }
    if command:
        summary["command"] = _codex_app_server_trim_text(command)
    available = params.get("availableDecisions") or params.get("available_decisions")
    if isinstance(available, list):
        summary["available_decisions"] = available
    if method in _CODEX_APP_SERVER_PERMISSION_APPROVAL_METHODS and isinstance(params.get("permissions"), dict):
        summary["requested_permissions"] = params.get("permissions")
    return summary


def _codex_app_server_record_server_request(request_id, method, params):
    global _CODEX_APP_SERVER_EVENT_SEQ
    if not isinstance(params, dict):
        params = {}
    thread_id = _codex_app_server_request_thread_id(method, params)
    turn_id = _codex_app_server_request_turn_id(method, params)
    if thread_id and turn_id:
        _CODEX_APP_SERVER_TURN_THREAD[turn_id] = thread_id
    if not thread_id:
        return False
    if method not in _CODEX_APP_SERVER_APPROVAL_REQUEST_METHODS:
        return False

    _CODEX_APP_SERVER_EVENT_SEQ += 1
    now = time.time()
    state = _CODEX_APP_SERVER_THREAD_STATE.setdefault(thread_id, {})
    state.update({
        "thread_id": thread_id,
        "event_seq": _CODEX_APP_SERVER_EVENT_SEQ,
        "last_event": method,
        "last_event_at": now,
        "last_activity_at": now,
        "status": "active",
        "thread_needs_approval": True,
    })
    if turn_id:
        state["last_turn_id"] = turn_id
        state["active_turn_id"] = turn_id
    flags = [str(flag) for flag in (state.get("active_flags") or []) if flag]
    if "waitingOnApproval" not in flags:
        flags.append("waitingOnApproval")
    state["active_flags"] = flags

    summary = _codex_app_server_approval_request_summary(request_id, method, params, now)
    if summary:
        active = state.setdefault("active_items", {})
        if not isinstance(active, dict):
            active = {}
            state["active_items"] = active
        item_key = summary.get("id") or summary.get("request_id")
        if item_key:
            active[item_key] = summary
        state["pending_approval_request"] = summary
        state["active_item"] = summary
        state["last_item"] = summary
    _save_codex_app_server_state_unlocked()
    try:
        _codex_telemetry_note_notification(method, params, thread_id, turn_id)
    except Exception:
        pass
    return True


def _codex_app_server_handle_server_request(request_id, method, params):
    if method in _CODEX_APP_SERVER_APPROVAL_REQUEST_METHODS:
        return _codex_app_server_record_server_request(request_id, method, params)
    return False


def _codex_app_server_activity_fields(session_id):
    fields = {
        "sidecar_status": None,
        "sidecar_has_writes": False,
        "sidecar_tool": None,
        "sidecar_file": None,
        "sidecar_ts": 0,
        "sidecar_in_flight": False,
        "needs_approval": False,
        "needs_approval_message": "",
    }
    state = _codex_app_server_thread_state(session_id)
    if not state:
        return fields
    approval_item = _codex_app_server_pending_approval_item(state)
    if approval_item:
        message = approval_item.get("approval_message") or approval_item.get("detail") or approval_item.get("output") or ""
        fields.update({
            "sidecar_status": "active",
            "sidecar_has_writes": False,
            "sidecar_tool": approval_item.get("tool") or "Approval",
            "sidecar_file": message,
            "sidecar_ts": approval_item.get("ts") or state.get("last_activity_at") or time.time(),
            "sidecar_in_flight": True,
            "needs_approval": True,
            "needs_approval_message": message or "Codex is waiting for approval",
        })
        return fields
    if _codex_app_server_thread_needs_approval(state):
        message = _codex_app_server_thread_approval_message(state)
        fields.update({
            "sidecar_status": "active",
            "sidecar_has_writes": False,
            "sidecar_tool": "Approval",
            "sidecar_file": message,
            "sidecar_ts": state.get("last_activity_at") or state.get("last_event_at") or time.time(),
            "sidecar_in_flight": True,
            "needs_approval": True,
            "needs_approval_message": message,
        })
        return fields
    recovery = state.get("compaction_recovery")
    recovery_status = str(
        recovery.get("status") if isinstance(recovery, dict) else ""
    )
    if recovery_status in ("interrupting", "recovering"):
        fields.update({
            "sidecar_status": "active",
            "sidecar_has_writes": False,
            "sidecar_tool": "Recovery",
            "sidecar_file": _codex_recovery_activity_text(recovery),
            "sidecar_ts": recovery.get("last_attempt_at") or state.get("last_activity_at") or time.time(),
            "sidecar_in_flight": True,
        })
        return fields
    status = str(state.get("status") or "").lower()
    active = bool(state.get("active_turn_id") or status == "active")
    if not active:
        return fields
    item = state.get("active_item") if isinstance(state.get("active_item"), dict) else None
    if item and item.get("tool") and item.get("tool") != "Thinking":
        fields.update({
            "sidecar_status": "active",
            "sidecar_has_writes": False,
            "sidecar_tool": item.get("tool"),
            "sidecar_file": item.get("detail") or item.get("output") or "",
            "sidecar_ts": item.get("ts") or state.get("last_activity_at") or time.time(),
            "sidecar_in_flight": bool(item.get("in_flight", True)),
        })
        return fields
    fields.update({
        "sidecar_status": "active",
        "sidecar_tool": "Thinking",
        "sidecar_file": (item or {}).get("detail") or "",
        "sidecar_ts": state.get("last_activity_at") or state.get("last_event_at") or time.time(),
        "sidecar_in_flight": True,
    })
    return fields


def _codex_app_server_handle_notification(method, params):
    global _CODEX_APP_SERVER_EVENT_SEQ
    if not isinstance(params, dict):
        params = {}
    thread = params.get("thread") if isinstance(params.get("thread"), dict) else None
    thread_id = _codex_notification_thread_id(method, params)
    turn_id = _codex_notification_turn_id(method, params)
    if thread_id and turn_id:
        _CODEX_APP_SERVER_TURN_THREAD[turn_id] = thread_id
    if thread and not thread_id and thread.get("id"):
        thread_id = str(thread["id"])
    if not thread_id:
        return
    pump_after_notification = False
    delivered_user_text = None
    _CODEX_APP_SERVER_EVENT_SEQ += 1
    now = time.time()
    state = _CODEX_APP_SERVER_THREAD_STATE.setdefault(thread_id, {})
    state.update({
        "thread_id": thread_id,
        "event_seq": _CODEX_APP_SERVER_EVENT_SEQ,
        "last_event": method,
        "last_event_at": now,
    })
    if turn_id:
        state["last_turn_id"] = turn_id
    if thread:
        _codex_app_server_record_thread(thread_id, thread)
    if method == "thread/status/changed":
        status_fields = _codex_app_server_status_fields(params.get("status"))
        status = status_fields.get("status")
        if status:
            state["status"] = str(status)
            state["active_flags"] = status_fields.get("active_flags") or []
            state["thread_needs_approval"] = bool(status_fields.get("thread_needs_approval"))
            if str(status).lower() == "idle":
                pump_after_notification = True
                state.pop("active_turn_id", None)
                state.pop("active_writer", None)
                state.pop("active_item", None)
                state.pop("active_items", None)
                state["thread_needs_approval"] = False
                state["active_flags"] = []
    elif method == "thread/settings/updated":
        settings = params.get("threadSettings") or params.get("thread_settings")
        if isinstance(settings, dict):
            state["thread_settings"] = settings
    elif method == "turn/started":
        known_ccc_turn = bool(
            state.get("active_writer") == "ccc"
            and turn_id
            and str(state.get("active_turn_id") or "") == str(turn_id)
        )
        if turn_id:
            state["active_turn_id"] = turn_id
            state["last_activity_at"] = now
        # A notification without our transient start marker proves that a turn
        # is active, but not who started it. This commonly happens when CCC
        # reconnects after a restart while its own earlier turn is still
        # running. Treat unproven ownership as unknown; the writer gate still
        # serializes behind it.
        writer = "ccc" if state.get("ccc_turn_start_pending") or known_ccc_turn else "unknown"
        state["active_writer"] = writer
        state["active_items"] = {}
        state.pop("active_item", None)
        state["status"] = "active"
        _codex_coordination_event_unlocked(
            state,
            "ccc_turn_started" if writer == "ccc" else "external_turn_started",
            writer=writer,
            now=now,
        )
    elif method in (
        "item/started",
        "item/completed",
        "item/agentMessage/delta",
        "item/commandExecution/outputDelta",
        "item/fileChange/patchUpdated",
        "item/fileChange/outputDelta",
        "item/mcpToolCall/progress",
        "item/reasoning/summaryTextDelta",
        "item/reasoning/summaryPartAdded",
        "item/reasoning/textDelta",
        "item/plan/delta",
        "thread/tokenUsage/updated",
    ):
        # A command can outlive its Codex turn and keep emitting output after
        # turn/completed. Those late deltas are process output, not evidence of
        # a new turn; accepting them resurrected idle threads as "Thinking".
        # A genuine new turn always arrives through turn/started first.
        late_completed_turn = bool(
            turn_id
            and str(state.get("last_completed_turn_id") or "") == str(turn_id)
            and not state.get("active_turn_id")
        )
        if not late_completed_turn:
            state["last_activity_at"] = now
            if turn_id:
                state["active_turn_id"] = turn_id
        if method == "thread/tokenUsage/updated":
            usage = params.get("tokenUsage") or params.get("token_usage") or params.get("usage")
            if isinstance(usage, dict):
                state["token_usage"] = usage
        elif not late_completed_turn and method in (
            "item/started",
            "item/completed",
            "item/commandExecution/outputDelta",
            "item/fileChange/patchUpdated",
            "item/fileChange/outputDelta",
        ):
            _codex_app_server_record_item_notification(state, method, params, now)
            item = params.get("item") if isinstance(params.get("item"), dict) else {}
            if method == "item/completed" and item.get("type") == "userMessage":
                delivered_user_text = str(item.get("text") or "").strip()
                if delivered_user_text:
                    state["last_delivered_user_text"] = delivered_user_text
                    state["last_delivered_user_turn_id"] = str(turn_id or "")
                    state["last_delivered_user_at"] = now
    elif method == "turn/completed":
        pump_after_notification = True
        completed_writer = str(state.get("active_writer") or "external")
        state["last_activity_at"] = now
        state["last_completed_turn_id"] = turn_id
        if not turn_id or state.get("active_turn_id") == turn_id:
            state.pop("active_turn_id", None)
            state.pop("active_writer", None)
        state.pop("active_item", None)
        state.pop("active_items", None)
        state["status"] = "idle"
        _codex_coordination_event_unlocked(
            state,
            "ccc_turn_completed" if completed_writer == "ccc" else "external_turn_completed",
            writer=completed_writer,
            now=now,
        )
    _codex_compaction_recovery_note_notification_unlocked(
        state, method, params, turn_id, now
    )
    _save_codex_app_server_state_unlocked()
    try:
        _codex_telemetry_note_notification(method, params, thread_id, turn_id)
    except Exception:
        pass
    if delivered_user_text:
        # The app-server's userMessage item is the authoritative delivery ack.
        # Reconcile any durable copy left queued by an unconfirmed/phantom-owner
        # attempt; duplicate prompts remain valid because only one copy is
        # consumed.
        _consume_matching_pending_input(thread_id, delivered_user_text)
    if pump_after_notification:
        _schedule_codex_queue_pump(thread_id)


def _codex_app_server_handle_message(payload):
    if not isinstance(payload, dict):
        return
    with _CODEX_APP_SERVER_LOCK:
        method = payload.get("method")
        if "id" in payload and method:
            _codex_app_server_handle_server_request(
                payload.get("id"),
                str(method),
                payload.get("params") or {},
            )
            _CODEX_APP_SERVER_LOCK.notify_all()
            return
        if "id" in payload:
            result = payload.get("result")
            if isinstance(result, dict):
                thread = result.get("thread")
                if isinstance(thread, dict) and thread.get("id"):
                    _codex_app_server_record_thread(str(thread["id"]), thread)
                    _save_codex_app_server_state_unlocked()
            _CODEX_APP_SERVER_RESPONSES[payload.get("id")] = payload
            _CODEX_APP_SERVER_LOCK.notify_all()
            return
        if method:
            _codex_app_server_handle_notification(str(method), payload.get("params") or {})
            _CODEX_APP_SERVER_LOCK.notify_all()


def _codex_app_server_thread_state(session_id):
    if not session_id:
        return {}
    with _CODEX_APP_SERVER_LOCK:
        return dict(_CODEX_APP_SERVER_THREAD_STATE.get(session_id) or {})


def _codex_app_server_int(value):
    if value is None:
        return None
    if isinstance(value, bool):
        return int(value)
    try:
        return int(value)
    except (TypeError, ValueError):
        return None


def _codex_app_server_pick_int(obj, *keys):
    if not isinstance(obj, dict):
        return None
    for key in keys:
        value = _codex_app_server_int(obj.get(key))
        if value is not None:
            return value
    return None


def _codex_app_server_token_breakdown_public(raw):
    if not isinstance(raw, dict):
        raw = {}
    input_tokens = _codex_app_server_pick_int(raw, "input_tokens", "inputTokens", "input")
    cached_input_tokens = _codex_app_server_pick_int(
        raw,
        "cached_input_tokens",
        "cachedInputTokens",
        "cache_read_input_tokens",
        "cacheReadInputTokens",
        "cached",
    )
    output_tokens = _codex_app_server_pick_int(raw, "output_tokens", "outputTokens", "output")
    reasoning_output_tokens = _codex_app_server_pick_int(
        raw,
        "reasoning_output_tokens",
        "reasoningOutputTokens",
        "reasoning",
    )
    total_tokens = _codex_app_server_pick_int(raw, "total_tokens", "totalTokens", "total")
    if total_tokens is None:
        total_tokens = (input_tokens or 0) + (output_tokens or 0)
    return {
        "input_tokens": input_tokens or 0,
        "cached_input_tokens": cached_input_tokens or 0,
        "output_tokens": output_tokens or 0,
        "reasoning_output_tokens": reasoning_output_tokens or 0,
        "total_tokens": total_tokens or 0,
    }


def _codex_app_server_token_usage_public(raw):
    if not isinstance(raw, dict) or not raw:
        return None
    last_raw = raw.get("last") or raw.get("last_token_usage") or raw.get("lastTokenUsage")
    total_raw = raw.get("total") or raw.get("total_token_usage") or raw.get("totalTokenUsage")
    if not isinstance(last_raw, dict):
        last_raw = {}
    if not isinstance(total_raw, dict):
        total_raw = raw
    last = _codex_app_server_token_breakdown_public(last_raw)
    total = _codex_app_server_token_breakdown_public(total_raw)
    context_limit = _codex_app_server_pick_int(
        raw,
        "modelContextWindow",
        "model_context_window",
        "context_limit",
        "contextLimit",
    )
    used_percent = None
    if context_limit and context_limit > 0:
        used_percent = round((total.get("total_tokens") or 0) * 100.0 / context_limit, 1)
    public = dict(total)
    public.update({
        "context_limit": context_limit or 0,
        "used_percent": used_percent,
        "last": last,
        "total": total,
    })
    return public


def _codex_app_server_item_public(item):
    if not isinstance(item, dict) or not item:
        return None
    public = {}
    for key in (
        "id",
        "type",
        "tool",
        "detail",
        "status",
        "command",
        "output",
        "approval_message",
        "request_id",
        "approval_method",
        "approval_id",
        "turn_id",
        "item_id",
    ):
        value = item.get(key)
        if value not in (None, "", [], {}):
            public[key] = value
    for key in ("in_flight", "needs_approval", "is_error", "can_approve"):
        if key in item:
            public[key] = bool(item.get(key))
    available = item.get("available_decisions")
    if isinstance(available, list):
        public["available_decisions"] = available
    for key in ("ts", "updated_at"):
        try:
            public[key] = float(item.get(key) or 0)
        except (TypeError, ValueError):
            public[key] = 0
    return public or None


def _codex_app_server_active_item_public(state):
    if not isinstance(state, dict) or not state:
        return None
    approval_item = _codex_app_server_pending_approval_item(state)
    if approval_item:
        return _codex_app_server_item_public(approval_item)
    active_item = state.get("active_item") if isinstance(state.get("active_item"), dict) else None
    if active_item:
        return _codex_app_server_item_public(active_item)
    latest = _codex_app_server_latest_active_item(state)
    if latest:
        return _codex_app_server_item_public(latest)
    status = str(state.get("status") or "").lower()
    if state.get("active_turn_id") or status == "active":
        ts = state.get("last_activity_at") or state.get("last_event_at") or time.time()
        return {
            "id": "",
            "type": "reasoning",
            "tool": "Thinking",
            "detail": "",
            "status": "inProgress",
            "in_flight": True,
            "needs_approval": False,
            "ts": float(ts or 0),
            "updated_at": float(ts or 0),
        }
    return None


def _codex_app_server_thread_public_status(session_id):
    """Small status payload for UI polling; no transcript/file reads."""
    state = _codex_app_server_thread_state(session_id)
    if not state:
        return {
            "event_seq": 0,
            "last_activity_at": 0,
            "last_event_at": 0,
            "last_item_id": "",
            "active_item": None,
            "token_usage": None,
            "compaction_recovery": None,
        }
    last_item = state.get("last_item") if isinstance(state.get("last_item"), dict) else {}
    active_item = _codex_app_server_active_item_public(state)
    item = active_item or last_item
    return {
        "event_seq": int(state.get("event_seq") or 0),
        "last_activity_at": float(state.get("last_activity_at") or 0),
        "last_event_at": float(state.get("last_event_at") or 0),
        "last_item_id": str((item or {}).get("id") or ""),
        "active_item": active_item,
        "token_usage": _codex_app_server_token_usage_public(state.get("token_usage")),
        "compaction_recovery": (
            dict(state.get("compaction_recovery"))
            if isinstance(state.get("compaction_recovery"), dict)
            else None
        ),
    }


def _codex_app_server_reader(transport):
    """Collect JSON-RPC responses and notifications from Codex app-server."""
    global _CODEX_APP_SERVER_PROC, _CODEX_APP_SERVER_TRANSPORT
    global _CODEX_APP_SERVER_INITIALIZED, _CODEX_APP_SERVER_INITIALIZING
    try:
        if transport.kind == "stdio":
            for line in transport.proc.stdout:
                line = (line or "").strip()
                if not line:
                    continue
                try:
                    payload = json.loads(line)
                except json.JSONDecodeError:
                    continue
                _codex_app_server_handle_message(payload)
        else:
            while True:
                try:
                    message = _websocket_recv_text(transport.sock)
                except OSError:
                    break
                try:
                    payload = json.loads(message)
                except json.JSONDecodeError:
                    continue
                _codex_app_server_handle_message(payload)
    finally:
        with _CODEX_APP_SERVER_LOCK:
            if _CODEX_APP_SERVER_TRANSPORT is transport:
                _CODEX_APP_SERVER_TRANSPORT = None
                _CODEX_APP_SERVER_PROC = None
                _CODEX_APP_SERVER_INITIALIZED = False
                _CODEX_APP_SERVER_INITIALIZING = False
            _CODEX_APP_SERVER_LOCK.notify_all()


def _codex_app_server_request_to_transport(transport, method, params=None, timeout=20):
    """Send one JSON-RPC request to an already-started Codex app-server."""
    with _CODEX_APP_SERVER_LOCK:
        global _CODEX_APP_SERVER_NEXT_ID
        req_id = _CODEX_APP_SERVER_NEXT_ID
        _CODEX_APP_SERVER_NEXT_ID += 1
        try:
            transport.send_json({
                "jsonrpc": "2.0",
                "id": req_id,
                "method": method,
                "params": params or {},
            })
        except (BrokenPipeError, OSError) as e:
            return {"ok": False, "error": str(e), "fallback": "exec"}

        deadline = time.time() + timeout
        while time.time() < deadline:
            response = _CODEX_APP_SERVER_RESPONSES.pop(req_id, None)
            if response is not None:
                return response
            remaining = max(0.05, deadline - time.time())
            _CODEX_APP_SERVER_LOCK.wait(min(0.5, remaining))
        return {
            "ok": False,
            "error": f"Codex app-server request timed out: {method}",
            "fallback": "exec",
        }


def _codex_app_server_request_to_proc(proc, method, params=None, timeout=20):
    return _codex_app_server_request_to_transport(
        _CodexAppServerTransport("stdio", proc=proc),
        method,
        params=params,
        timeout=timeout,
    )


def _codex_context_window_args():
    """Opt every Codex invocation into the model's full context window.

    Codex CLAMPS `model_context_window` to the model's advertised
    `max_context_window`, so passing 1M is a safe "give me the max" request, not
    a foot-gun — it is silently capped per model:
      - gpt-5.4: 272K default, 1M max -> reports ~950K effective context.
      - gpt-5.5: 272K max -> clamped to ~258K after reserved output/system
        tokens. CCC still defaults Codex spawns to gpt-5.5 because it is the
        stronger general model; choose gpt-5.4 explicitly when the larger
        window matters more than the 5.5 model quality.
    Passed as a global `-c` override on spawn, resume, and the app-server so the
    window is consistent across a session's whole life. Set CCC_CODEX_CONTEXT_1M=0
    to fall back to the model default.
    """
    if not _codex_context_1m_enabled():
        return []
    return ["-c", "model_context_window=1000000"]


def _codex_app_server_request(method, params=None, timeout=20):
    """Send one JSON-RPC request to Codex app-server.

    The app-server is the only local Codex interface that can append input to
    a loaded thread; `codex exec resume` can only start a one-shot process.
    """
    params = params or {}
    thread_id = _codex_app_server_request_thread_id(method, params)
    if method == "turn/start" and thread_id:
        with _CODEX_APP_SERVER_LOCK:
            state = _CODEX_APP_SERVER_THREAD_STATE.setdefault(thread_id, {})
            state["ccc_turn_start_pending"] = True
            state["ccc_turn_start_pending_at"] = time.time()
    transport = _ensure_codex_app_server()
    if transport is None:
        if method == "turn/start" and thread_id:
            with _CODEX_APP_SERVER_LOCK:
                state = _CODEX_APP_SERVER_THREAD_STATE.setdefault(thread_id, {})
                state.pop("ccc_turn_start_pending", None)
                state.pop("ccc_turn_start_pending_at", None)
        return {
            "ok": False,
            "error": "Codex app-server is unavailable",
            "fallback": "exec",
        }
    response = _codex_app_server_request_to_transport(
        transport, method, params=params, timeout=timeout,
    )
    if method == "turn/start" and thread_id:
        with _CODEX_APP_SERVER_LOCK:
            state = _CODEX_APP_SERVER_THREAD_STATE.setdefault(thread_id, {})
            state.pop("ccc_turn_start_pending", None)
            state.pop("ccc_turn_start_pending_at", None)
            if _codex_response_succeeded(response):
                turn = ((response.get("result") or {}).get("turn") or {})
                turn_id = str(turn.get("id") or "").strip()
                if turn_id:
                    state["active_turn_id"] = turn_id
                    state["active_writer"] = "ccc"
                    _CODEX_APP_SERVER_TURN_THREAD[turn_id] = thread_id
    return response


def _codex_app_server_refresh_thread_status(session_id, *, max_age=2.0):
    """Refresh app-server thread status flags from `thread/list`.

    Some approval blockers only appear as thread-level `activeFlags` such as
    `waitingOnApproval`; no item/started notification is emitted. Refreshing the
    compact thread list lets CCC match Codex mobile/desktop status without
    loading the full rollout or starting a turn.
    """
    if not session_id:
        return False
    now = time.time()
    with _CODEX_APP_SERVER_LOCK:
        state = _CODEX_APP_SERVER_THREAD_STATE.setdefault(str(session_id), {})
        try:
            last = float(state.get("thread_status_refreshed_at") or 0)
        except (TypeError, ValueError):
            last = 0.0
        if now - last < max_age:
            return False
        state["thread_status_refreshed_at"] = now
    try:
        response = _codex_app_server_request("thread/list", {}, timeout=3)
    except Exception:
        return False
    data = ((response or {}).get("result") or {}).get("data")
    if not isinstance(data, list):
        return False
    changed = False
    with _CODEX_APP_SERVER_LOCK:
        for thread in data:
            if not isinstance(thread, dict) or not thread.get("id"):
                continue
            _codex_app_server_record_thread(str(thread["id"]), thread)
            if str(thread["id"]) == str(session_id):
                changed = True
        if changed:
            _save_codex_app_server_state_unlocked()
    return changed


def _ensure_codex_app_server(*, allow_stdio=True):
    """Start and initialize a persistent Codex app-server if needed."""
    global _CODEX_APP_SERVER_PROC, _CODEX_APP_SERVER_TRANSPORT, _CODEX_APP_SERVER_READER
    global _CODEX_APP_SERVER_INITIALIZED, _CODEX_APP_SERVER_INITIALIZING
    with _CODEX_APP_SERVER_LOCK:
        while _CODEX_APP_SERVER_INITIALIZING:
            _CODEX_APP_SERVER_LOCK.wait(0.5)
            transport = _CODEX_APP_SERVER_TRANSPORT
            if transport is not None and transport.alive() and _CODEX_APP_SERVER_INITIALIZED:
                return transport
            if not _CODEX_APP_SERVER_INITIALIZING:
                break
        transport = _CODEX_APP_SERVER_TRANSPORT
        if transport is not None and transport.alive() and _CODEX_APP_SERVER_INITIALIZED:
            return transport
        if transport is not None:
            transport.close()
        _CODEX_APP_SERVER_PROC = None
        _CODEX_APP_SERVER_TRANSPORT = None
        _CODEX_APP_SERVER_INITIALIZED = False
        _CODEX_APP_SERVER_INITIALIZING = True

    candidates = []
    managed_path = _codex_managed_app_server_socket_path()
    if _codex_managed_app_server_enabled() and managed_path.exists():
        candidates.append(("managed-unix", managed_path))
    if allow_stdio:
        candidates.append(("stdio", None))

    for kind, arg in candidates:
        transport = None
        proc = None
        if kind == "managed-unix":
            try:
                transport = _connect_codex_managed_app_server(arg)
            except (OSError, socket.timeout):
                transport = None
        else:
            resolved = _resolve_codex_bin()
            if not resolved.get("available"):
                continue
            try:
                proc = subprocess.Popen(
                    [resolved["bin"], *_codex_context_window_args(), "app-server", "--listen", "stdio://"],
                    stdin=subprocess.PIPE,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.DEVNULL,
                    text=True,
                    bufsize=1,
                    start_new_session=True,
                )
                transport = _CodexAppServerTransport("stdio", proc=proc)
            except (FileNotFoundError, OSError):
                transport = None
        if transport is None:
            continue
        with _CODEX_APP_SERVER_LOCK:
            _CODEX_APP_SERVER_PROC = proc
            _CODEX_APP_SERVER_TRANSPORT = transport
            _CODEX_APP_SERVER_INITIALIZING = True
            _CODEX_APP_SERVER_READER = threading.Thread(
                target=_codex_app_server_reader,
                args=(transport,),
                daemon=True,
                name=f"codex-app-server-reader-{kind}",
            )
            _CODEX_APP_SERVER_READER.start()

        init = _codex_app_server_request_to_transport(
            transport,
            "initialize",
            {
                "clientInfo": {
                    "name": "claude-command-center",
                    "title": "Claude Command Center",
                    "version": __version__,
                },
                "capabilities": {"experimentalApi": True},
            },
            timeout=10,
        )
        if init.get("result") is not None:
            try:
                transport.send_json({"jsonrpc": "2.0", "method": "initialized", "params": {}})
            except (BrokenPipeError, OSError):
                pass
            with _CODEX_APP_SERVER_LOCK:
                if _CODEX_APP_SERVER_TRANSPORT is transport and transport.alive():
                    _CODEX_APP_SERVER_INITIALIZED = True
                    _CODEX_APP_SERVER_INITIALIZING = False
                    _CODEX_APP_SERVER_LOCK.notify_all()
                    return transport
        transport.close()
        with _CODEX_APP_SERVER_LOCK:
            if _CODEX_APP_SERVER_TRANSPORT is transport:
                _CODEX_APP_SERVER_TRANSPORT = None
                _CODEX_APP_SERVER_PROC = None
                _CODEX_APP_SERVER_INITIALIZED = False
            _CODEX_APP_SERVER_LOCK.notify_all()

    with _CODEX_APP_SERVER_LOCK:
        _CODEX_APP_SERVER_INITIALIZING = False
        _CODEX_APP_SERVER_LOCK.notify_all()
    return None


def _codex_app_server_shutdown():
    """Close CCC's Codex app-server transport on server exit."""
    global _CODEX_APP_SERVER_PROC, _CODEX_APP_SERVER_TRANSPORT
    global _CODEX_APP_SERVER_INITIALIZED, _CODEX_APP_SERVER_INITIALIZING
    with _CODEX_APP_SERVER_LOCK:
        transport = _CODEX_APP_SERVER_TRANSPORT
        _CODEX_APP_SERVER_PROC = None
        _CODEX_APP_SERVER_TRANSPORT = None
        _CODEX_APP_SERVER_INITIALIZED = False
        _CODEX_APP_SERVER_INITIALIZING = False
        _CODEX_APP_SERVER_LOCK.notify_all()
    if transport is not None:
        transport.close()


def _codex_app_server_is_live():
    """True iff CCC has a live initialized Codex app-server transport.

    This may be the managed Unix-socket app-server or CCC's fallback stdio
    subprocess. Read-only: it does NOT start the server, so polling stays cheap.
    """
    transport = _CODEX_APP_SERVER_TRANSPORT
    return bool(
        transport is not None
        and transport.alive()
        and _CODEX_APP_SERVER_INITIALIZED
    )


def _codex_app_server_transport_kind():
    """Return the active app-server transport label for UI/status surfaces."""
    transport = _CODEX_APP_SERVER_TRANSPORT
    if not (
        transport is not None
        and transport.alive()
        and _CODEX_APP_SERVER_INITIALIZED
    ):
        return None
    if transport.kind == "managed-unix":
        return "managed"
    if transport.kind == "stdio":
        return "stdio"
    return transport.kind


def _schedule_codex_managed_app_server_warmup():
    """Kick managed app-server attach in the background, never on a poll path."""
    global _CODEX_APP_SERVER_WARMUP_LAST
    if _codex_app_server_is_live():
        return False
    if not _codex_managed_app_server_enabled():
        return False
    try:
        if not _codex_managed_app_server_socket_path().exists():
            return False
    except Exception:
        return False
    with _CODEX_APP_SERVER_LOCK:
        if _CODEX_APP_SERVER_INITIALIZING:
            return False
    now = time.time()
    with _CODEX_APP_SERVER_WARMUP_LOCK:
        if now - _CODEX_APP_SERVER_WARMUP_LAST < 2.0:
            return False
        _CODEX_APP_SERVER_WARMUP_LAST = now

    def _warm():
        try:
            _ensure_codex_app_server(allow_stdio=False)
        except Exception:
            pass

    threading.Thread(
        target=_warm,
        daemon=True,
        name="codex-managed-app-server-warmup",
    ).start()
    return True


def _codex_user_input(text, image_paths=None):
    items = [{"type": "text", "text": str(text or "")}]
    for image_path in image_paths or []:
        if image_path:
            items.append({"type": "localImage", "path": str(image_path)})
    return items


def _codex_latest_active_turn(thread):
    turns = (thread or {}).get("turns") or []
    for turn in reversed(turns):
        if isinstance(turn, dict) and turn.get("status") == "inProgress" and turn.get("id"):
            return turn
    return None


def _codex_error_text(response):
    if not isinstance(response, dict):
        return "Codex app-server returned no response"
    err = response.get("error")
    if not isinstance(err, dict):
        return ""
    message = str(err.get("message") or "Codex app-server request failed")
    data = err.get("data")
    if data is not None:
        return f"{message}: {data}"
    return message


def _codex_error_is_not_steerable(response):
    text = _codex_error_text(response)
    return "activeTurnNotSteerable" in text or "not steerable" in text.lower()


def _codex_response_succeeded(response):
    return isinstance(response, dict) and "result" in response and not response.get("error")


def _codex_rollout_stat(session_id):
    try:
        path = _resolve_codex_rollout_path(session_id)
        if not path:
            return None
        st = Path(path).stat()
        return {"path": str(path), "size": st.st_size, "mtime_ns": st.st_mtime_ns}
    except OSError:
        return None


def _codex_rollout_grew(before, session_id):
    if not before:
        return False
    after = _codex_rollout_stat(session_id)
    if not after or after.get("path") != before.get("path"):
        return False
    return (
        int(after.get("size") or 0) > int(before.get("size") or 0)
        or int(after.get("mtime_ns") or 0) > int(before.get("mtime_ns") or 0)
    )


def _codex_rollout_contains_user_text_since(baseline, session_id, text):
    """True when an authoritative user-message row landed after `baseline`."""
    expected = _strip_ccc_session_state_instruction(str(text or "")).strip()
    if not expected:
        return True
    current = _codex_rollout_stat(session_id)
    if not current:
        return False
    path = current.get("path")
    offset = 0
    if baseline and baseline.get("path") == path:
        offset = max(0, int(baseline.get("size") or 0))
    try:
        with open(path, "rb") as fh:
            fh.seek(offset)
            for raw in fh:
                try:
                    event = json.loads(raw)
                except (json.JSONDecodeError, UnicodeDecodeError):
                    continue
                payload = event.get("payload") if isinstance(event.get("payload"), dict) else {}
                if event.get("type") != "event_msg" or payload.get("type") != "user_message":
                    continue
                actual = _strip_ccc_session_state_instruction(
                    str(payload.get("message") or "")
                ).strip()
                if actual == expected:
                    return True
    except OSError:
        return False
    return False


def _codex_wait_for_turn_activity(session_id, turn_id=None, *, baseline_state=None,
                                  baseline_rollout=None, expected_text=None,
                                  timeout=5.0):
    """Confirm that an accepted turn durably recorded its exact user input."""
    baseline_state = baseline_state or {}
    baseline_seq = int(baseline_state.get("event_seq") or 0)
    expected = _strip_ccc_session_state_instruction(str(expected_text or "")).strip()
    deadline = time.time() + max(0.0, float(timeout))
    while True:
        with _CODEX_APP_SERVER_LOCK:
            state = dict(_CODEX_APP_SERVER_THREAD_STATE.get(session_id) or {})
            seq = int(state.get("event_seq") or 0)
            state_turn = state.get("active_turn_id") or state.get("last_turn_id") or state.get("last_completed_turn_id")
            delivered_text = str(state.get("last_delivered_user_text") or "").strip()
            delivered_turn = state.get("last_delivered_user_turn_id")
            if expected and seq > baseline_seq and delivered_text == expected and (
                not turn_id or str(delivered_turn or "") == str(turn_id)
            ):
                return {"confirmed": True, "source": "app-server-notification", "state": state}
            if not expected and seq > baseline_seq and (not turn_id or state_turn == turn_id):
                return {"confirmed": True, "source": "app-server-notification", "state": state}
            if not expected and turn_id and state.get("last_completed_turn_id") == turn_id:
                return {"confirmed": True, "source": "app-server-notification", "state": state}
            remaining = deadline - time.time()
            if remaining <= 0:
                break
            _CODEX_APP_SERVER_LOCK.wait(min(0.25, remaining))
        if expected and _codex_rollout_contains_user_text_since(
            baseline_rollout, session_id, expected
        ):
            return {"confirmed": True, "source": "rollout-user-message", "state": _codex_app_server_thread_state(session_id)}
        if not expected and _codex_rollout_grew(baseline_rollout, session_id):
            return {"confirmed": True, "source": "rollout-growth", "state": _codex_app_server_thread_state(session_id)}
    if expected and _codex_rollout_contains_user_text_since(
        baseline_rollout, session_id, expected
    ):
        return {"confirmed": True, "source": "rollout-user-message", "state": _codex_app_server_thread_state(session_id)}
    if not expected and _codex_rollout_grew(baseline_rollout, session_id):
        return {"confirmed": True, "source": "rollout-growth", "state": _codex_app_server_thread_state(session_id)}
    return {
        "confirmed": False,
        "source": None,
        "state": _codex_app_server_thread_state(session_id),
        "warning": "turn accepted but no app-server events observed",
    }


def _codex_reconcile_thread_idle(session_id):
    """Clear volatile ownership after Codex authoritatively reports idle."""
    cleared_phantom = False
    with _CODEX_APP_SERVER_LOCK:
        state = _CODEX_APP_SERVER_THREAD_STATE.setdefault(str(session_id), {})
        previous_status = str(state.get("status") or "").lower()
        previous_turn_id = str(state.get("active_turn_id") or "").strip()
        previous_writer = str(state.get("active_writer") or "").strip()
        previous_item = (
            state.get("active_item")
            if isinstance(state.get("active_item"), dict)
            else {}
        )
        previous_tool = str(
            previous_item.get("tool") or previous_item.get("type") or ""
        ).strip()
        cleared_phantom = bool(
            previous_turn_id
            or previous_writer
            or previous_status == "active"
        )
        changed = bool(
            cleared_phantom
            or previous_status != "idle"
            or state.get("active_item")
            or state.get("active_items")
        )
        state["status"] = "idle"
        state.pop("active_turn_id", None)
        state.pop("active_writer", None)
        state.pop("active_item", None)
        state.pop("active_items", None)
        if cleared_phantom:
            evidence = []
            if previous_writer:
                evidence.append(f"writer={previous_writer}")
            if previous_turn_id:
                evidence.append(f"turn={previous_turn_id}")
            if previous_tool:
                evidence.append(f"stale item={previous_tool}")
            evidence_text = f"; cleared {', '.join(evidence)}" if evidence else ""
            _codex_coordination_event_unlocked(
                state,
                "external_turn_ended",
                detail=(
                    "Codex re-read found no live turn"
                    f"{evidence_text}; queued input may proceed"
                ),
            )
        if changed:
            _save_codex_app_server_state_unlocked()
    if cleared_phantom:
        _schedule_codex_queue_pump(session_id)
    return cleared_phantom


def _codex_app_server_thread_is_active(session_id, *, start_if_needed=False):
    """Best-effort read of whether CCC's live Codex app-server has an active turn.

    This deliberately does not start the app-server; it is used by the durable
    pending-input watcher to avoid popping and requeueing Codex messages while a
    volatile app-server turn is still in progress.
    """
    if not session_id:
        return False
    if not _codex_app_server_is_live():
        if not start_if_needed or _ensure_codex_app_server() is None:
            return False
    try:
        resumed = _codex_app_server_request(
            "thread/resume",
            {"threadId": session_id, "excludeTurns": False},
            timeout=5,
        )
    except Exception:
        return False
    if not _codex_response_succeeded(resumed):
        state = _codex_app_server_thread_state(session_id)
        return bool(state.get("active_turn_id") or str(state.get("status") or "").lower() == "active")
    thread = ((resumed.get("result") or {}).get("thread") or {})
    status = ((thread.get("status") or {}).get("type") or "").lower()
    if status == "active" or bool(_codex_latest_active_turn(thread)):
        return True

    # `thread/resume` is an authoritative re-read from Codex. If it says the
    # thread is idle, discard any volatile active/unknown writer left behind by
    # a lost notification, server restart, or ended app-server client. Keeping
    # the stale local marker here made FIFO input wait forever until somebody
    # opened the thread in a CLI and caused a fresh status transition.
    _codex_reconcile_thread_idle(session_id)
    return False


# ── Codex desktop ↔ CCC single-writer coordination ──────────────────────────
# Codex desktop (ChatGPT.app / Codex.app) runs its OWN `codex app-server`
# process; turns it starts are invisible to CCC's app-server notifications.
# Both processes append to the same rollout JSONL, so the rollout file is the
# shared ground truth. The coordination model:
#   * attachment  — the desktop app-server holds an open write fd on the
#     rollout of every thread it has loaded (verified via lsof). Attachment
#     alone does NOT mean activity: desktop keeps day-old threads open.
#   * activity    — rollout mtime advanced within _CODEX_EXTERNAL_WRITER_WINDOW_S
#     and the growth is not attributable to CCC's own app-server turn or a
#     CCC-spawned `codex exec resume` child ⇒ an external writer (the desktop
#     when attached, otherwise a CLI/TUI) is mid-turn.
#   * write-gate  — CCC never issues turn/start while an external writer is
#     active; the message falls into the existing durable pending-input queue
#     (fallback:"queue") and the resume-queue watcher drains it once the
#     thread goes quiet. A per-thread mutex serializes concurrent CCC sends.
# Residual gap (documented, not fixable from CCC): the desktop's in-memory
# copy of a thread does not reload CCC-originated turns until the desktop
# itself refreshes the thread.
_CODEX_DESKTOP_ATTACH_TTL_S = 10.0
_CODEX_EXTERNAL_WRITER_WINDOW_S = 20.0
_CODEX_COORD_EVENTS_MAX = 40
_CODEX_COORD_EVENTS_TAIL = 8
_codex_desktop_attach_cache = {"ts": 0.0, "rollouts": {}}
_codex_desktop_attach_lock = threading.Lock()
_codex_thread_turn_locks = {}
_codex_thread_turn_locks_lock = threading.Lock()
_codex_external_writer_last = {}
_codex_external_writer_last_lock = threading.Lock()
_codex_coord_state_loaded = False


def _codex_thread_turn_lock(thread_id):
    """Per-thread mutex so two CCC callers can't race resume→turn/start."""
    with _codex_thread_turn_locks_lock:
        lock = _codex_thread_turn_locks.get(thread_id)
        if lock is None:
            lock = threading.Lock()
            _codex_thread_turn_locks[thread_id] = lock
        return lock


def _codex_desktop_app_server_procs():
    """`codex app-server` processes owned by a desktop app bundle.

    The desktop app's bundled binary lives inside `.app/Contents/…`, which
    cleanly separates it from CCC's own stdio child (spawned from a bare CLI
    path) and from wt/CLI processes. CCC's own child pid is excluded
    explicitly as belt-and-braces.
    """
    procs = []
    try:
        own_pid = None
        proc = _CODEX_APP_SERVER_PROC
        if proc is not None:
            own_pid = proc.pid
        for p in find_live_codex_processes():
            cmd = p.get("command") or ""
            if "app-server" not in cmd:
                continue
            head = cmd.split()[0] if cmd.split() else ""
            if ".app/Contents/" not in head:
                continue
            if own_pid and p.get("pid") == own_pid:
                continue
            procs.append(p)
    except Exception:
        return []
    return procs


def _parse_lsof_open_rollouts(output):
    """Map rollout-jsonl path → pid from `lsof -Fpn` field output. Pure."""
    rollouts = {}
    pid = None
    for line in (output or "").splitlines():
        if not line:
            continue
        tag, rest = line[0], line[1:]
        if tag == "p":
            try:
                pid = int(rest)
            except ValueError:
                pid = None
        elif tag == "n" and pid is not None:
            if "/sessions/" in rest and rest.endswith(".jsonl"):
                rollouts[rest] = pid
    return rollouts


def _codex_desktop_attached_rollouts(now=None):
    """rollout abs path → desktop app-server pid. One batched lsof, TTL-cached.

    Perf gate compliance: at most one `lsof` subprocess per TTL window for the
    whole server, never per session row.
    """
    now = time.time() if now is None else float(now)
    with _codex_desktop_attach_lock:
        if now - _codex_desktop_attach_cache["ts"] < _CODEX_DESKTOP_ATTACH_TTL_S:
            return dict(_codex_desktop_attach_cache["rollouts"])
        # Claim the window before the subprocess so concurrent callers reuse
        # the (possibly slightly stale) map instead of piling up lsof forks.
        _codex_desktop_attach_cache["ts"] = now
    rollouts = {}
    procs = _codex_desktop_app_server_procs()
    if procs:
        pid_list = ",".join(str(p.get("pid")) for p in procs if p.get("pid"))
        # lsof lives in /usr/sbin, which the LaunchAgent's PATH does not
        # include — a bare "lsof" raises FileNotFoundError inside the service
        # and the attachment map silently stays empty.
        lsof_bin = shutil.which("lsof") or "/usr/sbin/lsof"
        if pid_list and os.path.isfile(lsof_bin):
            try:
                out = subprocess.run(
                    [lsof_bin, "-w", "-p", pid_list, "-Fpn"],
                    stdout=subprocess.PIPE,
                    stderr=subprocess.DEVNULL,
                    text=True,
                    timeout=3.0,
                    check=False,
                ).stdout
                rollouts = _parse_lsof_open_rollouts(out)
            except (OSError, subprocess.SubprocessError):
                rollouts = {}
    with _codex_desktop_attach_lock:
        _codex_desktop_attach_cache["rollouts"] = dict(rollouts)
    return rollouts


def _codex_ccc_exec_child_running(session_id):
    """True when a CCC-spawned `codex exec resume` child owns this sid."""
    try:
        return any(
            s.get("resumed_sid") == session_id and _poll_spawn_entry(s) is None
            for s in _spawned_sessions
            if s.get("engine") == "codex"
        )
    except Exception:
        return False


def _codex_thread_writer_snapshot(session_id, now=None, *, rollout=None,
                                  app_state=None, attached=None,
                                  exec_child=None):
    """Attribute the current writer of one Codex thread.

    Returns {writer, desktop_attached, external_active, mtime_age_s}:
      writer ∈ "ccc" | "desktop" | "external" | "unknown" | None (quiet).
    Keyword args exist for unit tests; production callers pass none of them.
    """
    now = time.time() if now is None else float(now)
    snap = {"writer": None, "desktop_attached": False, "external_active": False}
    if not session_id:
        return snap
    state = app_state if app_state is not None else _codex_app_server_thread_state(session_id)
    state = state or {}
    active_turn_id = state.get("active_turn_id")
    active_status = str(state.get("status") or "").strip().lower() == "active"
    active_writer = str(state.get("active_writer") or "").strip().lower()
    ccc_turn_active = bool(
        state.get("ccc_turn_start_pending")
        or (active_turn_id and active_writer == "ccc")
    )
    ccc_recent = ccc_turn_active
    if not ccc_recent:
        try:
            last_seen = float(state.get("last_activity_at") or state.get("last_event_at") or 0)
            ccc_recent = (now - last_seen) < _CODEX_EXTERNAL_WRITER_WINDOW_S
        except (TypeError, ValueError):
            ccc_recent = False
    if exec_child is None:
        exec_child = _codex_ccc_exec_child_running(session_id)
    if rollout is None:
        rollout = _codex_rollout_stat(session_id)
    path = (rollout or {}).get("path")
    mtime_recent = False
    if rollout:
        try:
            age = now - (float(rollout.get("mtime_ns") or 0) / 1e9)
            snap["mtime_age_s"] = round(age, 1)
            mtime_recent = age < _CODEX_EXTERNAL_WRITER_WINDOW_S
        except (TypeError, ValueError):
            pass
    if path:
        if attached is None:
            attached = _codex_desktop_attached_rollouts(now)
        snap["desktop_attached"] = str(path) in (attached or {})
    if ccc_turn_active or exec_child:
        snap["writer"] = "ccc"
        return snap
    # Trust an authoritative "idle" thread status (delivered via
    # thread/status/changed and captured into state["status"]) over the
    # rollout-mtime heuristic. CCC shares the managed app-server daemon with the
    # Codex mobile/desktop apps, so it receives their real active→idle
    # transitions; a thread the daemon reports idle is NOT being written, even
    # when the rollout mtime is fresh because an external surface merely OPENED
    # the thread (touching the file without starting a turn). Without this, an
    # opened-but-idle thread was mis-attributed to an active external writer and
    # every CCC send queued forever ("session is busy" that never clears). The
    # status is volatile (never restored across restarts), so its presence means
    # we heard it this process — trustworthy. When we have no status (a thread we
    # aren't attached to / haven't heard from), fall back to the mtime heuristic.
    if str(state.get("status") or "").strip().lower() == "idle":
        return snap
    # An authoritative active status without CCC ownership belongs to another
    # app-server client (mobile, desktop, or another integration). This is more
    # precise than rollout mtime and prevents CCC from becoming a second writer.
    if active_status and active_writer != "ccc":
        snap["external_active"] = True
        snap["writer"] = "desktop" if snap["desktop_attached"] else "unknown"
        return snap
    if mtime_recent and not ccc_recent:
        snap["external_active"] = True
        snap["writer"] = "desktop" if snap["desktop_attached"] else "unknown"
    return snap


def _codex_load_coordination_state():
    """Restore durable coordination and recovery state from app-server state.

    Volatile fields (active_turn_id, status) must never survive a restart; they
    would report phantom turns. A recovery latch is durable by design so the
    singleton watcher can finish an episode after CCC restarts.
    """
    global _codex_coord_state_loaded
    if _codex_coord_state_loaded:
        return
    _codex_coord_state_loaded = True
    try:
        with CODEX_APP_SERVER_STATE_FILE.open() as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        return
    threads = data.get("threads") if isinstance(data, dict) else None
    if not isinstance(threads, dict):
        return
    with _CODEX_APP_SERVER_LOCK:
        for sid, saved in threads.items():
            if not isinstance(saved, dict):
                continue
            events = saved.get("coordination_events")
            recovery = saved.get("compaction_recovery")
            durable_activity = any(
                saved.get(key)
                for key in ("last_activity_at", "last_event_at", "last_turn_id")
            )
            if (
                not (isinstance(events, list) and events)
                and not isinstance(recovery, dict)
                and not durable_activity
            ):
                continue
            state = _CODEX_APP_SERVER_THREAD_STATE.setdefault(str(sid), {})
            if isinstance(events, list) and events and not state.get("coordination_events"):
                state["coordination_events"] = [
                    e for e in events if isinstance(e, dict)
                ][-_CODEX_COORD_EVENTS_MAX:]
            if isinstance(recovery, dict) and not state.get("compaction_recovery"):
                state["compaction_recovery"] = dict(recovery)
            for key in ("last_activity_at", "last_event_at", "last_turn_id"):
                if saved.get(key) and not state.get(key):
                    state[key] = saved[key]


def _codex_coordination_event_unlocked(state, kind, writer=None, detail=None, now=None):
    """Append one coordination event to a thread state dict.

    Caller must hold _CODEX_APP_SERVER_LOCK (or own the dict exclusively) and
    is responsible for persisting.
    """
    event = {"ts": float(now if now is not None else time.time()), "kind": str(kind)}
    if writer:
        event["writer"] = str(writer)
    if detail:
        event["detail"] = str(detail)[:240]
    events = state.setdefault("coordination_events", [])
    events.append(event)
    del events[:-_CODEX_COORD_EVENTS_MAX]


def _codex_coordination_event(session_id, kind, writer=None, detail=None, now=None):
    """Append one durable coordination event to the thread's state + disk."""
    if not session_id or not kind:
        return
    _codex_load_coordination_state()
    with _CODEX_APP_SERVER_LOCK:
        state = _CODEX_APP_SERVER_THREAD_STATE.setdefault(str(session_id), {})
        _codex_coordination_event_unlocked(state, kind, writer=writer, detail=detail, now=now)
        _save_codex_app_server_state_unlocked()


def _codex_note_external_writer_transition(session_id, snap):
    """Record external-writer start/stop transitions as durable events."""
    if not session_id or not isinstance(snap, dict):
        return
    cur = bool(snap.get("external_active"))
    with _codex_external_writer_last_lock:
        prev = _codex_external_writer_last.get(session_id)
        if prev == cur:
            return
        _codex_external_writer_last[session_id] = cur
        if prev is None and not cur:
            return  # first observation of a quiet thread — nothing to record
    writer = snap.get("writer") if cur else None
    if cur:
        detail = (
            "Turn detected from Codex desktop"
            if writer == "desktop"
            else "Active Codex turn detected"
        )
        _codex_coordination_event(
            session_id, "external_turn_started", writer=writer,
            detail=detail,
        )
    else:
        _codex_coordination_event(
            session_id, "external_turn_ended",
            detail="Active turn went quiet; CCC may send again",
        )


_CODEX_COORD_EVENT_TEXT = {
    "external_turn_started": "Active Codex turn detected",
    "external_turn_ended": "Active Codex turn finished - thread is free",
    "input_queued": "Message queued behind the active turn",
    "ccc_turn_started": "CCC started a turn via the app-server",
    "ccc_turn_completed": "CCC turn completed",
    "compaction_recovery_armed": "Watching for progress after compaction",
    "compaction_recovery_interrupting": "Interrupting a stalled post-compaction turn",
    "compaction_recovery_started": "Recovering after compaction",
    "compaction_recovery_recovered": "Codex recovered after compaction",
    "compaction_recovery_suppressed": "Compaction recovery suppressed",
    "compaction_recovery_exhausted": "Compaction recovery attempts exhausted",
    "turn_recovery_armed": "Watching a silent active goal turn",
    "turn_recovery_interrupting": "Interrupting a silent stalled Codex turn",
    "turn_recovery_started": "Recovering a stalled Codex turn",
    "turn_recovery_recovered": "Codex recovered from a silent turn",
    "turn_recovery_suppressed": "Silent-turn recovery handed off",
    "turn_recovery_exhausted": "Silent-turn recovery attempts exhausted",
}


def _codex_synthetic_event_ts_iso(ts):
    try:
        return datetime.fromtimestamp(float(ts), timezone.utc).isoformat().replace("+00:00", "Z")
    except (TypeError, ValueError, OverflowError, OSError):
        return ""


def _get_codex_coordination_events_for_session(session_id):
    """Durable coordination events as synthetic conversation events.

    Each event carries a STABLE synthetic `line` id so the frontend's
    data-jsonl-line dedupe keeps re-polls idempotent.
    """
    if not session_id:
        return []
    _codex_load_coordination_state()
    with _CODEX_APP_SERVER_LOCK:
        state = _CODEX_APP_SERVER_THREAD_STATE.get(session_id) or {}
        events = list(state.get("coordination_events") or [])
    out = []
    for ev in events[-_CODEX_COORD_EVENTS_TAIL:]:
        if not isinstance(ev, dict):
            continue
        kind = str(ev.get("kind") or "")
        ts = ev.get("ts")
        writer = ev.get("writer")
        text = _CODEX_COORD_EVENT_TEXT.get(kind) or kind.replace("_", " ")
        if kind == "external_turn_started" and writer == "desktop":
            text = "Codex desktop started a turn on this thread"
        # ts as ISO-8601: the frontend's tsSpan does `new Date(ts)`, which
        # reads a bare number as epoch MILLISECONDS — raw epoch seconds
        # would render as January 1970.
        ts_iso = _codex_synthetic_event_ts_iso(ts)
        out.append({
            "line": f"coord-{session_id[:8]}-{int(float(ts or 0) * 1000)}-{kind}",
            "ts": ts_iso,
            "type": "system",
            "subtype": "codex_coordination",
            "kind": kind,
            "writer": writer,
            "text": ev.get("detail") or text,
        })
    return out


def _codex_app_server_item_line(session_id, item, active=False):
    item_id = str((item or {}).get("id") or "").strip()
    if not item_id:
        try:
            item_id = str(int(float((item or {}).get("ts") or 0) * 1000))
        except (TypeError, ValueError, OverflowError):
            item_id = "unknown"
    suffix = "active" if active else "done"
    return f"appitem-{session_id[:8]}-{item_id}-{suffix}"


def _codex_app_server_item_event(session_id, item, *, active=False):
    if not session_id or not isinstance(item, dict):
        return None
    tool = str(item.get("tool") or item.get("type") or "").strip()
    detail = str(item.get("detail") or "").strip()
    output = str(item.get("output") or "").strip()
    item_type = str(item.get("type") or "").strip()
    needs_approval = bool(item.get("needs_approval"))
    overlay_item_types = _CODEX_APP_SERVER_APPROVAL_ITEM_TYPES | {
        "webSearch",
        "imageView",
        "imageGeneration",
        "subAgentActivity",
    }
    if not needs_approval and item_type not in overlay_item_types:
        return None
    if item_type == "reasoning" and tool == "Thinking" and not detail and not output:
        return None
    if not (tool or detail or output):
        return None
    ts = item.get("updated_at") or item.get("ts") or time.time()
    status = str(item.get("status") or ("inProgress" if active else "completed"))
    approval_message = str(item.get("approval_message") or "").strip()
    text_bits = []
    label = tool or item_type or "Codex"
    if needs_approval:
        text_bits.append(f"App-server live: {label} needs approval")
    elif active:
        text_bits.append(f"App-server live: {label} running")
    elif item.get("is_error"):
        text_bits.append(f"App-server live: {label} failed")
    else:
        text_bits.append(f"App-server live: {label} completed")
    if approval_message:
        text_bits.append(approval_message)
    elif detail:
        text_bits.append(detail)
    elif output:
        text_bits.append(output)
    return {
        "line": _codex_app_server_item_line(session_id, item, active=active),
        "ts": _codex_synthetic_event_ts_iso(ts),
        "type": "system",
        "subtype": "codex_app_server_item",
        "item_type": item_type,
        "tool": tool,
        "detail": detail,
        "output": output,
        "status": status,
        "in_flight": bool(active or item.get("in_flight")),
        "is_error": bool(item.get("is_error")),
        "needs_approval": needs_approval,
        "approval_message": approval_message,
        "text": " - ".join(text_bits),
    }


def _get_codex_app_server_item_events_for_session(session_id):
    """Recent app-server item notifications as synthetic conversation rows.

    These are intentionally marked as app-server live overlays, not durable
    transcript rows. The rollout JSONL remains authoritative history, but these
    rows expose tool/message notifications that can arrive before the rollout
    tail flushes.
    """
    if not session_id:
        return []
    state = _codex_app_server_thread_state(session_id)
    if not state:
        return []
    out = []
    seen = set()

    def add(item, *, active=False):
        ev = _codex_app_server_item_event(session_id, item, active=active)
        if not ev:
            return
        key = ev.get("line")
        if key in seen:
            return
        seen.add(key)
        out.append(ev)

    recent = state.get("recent_items")
    if isinstance(recent, list):
        for item in recent[-8:]:
            add(item, active=False)
    active_item = state.get("active_item") if isinstance(state.get("active_item"), dict) else None
    if active_item:
        add(active_item, active=True)
    try:
        out.sort(key=lambda ev: datetime.fromisoformat(str(ev.get("ts") or "").replace("Z", "+00:00")).timestamp())
    except Exception:
        pass
    return out


def _codex_writer_gate_response(session_id, snap, *, stage="writer-gate",
                                total_start=None, extra=None):
    """Uniform fallback:"queue" response for a blocked CCC send."""
    writer = snap.get("writer")
    if writer == "desktop":
        reason = (
            "Codex desktop is running a turn on this thread - the message is "
            "queued and CCC will send it when the desktop turn finishes"
        )
    elif writer == "ccc":
        reason = "Another CCC send is already running a turn on this thread - queued"
    else:
        reason = "An active Codex turn is writing this thread - queued until it finishes"
    _resume_ledger_append(
        "codex_wake_queued", sid=session_id, stage=stage, reason=reason,
    )
    _codex_telemetry_append(
        "codex_wake",
        ok=False,
        via="codex-app-server",
        fallback="queue",
        fallback_reason=reason,
        stage=stage,
        writer=writer,
        desktop_attached=bool(snap.get("desktop_attached")),
        session_id=session_id,
        total_ms=_codex_elapsed_ms(total_start) if total_start is not None else None,
    )
    _codex_coordination_event(session_id, "input_queued", writer=writer)
    resp = {
        "ok": False,
        "via": "codex-app-server",
        "stage": stage,
        "fallback": "queue",
        "error": reason,
        "writer": writer,
        "desktop_attached": bool(snap.get("desktop_attached")),
    }
    if extra:
        resp.update(extra)
    return resp


def _codex_turn_params(thread_id, text, cwd=None, model=None, image_paths=None, effort=None):
    params = {
        "threadId": thread_id,
        "input": _codex_user_input(text, image_paths=image_paths),
    }
    if cwd:
        params["cwd"] = cwd
        params["runtimeWorkspaceRoots"] = [cwd]
    if model:
        params["model"] = model
    if effort:
        params["effort"] = effort
    # Match the existing `codex exec --dangerously-bypass-approvals-and-sandbox`
    # behavior used by CCC-spawned Codex runs.
    params["approvalPolicy"] = "never"
    params["sandboxPolicy"] = {"type": "dangerFullAccess"}
    return params


def _codex_app_server_spawn_enabled():
    for key in ("CCC_CODEX_APP_SERVER", "CCC_CODEX_SPAWN_APP_SERVER"):
        if os.environ.get(key, "1").lower() in ("0", "false", "no"):
            return False
    return True


def _codex_app_server_thread_start_params(cwd=None, model=None):
    params = {
        "approvalPolicy": "never",
        "sandbox": "danger-full-access",
        "threadSource": "ccc",
        "sessionStartSource": "startup",
        "ephemeral": False,
    }
    if cwd:
        params["cwd"] = cwd
        params["runtimeWorkspaceRoots"] = [cwd]
    if model:
        params["model"] = model
    if _codex_context_1m_enabled():
        params["config"] = {"model_context_window": 1000000}
    return params


def _codex_app_server_response_error(response, default="Codex app-server request failed"):
    if not isinstance(response, dict):
        return default
    return _codex_error_text(response) or str(response.get("error") or default)


def _codex_app_server_normalize_approval_decision(decision):
    raw = str(decision or "").strip()
    token = re.sub(r"[^a-z0-9]+", "_", raw.lower()).strip("_")
    mapping = {
        "accept": "accept",
        "approve": "accept",
        "approved": "accept",
        "yes": "accept",
        "acceptforsession": "acceptForSession",
        "accept_for_session": "acceptForSession",
        "approve_session": "acceptForSession",
        "approved_for_session": "acceptForSession",
        "session": "acceptForSession",
        "decline": "decline",
        "deny": "decline",
        "denied": "decline",
        "no": "decline",
        "cancel": "cancel",
        "abort": "cancel",
    }
    return mapping.get(token) or mapping.get(raw) or ""


def _codex_app_server_approval_result_payload(method, decision, pending):
    canonical = _codex_app_server_normalize_approval_decision(decision)
    if not canonical:
        return None, "invalid approval decision"
    if method in _CODEX_APP_SERVER_COMMAND_APPROVAL_METHODS or method in _CODEX_APP_SERVER_FILE_APPROVAL_METHODS:
        if method in ("execCommandApproval", "applyPatchApproval"):
            legacy = {
                "accept": "approved",
                "acceptForSession": "approved_for_session",
                "decline": "denied",
                "cancel": "abort",
            }
            return {"decision": legacy[canonical]}, ""
        return {"decision": canonical}, ""
    if method in _CODEX_APP_SERVER_PERMISSION_APPROVAL_METHODS:
        scope = "session" if canonical == "acceptForSession" else "turn"
        permissions = pending.get("requested_permissions") if isinstance(pending, dict) else None
        if canonical in ("decline", "cancel"):
            permissions = {}
        if not isinstance(permissions, dict):
            return None, "permission approval request did not include a grantable permissions profile"
        return {"permissions": permissions, "scope": scope}, ""
    return None, f"unsupported approval method: {method}"


def _codex_app_server_resolve_approval(session_id, decision):
    sid = str(session_id or "").strip()
    if not sid:
        return {"ok": False, "via": "codex-approval", "error": "missing session_id"}
    with _CODEX_APP_SERVER_LOCK:
        state = _CODEX_APP_SERVER_THREAD_STATE.get(sid) if sid else None
        pending = _codex_app_server_pending_approval_item(state or {})
        if not pending:
            return {
                "ok": False,
                "via": "codex-approval",
                "code": "codex_no_pending_approval",
                "error": "No pending Codex approval request for this session",
            }
        request_id = pending.get("request_id_raw")
        if request_id is None:
            request_id = pending.get("request_id")
        method = pending.get("approval_method") or ""
        if request_id is None or (isinstance(request_id, str) and not request_id.strip()):
            return {
                "ok": False,
                "via": "codex-approval",
                "code": "codex_approval_not_actionable",
                "error": "Codex approval is visible but does not include an app-server request id",
            }
        result, error = _codex_app_server_approval_result_payload(method, decision, pending)
        if error:
            return {
                "ok": False,
                "via": "codex-approval",
                "code": "codex_approval_not_actionable",
                "error": error,
            }

    transport = _ensure_codex_app_server()
    if transport is None:
        return {
            "ok": False,
            "via": "codex-approval",
            "code": "codex_app_server_unavailable",
            "error": "Codex app-server transport unavailable",
        }

    response = {"jsonrpc": "2.0", "id": request_id, "result": result}
    try:
        transport.send_json(response)
    except (BrokenPipeError, OSError) as e:
        return {
            "ok": False,
            "via": "codex-approval",
            "code": "codex_approval_send_failed",
            "error": str(e),
        }

    with _CODEX_APP_SERVER_LOCK:
        state = _CODEX_APP_SERVER_THREAD_STATE.get(sid) if sid else None
        if isinstance(state, dict):
            current = state.get("pending_approval_request")
            if isinstance(current, dict) and (
                current.get("request_id_raw") == request_id
                or current.get("request_id") == request_id
                or str(current.get("request_id") or "") == str(request_id)
            ):
                state.pop("pending_approval_request", None)
            flags = [
                flag for flag in (state.get("active_flags") or [])
                if not _codex_app_server_flags_need_approval([flag])
            ]
            state["active_flags"] = flags
            state["thread_needs_approval"] = False
            now = time.time()
            for key in ("active_item", "last_item"):
                item = state.get(key)
                if isinstance(item, dict) and (
                    item.get("request_id_raw") == request_id
                    or item.get("request_id") == request_id
                    or str(item.get("request_id") or "") == str(request_id)
                ):
                    item["needs_approval"] = False
                    item["can_approve"] = False
                    item["status"] = "approval_response_sent"
                    item["in_flight"] = True
                    item["updated_at"] = now
            active = state.get("active_items")
            if isinstance(active, dict):
                for item in active.values():
                    if isinstance(item, dict) and (
                        item.get("request_id_raw") == request_id
                        or item.get("request_id") == request_id
                        or str(item.get("request_id") or "") == str(request_id)
                    ):
                        item["needs_approval"] = False
                        item["can_approve"] = False
                        item["status"] = "approval_response_sent"
                        item["in_flight"] = True
                        item["updated_at"] = now
            state["last_activity_at"] = now
            _save_codex_app_server_state_unlocked()
        _CODEX_APP_SERVER_LOCK.notify_all()
    return {
        "ok": True,
        "via": "codex-approval",
        "session_id": sid,
        "request_id": request_id,
        "approval_method": method,
        "decision": _codex_app_server_normalize_approval_decision(decision),
    }


def _codex_spawn_id_for_thread(thread_id):
    cleaned = re.sub(r"[^A-Za-z0-9_.-]+", "-", str(thread_id or "")).strip("-")
    cleaned = cleaned[:32] or str(int(time.time() * 1000))
    return f"codex-app-{cleaned}"


def _codex_spawn_via_app_server(
    prompt,
    *,
    session_name,
    spawn_cwd,
    repo_for_logs,
    model_to_use,
    reasoning_effort="",
    image_paths=None,
    parent_session_id=None,
    timestamp=None,
    worktree_path=None,
    worktree_branch=None,
    parent_repo=None,
):
    """Start a fresh Codex thread through the app-server.

    Returns None when callers should fall back to the legacy `codex exec` path.
    Once a durable thread has been created, errors are returned to the caller
    instead of launching a second session for the same requested task.
    """
    if not _codex_app_server_spawn_enabled():
        _codex_telemetry_append(
            "codex_spawn",
            ok=False,
            via="codex-app-spawn",
            fallback="codex-exec",
            fallback_reason="app-server-disabled",
            cwd=spawn_cwd,
            model=model_to_use,
        )
        return None
    timestamp = timestamp or time.strftime("%Y%m%dT%H%M%S")
    total_start = time.monotonic()
    app_server_warm = _codex_app_server_is_live()
    thread_start_at = time.monotonic()
    start = _codex_app_server_request(
        "thread/start",
        _codex_app_server_thread_start_params(cwd=spawn_cwd, model=model_to_use),
        timeout=20,
    )
    thread_start_ms = _codex_elapsed_ms(thread_start_at)
    if not _codex_response_succeeded(start):
        _codex_telemetry_append(
            "codex_spawn",
            ok=False,
            via="codex-app-spawn",
            fallback="codex-exec",
            fallback_reason="thread/start failed",
            stage="thread/start",
            error=_codex_app_server_response_error(start),
            app_server_warm=app_server_warm,
            thread_start_ms=thread_start_ms,
            total_ms=_codex_elapsed_ms(total_start),
            transport=_codex_app_server_transport_kind(),
            cwd=spawn_cwd,
            model=model_to_use,
        )
        return None
    thread = ((start.get("result") or {}).get("thread") or {})
    thread_id = thread.get("id")
    if not thread_id:
        return None
    thread_id = str(thread_id)
    _codex_app_server_record_thread(thread_id, thread)

    rename_warning = ""
    name_set_ms = None
    if session_name:
        name_set_at = time.monotonic()
        renamed = _codex_app_server_request(
            "thread/name/set",
            {"threadId": thread_id, "name": session_name},
            timeout=10,
        )
        name_set_ms = _codex_elapsed_ms(name_set_at)
        if not _codex_response_succeeded(renamed):
            rename_warning = _codex_app_server_response_error(
                renamed,
                "Codex app-server accepted the thread but did not name it",
            )

    log_dir = repo_log_dir(repo_for_logs)
    log_dir.mkdir(parents=True, exist_ok=True)
    log_path = log_dir / f"spawn-codex-app-{session_name}-{timestamp}.log"
    log_fh = open(log_path, "w")
    try:
        log_fh.write(json.dumps({
            "event": "codex_app_server_spawn",
            "thread_id": thread_id,
            "name": session_name,
            "cwd": spawn_cwd,
            "model": model_to_use or "",
            "reasoning_effort": reasoning_effort or "",
            "transport": _codex_app_server_transport_kind(),
        }, sort_keys=True) + "\n")
        if rename_warning:
            log_fh.write(json.dumps({
                "event": "codex_app_server_name_warning",
                "warning": rename_warning,
            }, sort_keys=True) + "\n")
        log_fh.flush()
        if worktree_path:
            _run_worktree_init_hook(worktree_path, parent_repo or repo_for_logs, session_name, log_fh)

        baseline_state = _codex_app_server_thread_state(thread_id)
        baseline_rollout = _codex_rollout_stat(thread_id)
        turn_start_at = time.monotonic()
        started = _codex_app_server_request(
            "turn/start",
            _codex_turn_params(
                thread_id,
                prompt,
                cwd=spawn_cwd,
                model=model_to_use,
                image_paths=image_paths,
                effort=reasoning_effort or None,
            ),
            timeout=20,
        )
        turn_start_ms = _codex_elapsed_ms(turn_start_at)
        if not _codex_response_succeeded(started):
            error = _codex_app_server_response_error(started)
            log_fh.write(json.dumps({
                "event": "codex_app_server_turn_failed",
                "error": error,
            }, sort_keys=True) + "\n")
            log_fh.flush()
            _codex_telemetry_append(
                "codex_spawn",
                ok=False,
                via="codex-app-spawn",
                fallback="none-durable-thread-created",
                fallback_reason="turn/start failed after thread/start",
                stage="turn/start",
                error=error,
                app_server_warm=app_server_warm,
                thread_start_ms=thread_start_ms,
                name_set_ms=name_set_ms,
                turn_start_ms=turn_start_ms,
                total_ms=_codex_elapsed_ms(total_start),
                transport=_codex_app_server_transport_kind(),
                session_id=thread_id,
                cwd=spawn_cwd,
                model=model_to_use,
            )
            return {
                "ok": False,
                "error": error,
                "code": "codex_app_spawn_failed",
                "via": "codex-app-spawn",
                "session_id": thread_id,
                "log": str(log_path),
            }

        turn = ((started.get("result") or {}).get("turn") or {})
        turn_id = turn.get("id")
        _codex_telemetry_register_turn(
            thread_id,
            turn_id,
            path="spawn",
            started_at_monotonic=turn_start_at,
            transport=_codex_app_server_transport_kind(),
            cwd=spawn_cwd,
            model=model_to_use,
        )
        try:
            confirm_timeout = float(os.environ.get("CCC_CODEX_WAKE_CONFIRM_TIMEOUT", "5"))
        except ValueError:
            confirm_timeout = 5.0
        confirm_at = time.monotonic()
        confirmation = _codex_wait_for_turn_activity(
            thread_id,
            turn_id,
            baseline_state=baseline_state,
            baseline_rollout=baseline_rollout,
            expected_text=prompt,
            timeout=confirm_timeout,
        )
        confirm_ms = _codex_elapsed_ms(confirm_at)
        if not confirmation.get("confirmed"):
            log_fh.write(json.dumps({
                "event": "codex_app_server_spawn_warning",
                "warning": confirmation.get("warning"),
                "turn_id": turn_id,
            }, sort_keys=True) + "\n")
        log_fh.write(json.dumps({
            "event": "codex_app_server_turn_started",
            "turn_id": turn_id,
            "confirmed": bool(confirmation.get("confirmed")),
            "confirmation_source": confirmation.get("source"),
        }, sort_keys=True) + "\n")
        log_fh.flush()
        total_ms = _codex_elapsed_ms(total_start)
        _codex_telemetry_append(
            "codex_spawn",
            ok=True,
            via="codex-app-spawn",
            app_server_warm=app_server_warm,
            thread_start_ms=thread_start_ms,
            name_set_ms=name_set_ms,
            turn_start_ms=turn_start_ms,
            confirm_ms=confirm_ms,
            total_ms=total_ms,
            confirmed=bool(confirmation.get("confirmed")),
            confirmation_source=confirmation.get("source"),
            warning=confirmation.get("warning") or rename_warning or None,
            transport=_codex_app_server_transport_kind(),
            session_id=thread_id,
            turn_id=turn_id,
            cwd=spawn_cwd,
            model=model_to_use,
        )
    finally:
        log_fh.close()

    spawn_id = _codex_spawn_id_for_thread(thread_id)
    entry = {
        "pid": spawn_id,
        "spawn_id": spawn_id,
        "name": session_name,
        "log": str(log_path),
        "prompt": prompt[:200],
        "started": timestamp,
        "proc": None,
        "log_fh": None,
        "fifo": None,
        "stdin_fd": None,
        "engine": "codex",
        "cwd": spawn_cwd,
        "repo_path": repo_for_logs,
        "model": model_to_use or "",
        "parent_session_id": parent_session_id or "",
        "session_id": thread_id,
        "app_server_spawn": True,
        "turn_id": turn_id,
        "confirmed": bool(confirmation.get("confirmed")),
        "confirmation_source": confirmation.get("source"),
        "app_server_warm": app_server_warm,
        "thread_start_ms": thread_start_ms,
        "name_set_ms": name_set_ms,
        "turn_start_ms": turn_start_ms,
        "confirm_ms": confirm_ms,
        "latency_ms": total_ms,
    }
    _spawned_sessions.append(entry)
    _codex_thread_registry_upsert(
        thread_id,
        source="ccc-spawn",
        visibility="user-visible",
        transport_owner="ccc-managed-app-server",
        transport=_codex_app_server_transport_kind(),
        cwd=spawn_cwd,
        repo_path=repo_for_logs,
        title=session_name,
        name=session_name,
        parent_session_id=parent_session_id or "",
        model=model_to_use or "",
        ccc={
            "spawn_id": spawn_id,
            "log": str(log_path),
            "spawned_at": timestamp,
            "prompt": prompt[:200],
            "app_server_spawn": True,
            "worktree_path": worktree_path or "",
            "worktree_branch": worktree_branch or "",
        },
    )
    _set_session_override(thread_id, model_to_use, False, "codex", reasoning_effort)
    resp = {
        "ok": True,
        "pid": spawn_id,
        "spawn_id": spawn_id,
        "name": session_name,
        "log": str(log_path),
        "via": "codex-app-spawn",
        "accepted": True,
        "confirmed": bool(confirmation.get("confirmed")),
        "confirmation_source": confirmation.get("source"),
        "warning": confirmation.get("warning") or rename_warning or None,
        "turn_id": turn_id,
        "session_id": thread_id,
        "app_server_transport": _codex_app_server_transport_kind(),
        "app_server_warm": app_server_warm,
        "thread_start_ms": thread_start_ms,
        "name_set_ms": name_set_ms,
        "turn_start_ms": turn_start_ms,
        "confirm_ms": confirm_ms,
        "latency_ms": total_ms,
    }
    if worktree_path:
        resp["worktree_path"] = worktree_path
        resp["worktree_branch"] = worktree_branch
    return _finalize_spawn_response(resp, entry, {"cwd": spawn_cwd, "repo_path": repo_for_logs}, wait_for_session_id=False)


def _codex_resume_or_steer_via_app_server(
    session_id,
    text,
    cwd=None,
    model=None,
    image_paths=None,
    allow_start=True,
    reasoning_effort=None,
):
    """Write-gated wrapper: single-writer protocol for shared Codex threads.

    Blocks turn/start while an external writer (Codex desktop, CLI) is
    mid-turn on the thread, and serializes concurrent CCC sends with a
    per-thread mutex. Blocked sends return fallback:"queue" — the caller
    parks the text in the durable pending-input queue and the resume-queue
    watcher retries once the thread goes quiet.
    """
    total_start = time.monotonic()
    try:
        snap = _codex_thread_writer_snapshot(session_id)
    except Exception:
        snap = {}
    if snap.get("external_active"):
        _codex_note_external_writer_transition(session_id, snap)
        return _codex_writer_gate_response(session_id, snap, total_start=total_start)
    lock = _codex_thread_turn_lock(session_id)
    if not lock.acquire(blocking=False):
        return _codex_writer_gate_response(
            session_id, {"writer": "ccc", "desktop_attached": snap.get("desktop_attached")},
            total_start=total_start,
        )
    try:
        return _codex_resume_or_steer_via_app_server_locked(
            session_id,
            text,
            cwd=cwd,
            model=model,
            image_paths=image_paths,
            allow_start=allow_start,
            reasoning_effort=reasoning_effort,
        )
    finally:
        lock.release()


def _codex_resume_or_steer_via_app_server_locked(
    session_id,
    text,
    cwd=None,
    model=None,
    image_paths=None,
    allow_start=True,
    reasoning_effort=None,
):
    if os.environ.get("CCC_CODEX_APP_SERVER", "1").lower() in ("0", "false", "no"):
        _codex_telemetry_append(
            "codex_wake",
            ok=False,
            via="codex-app-server",
            fallback="exec",
            fallback_reason="app-server-disabled",
            stage="disabled",
            session_id=session_id,
            cwd=cwd,
            model=model,
        )
        return {"ok": False, "fallback": "exec", "error": "Codex app-server disabled"}
    total_start = time.monotonic()
    app_server_warm = _codex_app_server_is_live()
    resume_params = {
        "threadId": session_id,
        "excludeTurns": False,
    }
    if cwd:
        resume_params["cwd"] = cwd
    if model:
        resume_params["model"] = model
    if reasoning_effort:
        resume_params["effort"] = reasoning_effort
    # Finer stage breadcrumb for the live wake-status breakdown (diagnostic
    # only; wrapped so it can never affect control flow).
    try:
        _resume_ledger_append("codex_wake_stage", sid=session_id, stage="connect")
    except Exception:
        pass
    resume_at = time.monotonic()
    resumed = _codex_app_server_request("thread/resume", resume_params, timeout=20)
    resume_ms = _codex_elapsed_ms(resume_at)
    if resumed.get("error"):
        _err = _codex_error_text(resumed)
        _resume_ledger_append(
            "codex_wake_fail", sid=session_id,
            stage="thread/resume", error=_err, fallback="exec",
        )
        _codex_telemetry_append(
            "codex_wake",
            ok=False,
            via="codex-app-server",
            fallback="exec",
            fallback_reason="thread/resume failed",
            stage="thread/resume",
            error=_err,
            app_server_warm=app_server_warm,
            resume_ms=resume_ms,
            total_ms=_codex_elapsed_ms(total_start),
            transport=_codex_app_server_transport_kind(),
            session_id=session_id,
            cwd=cwd,
            model=model,
        )
        return {
            "ok": False,
            "via": "codex-app-server",
            "stage": "thread/resume",
            "fallback": "exec",
            "error": _err,
            "app_server_warm": app_server_warm,
            "resume_ms": resume_ms,
            "latency_ms": _codex_elapsed_ms(total_start),
        }
    thread = ((resumed.get("result") or {}).get("thread") or {})
    active_turn = _codex_latest_active_turn(thread)
    status = (thread.get("status") or {}).get("type")
    if status == "active" and active_turn:
        _reason = "Codex thread is active; queue the next message durably in CCC"
        _resume_ledger_append(
            "codex_wake_queued", sid=session_id,
            stage="thread/resume", reason=_reason,
        )
        _codex_telemetry_append(
            "codex_wake",
            ok=False,
            via="codex-app-server",
            fallback="queue",
            fallback_reason=_reason,
            stage="thread/resume",
            app_server_warm=app_server_warm,
            resume_ms=resume_ms,
            total_ms=_codex_elapsed_ms(total_start),
            transport=_codex_app_server_transport_kind(),
            session_id=session_id,
            cwd=cwd,
            model=model,
        )
        return {
            "ok": False,
            "via": "codex-app-server",
            "stage": "thread/resume",
            "fallback": "queue",
            "error": _reason,
            "app_server_warm": app_server_warm,
            "resume_ms": resume_ms,
            "latency_ms": _codex_elapsed_ms(total_start),
        }
    if status == "active":
        _reason = "Codex app-server reports an active turn without a steerable turn id"
        _resume_ledger_append(
            "codex_wake_queued", sid=session_id,
            stage="thread/resume", reason=_reason,
        )
        _codex_telemetry_append(
            "codex_wake",
            ok=False,
            via="codex-app-server",
            fallback="queue",
            fallback_reason=_reason,
            stage="thread/resume",
            app_server_warm=app_server_warm,
            resume_ms=resume_ms,
            total_ms=_codex_elapsed_ms(total_start),
            transport=_codex_app_server_transport_kind(),
            session_id=session_id,
            cwd=cwd,
            model=model,
        )
        return {
            "ok": False,
            "via": "codex-app-server",
            "stage": "thread/resume",
            "fallback": "queue",
            "error": _reason,
            "app_server_warm": app_server_warm,
            "resume_ms": resume_ms,
            "latency_ms": _codex_elapsed_ms(total_start),
        }
    if not allow_start:
        _reason = "Codex CLI resume is still running and app-server did not expose a steerable turn"
        _resume_ledger_append(
            "codex_wake_queued", sid=session_id,
            stage="thread/resume", reason=_reason,
        )
        _codex_telemetry_append(
            "codex_wake",
            ok=False,
            via="codex-app-server",
            fallback="queue",
            fallback_reason=_reason,
            stage="thread/resume",
            app_server_warm=app_server_warm,
            resume_ms=resume_ms,
            total_ms=_codex_elapsed_ms(total_start),
            transport=_codex_app_server_transport_kind(),
            session_id=session_id,
            cwd=cwd,
            model=model,
        )
        return {
            "ok": False,
            "via": "codex-app-server",
            "stage": "thread/resume",
            "fallback": "queue",
            "error": _reason,
            "app_server_warm": app_server_warm,
            "resume_ms": resume_ms,
            "latency_ms": _codex_elapsed_ms(total_start),
        }

    try:
        _resume_ledger_append("codex_wake_stage", sid=session_id, stage="turn-start")
    except Exception:
        pass
    baseline_state = _codex_app_server_thread_state(session_id)
    baseline_rollout = _codex_rollout_stat(session_id)
    # Re-check the writer gate at the last possible moment: the thread/resume
    # above takes seconds, plenty of time for the desktop user to hit enter.
    # Attachment is TTL-cached; the ACTIVITY read (rollout stat) is fresh.
    try:
        snap = _codex_thread_writer_snapshot(
            session_id, rollout=baseline_rollout, app_state=baseline_state,
        )
    except Exception:
        snap = {}
    if snap.get("external_active"):
        _codex_note_external_writer_transition(session_id, snap)
        return _codex_writer_gate_response(
            session_id, snap, stage="turn/start-gate", total_start=total_start,
            extra={"app_server_warm": app_server_warm, "resume_ms": resume_ms},
        )
    turn_start_at = time.monotonic()
    started = _codex_app_server_request(
        "turn/start",
        _codex_turn_params(session_id, text, cwd=cwd, model=model, image_paths=image_paths, effort=reasoning_effort),
        timeout=20,
    )
    turn_start_ms = _codex_elapsed_ms(turn_start_at)
    if _codex_response_succeeded(started):
        turn = ((started.get("result") or {}).get("turn") or {})
        _turn_id = turn.get("id")
        _codex_telemetry_register_turn(
            session_id,
            _turn_id,
            path="wake",
            started_at_monotonic=turn_start_at,
            transport=_codex_app_server_transport_kind(),
            cwd=cwd,
            model=model,
        )
        _resume_ledger_append(
            "codex_wake_ok", sid=session_id,
            via="codex-app-turn", turn_id=_turn_id,
        )
        try:
            confirm_timeout = float(os.environ.get("CCC_CODEX_WAKE_CONFIRM_TIMEOUT", "5"))
        except ValueError:
            confirm_timeout = 5.0
        confirm_at = time.monotonic()
        confirmation = _codex_wait_for_turn_activity(
            session_id,
            _turn_id,
            baseline_state=baseline_state,
            baseline_rollout=baseline_rollout,
            expected_text=text,
            timeout=confirm_timeout,
        )
        confirm_ms = _codex_elapsed_ms(confirm_at)
        if not confirmation.get("confirmed"):
            _resume_ledger_append(
                "codex_wake_warn", sid=session_id,
                via="codex-app-turn", turn_id=_turn_id,
                warning=confirmation.get("warning"),
            )
        total_ms = _codex_elapsed_ms(total_start)
        _codex_telemetry_append(
            "codex_wake",
            ok=True,
            via="codex-app-turn",
            app_server_warm=app_server_warm,
            resume_ms=resume_ms,
            turn_start_ms=turn_start_ms,
            confirm_ms=confirm_ms,
            total_ms=total_ms,
            confirmed=bool(confirmation.get("confirmed")),
            confirmation_source=confirmation.get("source"),
            warning=confirmation.get("warning"),
            transport=_codex_app_server_transport_kind(),
            session_id=session_id,
            turn_id=_turn_id,
            cwd=cwd,
            model=model,
        )
        return {
            "ok": True,
            "via": "codex-app-turn",
            "accepted": True,
            "confirmed": bool(confirmation.get("confirmed")),
            "confirmation_source": confirmation.get("source"),
            "warning": confirmation.get("warning"),
            "turn_id": _turn_id,
            "session_id": session_id,
            "app_server_transport": _codex_app_server_transport_kind(),
            "app_server_warm": app_server_warm,
            "resume_ms": resume_ms,
            "turn_start_ms": turn_start_ms,
            "confirm_ms": confirm_ms,
            "latency_ms": total_ms,
        }
    if _codex_error_is_not_steerable(started):
        _err = _codex_error_text(started)
        _resume_ledger_append(
            "codex_wake_fail", sid=session_id,
            stage="turn/start", error=_err, fallback="queue",
        )
        _codex_telemetry_append(
            "codex_wake",
            ok=False,
            via="codex-app-server",
            fallback="queue",
            fallback_reason="turn/start not steerable",
            stage="turn/start",
            error=_err,
            app_server_warm=app_server_warm,
            resume_ms=resume_ms,
            turn_start_ms=turn_start_ms,
            total_ms=_codex_elapsed_ms(total_start),
            transport=_codex_app_server_transport_kind(),
            session_id=session_id,
            cwd=cwd,
            model=model,
        )
        return {
            "ok": False,
            "via": "codex-app-server",
            "stage": "turn/start",
            "fallback": "queue",
            "error": _err,
            "app_server_warm": app_server_warm,
            "resume_ms": resume_ms,
            "turn_start_ms": turn_start_ms,
            "latency_ms": _codex_elapsed_ms(total_start),
        }
    _err = _codex_error_text(started)
    _resume_ledger_append(
        "codex_wake_fail", sid=session_id,
        stage="turn/start", error=_err, fallback="exec",
    )
    _codex_telemetry_append(
        "codex_wake",
        ok=False,
        via="codex-app-server",
        fallback="exec",
        fallback_reason="turn/start failed",
        stage="turn/start",
        error=_err,
        app_server_warm=app_server_warm,
        resume_ms=resume_ms,
        turn_start_ms=turn_start_ms,
        total_ms=_codex_elapsed_ms(total_start),
        transport=_codex_app_server_transport_kind(),
        session_id=session_id,
        cwd=cwd,
        model=model,
    )
    return {
        "ok": False,
        "via": "codex-app-server",
        "stage": "turn/start",
        "fallback": "exec",
        "error": _err,
        "app_server_warm": app_server_warm,
        "resume_ms": resume_ms,
        "turn_start_ms": turn_start_ms,
        "latency_ms": _codex_elapsed_ms(total_start),
    }


def _codex_steer_via_app_server(session_id, text, cwd=None, model=None, image_paths=None):
    if os.environ.get("CCC_CODEX_APP_SERVER", "1").lower() in ("0", "false", "no"):
        return {
            "ok": False,
            "via": "codex-steer",
            "code": "codex_steer_unavailable",
            "error": "Codex app-server disabled",
        }
    # A turn running in the DESKTOP's app-server cannot be steered from CCC's
    # app-server — the resumed replica isn't the executing turn. Fail fast
    # with the code the frontend already maps to its send-mode retry, which
    # then hits the write-gate and queues durably.
    try:
        snap = _codex_thread_writer_snapshot(session_id)
    except Exception:
        snap = {}
    if snap.get("external_active"):
        _codex_note_external_writer_transition(session_id, snap)
        writer = snap.get("writer")
        label = "Codex desktop" if writer == "desktop" else "another Codex process"
        return {
            "ok": False,
            "via": "codex-steer",
            "code": "codex_steer_unavailable",
            "writer": writer,
            "error": f"Active turn belongs to {label}; steering from CCC is not possible",
        }
    resume_params = {
        "threadId": session_id,
        "excludeTurns": False,
    }
    if cwd:
        resume_params["cwd"] = cwd
    if model:
        resume_params["model"] = model
    resumed = _codex_app_server_request("thread/resume", resume_params, timeout=20)
    if resumed.get("error"):
        return {
            "ok": False,
            "via": "codex-steer",
            "code": "codex_steer_unavailable",
            "error": _codex_error_text(resumed),
        }
    thread = ((resumed.get("result") or {}).get("thread") or {})
    active_turn = _codex_latest_active_turn(thread)
    status = (thread.get("status") or {}).get("type")
    if status != "active" or not active_turn:
        return {
            "ok": False,
            "via": "codex-steer",
            "code": "codex_no_active_turn",
            "error": "No running Codex turn to steer",
        }
    steered = _codex_app_server_request(
        "turn/steer",
        {
            "threadId": session_id,
            "expectedTurnId": active_turn["id"],
            "input": _codex_user_input(text, image_paths=image_paths),
        },
        timeout=20,
    )
    if _codex_response_succeeded(steered):
        return {
            "ok": True,
            "via": "codex-steer",
            "turn_id": (steered["result"] or {}).get("turnId") or active_turn["id"],
            "session_id": session_id,
        }
    return {
        "ok": False,
        "via": "codex-steer",
        "code": "codex_steer_failed",
        "error": _codex_error_text(steered) or "Codex steer failed",
    }


def _backup_codex_rollout_before_compact(session_id):
    """Copy the Codex thread's rollout JSONL to
    ~/.claude/command-center/compact-backups/ before `thread/compact/start`
    rewrites it. Returns the backup path or None on failure. Best-effort.

    Codex compaction is lossy — the app-server replaces the loaded thread's
    history with a compacted summary and rewrites the rollout on disk. Without
    a snapshot the pre-compact transcript is gone permanently. Mirrors the
    Claude `_backup_jsonl_before_compact` pattern and reuses its backup dir.
    """
    try:
        src = _resolve_codex_rollout_path(session_id)
        if not src:
            return None
        src = Path(src)
        if not src.is_file():
            return None
        backup_dir = Path.home() / ".claude" / "command-center" / "compact-backups"
        backup_dir.mkdir(parents=True, exist_ok=True)
        stamp = datetime.now().strftime("%Y%m%dT%H%M%S")
        dest = backup_dir / f"codex-{session_id}-{stamp}.jsonl"
        shutil.copy2(str(src), str(dest))
        # Keep at most 10 backups per thread — older ones rotate out.
        backups = sorted(backup_dir.glob(f"codex-{session_id}-*.jsonl"))
        for stale in backups[:-10]:
            try:
                stale.unlink()
            except OSError:
                pass
        return str(dest)
    except Exception as e:
        print(f"  [compact-backup] codex backup failed for {session_id}: {e}", file=sys.stderr)
        return None


def _codex_compact_via_app_server(session_id, cwd=None, model=None):
    """Compact a Codex thread via the app-server `thread/compact/start` RPC.

    Resumes the thread (loading it into the CCC-owned app-server) and then calls
    `thread/compact/start` with the schema-correct params (`{threadId}`).
    Compaction is lossy, so the caller is expected to have already backed up the
    rollout. Returns a result dict mirroring the other Codex app-server helpers
    (`{ok, via, ...}` / `{ok: False, error, ...}`). Handles "app-server
    unavailable" gracefully.
    """
    sid = (session_id or "").strip()
    if not sid:
        return {"ok": False, "via": "codex-compact", "error": "missing session_id"}
    if os.environ.get("CCC_CODEX_APP_SERVER", "1").lower() in ("0", "false", "no"):
        return {
            "ok": False,
            "via": "codex-compact",
            "code": "codex_compact_unavailable",
            "error": "Codex app-server disabled",
        }
    # The thread must be loaded into this app-server before it can be compacted.
    resume_params = {"threadId": sid, "excludeTurns": False}
    if cwd:
        resume_params["cwd"] = cwd
    if model:
        resume_params["model"] = model
    resumed = _codex_app_server_request("thread/resume", resume_params, timeout=20)
    if resumed.get("error"):
        return {
            "ok": False,
            "via": "codex-compact",
            "code": "codex_compact_unavailable",
            "error": _codex_error_text(resumed),
        }
    if resumed.get("ok") is False and "result" not in resumed:
        # `_codex_app_server_request` short-circuit (unavailable / timeout).
        return {
            "ok": False,
            "via": "codex-compact",
            "code": "codex_compact_unavailable",
            "error": resumed.get("error") or "Codex app-server unavailable",
        }
    compacted = _codex_app_server_request(
        "thread/compact/start", {"threadId": sid}, timeout=60
    )
    if _codex_response_succeeded(compacted):
        return {
            "ok": True,
            "via": "codex-compact",
            "session_id": sid,
        }
    if compacted.get("ok") is False and "result" not in compacted:
        return {
            "ok": False,
            "via": "codex-compact",
            "code": "codex_compact_unavailable",
            "error": compacted.get("error") or "Codex app-server unavailable",
        }
    return {
        "ok": False,
        "via": "codex-compact",
        "code": "codex_compact_failed",
        "error": _codex_error_text(compacted) or "Codex compact failed",
    }


def _codex_goal_via_app_server(session_id, action, objective=None, cwd=None):
    """Set, clear, pause, or resume a Codex thread goal.

    `action` is "clear" (-> `thread/goal/clear`, params `{threadId}`) or "set"
    (-> `thread/goal/set`, params `{threadId, objective}`). This is the non-live
    fallback for `/goal clear` / `/goal <objective>`: the codex `goals` feature
    is native, but its slash command only runs in a live TUI. The RPCs let CCC
    drive the same native goal store for a dormant thread — mirrors
    `_codex_compact_via_app_server` (`thread/compact/start`).

    The app-server RPC currently reports success without always updating the
    local goals sqlite used by Codex/CCC, so CCC verifies the same native store
    directly under a file lock. Pause/resume have no app-server RPC; they are
    direct status updates.
    """
    sid = (session_id or "").strip()
    if not sid:
        return {"ok": False, "via": "codex-goal", "error": "missing session_id"}
    action = (action or "").strip().lower()
    if action not in ("clear", "set", "pause", "resume"):
        return {
            "ok": False,
            "via": "codex-goal",
            "code": "codex_goal_unsupported_action",
            "error": f"unsupported goal action: {action!r}",
        }
    if action == "set" and not (objective or "").strip():
        return {
            "ok": False,
            "via": "codex-goal",
            "code": "codex_goal_empty_objective",
            "error": "Goal objective must not be empty.",
        }
    app_server_ok = False
    if action in ("clear", "set") and os.environ.get("CCC_CODEX_APP_SERVER", "1").lower() not in ("0", "false", "no"):
        # Best-effort: let Codex handle any side effects it knows about, then
        # enforce the durable store CCC actually reads below.
        resume_params = {"threadId": sid, "excludeTurns": False}
        if cwd:
            resume_params["cwd"] = cwd
        resumed = _codex_app_server_request("thread/resume", resume_params, timeout=20)
        if not (resumed.get("error") or (resumed.get("ok") is False and "result" not in resumed)):
            if action == "clear":
                rpc_method = "thread/goal/clear"
                rpc_params = {"threadId": sid}
            else:
                rpc_method = "thread/goal/set"
                rpc_params = {"threadId": sid, "objective": objective.strip()}
            result = _codex_app_server_request(rpc_method, rpc_params, timeout=30)
            app_server_ok = _codex_response_succeeded(result)

    store = _codex_goal_store_update(sid, action, objective=objective)
    if store.get("ok"):
        store.setdefault("engine", "codex")
        store["app_server_ok"] = app_server_ok
        return store
    return {
        "ok": False,
        "via": "codex-goal",
        "code": store.get("code") or "codex_goal_failed",
        "engine": "codex",
        "error": store.get("error") or f"Codex goal {action} failed",
        "app_server_ok": app_server_ok,
    }


def _codex_grab_back_settings_params(session_id, cwd=None, model=None, reasoning_effort=None):
    params = {
        "threadId": session_id,
        "approvalPolicy": "never",
        "approvalsReviewer": "user",
        "sandboxPolicy": {"type": "dangerFullAccess"},
    }
    if cwd:
        params["cwd"] = cwd
    if model:
        params["model"] = model
    if reasoning_effort:
        params["effort"] = reasoning_effort
    return params


def _codex_grab_back_via_app_server(
    session_id, cwd=None, model=None, reasoning_effort=None, deny_pending_approval=False
):
    sid = (session_id or "").strip()
    if not sid:
        return {"ok": False, "via": "codex-grab-back", "error": "missing session_id"}
    if os.environ.get("CCC_CODEX_APP_SERVER", "1").lower() in ("0", "false", "no"):
        return {
            "ok": False,
            "via": "codex-grab-back",
            "code": "codex_grab_back_unavailable",
            "error": "Codex app-server disabled",
        }
    if not cwd:
        cwd = find_session_cwd(sid)
    # If the thread is dead-ended on an in-flight approval that this reclaim is
    # meant to escape, decline it first — otherwise the stuck "Needs approval"
    # prompt can survive the interrupt + settings-reapply below. Only attempt
    # when a pending approval actually exists; best-effort (an externally-owned
    # approval with no app-server request id simply can't be answered here).
    approval_denied = False
    approval_decline = None
    if deny_pending_approval:
        with _CODEX_APP_SERVER_LOCK:
            state = _CODEX_APP_SERVER_THREAD_STATE.get(sid) if sid else None
            has_pending = _codex_app_server_pending_approval_item(state or {}) is not None
        if has_pending:
            approval_decline = _codex_app_server_resolve_approval(sid, "decline")
            approval_denied = bool(approval_decline.get("ok"))
    settings_params = _codex_grab_back_settings_params(
        sid,
        cwd=cwd,
        model=model,
        reasoning_effort=reasoning_effort,
    )
    _codex_app_server_refresh_thread_status(sid, max_age=0)
    settings_response = _codex_app_server_request(
        "thread/settings/update",
        settings_params,
        timeout=10,
    )
    settings_ok = _codex_response_succeeded(settings_response)
    interrupt = _codex_interrupt_via_app_server(sid, cwd=cwd)
    no_active_turn = (interrupt.get("code") == "codex_no_active_turn")
    _codex_app_server_refresh_thread_status(sid, max_age=0)
    public = _codex_app_server_thread_public_status(sid)
    ok = bool(settings_ok or interrupt.get("ok") or no_active_turn or approval_denied)
    result = {
        "ok": ok,
        "via": "codex-grab-back",
        "session_id": sid,
        "settings_applied": bool(settings_ok),
        "interrupted": bool(interrupt.get("ok")),
        "no_active_turn": bool(no_active_turn),
        "approval_denied": bool(approval_denied),
        "codex_app_server": _codex_app_server_is_live(),
        "codex_app_server_transport": _codex_app_server_transport_kind(),
        "codex_managed_app_server": _codex_app_server_transport_kind() == "managed",
        "codex_app_server_active_item": public.get("active_item"),
        "codex_app_server_token_usage": public.get("token_usage"),
    }
    if cwd:
        result["cwd"] = cwd
    if approval_decline is not None and not approval_denied:
        result["approval_decline_error"] = approval_decline.get("error") or "approval decline failed"
    if not settings_ok:
        result["settings_error"] = _codex_app_server_response_error(
            settings_response,
            "Codex app-server did not apply thread settings",
        )
    if interrupt:
        result["interrupt"] = interrupt
        if interrupt.get("error") and not interrupt.get("ok") and not no_active_turn:
            result["interrupt_error"] = interrupt.get("error")
    if not ok:
        result["error"] = (
            result.get("interrupt_error")
            or result.get("settings_error")
            or "Codex grab-back failed"
        )
        result.setdefault("code", "codex_grab_back_failed")
    return result


def _codex_interrupt_via_app_server(session_id, cwd=None):
    if os.environ.get("CCC_CODEX_APP_SERVER", "1").lower() in ("0", "false", "no"):
        return {
            "ok": False,
            "via": "codex-app-interrupt",
            "code": "codex_interrupt_unavailable",
            "error": "Codex app-server disabled",
        }
    if not _codex_app_server_is_live() and not (
        _codex_managed_app_server_enabled() and _codex_managed_app_server_socket_path().exists()
    ):
        return {
            "ok": False,
            "via": "codex-app-interrupt",
            "code": "codex_interrupt_unavailable",
            "error": "Codex app-server unavailable",
        }
    resume_params = {"threadId": session_id, "excludeTurns": False}
    if cwd:
        resume_params["cwd"] = cwd
    resumed = _codex_app_server_request("thread/resume", resume_params, timeout=10)
    thread = ((resumed.get("result") or {}).get("thread") or {})
    active_turn = _codex_latest_active_turn(thread)
    turn_id = (active_turn or {}).get("id") or _codex_app_server_thread_state(session_id).get("active_turn_id")
    status = ((thread.get("status") or {}).get("type") or "").lower()
    authoritative_idle = bool(
        _codex_response_succeeded(resumed)
        and status
        and status != "active"
        and not active_turn
    )
    if authoritative_idle:
        _codex_reconcile_thread_idle(session_id)
        turn_id = None
    if not turn_id or authoritative_idle:
        return {
            "ok": False,
            "via": "codex-app-interrupt",
            "code": "codex_no_active_turn",
            "error": "No running Codex turn to interrupt",
        }
    interrupted = _codex_app_server_request(
        "turn/interrupt",
        {"threadId": session_id, "turnId": turn_id},
        timeout=10,
    )
    if _codex_response_succeeded(interrupted):
        return {
            "ok": True,
            "via": "codex-app-interrupt",
            "turn_id": turn_id,
            "session_id": session_id,
        }
    return {
        "ok": False,
        "via": "codex-app-interrupt",
        "code": "codex_interrupt_failed",
        "error": _codex_error_text(interrupted) or interrupted.get("error") or "Codex interrupt failed",
    }


def _codex_state_db_candidates():
    """Existing Codex state DB paths, newest known schema first."""
    base = Path.home() / ".codex"
    candidates = [CODEX_STATE_DB]
    try:
        if base.is_dir():
            for p in sorted(base.glob("state*.sqlite"), key=lambda x: x.name, reverse=True):
                if p not in candidates:
                    candidates.append(p)
    except OSError:
        pass
    return [p for p in candidates if p.is_file()]


def _jsonl_line_ending(line):
    if line.endswith("\r\n"):
        return "\r\n"
    if line.endswith("\n"):
        return "\n"
    return ""


def _mark_codex_rollout_user_visible(thread_id, rollout_path):
    sid = str(thread_id or "").strip()
    if not sid or not rollout_path:
        return False
    try:
        path = Path(rollout_path).expanduser().resolve()
    except (OSError, RuntimeError, ValueError):
        return False
    if not path.is_file():
        return False
    try:
        original_stat = path.stat()
    except OSError:
        return False
    try:
        lines = path.read_text(encoding="utf-8").splitlines(keepends=True)
    except OSError:
        return False

    changed = False
    for idx, line in enumerate(lines):
        text = line.strip()
        if not text:
            continue
        try:
            obj = json.loads(text)
        except json.JSONDecodeError:
            continue
        if obj.get("type") != "session_meta":
            continue
        payload = obj.get("payload")
        if not isinstance(payload, dict):
            return False
        meta_id = str(payload.get("id") or "").strip()
        if meta_id and meta_id != sid:
            return False
        source = payload.get("source")
        thread_source = payload.get("thread_source")
        if source and source not in ("exec", "cli", "vscode"):
            return False
        if thread_source and thread_source != "user":
            return False
        if source != "vscode":
            payload["source"] = "vscode"
            changed = True
        if thread_source != "user":
            payload["thread_source"] = "user"
            changed = True
        if not changed:
            return True
        ending = _jsonl_line_ending(line)
        lines[idx] = json.dumps(obj, ensure_ascii=False, separators=(",", ":")) + ending
        break
    else:
        return False

    try:
        tmp = path.with_name(f"{path.name}.tmp-{os.getpid()}")
        tmp.write_text("".join(lines), encoding="utf-8")
        os.replace(tmp, path)
        os.utime(path, ns=(original_stat.st_atime_ns, original_stat.st_mtime_ns))
    except OSError:
        return False
    return True


def _codex_row_updated_epoch(row):
    if not isinstance(row, dict):
        return None
    for key, scale in (("updated_at_ms", 1000.0), ("updated_at", 1.0)):
        try:
            raw = row.get(key)
            if raw is None:
                continue
            value = float(raw) / scale
            if value > 0:
                return value
        except (TypeError, ValueError):
            continue
    return None


def _restore_codex_rollout_mtime_from_row(row):
    path = _codex_rollout_path_from_row(row)
    ts = _codex_row_updated_epoch(row)
    if not path or ts is None:
        return False
    try:
        p = Path(path).expanduser().resolve()
        if not p.is_file():
            return False
        os.utime(p, (ts, ts))
        return True
    except (OSError, RuntimeError, ValueError):
        return False


def _mark_codex_thread_user_visible(thread_id, update_rollout=True):
    """Mark a CCC-created Codex exec thread as visible in Codex.app.

    Codex Desktop starts sidebar-visible threads with `thread_source='user'`.
    Its sidebar also treats IDE-originated rows as `source='vscode'`; plain
    `codex exec` rows can otherwise stay hidden. Codex can rebuild SQLite from
    the rollout JSONL, so we patch the rollout metadata when it is safe too.
    """
    sid = str(thread_id or "").strip()
    if not sid:
        return False
    for db in _codex_state_db_candidates():
        con = None
        try:
            con = sqlite3.connect(f"file:{db}?mode=rw", uri=True, timeout=0.25)
            cols = {
                row[1]
                for row in con.execute("PRAGMA table_info(threads)").fetchall()
            }
            if "id" not in cols or "thread_source" not in cols:
                continue
            selected = ["thread_source"]
            if "source" in cols:
                selected.append("source")
            if "rollout_path" in cols:
                selected.append("rollout_path")
            row = con.execute(
                f"SELECT {', '.join(selected)} FROM threads WHERE id = ?",
                (sid,),
            ).fetchone()
            if not row:
                continue
            values_by_col = dict(zip(selected, row))
            current = values_by_col.get("thread_source")
            source = values_by_col.get("source", "vscode")
            if current and current != "user":
                return False
            if source and source not in ("exec", "cli", "vscode"):
                return False
            if update_rollout:
                _mark_codex_rollout_user_visible(
                    sid,
                    values_by_col.get("rollout_path"),
                )
            assignments = []
            values = []
            if current != "user":
                assignments.append("thread_source = ?")
                values.append("user")
            if "source" in cols and source != "vscode":
                assignments.append("source = ?")
                values.append("vscode")
            if assignments:
                values.append(sid)
                con.execute(
                    f"UPDATE threads SET {', '.join(assignments)} WHERE id = ?",
                    tuple(values),
                )
                con.commit()
            return True
        except sqlite3.Error:
            continue
        finally:
            if con is not None:
                try:
                    con.close()
                except sqlite3.Error:
                    pass
    return False


def _sync_codex_thread_title(thread_id, title):
    """Mirror a CCC user rename into Codex's user-facing thread title.

    Keep `first_user_message` intact as provenance; Codex mobile/sidebar list
    uses the shorter `title`/`preview` fields when present.
    """
    sid = str(thread_id or "").strip()
    name = _truncate_session_name(title)
    if not sid or not name:
        return False
    for db in _codex_state_db_candidates():
        con = None
        try:
            con = sqlite3.connect(f"file:{db}?mode=rw", uri=True, timeout=0.25)
            cols = {
                row[1]
                for row in con.execute("PRAGMA table_info(threads)").fetchall()
            }
            if "id" not in cols or "title" not in cols:
                continue
            assignments = ["title = ?"]
            values = [name]
            if "preview" in cols:
                assignments.append("preview = ?")
                values.append(name)
            values.append(sid)
            cur = con.execute(
                f"UPDATE threads SET {', '.join(assignments)} WHERE id = ?",
                tuple(values),
            )
            con.commit()
            if cur.rowcount:
                return True
        except sqlite3.Error:
            continue
        finally:
            if con is not None:
                try:
                    con.close()
                except sqlite3.Error:
                    pass
    return False


_codex_visibility_retry_sids = set()
_codex_visibility_retry_lock = threading.Lock()


def _schedule_codex_visibility_retry(session_id, spawn_entry=None, attempts=60, delay=1.0):
    sid = str(session_id or "").strip()
    if not sid:
        return False
    with _codex_visibility_retry_lock:
        if sid in _codex_visibility_retry_sids:
            return False
        _codex_visibility_retry_sids.add(sid)

    entry = dict(spawn_entry or {})

    def worker():
        try:
            for _idx in range(max(1, int(attempts or 1))):
                if _mark_codex_thread_user_visible(sid, update_rollout=True):
                    _register_codex_sidebar_project_for_spawn_entry(entry, sid)
                    return
                time.sleep(max(0.05, float(delay or 0.5)))
        except Exception:
            pass
        finally:
            with _codex_visibility_retry_lock:
                _codex_visibility_retry_sids.discard(sid)

    threading.Thread(
        target=worker,
        daemon=True,
        name=f"ccc-codex-visible-{sid[:8]}",
    ).start()
    return True


def _codex_fetch_threads(where="", params=(), limit=None):
    """Read rows from Codex's local thread index without creating files.

    Codex stores durable conversation metadata in ~/.codex/state_*.sqlite,
    with each row pointing at a rollout JSONL. We open SQLite in read-only URI
    mode so a dashboard scan cannot create a missing DB or mutate state.
    """
    for db in _codex_state_db_candidates():
        try:
            con = sqlite3.connect(f"file:{db}?mode=ro", uri=True, timeout=0.25)
            con.row_factory = sqlite3.Row
        except sqlite3.Error:
            continue
        try:
            cols = {
                row["name"]
                for row in con.execute("PRAGMA table_info(threads)").fetchall()
            }
            if not cols:
                continue
            wanted = [
                "id", "rollout_path", "created_at", "updated_at",
                "created_at_ms", "updated_at_ms", "source", "model_provider",
                "cwd", "title", "tokens_used", "has_user_event", "archived",
                "archived_at", "git_sha", "git_branch", "git_origin_url",
                "cli_version", "first_user_message", "agent_nickname",
                "agent_path", "agent_role", "memory_mode", "model", "reasoning_effort",
                "thread_source",
            ]
            selected = [c for c in wanted if c in cols]
            if "id" not in selected:
                return []
            order_terms = []
            if "updated_at_ms" in cols:
                order_terms.append("updated_at_ms")
            if "updated_at" in cols:
                order_terms.append("updated_at * 1000")
            if "created_at_ms" in cols:
                order_terms.append("created_at_ms")
            if "created_at" in cols:
                order_terms.append("created_at * 1000")
            order = f"COALESCE({', '.join(order_terms)}) DESC" if order_terms else "id DESC"
            sql = f"SELECT {', '.join(selected)} FROM threads"
            if where:
                sql += f" WHERE {where}"
            sql += f" ORDER BY {order}"
            if limit:
                sql += " LIMIT ?"
                params = tuple(params) + (int(limit),)
            rows = [dict(r) for r in con.execute(sql, tuple(params)).fetchall()]
            return rows
        except sqlite3.Error:
            continue
        finally:
            try:
                con.close()
            except sqlite3.Error:
                pass
    return []


def _codex_spawn_parent_by_child():
    """Map each spawned Codex thread to the thread that spawned it.

    Codex records sub-agent spawns in ~/.codex/state_*.sqlite's
    `thread_spawn_edges` (parent_thread_id, child_thread_id). CCC uses this to
    set parent_session_id on a spawned agent's row so it nests under its parent
    in the Current-sessions tree — a "one job, many agents" fan-out (a fixer
    plus reviewers) then reads as one cluster instead of a pile of loose rows.
    Read-only; tolerant of the table being absent on older Codex builds.
    Returns {child_thread_id: parent_thread_id}. (CCC-298)
    """
    out = {}
    for db in _codex_state_db_candidates():
        try:
            con = sqlite3.connect(f"file:{db}?mode=ro", uri=True, timeout=0.25)
            con.row_factory = sqlite3.Row
        except sqlite3.Error:
            continue
        try:
            has_table = con.execute(
                "SELECT name FROM sqlite_master "
                "WHERE type='table' AND name='thread_spawn_edges'"
            ).fetchone()
            if not has_table:
                continue
            for r in con.execute(
                "SELECT parent_thread_id, child_thread_id FROM thread_spawn_edges"
            ).fetchall():
                child = (r["child_thread_id"] or "").strip()
                parent = (r["parent_thread_id"] or "").strip()
                # First edge wins (DBs scanned newest-first); never self-parent.
                if child and parent and child != parent:
                    out.setdefault(child, parent)
        except sqlite3.Error:
            continue
        finally:
            try:
                con.close()
            except sqlite3.Error:
                pass
    return out


_codex_goals_cache = {"key": None, "data": {}, "ts": 0.0}
_codex_goals_lock = threading.Lock()
_CODEX_GOALS_TTL = 2.0


def _codex_goals_db_path():
    """Newest existing goals sqlite among the known candidates, or None."""
    best = None
    best_mtime = -1.0
    for cand in CODEX_GOALS_DB_CANDIDATES:
        try:
            st = cand.stat()
        except OSError:
            continue
        if st.st_mtime > best_mtime:
            best_mtime = st.st_mtime
            best = cand
    return best


def _invalidate_codex_goals_cache():
    with _codex_goals_lock:
        _codex_goals_cache["key"] = None
        _codex_goals_cache["data"] = {}
        _codex_goals_cache["ts"] = 0.0


def _codex_goal_store_update(session_id, action, objective=None):
    """Mutate Codex's native goals sqlite under a file lock.

    The Codex app-server goal RPC is not a reliable postcondition on every
    transport/version: it can return a JSON-RPC result while the `thread_goals`
    row CCC and Codex read remains unchanged. This helper writes the same store
    directly for dormant-thread `/goal` actions.
    """
    sid = str(session_id or "").strip()
    action = str(action or "").strip().lower()
    if not sid:
        return {"ok": False, "via": "codex-goal-store", "error": "missing session_id"}
    if action not in ("clear", "set", "pause", "resume"):
        return {
            "ok": False,
            "via": "codex-goal-store",
            "code": "codex_goal_unsupported_action",
            "error": f"unsupported goal action: {action!r}",
        }
    obj = str(objective or "").strip()
    if action == "set" and not obj:
        return {
            "ok": False,
            "via": "codex-goal-store",
            "code": "codex_goal_empty_objective",
            "error": "Goal objective must not be empty.",
        }
    db = _codex_goals_db_path() or CODEX_GOALS_DB_CANDIDATES[0]
    lock_path = db.with_suffix(db.suffix + ".lock")
    con = None
    lock_fh = None
    try:
        db.parent.mkdir(parents=True, exist_ok=True)
        lock_fh = lock_path.open("a+")
        fcntl.flock(lock_fh.fileno(), fcntl.LOCK_EX)
        con = sqlite3.connect(f"file:{db}?mode=rwc", uri=True, timeout=5.0)
        con.execute(
            """
            CREATE TABLE IF NOT EXISTS thread_goals (
              thread_id TEXT PRIMARY KEY NOT NULL,
              goal_id TEXT NOT NULL,
              objective TEXT NOT NULL,
              status TEXT NOT NULL,
              token_budget INTEGER,
              tokens_used INTEGER NOT NULL DEFAULT 0,
              time_used_seconds INTEGER NOT NULL DEFAULT 0,
              created_at_ms INTEGER NOT NULL,
              updated_at_ms INTEGER NOT NULL
            )
            """
        )
        cols = {r[1] for r in con.execute("PRAGMA table_info(thread_goals)").fetchall()}
        required = {"thread_id", "goal_id", "objective", "status", "created_at_ms", "updated_at_ms"}
        if not required.issubset(cols):
            return {
                "ok": False,
                "via": "codex-goal-store",
                "code": "codex_goal_schema_unsupported",
                "error": "Codex goals DB schema is not supported.",
            }
        now_ms = int(time.time() * 1000)
        if action == "clear":
            con.execute("DELETE FROM thread_goals WHERE thread_id = ?", (sid,))
            con.commit()
            _invalidate_codex_goals_cache()
            return {"ok": True, "via": "codex-goal-store", "action": "clear", "session_id": sid}

        if action == "set":
            existing = con.execute(
                "SELECT goal_id, created_at_ms FROM thread_goals WHERE thread_id = ?",
                (sid,),
            ).fetchone()
            goal_id = existing[0] if existing and existing[0] else str(uuid.uuid4())
            created_at_ms = int(existing[1]) if existing and existing[1] else now_ms
            con.execute(
                """
                INSERT INTO thread_goals (
                  thread_id, goal_id, objective, status, token_budget,
                  tokens_used, time_used_seconds, created_at_ms, updated_at_ms
                )
                VALUES (?, ?, ?, 'active', NULL, 0, 0, ?, ?)
                ON CONFLICT(thread_id) DO UPDATE SET
                  goal_id = excluded.goal_id,
                  objective = excluded.objective,
                  status = 'active',
                  token_budget = excluded.token_budget,
                  tokens_used = 0,
                  time_used_seconds = 0,
                  updated_at_ms = excluded.updated_at_ms
                """,
                (sid, goal_id, obj, created_at_ms, now_ms),
            )
            con.commit()
            _invalidate_codex_goals_cache()
            return {"ok": True, "via": "codex-goal-store", "action": "set", "session_id": sid}

        status = "active" if action == "resume" else "paused"
        cur = con.execute(
            "UPDATE thread_goals SET status = ?, updated_at_ms = ? WHERE thread_id = ?",
            (status, now_ms, sid),
        )
        con.commit()
        if cur.rowcount <= 0:
            return {
                "ok": False,
                "via": "codex-goal-store",
                "code": "codex_goal_missing",
                "error": "No Codex goal exists for this thread.",
            }
        _invalidate_codex_goals_cache()
        return {"ok": True, "via": "codex-goal-store", "action": action, "session_id": sid}
    except (OSError, sqlite3.Error, ValueError) as e:
        return {
            "ok": False,
            "via": "codex-goal-store",
            "code": "codex_goal_store_failed",
            "error": str(e) or "Codex goal store update failed.",
        }
    finally:
        if con is not None:
            try:
                con.close()
            except sqlite3.Error:
                pass
        if lock_fh is not None:
            try:
                fcntl.flock(lock_fh.fileno(), fcntl.LOCK_UN)
                lock_fh.close()
            except OSError:
                pass


def _codex_goals_snapshot():
    """Map thread_id -> {objective, status, token_budget, tokens_used} for every
    codex thread that currently has a goal.

    ONE batched read of ~/.codex/goals_1.sqlite, cached by (path, mtime, size)
    with a short TTL so a full conversation build does at most one stat+read
    regardless of row count (perf gate: never per-row). Returns {} when no
    goals DB exists or it's empty — codex clears the row on `/goal clear`.
    """
    now = time.monotonic()
    with _codex_goals_lock:
        cached_ts = _codex_goals_cache["ts"]
        cached_key = _codex_goals_cache["key"]
        cached_data = _codex_goals_cache["data"]
    db = _codex_goals_db_path()
    if db is None:
        with _codex_goals_lock:
            _codex_goals_cache["key"] = None
            _codex_goals_cache["data"] = {}
            _codex_goals_cache["ts"] = now
        return {}
    try:
        st = db.stat()
        key = (str(db), st.st_mtime, st.st_size)
    except OSError:
        return cached_data if cached_key else {}
    if cached_key == key and (now - cached_ts) < _CODEX_GOALS_TTL:
        return cached_data
    data = {}
    try:
        con = sqlite3.connect(f"file:{db}?mode=ro", uri=True, timeout=0.25)
        con.row_factory = sqlite3.Row
    except sqlite3.Error:
        return cached_data if cached_key else {}
    try:
        cols = {r["name"] for r in con.execute("PRAGMA table_info(thread_goals)").fetchall()}
        if "thread_id" in cols and "objective" in cols:
            sel = [c for c in ("thread_id", "objective", "status",
                               "token_budget", "tokens_used") if c in cols]
            for r in con.execute(f"SELECT {', '.join(sel)} FROM thread_goals").fetchall():
                tid = r["thread_id"]
                obj = (r["objective"] or "").strip() if "objective" in sel else ""
                if not tid or not obj:
                    continue
                data[tid] = {
                    "objective": obj,
                    "status": (r["status"] or "").strip() if "status" in sel else "",
                    "token_budget": r["token_budget"] if "token_budget" in sel else None,
                    "tokens_used": r["tokens_used"] if "tokens_used" in sel else None,
                }
    except sqlite3.Error:
        data = cached_data if cached_key else {}
    finally:
        try:
            con.close()
        except sqlite3.Error:
            pass
    with _codex_goals_lock:
        _codex_goals_cache["key"] = key
        _codex_goals_cache["data"] = data
        _codex_goals_cache["ts"] = now
    return data


def _codex_thread_row(thread_id):
    if not thread_id:
        return None
    rows = _codex_fetch_threads("id = ?", (thread_id,), limit=1)
    return rows[0] if rows else None


def _codex_agent_path(row):
    raw = str((row or {}).get("agent_path") or "").strip()
    if raw:
        return raw
    source = (row or {}).get("source")
    if not isinstance(source, str) or not source.strip().startswith("{"):
        return ""
    try:
        data = json.loads(source)
    except (TypeError, ValueError, json.JSONDecodeError):
        return ""
    if not isinstance(data, dict):
        return ""
    subagent = data.get("subagent")
    if not isinstance(subagent, dict):
        return ""
    spawn = subagent.get("thread_spawn")
    if not isinstance(spawn, dict):
        return ""
    return str(spawn.get("agent_path") or "").strip()


def _codex_agent_task_label(row):
    path = _codex_agent_path(row).rstrip("/")
    leaf = path.rsplit("/", 1)[-1].strip() if path else ""
    if not leaf or leaf.lower() in ("root", "agent", "subagent"):
        return ""
    label = re.sub(r"[_-]+", " ", leaf).strip()
    label = re.sub(
        r"^([A-Za-z][A-Za-z0-9]*)\s+(\d+)(?=\s|$)",
        lambda m: f"{m.group(1).upper()}-{m.group(2)}",
        label,
    )
    if label and not re.match(r"^[A-Z]+-\d+", label):
        label = label[:1].upper() + label[1:]
    return _truncate_session_name(label) or ""


def _codex_display_name(row, override=None, title="", first_message=""):
    return (
        _truncate_session_name(override)
        or _truncate_session_name(title)
        or _truncate_session_name(first_message)
        or _codex_agent_task_label(row)
        or _truncate_session_name((row or {}).get("agent_nickname"))
    )


def _codex_ts_seconds(row, prefix="updated"):
    ms = row.get(f"{prefix}_at_ms")
    if ms:
        try:
            return float(ms) / 1000.0
        except (TypeError, ValueError):
            pass
    val = row.get(f"{prefix}_at")
    if val:
        try:
            val = float(val)
            return val / 1000.0 if val > 100000000000 else val
        except (TypeError, ValueError):
            pass
    return 0.0


def _codex_rollout_path_from_row(row):
    if not row:
        return None
    raw = row.get("rollout_path") or ""
    if raw:
        p = Path(os.path.expanduser(raw))
        if p.is_file():
            return p
    tid = row.get("id") or ""
    if tid and CODEX_SESSIONS_ROOT.is_dir():
        try:
            matches = list(CODEX_SESSIONS_ROOT.glob(f"**/*{tid}*.jsonl"))
        except OSError:
            matches = []
        if matches:
            matches.sort(key=lambda p: p.stat().st_mtime if p.exists() else 0, reverse=True)
            return matches[0]
    return None


def _resolve_codex_rollout_path(thread_id):
    row = _codex_thread_row(thread_id)
    return _codex_rollout_path_from_row(row)


def _is_codex_session(session_id):
    return bool(_codex_thread_row(session_id))


def _codex_tool_name(name):
    return (name or "").rsplit(".", 1)[-1]


def _codex_js_string_literal_value(literal):
    if not isinstance(literal, str) or not literal:
        return ""
    try:
        value = json.loads(literal)
        return value if isinstance(value, str) else ""
    except (json.JSONDecodeError, TypeError, ValueError):
        pass
    try:
        value = ast.literal_eval(literal)
        return value if isinstance(value, str) else ""
    except (SyntaxError, ValueError, TypeError):
        return literal.strip("\"'")


def _codex_custom_tool_arg(source, key):
    if not isinstance(source, str) or not source or not key:
        return ""
    # Handles the current Codex custom-tool JS body:
    #   tools.exec_command({ cmd: "...", sandbox_permissions: "..." })
    # It is intentionally small and best-effort; rollout remains authoritative.
    pattern = (
        r"(?<![A-Za-z0-9_$])(?:" + re.escape(key)
        + r'|"' + re.escape(key) + r'"|\'' + re.escape(key) + r"')"
        + r"\s*:\s*(?P<quote>[\"'])(?P<body>(?:\\.|(?!(?P=quote)).)*)(?P=quote)"
    )
    match = re.search(pattern, source, re.DOTALL)
    if not match:
        return ""
    return _codex_js_string_literal_value(match.group("quote") + match.group("body") + match.group("quote"))


def _codex_custom_tool_kind(source, fallback_name=""):
    text = source if isinstance(source, str) else ""
    if "tools.exec_command" in text:
        return "Bash"
    if "tools.apply_patch" in text:
        return "apply_patch"
    if "tools.update_plan" in text:
        return "update_plan"
    if "tools.write_stdin" in text:
        return "write_stdin"
    return _codex_tool_name(fallback_name) or "tool"


def _codex_custom_tool_detail(source, fallback_name=""):
    text = source if isinstance(source, str) else ""
    cmd = _codex_custom_tool_arg(text, "cmd") or _codex_custom_tool_arg(text, "command")
    if cmd:
        return _shell_command_activity_label(cmd)
    for key in ("path", "file_path", "filename", "query", "pattern", "prompt", "message"):
        value = _codex_custom_tool_arg(text, key)
        if value:
            return value
    return _codex_custom_tool_kind(text, fallback_name)


def _codex_custom_tool_command(source):
    text = source if isinstance(source, str) else ""
    return _codex_custom_tool_arg(text, "cmd") or _codex_custom_tool_arg(text, "command")


def _codex_custom_tool_workdir(source):
    return _codex_custom_tool_arg(source if isinstance(source, str) else "", "workdir")


def _codex_tool_requires_approval(name, args=None, raw_text=""):
    args = args if isinstance(args, dict) else {}
    sandbox = args.get("sandbox_permissions") or args.get("sandboxPermissions") or ""
    if str(sandbox) == "require_escalated":
        return True
    return _codex_custom_tool_arg(raw_text, "sandbox_permissions") == "require_escalated"


def _codex_tool_approval_message(args=None, raw_text=""):
    args = args if isinstance(args, dict) else {}
    for key in ("justification", "approval_prompt", "approvalPrompt"):
        value = args.get(key)
        if isinstance(value, str) and value.strip():
            return value.strip()
    return _codex_custom_tool_arg(raw_text, "justification").strip()


def _codex_args(raw):
    if isinstance(raw, dict):
        return raw
    if isinstance(raw, str) and raw:
        try:
            parsed = json.loads(raw)
            return parsed if isinstance(parsed, dict) else {}
        except (json.JSONDecodeError, ValueError):
            return {}
    return {}


def _codex_tool_detail(name, args):
    lname = _codex_tool_name(name)
    if lname == "exec_command":
        return _shell_command_activity_label(args.get("cmd") or args.get("command") or "")
    if lname == "write_stdin":
        return args.get("chars") or args.get("session_id") or ""
    for key in ("path", "file_path", "filename", "query", "pattern", "prompt", "message"):
        val = args.get(key)
        if isinstance(val, str) and val:
            return val
    return ""


def _codex_tool_command(name, args):
    lname = _codex_tool_name(name)
    if lname == "exec_command":
        cmd = args.get("cmd") or args.get("command") or ""
        return cmd if isinstance(cmd, str) else ""
    return ""


def _codex_tool_workdir(name, args):
    lname = _codex_tool_name(name)
    if lname == "exec_command":
        workdir = args.get("workdir") or ""
        return workdir if isinstance(workdir, str) else ""
    return ""


def _codex_event_epoch(ev):
    ts = ev.get("timestamp") or ""
    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
    ts = ts or payload.get("timestamp") or payload.get("started_at") or payload.get("completed_at") or ""
    if not ts:
        return 0.0
    try:
        return datetime.fromisoformat(str(ts).replace("Z", "+00:00")).timestamp()
    except (TypeError, ValueError):
        return 0.0


def _codex_event_timestamp(ev):
    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
    return ev.get("timestamp") or payload.get("timestamp") or payload.get("started_at") or ""


_SHELL_ASSIGNMENT_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*=")
_SHELL_WRAPPERS = {"command", "builtin", "exec", "noglob"}
_SHELLS = {"sh", "bash", "zsh"}
_GIT_OPTS_WITH_VALUE = {
    "-C",
    "-c",
    "--git-dir",
    "--work-tree",
    "--namespace",
    "--config-env",
    "--exec-path",
    "--super-prefix",
}
_GIT_OPTS_WITH_VALUE_PREFIXES = (
    "-C",
    "-c",
    "--git-dir=",
    "--work-tree=",
    "--namespace=",
    "--config-env=",
    "--exec-path=",
    "--super-prefix=",
)
_ENV_OPTS_WITH_VALUE = {"-u", "--unset", "-C", "--chdir", "-S", "--split-string"}
_SUDO_OPTS_WITH_VALUE = {"-u", "-g", "-h", "-p", "-C", "-T"}


def _shell_words(cmd):
    """Tokenize shell-ish command text without treating quoted text as code."""
    src = cmd or ""
    if "<<" not in src:
        src = src.replace("\n", " ; ")
    try:
        lex = shlex.shlex(src, posix=True, punctuation_chars=";&|")
        lex.whitespace_split = True
        return list(lex)
    except (TypeError, ValueError):
        try:
            return shlex.split(src)
        except ValueError:
            return src.split()


def _shell_segments(cmd):
    segment = []
    for tok in _shell_words(cmd):
        if tok and all(ch in ";&|" for ch in tok):
            if segment:
                yield segment
                segment = []
            continue
        segment.append(tok)
    if segment:
        yield segment


def _is_shell_assignment(tok):
    return bool(_SHELL_ASSIGNMENT_RE.match(tok or ""))


def _skip_sudo_options(tokens, i):
    while i < len(tokens) and tokens[i].startswith("-"):
        opt = tokens[i]
        if opt in _SUDO_OPTS_WITH_VALUE and i + 1 < len(tokens):
            i += 2
        else:
            i += 1
    return i


def _skip_env_options(tokens, i):
    while i < len(tokens):
        opt = tokens[i]
        if _is_shell_assignment(opt):
            i += 1
        elif opt in _ENV_OPTS_WITH_VALUE and i + 1 < len(tokens):
            i += 2
        elif opt.startswith("--unset=") or opt.startswith("--chdir="):
            i += 1
        elif opt.startswith("-"):
            i += 1
        else:
            break
    return i


def _shell_command_start(tokens):
    i = 0
    while i < len(tokens):
        tok = tokens[i]
        if _is_shell_assignment(tok) or tok in _SHELL_WRAPPERS:
            i += 1
            continue
        base = os.path.basename(tok)
        if base == "sudo":
            i = _skip_sudo_options(tokens, i + 1)
            continue
        if base == "env":
            i = _skip_env_options(tokens, i + 1)
            continue
        break
    return i


def _shell_nested_command(tokens, start):
    if start >= len(tokens) or os.path.basename(tokens[start]) not in _SHELLS:
        return None
    i = start + 1
    while i < len(tokens):
        tok = tokens[i]
        if tok == "--":
            i += 1
            continue
        if tok.startswith("-") and "c" in tok[1:]:
            return tokens[i + 1] if i + 1 < len(tokens) else None
        i += 1
    return None


def _resolve_shell_path(path, base_cwd=None):
    if not path:
        return None
    expanded = os.path.expanduser(path)
    if os.path.isabs(expanded):
        return os.path.abspath(expanded)
    base = os.path.expanduser(base_cwd) if base_cwd else os.getcwd()
    return os.path.abspath(os.path.join(base, expanded))


def _git_invocation(tokens, start, base_cwd=None):
    if start >= len(tokens) or os.path.basename(tokens[start]) != "git":
        return None
    used_dash_c = False
    dash_c_path = None
    i = start + 1
    while i < len(tokens):
        opt = tokens[i]
        if opt == "--":
            i += 1
            break
        if opt in _GIT_OPTS_WITH_VALUE and i + 1 < len(tokens):
            used_dash_c = used_dash_c or opt == "-C"
            if opt == "-C":
                dash_c_path = _resolve_shell_path(tokens[i + 1], base_cwd)
            i += 2
            continue
        if any(opt.startswith(prefix) and opt != prefix for prefix in _GIT_OPTS_WITH_VALUE_PREFIXES):
            used_dash_c = used_dash_c or opt.startswith("-C")
            if opt.startswith("-C"):
                dash_c_path = _resolve_shell_path(opt[2:], base_cwd)
            i += 1
            continue
        if opt.startswith("-"):
            i += 1
            continue
        break
    subcmd = tokens[i] if i < len(tokens) else ""
    return {
        "subcmd": subcmd,
        "subcmd_index": i,
        "used_dash_c": used_dash_c,
        "dash_c_path": dash_c_path,
    }


def _gh_pr_create(tokens, start):
    if start >= len(tokens) or os.path.basename(tokens[start]) != "gh":
        return False
    i = start + 1
    while i < len(tokens) and tokens[i].startswith("-"):
        opt = tokens[i]
        if opt in ("-R", "--repo", "--hostname") and i + 1 < len(tokens):
            i += 2
        else:
            i += 1
    return tokens[i:i + 2] == ["pr", "create"]


def _shell_command_signals(cmd, base_cwd=None, _depth=0):
    """Return edit/commit/push/pr/external-cd flags for a shell command."""
    cmd = cmd or ""
    worktree_path = None
    worktree_branch = None
    subcommands = set()
    pr_create = False
    external_cd = False
    for toks in _shell_segments(cmd):
        start = _shell_command_start(toks)
        if start >= len(toks):
            continue

        nested = _shell_nested_command(toks, start)
        if nested and _depth < 2:
            child = _shell_command_signals(nested, base_cwd=base_cwd, _depth=_depth + 1)
            subcommands.update(k for k in ("commit", "push") if child[k])
            pr_create = pr_create or child["pr"]
            external_cd = external_cd or child["external_cd"]
            worktree_path = child.get("worktree_path") or worktree_path
            worktree_branch = child.get("worktree_branch") or worktree_branch
            continue

        exe = os.path.basename(toks[start])
        if exe == "cd":
            target = toks[start + 1] if start + 1 < len(toks) else ""
            external_cd = external_cd or target.startswith("/") or target.startswith("~")
            continue

        git = _git_invocation(toks, start, base_cwd=base_cwd)
        if git:
            subcmd = git["subcmd"]
            if subcmd in ("commit", "push"):
                subcommands.add(subcmd)
            external_cd = external_cd or git["used_dash_c"]
            if subcmd == "worktree" and git["subcmd_index"] + 1 < len(toks):
                if toks[git["subcmd_index"] + 1] == "add":
                    branch = None
                    path = None
                    k = git["subcmd_index"] + 2
                    while k < len(toks):
                        part = toks[k]
                        if part in ("-b", "-B") and k + 1 < len(toks):
                            branch = toks[k + 1]
                            k += 2
                            continue
                        if part in ("--reason", "--lock") and k + 1 < len(toks):
                            k += 2
                            continue
                        if part == "--":
                            k += 1
                            continue
                        if part.startswith("-"):
                            k += 1
                            continue
                        path = part
                        break
                    if path:
                        path_base = git.get("dash_c_path") or base_cwd
                        worktree_path = _resolve_shell_path(path, path_base)
                        worktree_branch = branch or worktree_branch
            continue

        pr_create = pr_create or _gh_pr_create(toks, start)

    edit_like = bool(re.search(
        r"\b(apply_patch|tee|sed\s+-i|perl\s+-pi)\b|"
        r"(?:^|[\s;&|])cat\s+>|write_text\s*\(|"
        r"(?:^|[\s;&|])(?:printf|echo)\b[^;\n]*>\s*\S+",
        cmd,
    ))
    return {
        "edit": edit_like,
        "commit": "commit" in subcommands,
        "push": "push" in subcommands,
        "pr": pr_create,
        "external_cd": external_cd,
        "worktree_path": worktree_path,
        "worktree_branch": worktree_branch,
    }


def _codex_command_signals(cmd, base_cwd=None):
    return _shell_command_signals(cmd, base_cwd=base_cwd)


_CODEX_SUMMARY_BRANCH_RE = re.compile(r"(?im)^\s*(?:[-*]\s*)?Branch:\s*`?([^\r\n`]+?)`?\s*$")
_CODEX_SUMMARY_WORKTREE_RE = re.compile(r"(?im)^\s*(?:[-*]\s*)?Worktree:\s*`?([^\r\n`]+?)`?\s*$")


def _extract_codex_summary_signals(text, pr_url_re):
    """Extract final-summary PR/worktree fields from Codex prose."""
    out = {}
    if not isinstance(text, str) or not text:
        return out
    mp = pr_url_re.search(text)
    if mp:
        out["tail_pr_number"] = int(mp.group(2))
        out["tail_pr_url"] = (
            "https://github.com/" + mp.group(1) + "/pull/" + mp.group(2)
        )
    mb = _CODEX_SUMMARY_BRANCH_RE.search(text)
    if mb:
        branch = mb.group(1).strip().strip("`")
        if branch:
            out["tail_branch"] = branch
    mw = _CODEX_SUMMARY_WORKTREE_RE.search(text)
    if mw:
        worktree = mw.group(1).strip().strip("`")
        if worktree:
            out["tail_worktree_path"] = worktree
    return out


def _extract_codex_thread_id_from_log(log_path):
    if not log_path:
        return None
    try:
        with open(log_path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                line = line.strip()
                if not line or not line.startswith("{"):
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                if ev.get("type") == "thread.started" and ev.get("thread_id"):
                    return ev["thread_id"]
    except OSError:
        return None
    return None


def _codex_turn_failed_error_from_log(log_path):
    """Last `turn.failed` error message in a codex spawn/resume .log, or None.

    codex's own resumable rollout.jsonl never records turn.failed (only
    task_complete with last_agent_message:null) — the real reason a turn
    produced no visible text lives only in CCC's raw process capture. One
    spawn/resume invocation is one turn, so at most one turn.failed exists
    per log (CCC-424).
    """
    if not log_path:
        return None
    last_error = None
    try:
        with open(log_path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                line = line.strip()
                if not line or not line.startswith("{"):
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                if ev.get("type") == "turn.failed":
                    err = ev.get("error")
                    msg = err.get("message") if isinstance(err, dict) else None
                    if msg:
                        last_error = str(msg).strip()
    except OSError:
        return None
    return last_error


def _codex_logs_for_session(session_id):
    """Every CCC spawn/resume .log whose thread_id matches session_id, as
    (mtime, path) pairs sorted oldest-first.

    Scope the log search to the thread's own repository. Falling back to all
    recent Codex repositories made opening a silent result scan hundreds of
    unrelated worktrees before its transcript could render.
    """
    if not session_id:
        return []
    repo_paths = []
    row = _codex_thread_row(session_id) or {}
    cwd = row.get("cwd") or ""
    if cwd:
        try:
            repo = (
                _git_toplevel_for_existing_dir(cwd)
                or _nearest_marked_repo_dir(cwd)
                or str(Path(cwd).expanduser().resolve())
            )
        except (OSError, RuntimeError, ValueError):
            repo = ""
        if repo:
            repo_paths.append(repo)
    out = []
    for log in _recent_codex_ccc_log_paths(repo_paths=repo_paths):
        if _extract_codex_thread_id_from_log(log) != session_id:
            continue
        try:
            mtime = Path(log).stat().st_mtime
        except OSError:
            continue
        out.append((mtime, str(log)))
    out.sort(key=lambda item: item[0])
    return out


def _enrich_codex_no_agent_output_events(conversation_id, events):
    """Attach the real turn.failed error to codex 'no visible response'
    result events by correlating with CCC's raw spawn/resume .log capture
    (CCC-424). No-op, and cheap, when nothing in `events` is silent."""
    silent = [e for e in events if e.get("type") == "result" and e.get("no_agent_output")]
    if not silent:
        return events
    logs = _codex_logs_for_session(conversation_id)
    if not logs:
        return events
    for ev in silent:
        target_epoch = _iso_to_epoch(ev.get("ts")) or 0.0
        best_log = min(logs, key=lambda item: abs(item[0] - target_epoch))[1] if target_epoch else logs[-1][1]
        error = _codex_turn_failed_error_from_log(best_log)
        if error:
            ev["turn_failed_error"] = error[:400]
    return events


def _codex_sidebar_backfill_window_days():
    raw = os.environ.get("CCC_CODEX_SIDEBAR_BACKFILL_DAYS", "7")
    try:
        days = float(raw)
    except (TypeError, ValueError):
        days = 7.0
    return days if days > 0 else 7.0


def _spawn_registry_entry_epoch(entry):
    raw = (entry or {}).get("spawned_at") or (entry or {}).get("started")
    if not raw:
        return 0.0
    text = str(raw).strip()
    try:
        return datetime.strptime(text, "%Y%m%dT%H%M%S").timestamp()
    except ValueError:
        pass
    try:
        return datetime.fromisoformat(text.replace("Z", "+00:00")).timestamp()
    except ValueError:
        return 0.0


def _codex_registry_entry_epoch(entry):
    return _spawn_registry_entry_epoch(entry)


def _recent_codex_thread_repo_paths(days=None, now=None, limit=1000):
    if days is None:
        days = _codex_sidebar_backfill_window_days()
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    out = []
    rows = _codex_fetch_threads(limit=limit)
    for row in rows:
        ts = _codex_ts_seconds(row, "updated") or _codex_ts_seconds(row, "created")
        if ts and ts < cutoff:
            break
        cwd = row.get("cwd") or ""
        if not cwd:
            continue
        try:
            repo = (
                _git_toplevel_for_existing_dir(cwd)
                or _nearest_marked_repo_dir(cwd)
                or str(Path(cwd).expanduser().resolve())
            )
        except (OSError, RuntimeError, ValueError):
            continue
        if repo:
            out.append(repo)
    return out


def _recent_codex_ccc_log_paths(repo_paths=None, days=None, now=None, max_logs=2000):
    """Recent CCC Codex spawn/resume logs, bounded to known repos."""
    if days is None:
        days = _codex_sidebar_backfill_window_days()
    try:
        max_logs = max(1, int(max_logs or 2000))
    except (TypeError, ValueError):
        max_logs = 2000
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    raw_paths = []
    try:
        for entry in _load_spawn_registry():
            if entry.get("engine") == "codex" and entry.get("log"):
                raw_paths.append(entry.get("log"))
    except Exception:
        pass
    if repo_paths is None:
        try:
            repo_paths = [
                *_known_repo_paths(),
                *_recent_codex_thread_repo_paths(days=days, now=now),
            ]
        except Exception:
            repo_paths = []
    for repo_path in repo_paths or []:
        try:
            log_dir = repo_log_dir(repo_path)
        except Exception:
            continue
        if not log_dir.is_dir():
            continue
        for pattern in ("spawn-codex-*.log", "resume-codex-*.log"):
            try:
                raw_paths.extend(log_dir.glob(pattern))
            except OSError:
                continue

    seen = set()
    recent = []
    for raw in raw_paths:
        try:
            p = Path(raw).expanduser().resolve()
            key = str(p)
            if key in seen:
                continue
            seen.add(key)
            st = p.stat()
        except (OSError, ValueError, RuntimeError):
            continue
        if st.st_mtime < cutoff:
            continue
        recent.append((st.st_mtime, p))
    recent.sort(key=lambda item: item[0], reverse=True)
    return [p for _, p in recent[:max_logs]]


def _codex_sidebar_project_root_for_thread(row):
    cwd = (row or {}).get("cwd") or ""
    if not cwd:
        return None
    try:
        root = (
            _git_toplevel_for_existing_dir(cwd)
            or _nearest_marked_repo_dir(cwd)
            or str(Path(cwd).expanduser().resolve())
        )
    except (OSError, RuntimeError, ValueError):
        return None
    try:
        p = Path(root).expanduser().resolve()
    except (OSError, RuntimeError, ValueError):
        return None
    return str(p) if p.is_dir() else None


def _codex_sidebar_project_roots_from_values(repo_paths):
    roots = []
    seen = set()
    for repo in repo_paths or []:
        try:
            root = str(Path(repo).expanduser().resolve())
        except (OSError, RuntimeError, ValueError):
            continue
        if root in seen or not Path(root).is_dir():
            continue
        seen.add(root)
        roots.append(root)
    return roots


def _codex_backfill_candidate_rows(days=None, repo_paths=None, now=None, limit=1000):
    """Recent Codex exec/cli rows that can be made sidebar-visible.

    This complements CCC spawn logs: the Codex DB is the durable index, while
    old CCC logs/registry entries can be pruned or missed. Keep the candidate
    set narrow so we only rewrite rows that Codex itself classifies as
    non-interactive and otherwise user-owned.
    """
    if days is None:
        days = _codex_sidebar_backfill_window_days()
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    try:
        limit = max(1, int(limit or 1000))
    except (TypeError, ValueError):
        limit = 1000

    allowed_roots = None
    if repo_paths is not None:
        allowed_roots = set(_codex_sidebar_project_roots_from_values(repo_paths))

    out = []
    for row in _codex_fetch_threads(limit=limit):
        source = row.get("source")
        thread_source = row.get("thread_source")
        if source not in ("exec", "cli"):
            continue
        if thread_source and thread_source != "user":
            continue
        ts = _codex_ts_seconds(row, "updated") or _codex_ts_seconds(row, "created")
        if ts and ts < cutoff:
            break
        if allowed_roots is not None:
            root = _codex_sidebar_project_root_for_thread(row)
            if root not in allowed_roots:
                continue
        out.append(row)
    return out


def _codex_global_state_path():
    return Path.home() / ".codex" / ".codex-global-state.json"


def _read_codex_global_state():
    try:
        data = json.loads(_codex_global_state_path().read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None
    return data if isinstance(data, dict) else None


def _codex_global_state_string_list(data, key):
    values = (data or {}).get(key)
    if not isinstance(values, list):
        return []
    return [str(x) for x in values if isinstance(x, str) and x.strip()]


def _codex_saved_workspace_roots():
    return _codex_global_state_string_list(
        _read_codex_global_state(),
        "electron-saved-workspace-roots",
    )


def _codex_desktop_app_is_running():
    if platform.system() != "Darwin":
        return False
    try:
        proc = subprocess.run(
            ["ps", "-axo", "command"],
            stdout=subprocess.PIPE,
            stderr=subprocess.DEVNULL,
            text=True,
            timeout=1.0,
            check=False,
        )
    except (OSError, subprocess.SubprocessError):
        return False
    if proc.returncode != 0:
        return False
    for line in proc.stdout.splitlines():
        if ".app/Contents/MacOS/Codex" in line:
            return True
    return False


def _open_codex_workspace_root_deeplink(root):
    if platform.system() != "Darwin" or not shutil.which("open"):
        return False
    url = "codex://new?path=" + urllib.parse.quote(str(root), safe="")
    try:
        proc = subprocess.run(
            ["open", url],
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            timeout=2.0,
            check=False,
        )
    except (OSError, subprocess.SubprocessError):
        return False
    return proc.returncode == 0


def _wait_for_codex_workspace_roots(roots, timeout_s=2.0):
    wanted = set(roots or [])
    if not wanted:
        return set()
    deadline = time.monotonic() + max(0.0, float(timeout_s or 0))
    present = set(_codex_saved_workspace_roots())
    while not wanted.issubset(present) and time.monotonic() < deadline:
        time.sleep(0.1)
        present = set(_codex_saved_workspace_roots())
    return present


def _register_codex_sidebar_project_roots_live(roots):
    current = set(_codex_saved_workspace_roots())
    missing = [root for root in roots if root not in current]
    if not missing:
        return 0
    data = _read_codex_global_state() or {}
    active_roots = _codex_global_state_string_list(data, "active-workspace-roots")
    for root in missing:
        _open_codex_workspace_root_deeplink(root)
    if active_roots:
        active = active_roots[0]
        try:
            if Path(active).expanduser().is_dir():
                _open_codex_workspace_root_deeplink(active)
        except (OSError, RuntimeError, ValueError):
            pass
    present = _wait_for_codex_workspace_roots(missing)
    return sum(1 for root in missing if root in present)


def _append_codex_project_roots_to_global_state(roots):
    state_path = _codex_global_state_path()
    data = _read_codex_global_state()
    if data is None:
        return 0

    saved_before = set(_codex_global_state_string_list(
        data,
        "electron-saved-workspace-roots",
    ))
    changed = False
    for key in ("electron-saved-workspace-roots", "project-order"):
        current = _codex_global_state_string_list(data, key)
        present = set(current)
        added = [root for root in roots if root not in present]
        if not added:
            data[key] = current
            continue
        data[key] = added + current
        changed = True

    if not changed:
        return 0
    try:
        tmp = state_path.with_name(f"{state_path.name}.tmp-{os.getpid()}")
        tmp.write_text(json.dumps(data, indent=2, ensure_ascii=False) + "\n", encoding="utf-8")
        os.replace(tmp, state_path)
    except OSError:
        return 0
    saved_after = set(_codex_saved_workspace_roots())
    return sum(1 for root in roots if root not in saved_before and root in saved_after)


def _append_codex_sidebar_project_roots(repo_paths):
    """Add CCC-proven Codex repos to Codex Desktop's project sidebar state."""
    roots = _codex_sidebar_project_roots_from_values(repo_paths)
    if not roots:
        return 0
    if _read_codex_global_state() is None:
        return 0

    if _codex_desktop_app_is_running():
        return _register_codex_sidebar_project_roots_live(roots)
    return _append_codex_project_roots_to_global_state(roots)


def backfill_codex_sidebar_visibility(days=None, repo_paths=None, now=None, max_logs=2000):
    """Mark recent CCC-spawned Codex threads as Codex Desktop sidebar-visible."""
    if days is None:
        days = _codex_sidebar_backfill_window_days()
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    ids = []
    seen_ids = set()

    def add_sid(sid):
        sid = str(sid or "").strip()
        if sid and sid not in seen_ids:
            seen_ids.add(sid)
            ids.append(sid)

    log_paths = _recent_codex_ccc_log_paths(
        repo_paths=repo_paths,
        days=days,
        now=now,
        max_logs=max_logs,
    )
    for path in log_paths:
        add_sid(_extract_codex_thread_id_from_log(path))

    try:
        registry_entries = _load_spawn_registry()
    except Exception:
        registry_entries = []
    for entry in registry_entries:
        if entry.get("engine") != "codex":
            continue
        entry_epoch = _codex_registry_entry_epoch(entry)
        if entry_epoch and entry_epoch < cutoff:
            continue
        log_path = entry.get("log")
        if log_path and not entry_epoch:
            try:
                if Path(log_path).expanduser().stat().st_mtime < cutoff:
                    continue
            except OSError:
                continue
        if not entry_epoch and not log_path:
            continue
        add_sid(entry.get("session_id") or entry.get("resumed_sid"))
        if log_path:
            add_sid(_extract_codex_thread_id_from_log(log_path))

    for row in _codex_backfill_candidate_rows(
        days=days,
        repo_paths=repo_paths,
        now=now,
        limit=max_logs,
    ):
        add_sid(row.get("id"))

    updated = 0
    already_visible = 0
    skipped = 0
    project_roots = []
    for sid in ids:
        before_row = _codex_thread_row(sid) or {}
        ok = _mark_codex_thread_user_visible(sid)
        after_row = _codex_thread_row(sid) or {}
        _restore_codex_rollout_mtime_from_row(after_row)
        root = _codex_sidebar_project_root_for_thread(after_row)
        if root:
            project_roots.append(root)
        after_thread_source = after_row.get("thread_source")
        after_source = after_row.get("source")
        if ok and after_thread_source == "user" and (after_source in (None, "vscode")):
            if (
                before_row.get("thread_source") == "user"
                and before_row.get("source") in (None, "vscode")
            ):
                already_visible += 1
            else:
                updated += 1
        else:
            skipped += 1
    projects_added = _append_codex_sidebar_project_roots(project_roots)
    return {
        "ok": True,
        "days": days,
        "scanned_logs": len(log_paths),
        "found": len(ids),
        "updated": updated,
        "already_visible": already_visible,
        "skipped": skipped,
        "projects_added": projects_added,
    }


def _codex_sidebar_visibility_backfill_once():
    try:
        result = backfill_codex_sidebar_visibility()
    except Exception as e:
        print(f"  [codex-sidebar] backfill skipped ({e})")
        return
    if result.get("updated"):
        print(
            "  [codex-sidebar] marked "
            f"{result['updated']} recent CCC Codex thread(s) as IDE-visible"
        )
    if result.get("projects_added"):
        print(
            "  [codex-sidebar] registered "
            f"{result['projects_added']} recent CCC Codex project(s) with Codex Desktop"
        )


def _claude_desktop_backfill_window_days():
    raw = os.environ.get("CCC_CLAUDE_DESKTOP_BACKFILL_DAYS", "7")
    try:
        days = float(raw)
    except (TypeError, ValueError):
        days = 7.0
    return days if days > 0 else 7.0


def _claude_desktop_startup_backfill_max_logs():
    raw = os.environ.get("CCC_CLAUDE_DESKTOP_STARTUP_BACKFILL_MAX_LOGS", "200")
    try:
        max_logs = int(raw)
    except (TypeError, ValueError):
        max_logs = 200
    return max(1, max_logs)


def _is_probable_claude_spawn_log(path):
    name = Path(path).name
    blocked_prefixes = (
        "spawn-codex-",
        "resume-codex-",
        "spawn-gemini-",
        "resume-gemini-",
        "spawn-antigravity-",
        "resume-antigravity-",
    )
    if name.startswith(blocked_prefixes):
        return False
    return (
        (name.startswith("spawn-") or name.startswith("resume-"))
        and name.endswith(".log")
        and not name.endswith(".agy.log")
    )


def _recent_claude_ccc_log_paths(repo_paths=None, days=None, now=None, max_logs=2000):
    """Recent CCC Claude spawn/resume logs, bounded to known repos."""
    if days is None:
        days = _claude_desktop_backfill_window_days()
    try:
        max_logs = max(1, int(max_logs or 2000))
    except (TypeError, ValueError):
        max_logs = 2000
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    raw_paths = []
    registry_entries = []
    try:
        registry_entries = _load_spawn_registry()
    except Exception:
        registry_entries = []
    for entry in registry_entries:
        engine = entry.get("engine") or "claude"
        if engine == "claude" and entry.get("log"):
            raw_paths.append(entry.get("log"))

    if repo_paths is None:
        candidates = []
        try:
            candidates.extend(_known_repo_paths())
        except Exception:
            pass
        try:
            candidates.extend(_discover_repo_paths_from_projects())
        except Exception:
            pass
        for entry in registry_entries:
            engine = entry.get("engine") or "claude"
            if engine != "claude":
                continue
            for key in ("repo_path", "cwd"):
                if entry.get(key):
                    candidates.append(entry.get(key))
        repo_paths = candidates

    seen_repos = set()
    for repo_path in repo_paths or []:
        try:
            repo = str(Path(repo_path).expanduser().resolve())
        except (OSError, RuntimeError, ValueError, TypeError):
            continue
        if repo in seen_repos:
            continue
        seen_repos.add(repo)
        try:
            log_dir = repo_log_dir(repo)
        except Exception:
            continue
        if not log_dir.is_dir():
            continue
        for pattern in ("spawn-*.log", "resume-*.log"):
            try:
                raw_paths.extend(log_dir.glob(pattern))
            except OSError:
                continue

    seen = set()
    recent = []
    for raw in raw_paths:
        try:
            p = Path(raw).expanduser().resolve()
            key = str(p)
            if key in seen or not _is_probable_claude_spawn_log(p):
                continue
            seen.add(key)
            st = p.stat()
        except (OSError, ValueError, RuntimeError, TypeError):
            continue
        if st.st_mtime < cutoff:
            continue
        recent.append((st.st_mtime, p))
    recent.sort(key=lambda item: item[0], reverse=True)
    return [p for _mtime, p in recent[:max_logs]]


def backfill_claude_desktop_visibility(
    days=None,
    repo_paths=None,
    now=None,
    max_logs=2000,
    skip_existing=False,
):
    """Create Claude Desktop sidebar metadata for recent CCC-spawned sessions."""
    if days is None:
        days = _claude_desktop_backfill_window_days()
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    pruned = prune_unresumable_claude_desktop_metadata().get("pruned", 0)
    ids = []
    seen_ids = set()
    entries_by_sid = {}

    def add_sid(sid, entry=None):
        sid = str(sid or "").strip()
        if not sid or not _SESSION_UUID_RE.match(sid):
            return
        if entry and sid not in entries_by_sid:
            entries_by_sid[sid] = entry
        if sid not in seen_ids:
            seen_ids.add(sid)
            ids.append(sid)

    log_paths = _recent_claude_ccc_log_paths(
        repo_paths=repo_paths,
        days=days,
        now=now,
        max_logs=max_logs,
    )
    for path in log_paths:
        add_sid(extract_session_id(path))

    try:
        registry_entries = _load_spawn_registry()
    except Exception:
        registry_entries = []
    for entry in registry_entries:
        engine = entry.get("engine") or "claude"
        if engine != "claude":
            continue
        entry_epoch = _spawn_registry_entry_epoch(entry)
        if entry_epoch and entry_epoch < cutoff:
            continue
        log_path = entry.get("log")
        if log_path and not entry_epoch:
            try:
                if Path(log_path).expanduser().stat().st_mtime < cutoff:
                    continue
            except OSError:
                continue
        if not entry_epoch and not log_path:
            continue
        add_sid(entry.get("session_id") or entry.get("resumed_sid"), entry)
        if log_path:
            add_sid(extract_session_id(log_path), entry)

    metadata_index = _claude_desktop_metadata_index()
    updated = 0
    already_visible = 0
    skipped = 0
    for sid in ids:
        before_path = _claude_desktop_metadata_path_for_cli_session(
            sid,
            metadata_index=metadata_index,
        )
        if skip_existing and before_path:
            already_visible += 1
            continue
        ok = _ensure_claude_desktop_session_visible(
            sid,
            spawn_entry=entries_by_sid.get(sid),
            metadata_index=metadata_index,
        )
        if ok:
            if before_path:
                already_visible += 1
            else:
                updated += 1
        else:
            skipped += 1

    return {
        "ok": True,
        "days": days,
        "scanned_logs": len(log_paths),
        "found": len(ids),
        "updated": updated,
        "already_visible": already_visible,
        "skipped": skipped,
        "pruned": pruned,
        "skip_existing": bool(skip_existing),
    }


def _claude_desktop_visibility_backfill_once():
    try:
        result = backfill_claude_desktop_visibility(
            max_logs=_claude_desktop_startup_backfill_max_logs(),
            skip_existing=True,
        )
    except Exception as e:
        print(f"  [claude-desktop] backfill skipped ({e})")
        return
    if result.get("updated"):
        print(
            "  [claude-desktop] added "
            f"{result['updated']} recent CCC Claude session(s) to the Desktop sidebar"
        )


def _register_codex_sidebar_project_for_spawn_entry(entry, sid=None):
    if not isinstance(entry, dict):
        return 0
    root = None
    for key in ("repo_path", "cwd"):
        root = _codex_sidebar_project_root_for_thread({"cwd": entry.get(key) or ""})
        if root:
            break
    if not root and sid:
        root = _codex_sidebar_project_root_for_thread(_codex_thread_row(sid))
    if not root:
        return 0
    return _append_codex_sidebar_project_roots([root])


def _codex_spawn_pid_by_thread_id():
    out = {}
    for s in _spawned_sessions:
        if s.get("engine") != "codex":
            continue
        sid = s.get("session_id") or s.get("resumed_sid") or _extract_codex_thread_id_from_log(s.get("log"))
        if sid:
            try:
                alive = _poll_spawn_entry(s) is None
            except Exception:
                alive = False
            if _mark_codex_thread_user_visible(sid, update_rollout=True):
                _register_codex_sidebar_project_for_spawn_entry(s, sid)
            else:
                _schedule_codex_visibility_retry(sid, spawn_entry=s)
            if not s.get("session_id"):
                s["session_id"] = sid
                _update_spawn_session_id_in_registry(s.get("pid"), sid)
            parent_sid = s.get("parent_session_id") or ""
            if parent_sid:
                # Persist the link so it survives spawn-registry pruning.
                # First-time only (idempotent); cheap dict check skips the
                # file write on subsequent polls. (CCC-465)
                _persist_codex_parent_link(sid, parent_sid)
            _codex_thread_registry_upsert(
                sid,
                source="ccc-spawn-registry",
                visibility="user-visible",
                transport_owner=(
                    "ccc-managed-app-server"
                    if s.get("app_server_spawn") else
                    "ccc-codex-exec"
                ),
                transport=(
                    _codex_app_server_transport_kind()
                    if s.get("app_server_spawn") else
                    "codex-exec"
                ),
                cwd=s.get("cwd") or "",
                repo_path=s.get("repo_path") or "",
                title=s.get("name") or "",
                name=s.get("name") or "",
                parent_session_id=parent_sid,
                model=s.get("model") or "",
                ccc={
                    "spawn_id": s.get("spawn_id") or s.get("pid") or "",
                    "pid": s.get("pid") or "",
                    "log": s.get("log") or "",
                    "spawned_at": s.get("started") or "",
                    "prompt": s.get("prompt") or "",
                    "app_server_spawn": bool(s.get("app_server_spawn")),
                },
            )
            if sid not in out:
                out[sid] = {
                    "pid": s.get("pid"),
                    "alive": alive,
                    "log": s.get("log"),
                    "cwd": s.get("cwd") or "",
                    "repo_path": s.get("repo_path") or "",
                    "spawned_at": s.get("started") or "",
                    "prompt": s.get("prompt") or "",
                    "model": s.get("model") or "",
                    "parent_session_id": parent_sid,
                }
    for sid, entry in _codex_thread_registry_entries().items():
        if sid and sid not in out:
            out[sid] = _codex_thread_registry_spawn_shape(entry)
    return out


def _codex_cwd_matches_repo(cwd, repo_path, git_top_cache):
    if not cwd:
        return False
    try:
        p = Path(cwd).expanduser().resolve()
        root = Path(repo_path).expanduser().resolve()
    except (OSError, RuntimeError, ValueError):
        p = Path(str(cwd))
        root = Path(str(repo_path))
    try:
        if p == root or root in p.parents:
            return True
    except RuntimeError:
        pass
    try:
        return _git_toplevel_for_path(str(p), git_top_cache) == str(root)
    except Exception:
        return False


# Per-file resume state for incremental codex tail parsing: path -> {offset,
# pos, pending_calls, meta, meta_version}. In-memory only (NOT persisted with
# _conv_meta_cache) — after a restart the first poll does one full parse and
# rebuilds it. Guarded by _conv_meta_cache_lock.
_codex_tail_resume = {}


def _extract_codex_tail_meta(path):
    try:
        st = path.stat()
    except OSError:
        return {}
    mtime = st.st_mtime
    size = st.st_size
    spath = str(path)
    cached = _conv_meta_cache.get(spath)
    if (
        cached
        and cached.get("mtime") == mtime
        and cached.get("engine") == "codex"
        and cached.get("meta_version") == _CODEX_META_VERSION
    ):
        return cached

    # Incremental resume. Rollout JSONL is append-only, so rather than
    # re-parsing the whole (often multi-MB) file on every poll — the mtime
    # cache above *always* misses for a live, actively-appending session, which
    # is exactly the session live-activity polls — carry forward the prior
    # parse state and read only the bytes appended since the last call.
    with _conv_meta_cache_lock:
        resume = _codex_tail_resume.get(spath)
    if (
        resume
        and resume.get("meta_version") == _CODEX_META_VERSION
        and size >= resume.get("offset", 0)
    ):
        meta = resume["meta"]
        pending_calls = resume["pending_calls"]
        pos = resume["pos"]
        start_offset = resume["offset"]
    else:
        meta = {
            "engine": "codex",
            "meta_version": _CODEX_META_VERSION,
            "mtime": mtime,
            "first_message": None,
            "last_meaningful_ts": 0,
            "last_prompt": None,
            "last_assistant_text": None,
            "last_event_type": None,
            "pending_tool": None,
            "pending_file": None,
            "pending_tool_ts": 0,
            "needs_approval": False,
            "needs_approval_message": "",
            "pending_approval_call_id": "",
            "has_edit": False,
            "has_commit": False,
            "has_push": False,
            "last_edit_pos": 0,
            "last_commit_pos": 0,
            "last_push_pos": 0,
            "tail_pr_number": None,
            "tail_pr_url": None,
            "tail_branch": None,
            "tail_worktree_path": None,
            "has_external_cd": False,
            "cwd": None,
            "model": None,
            "latest_input_tokens": 0,
            "context_limit": 0,
        }
        pending_calls = {}
        pos = 0
        start_offset = 0
    pr_url_re = re.compile(r"github\.com/([^/\s]+/[^/\s]+)/pull/(\d{1,7})")
    # Binary + readline() so f.tell()/offset accounting stays exact (text-mode
    # iteration buffers ahead and corrupts the resume offset).
    try:
        with open(path, "rb") as f:
            if start_offset:
                f.seek(start_offset)
            while True:
                raw = f.readline()
                if not raw:
                    break
                if not raw.endswith(b"\n"):
                    # Partial trailing line — writer is mid-append. Leave the
                    # offset before it so the next poll re-reads it complete.
                    break
                start_offset += len(raw)
                pos += 1
                line = raw.decode("utf-8", "replace").strip()
                if not line:
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                usage = _codex_token_usage_from_event(ev)
                if usage:
                    inp = _codex_int(usage.get("input_tokens"))
                    if inp:
                        meta["latest_input_tokens"] = inp
                    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
                    info = payload.get("info") or {}
                    if isinstance(info, dict):
                        cl = _codex_int(info.get("model_context_window"))
                        if cl:
                            meta["context_limit"] = cl
                    continue
                payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
                ts_epoch = _codex_event_epoch(ev)
                ev_type = ev.get("type")
                ptype = payload.get("type")
                if ev_type in ("session_meta", "turn_context"):
                    meta["cwd"] = payload.get("cwd") or meta["cwd"]
                    meta["model"] = payload.get("model") or meta["model"]
                    continue
                if ev_type == "event_msg":
                    if ptype == "user_message":
                        text = _strip_ccc_session_state_instruction(
                            payload.get("message") or ""
                        ).strip()
                        if text:
                            meta["first_message"] = meta["first_message"] or text
                            meta["last_prompt"] = text
                        meta["last_event_type"] = "user"
                        meta["pending_tool"] = None
                        meta["pending_file"] = None
                        meta["pending_tool_ts"] = 0
                        meta["needs_approval"] = False
                        meta["needs_approval_message"] = ""
                        meta["pending_approval_call_id"] = ""
                        pending_calls.clear()
                        if ts_epoch:
                            meta["last_meaningful_ts"] = ts_epoch
                    elif ptype == "agent_message":
                        text = (payload.get("message") or "").strip()
                        if text:
                            meta["last_assistant_text"] = text
                            meta.update(_extract_codex_summary_signals(text, pr_url_re))
                        meta["last_event_type"] = "assistant"
                        if ts_epoch:
                            meta["last_meaningful_ts"] = ts_epoch
                    elif ptype == "task_complete":
                        text = (payload.get("last_agent_message") or payload.get("message") or "").strip()
                        if text:
                            meta.update(_extract_codex_summary_signals(text, pr_url_re))
                        meta["last_event_type"] = "result"
                        meta["pending_tool"] = None
                        meta["pending_file"] = None
                        meta["pending_tool_ts"] = 0
                        meta["needs_approval"] = False
                        meta["needs_approval_message"] = ""
                        meta["pending_approval_call_id"] = ""
                        pending_calls.clear()
                        if ts_epoch:
                            meta["last_meaningful_ts"] = ts_epoch
                    continue
                if ev_type != "response_item":
                    continue
                if ptype in ("function_call", "custom_tool_call"):
                    name = payload.get("name") or ""
                    is_custom_tool = ptype == "custom_tool_call"
                    raw_input = payload.get("input") if isinstance(payload.get("input"), str) else ""
                    args = {} if is_custom_tool else _codex_args(payload.get("arguments"))
                    detail = (
                        _codex_custom_tool_detail(raw_input, name)
                        if is_custom_tool else _codex_tool_detail(name, args)
                    )
                    call_id = payload.get("call_id") or ""
                    meta["last_event_type"] = "assistant"
                    if ts_epoch:
                        meta["last_meaningful_ts"] = ts_epoch
                    tool_name = (
                        _codex_custom_tool_kind(raw_input, name)
                        if is_custom_tool else (_codex_tool_name(name) or name)
                    )
                    meta["pending_tool"] = tool_name
                    meta["pending_file"] = (detail[:80] if isinstance(detail, str) else None)
                    meta["pending_tool_ts"] = ts_epoch or meta.get("last_meaningful_ts") or mtime
                    approval_required = _codex_tool_requires_approval(name, args, raw_input)
                    approval_message = _codex_tool_approval_message(args, raw_input)
                    if approval_required:
                        meta["needs_approval"] = True
                        meta["needs_approval_message"] = approval_message
                        meta["pending_approval_call_id"] = call_id
                    if tool_name == "apply_patch":
                        meta["has_edit"] = True
                        meta["last_edit_pos"] = pos
                    cmd = (
                        _codex_custom_tool_command(raw_input)
                        if is_custom_tool else _codex_tool_command(name, args)
                    )
                    tool_workdir = (
                        _codex_custom_tool_workdir(raw_input)
                        if is_custom_tool else _codex_tool_workdir(name, args)
                    ) or meta.get("cwd")
                    if cmd:
                        signals = _codex_command_signals(cmd, base_cwd=tool_workdir)
                        if signals["edit"]:
                            meta["has_edit"] = True
                            meta["last_edit_pos"] = pos
                        if signals["commit"]:
                            meta["has_commit"] = True
                            meta["last_commit_pos"] = pos
                        if signals["push"]:
                            meta["has_push"] = True
                            meta["last_push_pos"] = pos
                        if signals["external_cd"]:
                            meta["has_external_cd"] = True
                        if signals.get("worktree_path"):
                            meta["tail_worktree_path"] = signals["worktree_path"]
                        if signals.get("worktree_branch"):
                            meta["tail_branch"] = signals["worktree_branch"]
                        if call_id:
                            pending_calls[call_id] = {
                                "cmd": cmd,
                                "pr": signals["pr"],
                                "approval": approval_required,
                            }
                    elif call_id:
                        pending_calls[call_id] = {
                            "cmd": "",
                            "pr": False,
                            "approval": approval_required,
                        }
                elif ptype in ("function_call_output", "custom_tool_call_output"):
                    call_id = payload.get("call_id") or ""
                    call = pending_calls.pop(call_id, {})
                    if call:
                        meta["pending_tool"] = None
                        meta["pending_file"] = None
                        meta["pending_tool_ts"] = 0
                        if call.get("approval") and meta.get("pending_approval_call_id") == call_id:
                            meta["needs_approval"] = False
                            meta["needs_approval_message"] = ""
                            meta["pending_approval_call_id"] = ""
                    meta["last_event_type"] = "assistant"
                    if ts_epoch:
                        meta["last_meaningful_ts"] = ts_epoch
                    out = payload.get("output") or ""
                    if call.get("pr") and isinstance(out, str):
                        mp = pr_url_re.search(out)
                        if mp:
                            meta["tail_pr_number"] = int(mp.group(2))
                            meta["tail_pr_url"] = (
                                "https://github.com/" + mp.group(1) + "/pull/" + mp.group(2)
                            )
                else:
                    meta["last_event_type"] = "assistant"
                    if ts_epoch:
                        meta["last_meaningful_ts"] = ts_epoch
            end_offset = start_offset
    except OSError:
        return {}

    meta["mtime"] = mtime
    if not meta.get("last_meaningful_ts"):
        meta["last_meaningful_ts"] = mtime
    with _conv_meta_cache_lock:
        _conv_meta_cache[spath] = meta
        _codex_tail_resume[spath] = {
            "meta_version": _CODEX_META_VERSION,
            "offset": end_offset,
            "pos": pos,
            "pending_calls": pending_calls,
            "meta": meta,
        }
        global _conv_meta_cache_dirty
        _conv_meta_cache_dirty = True
    return meta


def _codex_stale_tool_threshold_s():
    try:
        threshold = float(os.environ.get("CCC_CODEX_STALE_TOOL_SEC", "900"))
    except (TypeError, ValueError):
        threshold = 900.0
    return max(0.0, threshold)


def _codex_stale_tool_fields(tail, now=None, threshold_s=None):
    threshold = _codex_stale_tool_threshold_s() if threshold_s is None else max(0.0, float(threshold_s))
    fields = {
        "stale_tool_call": False,
        "stale_tool_age_s": 0,
        "stale_tool_threshold_s": int(threshold),
    }
    if not tail or not tail.get("pending_tool"):
        return fields
    ts = tail.get("pending_tool_ts") or 0
    if not ts:
        return fields
    try:
        age = max(0.0, float(now if now is not None else time.time()) - float(ts))
    except (TypeError, ValueError):
        return fields
    fields["stale_tool_age_s"] = int(age)
    fields["stale_tool_call"] = bool(threshold > 0 and age >= threshold)
    return fields


def _stale_tool_threshold_s():
    """Stale-tool threshold for Claude/headless sessions (seconds).

    Mirrors the Codex knob but for the headless tool-child path. A tool child
    that has been "running" longer than this with no result is treated as hung,
    so the UI can warn the user (queued input cannot drain while a tool child is
    active). Configurable via ``CCC_STALE_TOOL_SEC`` (default 900s / 15m).
    """
    try:
        threshold = float(os.environ.get("CCC_STALE_TOOL_SEC", "900"))
    except (TypeError, ValueError):
        threshold = 900.0
    return max(0.0, threshold)


def _claude_stale_tool_fields(started_at, in_flight, now=None, threshold_s=None):
    """Stale-tool fields for a Claude headless session's active tool child.

    Codex synthesizes these from its rollout tail; Claude headless sessions have
    no rollout, but ``_spawn_entry_active_tool_child`` gives the real child start
    time (from ``ps`` etime). When an in-flight tool child has aged past the
    threshold it is almost certainly wedged (the real case: ``rg`` blocked on a
    ``.stdin`` FIFO for ~3.7h), and the input queue cannot drain while a child
    is alive — so flag it for the UI.
    """
    threshold = _stale_tool_threshold_s() if threshold_s is None else max(0.0, float(threshold_s))
    fields = {
        "stale_tool_call": False,
        "stale_tool_age_s": 0,
        "stale_tool_threshold_s": int(threshold),
    }
    if not in_flight or not started_at:
        return fields
    try:
        age = max(0.0, float(now if now is not None else time.time()) - float(started_at))
    except (TypeError, ValueError):
        return fields
    fields["stale_tool_age_s"] = int(age)
    fields["stale_tool_call"] = bool(threshold > 0 and age >= threshold)
    return fields


def _codex_activity_fields_from_tail(tail, live):
    """Map Codex rollout tail state into the sidecar-shaped UI fields.

    Claude sessions get this from command-center hooks. Codex does not run
    those hooks, so live rows synthesize equivalent activity from the rollout:
    an unfinished tool call names the tool; otherwise a mid-turn user/assistant
    tail shows as generic thinking.
    """
    fields = {
        "sidecar_status": None,
        "sidecar_has_writes": False,
        "sidecar_tool": None,
        "sidecar_file": None,
        "sidecar_ts": 0,
        "sidecar_in_flight": False,
        "question_waiting": False,
        "question_text": "",
        "question_header": "",
        "question_preamble": "",
        "question_options": [],
        "question_option_details": [],
        "needs_approval": bool((tail or {}).get("needs_approval")),
        "needs_approval_message": (tail or {}).get("needs_approval_message") or "",
    }
    if not live or not tail:
        return fields
    if _codex_stale_tool_fields(tail).get("stale_tool_call"):
        return fields

    ts = tail.get("last_meaningful_ts") or 0
    pending_tool = tail.get("pending_tool")
    if pending_tool:
        fields.update({
            "sidecar_status": "active",
            "sidecar_tool": pending_tool,
            "sidecar_file": tail.get("pending_file"),
            "sidecar_ts": ts,
            "sidecar_in_flight": True,
        })
        return fields

    if tail.get("last_event_type") in ("user", "assistant"):
        fields.update({
            "sidecar_status": "active",
            "sidecar_tool": "Thinking",
            "sidecar_file": None,
            "sidecar_ts": ts,
            "sidecar_in_flight": True,
        })
    return fields


def _codex_app_activity_superseded_by_tail(app_activity, tail):
    if not app_activity or not app_activity.get("sidecar_status") or not tail:
        return False
    # Recovery describes why the whole turn exists, not merely its latest
    # item. A newer rollout reasoning/tool event must not replace the recovery
    # label with ordinary "Thinking" while the watchdog continuation runs.
    if app_activity.get("sidecar_tool") == "Recovery":
        return False
    try:
        app_ts = float(app_activity.get("sidecar_ts") or 0)
        tail_ts = float(tail.get("last_meaningful_ts") or 0)
        pending_ts = float(tail.get("pending_tool_ts") or 0)
    except (TypeError, ValueError):
        return False
    newest_tail_ts = max(tail_ts, pending_ts)
    if not app_ts or newest_tail_ts <= app_ts + 2:
        return False
    if tail.get("needs_approval"):
        return True
    pending_tool = tail.get("pending_tool")
    if not pending_tool:
        return True
    return pending_tool != app_activity.get("sidecar_tool")


def _codex_fresh_threshold_s():
    try:
        v = float(os.environ.get("CCC_CODEX_FRESH_SEC", "40"))
    except (TypeError, ValueError):
        v = 40.0
    return max(0.0, v)


def _codex_recent_window_s():
    try:
        v = float(os.environ.get("CCC_CODEX_RECENT_SEC", str(24 * 3600)))
    except (TypeError, ValueError):
        v = float(24 * 3600)
    return max(0.0, v)


def _codex_row_state(tail, mtime, now, pool_alive, has_live_proc):
    """Classify one codex session into working / idle / stuck / offline.

    Pure function (no I/O) so it is unit-testable. Caller applies the
    recency gate and resolves pool/liveness/mtime before calling.

    Priority: offline (engine down) > stuck (mid-turn, stale) >
    working (mid-turn, fresh) > idle (turn complete).
    """
    if not tail:
        return None
    if tail.get("needs_approval"):
        return "waiting"
    mid_turn = bool(tail.get("pending_tool")) or (
        tail.get("last_event_type") in ("user", "assistant")
    )
    if not pool_alive and not has_live_proc:
        return "offline"
    if mid_turn:
        try:
            age = max(0.0, float(now) - float(mtime or 0))
        except (TypeError, ValueError):
            age = 0.0
        if age >= _codex_stale_tool_threshold_s():
            return "stuck"
        return "working"
    return "idle"


def _codex_pool_alive(now=None):
    """True when a `codex app-server` pool process is running.

    Cached for _ENGINE_LIVE_TTL like the engine-live scan. On any error,
    fall back to the last value (default True) so a transient ps failure
    never flips every codex row to a false 'offline'.
    """
    now = now if now is not None else time.time()
    cached = _codex_pool_alive_cache
    if now - cached["ts"] < _ENGINE_LIVE_TTL:
        return cached["alive"]
    try:
        alive = False
        for p in find_live_codex_processes():
            if "app-server" in (p.get("command") or ""):
                alive = True
                break
    except Exception:
        return cached["alive"]
    _codex_pool_alive_cache["ts"] = now
    _codex_pool_alive_cache["alive"] = alive
    return alive


def _codex_state_fields(
    sid,
    now=None,
    note_writer_transition=True,
    rollout_path=None,
    rollout_stat=None,
    rollout_tail=None,
):
    """Resolve {codex_state, codex_fresh} for one codex session id.

    Applies the recency gate (no chip for sessions whose rollout hasn't
    been touched within _codex_recent_window_s). Fails quiet to nulls.
    """
    fields = {"codex_state": None, "codex_fresh": False}
    if not sid:
        return fields
    now = now if now is not None else time.time()
    # Resolve + stat the rollout ONCE (the thread-row lookup behind
    # _resolve_codex_rollout_path is a sqlite query — this function sits on
    # liveness paths, so it must not pay it twice).
    path = Path(rollout_path) if rollout_path is not None else None
    rollout = {}
    mtime = None
    try:
        if path is None:
            path = _resolve_codex_rollout_path(sid)
        if path:
            st = rollout_stat if rollout_stat is not None else Path(path).stat()
            mtime = st.st_mtime
            rollout = {
                "path": str(path),
                "size": getattr(st, "st_size", 0),
                "mtime_ns": getattr(st, "st_mtime_ns", int(mtime * 1_000_000_000)),
            }
    except OSError:
        path = None
        rollout = {}
    snap = {}
    try:
        app_state = _codex_app_server_thread_state(sid)
    except Exception:
        app_state = {}
    tail = rollout_tail if isinstance(rollout_tail, dict) else {}
    if path and mtime is not None and (now - mtime) <= _codex_recent_window_s():
        if rollout_tail is None:
            try:
                tail = _extract_codex_tail_meta(path) or {}
            except Exception:
                tail = {}
        if tail.get("needs_approval"):
            fields["codex_state"] = "waiting"
            fields["codex_fresh"] = True
            fields["codex_state_reason"] = tail.get("needs_approval_message") or "Codex is waiting for approval"
            return fields
    approval_item = _codex_app_server_pending_approval_item(app_state)
    if approval_item:
        fields["codex_state"] = "waiting"
        fields["codex_fresh"] = True
        fields["codex_state_reason"] = (
            approval_item.get("approval_message")
            or approval_item.get("detail")
            or "Codex is waiting for approval"
        )
        return fields
    if _codex_app_server_thread_needs_approval(app_state):
        fields["codex_state"] = "waiting"
        fields["codex_fresh"] = True
        fields["codex_state_reason"] = _codex_app_server_thread_approval_message(app_state)
        return fields
    try:
        # Writer attribution (desktop ↔ CCC coordination): reuses the rollout
        # stat above + the TTL-cached desktop-attachment map. Also feeds the
        # durable external-turn transition events.
        snap = _codex_thread_writer_snapshot(sid, now, app_state=app_state, rollout=rollout)
        if note_writer_transition:
            _codex_note_external_writer_transition(sid, snap)
        if snap.get("writer"):
            fields["codex_writer"] = snap["writer"]
        if snap.get("desktop_attached"):
            fields["codex_desktop_attached"] = True
    except Exception:
        snap = {}
    try:
        if app_state and (app_state.get("active_turn_id") or str(app_state.get("status") or "").lower() == "active"):
            try:
                app_ts = float(app_state.get("last_activity_at") or app_state.get("last_event_at") or 0)
                tail_ts = float((tail or {}).get("last_meaningful_ts") or 0)
            except (TypeError, ValueError):
                app_ts = 0.0
                tail_ts = 0.0
            if not (tail_ts > app_ts + 2 and (tail or {}).get("last_event_type") == "result"):
                fields["codex_state"] = "working"
                fields["codex_fresh"] = True
                return fields
    except Exception:
        pass
    if snap.get("external_active"):
        # A desktop or ownership-unknown turn is in flight: the session is live
        # and busy even though CCC cannot prove that it owns the active turn.
        fields["codex_state"] = "working"
        fields["codex_fresh"] = True
        fields["codex_state_reason"] = (
            "Codex desktop is writing this thread"
            if snap.get("writer") == "desktop"
            else "An active Codex turn is writing this thread"
        )
        return fields
    if not path or mtime is None:
        return fields
    if (now - mtime) > _codex_recent_window_s():
        return fields
    try:
        if not tail:
            tail = _extract_codex_tail_meta(path) or {}
        pool_alive = _codex_pool_alive(now)
        has_live_proc = sid in _live_engine_session_ids()
        state = _codex_row_state(tail, mtime, now, pool_alive, has_live_proc)
    except Exception:
        return fields
    fields["codex_state"] = state
    if state == "working":
        fields["codex_fresh"] = (now - float(mtime)) < _codex_fresh_threshold_s()
    elif state == "stuck":
        fields["codex_state_reason"] = _codex_stuck_reason(tail, mtime, now)
    return fields


def _codex_stuck_reason(tail, mtime, now):
    """Human-readable 'why is this codex session stuck' string.

    Stuck = mid-turn but the rollout has not advanced past the stale
    threshold. Name the tool it stalled on (if any) and how long it has been
    silent, so the UI can answer 'do we know why it was stuck?'.
    """
    try:
        mins = int(max(0.0, float(now) - float(mtime or 0)) // 60)
    except (TypeError, ValueError):
        mins = 0
    ago = f"{mins}m" if mins else "under a minute"
    pending = (tail or {}).get("pending_tool")
    if pending:
        target = (tail or {}).get("pending_file") or ""
        label = (f"{pending} {target}".strip())
        return f"No output for {ago} while running {label} - the tool call looks hung."
    return f"No output for {ago} after the last message - the turn stalled with no tool running."


_codex_stuck_summary_cache = {"ts": 0.0, "value": None}
_codex_stuck_summary_lock = threading.Lock()


def _codex_stuck_summary_ttl_s():
    try:
        value = float(os.environ.get("CCC_CODEX_STUCK_SUMMARY_TTL_SEC", "60"))
    except (TypeError, ValueError):
        value = 60.0
    return max(1.0, value)


def build_codex_stuck_summary(now=None, force=False):
    """Count recent Codex threads carrying the dashboard's ``Stuck`` label.

    The cheap pure classifier prefilters recent rollout tails before the more
    authoritative app-server/writer check. Results are cached because the
    footer is monitoring a fleet-level heuristic, not a millisecond-precise
    process signal. The read-only confirmation deliberately avoids recording
    writer-transition events: observing the counter must not mutate threads.
    """
    now = float(now if now is not None else time.time())
    cache_now = time.monotonic()
    with _codex_stuck_summary_lock:
        cached = _codex_stuck_summary_cache.get("value")
        cached_at = float(_codex_stuck_summary_cache.get("ts") or 0)
        if (
            not force
            and cached is not None
            and (cache_now - cached_at) < _codex_stuck_summary_ttl_s()
        ):
            return dict(cached)

    rows = _codex_fetch_threads()
    pool_alive = _codex_pool_alive(now)
    live_ids = _live_engine_session_ids()
    recent_sessions = 0
    candidates = 0
    stuck_ids = []
    recent_window = _codex_recent_window_s()
    threshold = _codex_stale_tool_threshold_s()

    for row in rows:
        sid = row.get("id") or ""
        if not sid:
            continue
        path = _codex_rollout_path_from_row(row)
        if not path:
            continue
        try:
            rollout_stat = path.stat()
            mtime = rollout_stat.st_mtime
        except OSError:
            continue
        if max(0.0, now - float(mtime or 0)) > recent_window:
            continue
        recent_sessions += 1
        try:
            tail = _extract_codex_tail_meta(path) or {}
            coarse = _codex_row_state(tail, mtime, now, pool_alive, sid in live_ids)
        except Exception:
            continue
        if coarse != "stuck":
            continue
        candidates += 1
        confirmed = _codex_state_fields(
            sid,
            now,
            note_writer_transition=False,
            rollout_path=path,
            rollout_stat=rollout_stat,
            rollout_tail=tail,
        )
        if confirmed.get("codex_state") == "stuck":
            stuck_ids.append(sid)

    value = {
        "count": len(stuck_ids),
        "session_ids": stuck_ids,
        "candidates": candidates,
        "recent_sessions": recent_sessions,
        "threshold_s": int(threshold),
        "recent_window_s": int(recent_window),
        "as_of": now,
        "heuristic": True,
    }
    with _codex_stuck_summary_lock:
        _codex_stuck_summary_cache["ts"] = cache_now
        _codex_stuck_summary_cache["value"] = dict(value)
    return value


def find_codex_conversations(
    repo_path=None,
    include_old=True,
    repo_only=True,
    progress=None,
    limit=None,
    resolve_pr_states=True,
    resolve_worktree_dirty=True,
):
    rows = _codex_fetch_threads(limit=limit)
    if not rows:
        return []
    if repo_only:
        repo_path = resolve_repo_path(repo_path)
        repo_path_obj = Path(repo_path)
    try:
        repo_pins = _load_repo_pins()
    except Exception:
        repo_pins = {}
    try:
        name_overrides = _load_session_name_overrides()
    except Exception:
        name_overrides = {}
    try:
        archived_set, trashed_set = _load_conversation_lifecycle_sets()
    except Exception:
        archived_set, trashed_set = set(), set()
    try:
        verified_set = set(_load_verified_conversations())
    except Exception:
        verified_set = set()
    try:
        last_interactions = _load_last_interactions()
    except Exception:
        last_interactions = {}

    cutoff = _session_scan_cutoff_ts(include_old)
    max_rows = _session_scan_file_limit(include_old)
    spawn_by_sid = _codex_spawn_pid_by_thread_id()
    # One read of the spawn-edge table for the whole scan; per-row lookups are
    # O(1) dict hits (perf gate: no per-row DB work). Lets a spawned agent nest
    # under its parent in the Current-sessions tree. (CCC-298)
    codex_parent_by_child = _codex_spawn_parent_by_child()
    # Durable CCC-spawn parent links (survive spawn-registry pruning). One
    # read per scan; O(1) dict hits per row. (CCC-465)
    codex_durable_parents = _load_codex_parent_links()
    # One batched, cached read of the codex goals sqlite for the whole scan —
    # per-row lookups are O(1) dict hits (perf gate: no per-row DB work).
    goals_by_sid = _codex_goals_snapshot()
    git_top_cache = {}
    out = []
    scanned = 0
    for row in rows:
        sid = row.get("id") or ""
        if not sid:
            continue
        cwd = row.get("cwd") or ""
        pinned = repo_pins.get(sid)
        pinned_repo = False
        if repo_only:
            if pinned and pinned != repo_path:
                continue
            if pinned == repo_path:
                pinned_repo = True
            elif not _codex_cwd_matches_repo(cwd, repo_path_obj, git_top_cache):
                continue
        path = _codex_rollout_path_from_row(row)
        if not path or not path.is_file():
            continue
        scanned += 1
        try:
            st = path.stat()
        except OSError:
            continue
        tail = _extract_codex_tail_meta(path) or {}
        cwd = tail.get("cwd") or cwd
        modified = (
            tail.get("last_meaningful_ts")
            or _codex_ts_seconds(row, "updated")
            or st.st_mtime
        )
        freshness = max(modified, last_interactions.get(sid) or 0)
        if (
            not include_old
            and not (spawn_by_sid.get(sid) or {}).get("alive")
            and cutoff > 0
            and freshness < cutoff
        ):
            continue
        if not include_old and max_rows > 0 and len(out) >= max_rows:
            continue
        row_first_message = _strip_ccc_session_state_instruction(
            row.get("first_user_message") or ""
        ).strip()
        tail_first_message = _strip_ccc_session_state_instruction(
            tail.get("first_message") or ""
        ).strip()
        first_message = row_first_message or tail_first_message
        title = _strip_ccc_session_state_instruction(
            (row.get("title") or "").strip()
        ).strip()
        # Codex sometimes stores the verbatim first user message as the
        # "title" when the prompt is too short to summarize. Only treat the
        # title as AI-generated when it actually differs from first_message
        # — otherwise the ✨ glyph would show on rows where Codex did no
        # summarization.
        codex_ai_title = title if (title and title != first_message) else None
        # Codex's SQLite `title` is the raw first user message when the
        # prompt was too short to summarize — for annotation prompts that
        # can be many kilobytes, so clamp before it becomes the row title.
        # Codex assigns spawned agents a short random codename (agent_nickname,
        # e.g. "Euclid") that tells the user nothing about the work. Prefer a
        # meaningful name: Codex's own (often AI-summarized) title, then the
        # original ask (first user message) — the same fallback unnamed Claude
        # sessions use — and only fall back to the codename when there's nothing
        # else to show. (CCC-296)
        display_name = _codex_display_name(
            row,
            override=name_overrides.get(sid),
            title=title,
            first_message=first_message,
        )
        agent_task_name = _codex_agent_task_label(row)
        # Keep the sidebar's defensive title cap, but retain Codex's complete
        # generated title for the roomier status rail.  When Codex merely
        # copied the opening prompt into `title`, use the compact row title so
        # an annotation-sized prompt cannot fill the rail.
        status_rail_title = title if title and title != first_message else display_name
        branch = row.get("git_branch") or ""
        tail_branch = tail.get("tail_branch") or ""
        tail_worktree_path = tail.get("tail_worktree_path") or ""
        # Prefer the FIRST cwd candidate that still exists on disk. Without
        # this, a tail-extracted worktree path that has since been deleted
        # (deleted worktree, moved repo) would land in `session_cwd` and
        # Launch would try `cd '/.../no-such-worktree' && codex resume …`
        # — which fails and leaves the user in their home dir.
        effective_cwd = _first_existing_dir(
            tail_worktree_path, cwd, pinned
        ) or tail_worktree_path or cwd
        try:
            cwd_exists = bool(effective_cwd and Path(effective_cwd).is_dir())
        except OSError:
            cwd_exists = False
        folder_path = pinned or cwd or effective_cwd or ""
        if folder_path:
            _git_root = _find_git_root(folder_path)
            folder_label = _resolve_dir_case(_git_root or folder_path)
        else:
            folder_label = "Codex"
        _wt_worktree_label = None
        _wt_idx = folder_label.find("-wt-")
        if _wt_idx > 0:
            _wt_worktree_label = folder_label[_wt_idx + 4:]
            folder_label = folder_label[:_wt_idx]
        spawn_info = spawn_by_sid.get(sid) or {}
        spawn_pid = spawn_info.get("pid")
        spawn_alive = bool(spawn_info.get("alive"))
        codex_activity = _codex_activity_fields_from_tail(tail, spawn_alive)
        app_activity = _codex_app_server_activity_fields(sid)
        if app_activity.get("sidecar_status") and not _codex_app_activity_superseded_by_tail(app_activity, tail):
            codex_activity.update(app_activity)
        codex_stale_tool = _codex_stale_tool_fields(tail)
        needs_approval = bool(tail.get("needs_approval") or codex_activity.get("needs_approval"))
        needs_approval_message = (
            tail.get("needs_approval_message")
            or codex_activity.get("needs_approval_message")
            or ""
        )
        _goal = goals_by_sid.get(sid) or {}
        out.append({
            "id": sid,
            "session_id": sid,
            "source": "codex",
            "engine": "codex",
            "timestamp": "",
            "branch": branch,
            "git_branch": branch,
            "first_message": first_message[:200],
            "display_name": display_name,
            "agent_task_name": agent_task_name,
            "status_rail_title": status_rail_title,
            "ai_title": codex_ai_title,
            "name_overridden": bool(name_overrides.get(sid)),
            "last_prompt": (tail.get("last_prompt") or "")[:200],
            "size": st.st_size,
            "modified": modified,
            "modified_human": time.strftime("%Y-%m-%d %H:%M", time.localtime(modified)),
            "mtime": modified,
            "jsonl_path": str(path),
            "folder_label": folder_label,
            "folder_path": folder_path,
            "worktree_label": _wt_worktree_label,
            "session_cwd": effective_cwd,
            "session_cwd_exists": cwd_exists,
            "session_cwd_is_worktree": bool(
                tail_worktree_path or (effective_cwd and (Path(effective_cwd) / ".git").is_file())
            ),
            "worktree_dirty": (
                _worktree_dirty_cached(effective_cwd, modified)
                if resolve_worktree_dirty and effective_cwd else False
            ),
            "effective_branch": tail_branch or None,
            "effective_kind": "worktree" if tail_worktree_path else None,
            "has_edit": tail.get("has_edit", False),
            "has_commit": tail.get("has_commit", False),
            "has_push": tail.get("has_push", False),
            "last_edit_pos": tail.get("last_edit_pos", 0),
            "last_commit_pos": tail.get("last_commit_pos", 0),
            "last_push_pos": tail.get("last_push_pos", 0),
            "last_event_type": tail.get("last_event_type"),
            "pending_tool": tail.get("pending_tool"),
            "pending_file": tail.get("pending_file"),
            "pending_tool_ts": tail.get("pending_tool_ts") or 0,
            "last_assistant_text": tail.get("last_assistant_text"),
            "tail_issue_number": None,
            "tail_pr_number": tail.get("tail_pr_number"),
            "tail_pr_url": tail.get("tail_pr_url"),
            "pr_state": None,
            "session_state": _parse_session_state(tail.get("last_assistant_text")),
            "archived": sid in archived_set or bool(row.get("archived")),
            "trashed": sid in trashed_set or bool(row.get("trashed")),
            "verified": sid in verified_set,
            "pinned_repo": pinned_repo,
            "last_interacted": last_interactions.get(sid),
            "is_live": spawn_alive,
            "spawn_pid": spawn_pid,
            # Prefer the Codex spawn-edge parent so a spawned sub-agent nests
            # under the thread that spawned it in the Current-sessions tree;
            # fall back to the durable CCC-spawn parent link (survives
            # registry pruning), then the live spawn-registry parent. (CCC-298, CCC-465)
            "parent_session_id": (
                codex_parent_by_child.get(sid)
                or codex_durable_parents.get(sid)
                or spawn_info.get("parent_session_id")
                or ""
            ),
            **codex_activity,
            **codex_stale_tool,
            "needs_approval": needs_approval,
            "needs_approval_message": needs_approval_message,
            "model": row.get("model") or tail.get("model") or "",
            "reasoning_effort": row.get("reasoning_effort") or "",
            "latest_input_tokens": tail.get("latest_input_tokens") or 0,
            "context_limit": tail.get("context_limit") or 0,
            **_token_optimizer_quality_for_session(sid),
            "goal": _goal.get("objective") or "",
            "goal_status": _goal.get("status") or "",
        })
    if resolve_pr_states:
        _prime_pr_states(c.get("tail_pr_url") for c in out)
        for c in out:
            if c.get("tail_pr_url"):
                c["pr_state"] = _get_pr_state(c["tail_pr_url"])
    out.sort(key=lambda x: x.get("last_interacted") or x.get("modified") or 0, reverse=True)
    if progress:
        progress(
            "codex",
            state="done",
            count=len(out),
            total=scanned,
            detail=f"{len(out)} Codex thread card(s) ready.",
        )
    return out


def _codex_int(value):
    try:
        return int(value or 0)
    except (TypeError, ValueError):
        return 0


def _codex_token_usage_from_event(ev):
    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
    if payload.get("type") != "token_count":
        return None
    info = payload.get("info") or {}
    if not isinstance(info, dict):
        return None
    usage = info.get("last_token_usage") or info.get("total_token_usage") or {}
    if not isinstance(usage, dict) or not usage:
        return None
    return {
        "input_tokens": _codex_int(usage.get("input_tokens")),
        "cached_input_tokens": _codex_int(usage.get("cached_input_tokens")),
        "output_tokens": _codex_int(usage.get("output_tokens")),
        "reasoning_output_tokens": _codex_int(usage.get("reasoning_output_tokens")),
        "total_tokens": _codex_int(usage.get("total_tokens")),
    }


def _codex_turn_meta_from_event(ev):
    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
    if ev.get("type") != "turn_context" or not isinstance(payload, dict):
        return None
    collaboration = payload.get("collaboration_mode")
    if not isinstance(collaboration, dict):
        collaboration = {}
    settings = collaboration.get("settings", {})
    if not isinstance(settings, dict):
        settings = {}
    model = payload.get("model") or settings.get("model") or ""
    effort = (
        payload.get("effort")
        or payload.get("reasoning_effort")
        or settings.get("reasoning_effort")
        or ""
    )
    out = {}
    if model:
        out["model"] = str(model)
    if effort:
        out["reasoning_effort"] = str(effort)
    return out or None


def _apply_codex_turn_meta(parsed, codex_turn_meta):
    if not parsed or not isinstance(codex_turn_meta, dict):
        return parsed
    if codex_turn_meta.get("model") and not parsed.get("model"):
        parsed["model"] = codex_turn_meta.get("model")
    if codex_turn_meta.get("reasoning_effort") and not parsed.get("reasoning_effort"):
        parsed["reasoning_effort"] = codex_turn_meta.get("reasoning_effort")
    return parsed


_CODEX_IN_APP_BROWSER_CONTEXT_RE = re.compile(
    r"^\s*<in-app-browser-context(?P<attrs>\s+[^>]*)?>(?P<body>.*?)</in-app-browser-context>\s*",
    re.IGNORECASE | re.DOTALL,
)
_CODEX_IN_APP_BROWSER_CONTEXT_SOURCE_RE = re.compile(
    r'''\bsource\s*=\s*["'](?P<source>[^"']+)["']''', re.IGNORECASE,
)


def _extract_codex_in_app_browser_context(text):
    """Split Codex Desktop's injected browser state from the typed request."""
    text = str(text or "")
    match = _CODEX_IN_APP_BROWSER_CONTEXT_RE.match(text)
    if not match:
        return text, None
    source_match = _CODEX_IN_APP_BROWSER_CONTEXT_SOURCE_RE.search(match.group("attrs") or "")
    context = {
        "source": (source_match.group("source").strip() if source_match else "in-app-browser"),
        "text": match.group("body").strip(),
    }
    return text[match.end():].strip(), context


def _codex_usage_delta_from_event(ev, previous_totals=None):
    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
    if payload.get("type") != "token_count":
        return None, previous_totals
    info = payload.get("info") or {}
    if not isinstance(info, dict):
        return None, previous_totals
    last_usage = info.get("last_token_usage")
    total_usage = info.get("total_token_usage")
    if isinstance(last_usage, dict) and last_usage:
        usage = last_usage
    elif isinstance(total_usage, dict) and total_usage:
        prev = previous_totals if isinstance(previous_totals, dict) else {}
        usage = {
            "input_tokens": max(
                _codex_int(total_usage.get("input_tokens"))
                - _codex_int(prev.get("input_tokens")),
                0,
            ),
            "cached_input_tokens": max(
                _codex_int(total_usage.get("cached_input_tokens"))
                - _codex_int(prev.get("cached_input_tokens")),
                0,
            ),
            "output_tokens": max(
                _codex_int(total_usage.get("output_tokens"))
                - _codex_int(prev.get("output_tokens")),
                0,
            ),
            "reasoning_output_tokens": max(
                _codex_int(total_usage.get("reasoning_output_tokens"))
                - _codex_int(prev.get("reasoning_output_tokens")),
                0,
            ),
            "total_tokens": max(
                _codex_int(total_usage.get("total_tokens"))
                - _codex_int(prev.get("total_tokens")),
                0,
            ),
        }
    else:
        return None, previous_totals
    next_totals = total_usage if isinstance(total_usage, dict) else previous_totals
    return {
        "input_tokens": _codex_int(usage.get("input_tokens")),
        "cached_input_tokens": _codex_int(usage.get("cached_input_tokens")),
        "output_tokens": _codex_int(usage.get("output_tokens")),
        "reasoning_output_tokens": _codex_int(usage.get("reasoning_output_tokens")),
        "total_tokens": _codex_int(usage.get("total_tokens")),
    }, next_totals


def _parse_codex_event(ev, line_num, token_usage=None, codex_turn_meta=None):
    ev_type = ev.get("type", "")
    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
    ptype = payload.get("type", "")
    ts = _codex_event_timestamp(ev)
    if ev_type == "event_msg":
        if ptype == "user_message":
            text = _strip_ccc_session_state_instruction(payload.get("message") or "")
            text = _strip_mode3_instruction(text)
            text, ambient_context = _extract_codex_in_app_browser_context(text)
            images = []
            if text or images or ambient_context:
                result = {"line": line_num, "ts": ts, "type": "user_text", "text": text, "images": images}
                if ambient_context:
                    result["ambient_context"] = ambient_context
                return _apply_codex_turn_meta(result, codex_turn_meta)
        if ptype == "agent_message":
            text = (payload.get("message") or "").strip()
            text, artifact, artifact_error = _extract_presentation_artifact(text)
            if text or artifact is not None or artifact_error:
                result = {
                    "line": line_num,
                    "ts": ts,
                    "type": "assistant",
                    "message_id": f"codex-{line_num}",
                    "blocks": ([{"kind": "text", "text": text}] if text else []),
                }
                if artifact is not None:
                    result["presentation_artifact"] = artifact
                if artifact_error:
                    result["presentation_artifact_error"] = artifact_error
                return _apply_codex_turn_meta(result, codex_turn_meta)
        if ptype == "task_complete":
            text = (payload.get("last_agent_message") or payload.get("message") or "").strip()
            result = {
                "line": line_num,
                "ts": ts,
                "type": "result",
                "duration_ms": payload.get("duration_ms", "?"),
            }
            if not text:
                result["no_agent_output"] = True
            if token_usage:
                result["token_usage"] = token_usage
            return result
        return None
    if ev_type != "response_item":
        return None
    if ptype in ("function_call", "custom_tool_call"):
        name = payload.get("name") or "tool"
        is_custom_tool = ptype == "custom_tool_call"
        raw_input = payload.get("input") if isinstance(payload.get("input"), str) else ""
        args = {} if is_custom_tool else _codex_args(payload.get("arguments"))
        detail = (
            _codex_custom_tool_detail(raw_input, name)
            if is_custom_tool else _codex_tool_detail(name, args)
        )
        if isinstance(detail, str) and len(detail) > 200:
            detail = detail[:200] + "..."
        block = {
            "kind": "tool_use",
            "name": _codex_custom_tool_kind(raw_input, name) if is_custom_tool else _codex_tool_name(name),
            "detail": detail or "",
            "id": payload.get("call_id") or payload.get("id") or "",
        }
        approval_required = _codex_tool_requires_approval(name, args, raw_input)
        approval_message = _codex_tool_approval_message(args, raw_input)
        if approval_required:
            block["approval_required"] = True
            block["approval_message"] = approval_message
        command_text = (
            _codex_custom_tool_command(raw_input)
            if is_custom_tool else _codex_tool_command(name, args)
        )
        if command_text:
            redacted_command = _redacted_shell_command_text(command_text, max_len=12000)
            if redacted_command and (
                "\n" in redacted_command
                or len(redacted_command) > 160
                or re.sub(r"\s+", " ", redacted_command).strip() != (detail or "")
            ):
                block["command"] = redacted_command
                here = _extract_shell_heredoc(command_text)
                block["command_kind"] = _shell_script_label(here.get("head", "")) if here else "Shell command"
        return {
            "line": line_num,
            "ts": ts,
            "type": "assistant",
            "message_id": f"codex-tool-{line_num}",
            "blocks": [block],
        }
    if ptype in ("function_call_output", "custom_tool_call_output"):
        output = payload.get("output") or ""
        images = []
        if isinstance(output, list):
            # Structured output (e.g. screenshots). Inlining the base64 here
            # balloons the payload to tens of MB and stalls the open, so pull
            # images out as lazy (line, idx) refs — same scheme the claude
            # parser uses — and /api/conv-image fetches them on demand.
            parts = []
            for item in output:
                if isinstance(item, str):
                    parts.append(item)
                elif isinstance(item, dict):
                    it = item.get("type")
                    url = item.get("image_url") or ""
                    if it == "input_image" and isinstance(url, str) and url.startswith("data:") and "base64," in url:
                        mt = url[5:].split(";", 1)[0] or "image/png"
                        images.append({"kind": "base64", "media_type": mt,
                                       "line": line_num, "idx": len(images)})
                    elif isinstance(item.get("text"), str):
                        parts.append(item["text"])
            output = "\n".join(parts)
        if not isinstance(output, str):
            output = str(output)
        if len(output) > 800:
            output = output[:800] + "\n..."
        result = {
            "line": line_num,
            "ts": ts,
            "type": "tool_result",
            "text": output,
            "tool_use_id": payload.get("call_id", ""),
            "is_error": False,
        }
        if images:
            result["images"] = images
        return result
    return None


def _parse_codex_conversation(thread_id, after_line=0):
    filepath = _resolve_codex_rollout_path(thread_id)
    events = []
    line_num = 0
    codex_token_usage = None
    codex_turn_meta = None
    if not filepath:
        return {"events": [], "last_line": 0}
    try:
        with open(filepath, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                line_num += 1
                if line_num <= after_line:
                    try:
                        skipped_ev = json.loads(line.strip())
                    except json.JSONDecodeError:
                        skipped_ev = None
                    if skipped_ev:
                        turn_meta = _codex_turn_meta_from_event(skipped_ev)
                        if turn_meta:
                            codex_turn_meta = turn_meta
                    continue
                line = line.strip()
                if not line:
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                turn_meta = _codex_turn_meta_from_event(ev)
                if turn_meta:
                    codex_turn_meta = turn_meta
                    continue
                usage = _codex_token_usage_from_event(ev)
                if usage:
                    codex_token_usage = usage
                    continue
                parsed = _parse_codex_event(ev, line_num, codex_token_usage, codex_turn_meta=codex_turn_meta)
                if parsed:
                    events.append(parsed)
    except FileNotFoundError:
        pass
    return {"events": events, "last_line": line_num}


_pending_resume_queue: dict = {}   # session_id → [text, ...]
_pending_resume_lock = threading.Lock()
_pending_resume_retry_after: dict = {}
_PENDING_RESUME_RETRY_DELAY_S = 60.0
_pending_terminal_input_queue: dict = {}   # session_id → [text, ...]
_pending_terminal_input_lock = threading.Lock()
_pending_inputs_lock = threading.Lock()
_pending_inputs_watcher_lock_file = None
_pending_inputs_watcher_retry_started = False
_codex_queue_pump_locks = {}
_codex_queue_pump_locks_guard = threading.Lock()


def _acquire_pending_inputs_watcher_lock(lock_path):
    """Return an exclusive process-wide watcher lock, or None when owned."""
    handle = None
    try:
        lock_path.parent.mkdir(parents=True, exist_ok=True)
        handle = open(lock_path, "a+")
        fcntl.flock(handle.fileno(), fcntl.LOCK_EX | fcntl.LOCK_NB)
        return handle
    except OSError:
        if handle is not None:
            handle.close()
        return None


def _load_pending_inputs():
    """Load pending queues from PENDING_INPUTS_FILE into memory."""
    global _pending_resume_queue, _pending_terminal_input_queue
    try:
        with open(PENDING_INPUTS_FILE) as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        return
    if not isinstance(data, dict):
        return
    with _pending_resume_lock:
        rq = data.get("resume_queue")
        if isinstance(rq, dict):
            _pending_resume_queue.update({k: list(v) for k, v in rq.items() if isinstance(v, list)})
    with _pending_terminal_input_lock:
        tq = data.get("terminal_queue")
        if isinstance(tq, dict):
            _pending_terminal_input_queue.update({k: list(v) for k, v in tq.items() if isinstance(v, list)})


def _save_pending_inputs():
    """Save pending queues from memory to PENDING_INPUTS_FILE."""
    with _pending_inputs_lock:
        with _pending_resume_lock:
            rq = dict(_pending_resume_queue)
        with _pending_terminal_input_lock:
            tq = dict(_pending_terminal_input_queue)
        payload = {"resume_queue": rq, "terminal_queue": tq}
        try:
            PENDING_INPUTS_FILE.parent.mkdir(parents=True, exist_ok=True)
            tmp = PENDING_INPUTS_FILE.with_suffix(".json.tmp")
            with open(tmp, "w") as f:
                json.dump(payload, f, indent=2, sort_keys=True)
            tmp.replace(PENDING_INPUTS_FILE)
        except OSError as e:
            print(f"  [pending-inputs] save failed: {e}")


def _get_queued_events_for_session(session_id):
    """Get synthetic events for any queued messages of this session."""
    events = []
    if not session_id:
        return events
    with _pending_resume_lock:
        resume_queue = list(_pending_resume_queue.get(session_id, []))
    with _pending_terminal_input_lock:
        term_queue = list(_pending_terminal_input_queue.get(session_id, []))
    ts = time.time()
    for text in resume_queue:
        visible_text = _strip_mode3_instruction(text)
        if not visible_text:
            continue
        events.append({
            "line": None,
            "ts": ts,
            "type": "user_text",
            "text": visible_text,
            "images": [],
            "pending": True
        })
    for text in term_queue:
        visible_text = _strip_mode3_instruction(text)
        if not visible_text:
            continue
        events.append({
            "line": None,
            "ts": ts,
            "type": "user_text",
            "text": visible_text,
            "images": [],
            "pending": True
        })
    # Codex threads also surface durable desktop↔CCC coordination events
    # (external turn detected, input queued, CCC turn boundaries) so the
    # ownership story is part of the conversation, not just transient status.
    try:
        if _detect_session_engine(session_id) == "codex":
            events.extend(_get_codex_coordination_events_for_session(session_id))
            events.extend(_get_codex_app_server_item_events_for_session(session_id))
    except Exception:
        pass
    return events


def _merge_synthetic_conversation_events(events, synthetic_events):
    """Chronologically merge transcript and CCC-generated overlay events."""
    combined = list(events or []) + list(synthetic_events or [])

    def _epoch(event):
        value = event.get("ts") if isinstance(event, dict) else None
        if isinstance(value, (int, float)):
            return float(value)
        try:
            return datetime.fromisoformat(str(value or "").replace("Z", "+00:00")).timestamp()
        except (TypeError, ValueError):
            return float("inf")

    # Python's sort is stable, so equal/missing timestamps retain their source
    # order while old coordination rows move beside the turn that produced them.
    combined.sort(key=_epoch)
    return combined

_BUSY_SESSION_STATUSES = {"busy", "running"}


def _session_status_is_busy(status):
    return (status.get("status") or "").lower() in _BUSY_SESSION_STATUSES


def _pending_question_option_matches_text(session_id, text):
    """True when text is exactly one of the current terminal question options."""
    clean = str(text or "").strip()
    if not clean:
        return False
    pending = _pending_ask_user_question_for_session(session_id)
    if not isinstance(pending, dict):
        return False
    candidates = []
    options = pending.get("options")
    if isinstance(options, list):
        candidates.extend(options)
    option_details = pending.get("option_details")
    if isinstance(option_details, list):
        for detail in option_details:
            if isinstance(detail, dict):
                candidates.append(detail.get("label"))
    return any(str(candidate or "").strip() == clean for candidate in candidates)


def _drop_matching_terminal_queue_entries(session_id, text):
    """Remove stale duplicate answer clicks already parked in the terminal queue."""
    clean = str(text or "").strip()
    if not session_id or not clean:
        return 0
    removed = 0
    with _pending_terminal_input_lock:
        queue = _pending_terminal_input_queue.get(session_id)
        if not queue:
            return 0
        kept = []
        for item in queue:
            if str(item or "").strip() == clean:
                removed += 1
            else:
                kept.append(item)
        if removed:
            if kept:
                _pending_terminal_input_queue[session_id] = kept
            else:
                _pending_terminal_input_queue.pop(session_id, None)
    if removed:
        _save_pending_inputs()
    return removed


def _consume_matching_pending_input(session_id, text):
    """Remove one queued copy before re-routing it through Steer.

    Duplicate prompts are valid, so consume at most one item. Resume-queued
    input is checked first because it is the queue used by dormant Codex turns;
    the terminal queue is the fallback used by live terminal sessions.
    """
    clean = str(text or "").strip()
    if not session_id or not clean:
        return 0
    for queue, lock in (
        (_pending_resume_queue, _pending_resume_lock),
        (_pending_terminal_input_queue, _pending_terminal_input_lock),
    ):
        removed = False
        with lock:
            items = queue.get(session_id)
            if not items:
                continue
            for index, item in enumerate(items):
                if str(item or "").strip() != clean:
                    continue
                items.pop(index)
                if not items:
                    queue.pop(session_id, None)
                removed = True
                break
        if removed:
            _save_pending_inputs()
            return 1
    return 0


def _finalize_queued_steer_result(session_id, text, result):
    """Commit a queued-row Steer only when Codex confirmed delivery.

    The durable FIFO remains untouched for unavailable/failed steering. This
    prevents a retry from silently moving the selected item to the queue tail.
    """
    result = dict(result or {})
    if result.get("ok") and result.get("via") == "codex-steer":
        consumed = _consume_matching_pending_input(session_id, text)
        if consumed:
            result["queued_consumed"] = consumed
        return result
    if result.get("code") == "codex_no_active_turn":
        # Steer is meaningful only while a turn is running. If the turn ended
        # between rendering the queued row and the click, leave every durable
        # item in place and wake the normal pump. The pump owns FIFO selection,
        # delivery confirmation, and removal, so clicking a later row can never
        # jump it ahead of an older message.
        _schedule_codex_queue_pump(session_id)
        result.update({
            "ok": True,
            "queued": True,
            "queued_preserved": True,
            "queue_pump_started": True,
        })
        return result
    result["queued"] = True
    result["queued_preserved"] = True
    return result


_CCC_HOOK_SCRIPTS = CCC_HOOK_SCRIPT_NAMES


def _is_ccc_hook_command(command):
    """True if a child process is one of our own Claude Code hook scripts.

    The PreToolUse hook blocks (in its own process group) while a relayed
    AskUserQuestion waits for an answer. That hook is NOT a tool the agent is
    running — counting it as one flips the sidecar to a phantom "Bash" command,
    which masks the question and suppresses the answer modal.
    """
    return any(name in (command or "") for name in _CCC_HOOK_SCRIPTS)


def _spawn_entry_active_tool_child(entry):
    """Return metadata for a transient child tool process under a spawned agent.

    Claude's long-lived MCP servers stay in the Claude process group. Bash/tool
    subprocesses are launched as their own process group, so a direct child with
    a different PGID is a strong signal that the session is still busy even when
    the sidecar says "waiting". Our own hook processes are skipped — a blocked
    question-relay hook is not a running tool.
    """
    try:
        parent_pid = int((entry or {}).get("pid") or 0)
    except (TypeError, ValueError):
        return None
    if parent_pid <= 0:
        return None
    try:
        proc = subprocess.run(
            ["ps", "-axo", "pid=,ppid=,pgid=,stat=,etime=,command="],
            capture_output=True,
            text=True,
            timeout=2,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
        return None
    if proc.returncode != 0:
        return None
    for raw in (proc.stdout or "").splitlines():
        parts = raw.strip().split(None, 5)
        if len(parts) < 5:
            continue
        try:
            pid = int(parts[0])
            ppid = int(parts[1])
            pgid = int(parts[2])
        except ValueError:
            continue
        if ppid != parent_pid or pgid == parent_pid:
            continue
        command = parts[5] if len(parts) > 5 else ""
        if _is_ccc_hook_command(command):
            continue
        # Derive the child's real start time from elapsed (ps etime) so the
        # UI shows the true tool age. Without this the caller stamps
        # time.time() every poll, freezing a hung child at "running <1s"
        # forever and dodging the frontend's 5-minute stale-tool cap.
        elapsed = _parse_ps_etime(parts[4])
        started_at = (time.time() - elapsed) if elapsed is not None else None
        return {
            "pid": pid,
            "pgid": pgid,
            "stat": parts[3],
            "command": command,
            "started_at": started_at,
        }
    return None


def _parse_ps_etime(text):
    """Parse BSD ps ``etime`` ([[DD-]HH:]MM:SS) into elapsed seconds.

    Returns None on anything unparseable so callers can fall back.
    """
    text = (text or "").strip()
    if not text:
        return None
    days = 0
    if "-" in text:
        day_part, _, text = text.partition("-")
        try:
            days = int(day_part)
        except ValueError:
            return None
    bits = text.split(":")
    try:
        nums = [int(b) for b in bits]
    except ValueError:
        return None
    if len(nums) == 3:
        h, m, s = nums
    elif len(nums) == 2:
        h, m, s = 0, nums[0], nums[1]
    else:
        return None
    return days * 86400 + h * 3600 + m * 60 + s


def _queue_terminal_input(session_id, text, status=None):
    """Queue input until a live Claude session reports it is idle again."""
    with _pending_terminal_input_lock:
        queue = _pending_terminal_input_queue.setdefault(session_id, [])
        queue.append(text)
        queued_count = len(queue)
    _save_pending_inputs()
    payload = {

        "ok": True,
        "queued": True,
        "via": "terminal-queued",
        "session_id": session_id,
        "queued_count": queued_count,
    }
    if status:
        payload["pid"] = status.get("pid")
        payload["status"] = status.get("status")
    return payload


def _terminal_input_queue_has_pending(session_id):
    with _pending_terminal_input_lock:
        return bool(_pending_terminal_input_queue.get(session_id))


def _load_daemon_roster():
    """Read Claude Code's background-agent roster, if the daemon is running."""
    try:
        data = json.loads(DAEMON_ROSTER_FILE.read_text())
    except (OSError, json.JSONDecodeError):
        return {}
    return data if isinstance(data, dict) else {}


def _find_live_bg_agent_entry_for_session(session_id):
    """Return the daemon roster worker for a live background Claude session."""
    if not session_id:
        return None
    workers = (_load_daemon_roster().get("workers") or {})
    if not isinstance(workers, dict):
        return None
    for short, worker in workers.items():
        if not isinstance(worker, dict):
            continue
        if worker.get("sessionId") != session_id:
            continue
        entry = dict(worker)
        entry["short"] = short
        return entry
    return None


def _bg_agent_state_for_session(session_id, status=None):
    """Read ~/.claude/jobs/<short>/state.json for a background agent."""
    if not session_id:
        return None
    status = status or {}
    candidates = []
    job_id = status.get("job_id") or status.get("jobId") or ""
    if job_id:
        candidates.append(CLAUDE_JOBS_ROOT / str(job_id) / "state.json")
    candidates.append(CLAUDE_JOBS_ROOT / session_id[:8] / "state.json")

    seen = set()
    for path in candidates:
        if path in seen:
            continue
        seen.add(path)
        try:
            data = json.loads(path.read_text())
        except (OSError, json.JSONDecodeError):
            continue
        if not isinstance(data, dict):
            continue
        if data.get("sessionId") in (None, session_id) or data.get("resumeSessionId") == session_id:
            return data

    try:
        state_files = list(CLAUDE_JOBS_ROOT.glob("*/state.json"))
    except OSError:
        return None
    for path in state_files:
        try:
            data = json.loads(path.read_text())
        except (OSError, json.JSONDecodeError):
            continue
        if not isinstance(data, dict):
            continue
        if data.get("sessionId") == session_id or data.get("resumeSessionId") == session_id:
            return data
    return None


def _bg_agent_ready_for_input(session_id, status=None):
    """Whether a live background agent has a prompt ready for user text.

    Claude's registry can report `busy` while the main agent is blocked for
    user input but a child local agent is still running. The jobs state is the
    better signal for background-agent input readiness.
    """
    sc = _read_sidecar_state(session_id)
    if sc and (sc.get("status") or "").lower() == "waiting":
        return True

    job_state = _bg_agent_state_for_session(session_id, status)
    if job_state:
        state = (job_state.get("state") or "").lower()
        if state in {"blocked", "done", "idle", "waiting"}:
            return True
        if state in {"active", "busy", "running", "working"}:
            return False

    status_text = ((status or {}).get("status") or "").lower()
    if status_text in {"idle", "waiting"}:
        return True
    if status_text in _BUSY_SESSION_STATUSES:
        return False
    return True


def _daemon_socket_path_allowed(path):
    """Clamp daemon socket use to Claude's per-user temp daemon directory."""
    if not path:
        return False
    try:
        real = os.path.realpath(path)
        daemon_dir = f"cc-daemon-{os.getuid()}"
        base_parents = {tempfile.gettempdir(), "/tmp", "/private/tmp"}
        for base_parent in base_parents:
            base = os.path.realpath(os.path.join(base_parent, daemon_dir))
            if real == base or real.startswith(base + os.sep):
                return True
        return False
    except (TypeError, ValueError, OSError):
        return False


def _clean_pty_prompt_text(text):
    """Drop terminal-control characters before writing into a background PTY."""
    text = str(text or "").replace("\r\n", "\n").replace("\r", "\n")
    return "".join(
        ch for ch in text
        if ch in ("\n", "\t") or (ord(ch) >= 32 and ord(ch) != 127)
    )


def _inject_bg_agent_via_pty_socket(worker, text, session_id=None):
    """Send text to a live `claude agents` background session.

    The daemon PTY socket uses framed messages:
      4-byte big-endian payload length, 1-byte channel, payload bytes.
    Channel 0 is PTY data. We bracket-paste the body so multi-line prompts
    land as text, then send Return to submit.
    """
    if not worker:
        return {
            "ok": False,
            "via": "bg-agent-pty",
            "error": "background agent is live, but its daemon worker was not found",
        }
    pty_sock = worker.get("ptySock") or ""
    if not _daemon_socket_path_allowed(pty_sock):
        return {
            "ok": False,
            "via": "bg-agent-pty",
            "error": "background agent PTY socket is outside the expected daemon directory",
        }
    try:
        mode = os.stat(pty_sock).st_mode
    except OSError as e:
        return {"ok": False, "via": "bg-agent-pty", "error": str(e)}
    if not stat.S_ISSOCK(mode):
        return {
            "ok": False,
            "via": "bg-agent-pty",
            "error": "background agent PTY path is not a socket",
        }

    clean_text = _clean_pty_prompt_text(text)
    if not clean_text.strip():
        return {"ok": False, "via": "bg-agent-pty", "error": "missing text"}
    payload = ("\x1b[200~" + clean_text + "\x1b[201~").encode("utf-8")
    frame = len(payload).to_bytes(4, "big") + b"\x00" + payload
    submit = b"\r"
    submit_frame = len(submit).to_bytes(4, "big") + b"\x00" + submit

    sock = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
    sock.settimeout(2)
    try:
        sock.connect(pty_sock)
        sock.sendall(frame)
        time.sleep(0.05)
        sock.sendall(submit_frame)
    except (OSError, socket.timeout) as e:
        return {"ok": False, "via": "bg-agent-pty", "error": str(e)}
    finally:
        try:
            sock.close()
        except OSError:
            pass
    # A successful socket write is NOT delivery (CCC-113): app-managed
    # bg-pty daemons accept the connection and silently discard the input
    # frames, so "ok" here used to mean "vanished without a trace". Confirm
    # the text actually lands in the transcript before claiming success.
    sid = session_id or worker.get("sessionId") or ""
    if sid and not _transcript_gains_text(sid, clean_text):
        _bg_pty_inject_failures[sid] = time.time()
        return {
            "ok": False,
            "via": "bg-agent-pty",
            "delivery_unconfirmed": True,
            "pid": worker.get("pid"),
            "error": (
                "The input was written to the session's pty socket but never "
                "appeared in its transcript — this app-managed terminal "
                "ignores socket input. Type in its window instead."
            ),
        }
    return {
        "ok": True,
        "via": "bg-agent-pty",
        "pid": worker.get("pid"),
        "session_id": worker.get("sessionId"),
    }


# sid → epoch of the last pty inject whose delivery could not be confirmed.
# The queue watcher backs off such sessions so parked messages don't churn
# through a known-broken channel every tick.
_bg_pty_inject_failures: dict = {}


def _transcript_gains_text(session_id, text, timeout_s=6.0):
    """True once `text`'s first line shows up in the session transcript tail.

    Polls the last 128KB of the JSONL for up to `timeout_s`. Callers queue
    ahead of this when the session is busy, so a working channel lands the
    text within a second or two of an idle inject.
    """
    needle = ""
    for line in str(text or "").splitlines():
        line = line.strip()
        if line:
            needle = line[:60]
            break
    if not needle:
        return True
    # JSONL stores the message JSON-encoded; escape so multi-byte and
    # quote-bearing needles match the on-disk form.
    needle_json = json.dumps(needle, ensure_ascii=False)[1:-1]
    path = _resolve_conversation_path(session_id)
    deadline = time.time() + timeout_s
    while time.time() < deadline:
        try:
            with open(path, "rb") as fh:
                fh.seek(0, 2)
                size = fh.tell()
                fh.seek(max(0, size - 131072))
                tail = fh.read().decode("utf-8", "replace")
            if needle_json in tail:
                return True
        except OSError:
            pass
        time.sleep(1.0)
    return False


def _resume_queue_engine_busy(sid):
    if any(
        s.get("resumed_sid") == sid and _poll_spawn_entry(s) is None
        for s in _spawned_sessions
        if s.get("engine") in ("codex", "gemini", "cursor", "antigravity", "hermes")
    ):
        return True
    if _is_codex_session(sid):
        # Preserve proven external writers on the cheap stat/lsof path. Only an
        # ownership-unknown turn needs the authoritative reattachment that
        # opening a CLI would otherwise trigger for the user.
        snap = {}
        try:
            snap = _codex_thread_writer_snapshot(sid)
            _codex_note_external_writer_transition(sid, snap)
            if snap.get("external_active") and snap.get("writer") != "unknown":
                return True
        except Exception:
            snap = {}
        if _codex_app_server_thread_is_active(sid, start_if_needed=True):
            return True
        if snap.get("external_active"):
            # Re-check after idle reconciliation. A real CLI is still visible
            # through rollout activity; a phantom in-memory owner disappears.
            try:
                snap = _codex_thread_writer_snapshot(sid)
                _codex_note_external_writer_transition(sid, snap)
                if snap.get("external_active"):
                    return True
            except Exception:
                return True
    return False


def _pending_resume_retry_due(sid, now=None):
    now = time.time() if now is None else float(now)
    return now >= float(_pending_resume_retry_after.get(sid, 0.0) or 0.0)


def _mark_pending_resume_retry(sid, now=None, delay=None):
    now = time.time() if now is None else float(now)
    delay = _PENDING_RESUME_RETRY_DELAY_S if delay is None else float(delay)
    _pending_resume_retry_after[sid] = now + max(0.0, delay)


def _codex_queue_pump_lock(session_id):
    """Return the process-local delivery lock for one Codex conversation."""
    with _codex_queue_pump_locks_guard:
        return _codex_queue_pump_locks.setdefault(session_id, threading.Lock())


def _schedule_codex_queue_pump(session_id):
    """Trigger FIFO delivery for one conversation without blocking the caller."""
    if not session_id:
        return
    threading.Thread(
        target=_pump_codex_resume_queue,
        args=(session_id,),
        daemon=True,
        name=f"codex-queue-pump-{session_id[:8]}",
    ).start()


def _pump_codex_resume_queue(session_id):
    """Deliver at most one durable Codex message, preserving FIFO order."""
    lock = _codex_queue_pump_lock(session_id)
    if not lock.acquire(blocking=False):
        return {"ok": True, "waiting": "already-pumping"}
    try:
        if not _pending_resume_retry_due(session_id):
            return {"ok": True, "waiting": "backoff"}
        if _resume_queue_engine_busy(session_id):
            return {"ok": True, "waiting": "busy"}
        with _pending_resume_lock:
            queue = _pending_resume_queue.get(session_id) or []
            text = queue[0] if queue else None
        if text is None:
            return {"ok": True, "empty": True}

        result = resume_session_codex(session_id, text, _from_queue=True)
        delivery_unconfirmed = bool(
            result
            and result.get("accepted")
            and result.get("confirmed") is not True
        )
        if (
            not result
            or not result.get("ok")
            or result.get("queued")
            or delivery_unconfirmed
        ):
            _mark_pending_resume_retry(session_id)
            return {"ok": False, "delivered": False, "result": result}

        removed = False
        with _pending_resume_lock:
            queue = _pending_resume_queue.get(session_id) or []
            if queue and queue[0] == text:
                queue.pop(0)
                removed = True
                if not queue:
                    _pending_resume_queue.pop(session_id, None)
        if removed:
            _save_pending_inputs()
        _pending_resume_retry_after.pop(session_id, None)
        return {"ok": True, "delivered": removed, "result": result}
    finally:
        lock.release()


def _codex_compaction_recovery_prompt(session_id, goals=None, recovery=None):
    goals = _codex_goals_snapshot() if goals is None else goals
    goal = goals.get(session_id) if isinstance(goals, dict) else None
    silent_turn = _codex_recovery_is_silent_turn(recovery)
    if isinstance(goal, dict) and str(goal.get("status") or "active").lower() == "active":
        if silent_turn:
            return (
                "Continue working toward the active goal after the previous turn went silent. "
                "Resume from the current repository and conversation state, do not "
                "repeat completed work, and finish and verify the original objective."
            )
        return (
            "Continue working toward the active goal after context compaction. "
            "Resume from the current repository and conversation state, do not "
            "repeat completed work, and finish and verify the original objective."
        )
    if silent_turn:
        return (
            "Continue the task after the previous turn went silent. Resume from the "
            "current repository and conversation state, do not repeat completed work, "
            "and finish and verify the original request."
        )
    return (
        "Continue the task that was interrupted by context compaction. Resume "
        "from the current repository and conversation state, do not repeat "
        "completed work, and finish and verify the original request."
    )


def _codex_compaction_recovery_suppress_unlocked(state, reason, now):
    recovery = state.get("compaction_recovery")
    if not isinstance(recovery, dict):
        return
    recovery["status"] = "suppressed"
    recovery["suppressed_reason"] = str(reason)
    label = (
        "Silent-turn recovery"
        if _codex_recovery_is_silent_turn(recovery)
        else "Compaction recovery"
    )
    recovery["reason"] = f"{label} suppressed: {reason}"
    recovery["suppressed_at"] = float(now)
    _codex_coordination_event_unlocked(
        state,
        _codex_recovery_event_kind(recovery, "suppressed"),
        detail=recovery["reason"],
        now=now,
    )


def _run_codex_compaction_recovery_once(session_id, now=None):
    """Advance one conversation's bounded post-compaction recovery episode."""
    sid = str(session_id or "").strip()
    now = time.time() if now is None else float(now)
    if not sid:
        return {"ok": False, "waiting": "missing-session"}

    goals = _codex_goals_snapshot()
    with _pending_resume_lock:
        has_user_input = bool(_pending_resume_queue.get(sid))

    with _CODEX_APP_SERVER_LOCK:
        state = _CODEX_APP_SERVER_THREAD_STATE.get(sid)
        recovery = state.get("compaction_recovery") if isinstance(state, dict) else None
        if not isinstance(recovery, dict):
            return {"ok": True, "waiting": "not-armed"}
        recovery_status = str(recovery.get("status") or "waiting")
        if recovery_status in _CODEX_COMPACTION_RECOVERY_TERMINAL:
            return {"ok": True, "waiting": "terminal"}
        silent_turn = _codex_recovery_is_silent_turn(recovery)

        suppressed = None
        if state.get("thread_needs_approval") or _codex_app_server_pending_approval_item(state):
            suppressed = "approval"
        elif state.get("active_flags"):
            suppressed = "active-flag"
        elif has_user_input and not silent_turn:
            suppressed = "queued-user-input"
        else:
            goal = goals.get(sid) if isinstance(goals, dict) else None
            goal_status = str(goal.get("status") or "") if isinstance(goal, dict) else ""
            if goal_status.lower() in ("paused", "blocked", "complete", "completed"):
                suppressed = f"goal-{'complete' if goal_status.lower() == 'completed' else goal_status.lower()}"
        if suppressed:
            _codex_compaction_recovery_suppress_unlocked(state, suppressed, now)
            _save_codex_app_server_state_unlocked()
            return {"ok": True, "suppressed": suppressed}

        last_progress_at = float(
            max(
                float(recovery.get("last_progress_at") or 0.0),
                float(recovery.get("last_attempt_at") or 0.0),
                float(recovery.get("compacted_at") or 0.0),
            )
        )
        if (
            recovery_status == "recovering"
            and now - last_progress_at < _CODEX_COMPACTION_RECOVERY_STALL_S
        ):
            return {"ok": True, "waiting": "recovery-in-flight"}
        if (
            recovery_status == "waiting"
            and int(recovery.get("attempts") or 0) == 0
            and not silent_turn
            and now - last_progress_at < _CODEX_COMPACTION_RECOVERY_GRACE_S
        ):
            return {"ok": True, "waiting": "grace"}
        if now < float(recovery.get("next_attempt_at") or 0.0):
            return {"ok": True, "waiting": "backoff"}

        active_item = state.get("active_item") if isinstance(state.get("active_item"), dict) else None
        if active_item and active_item.get("in_flight", True):
            if active_item.get("type") == "contextCompaction":
                return {"ok": True, "waiting": "compacting"}
            return {"ok": True, "waiting": "active-tool"}

        active_turn = bool(
            state.get("active_turn_id")
            or str(state.get("status") or "").lower() == "active"
        )

    if active_turn:
        # Mark and persist before the RPC: Codex can emit turn/completed while
        # turn/interrupt is still waiting for its JSON-RPC response. Reset any
        # partial assistant delta so that interrupt completion cannot be
        # mistaken for a successful terminal reply.
        with _CODEX_APP_SERVER_LOCK:
            state = _CODEX_APP_SERVER_THREAD_STATE.get(sid) or {}
            recovery = state.get("compaction_recovery")
            if not isinstance(recovery, dict):
                return {"ok": False, "waiting": "not-armed"}
            recovery["status"] = "interrupting"
            recovery["reason"] = (
                "Interrupting silent stalled Codex turn"
                if _codex_recovery_is_silent_turn(recovery)
                else "Interrupting stalled Codex turn after compaction"
            )
            recovery["saw_agent_output"] = False
            recovery["last_attempt_at"] = now
            recovery["next_attempt_at"] = now + _CODEX_COMPACTION_RECOVERY_INTERRUPT_SETTLE_S
            _codex_coordination_event_unlocked(
                state,
                _codex_recovery_event_kind(recovery, "interrupting"),
                detail=recovery["reason"],
                now=now,
            )
            _save_codex_app_server_state_unlocked()
        interrupted = _codex_interrupt_via_app_server(sid)
        with _CODEX_APP_SERVER_LOCK:
            state = _CODEX_APP_SERVER_THREAD_STATE.get(sid) or {}
            recovery = state.get("compaction_recovery")
            if not isinstance(recovery, dict):
                return {"ok": False, "waiting": "not-armed"}
            if interrupted.get("ok"):
                # The interrupt RPC is authoritative. Clearing the volatile
                # local turn marker prevents a lost completion notification
                # from causing an unbounded interrupt loop; the normal writer
                # gate still re-checks Codex before starting the retry.
                state["status"] = "idle"
                state.pop("active_turn_id", None)
                state.pop("active_writer", None)
                queue_handoff = bool(
                    has_user_input and _codex_recovery_is_silent_turn(recovery)
                )
                if queue_handoff:
                    _codex_compaction_recovery_suppress_unlocked(
                        state, "queued-user-input", now
                    )
                _save_codex_app_server_state_unlocked()
                if queue_handoff:
                    _schedule_codex_queue_pump(sid)
                return {
                    "ok": True,
                    "interrupted": True,
                    "queue_handoff": queue_handoff,
                    "result": interrupted,
                }
            if str(recovery.get("status") or "") not in _CODEX_COMPACTION_RECOVERY_TERMINAL:
                recovery["status"] = "waiting"
                recovery["reason"] = interrupted.get("error") or "Could not interrupt stalled Codex turn"
                recovery["next_attempt_at"] = now + _CODEX_COMPACTION_RECOVERY_RETRY_S
                if interrupted.get("code") == "codex_no_active_turn":
                    state["status"] = "idle"
                    state.pop("active_turn_id", None)
                    recovery["next_attempt_at"] = now
            _save_codex_app_server_state_unlocked()
        return {"ok": False, "interrupted": False, "result": interrupted}

    with _CODEX_APP_SERVER_LOCK:
        recovery_snapshot = dict(
            (_CODEX_APP_SERVER_THREAD_STATE.get(sid) or {}).get("compaction_recovery")
            or {}
        )
    prompt = _codex_compaction_recovery_prompt(
        sid, goals=goals, recovery=recovery_snapshot
    )
    with _CODEX_APP_SERVER_LOCK:
        state = _CODEX_APP_SERVER_THREAD_STATE.get(sid) or {}
        recovery = state.get("compaction_recovery")
        if not isinstance(recovery, dict):
            return {"ok": False, "waiting": "not-armed"}
        attempts = int(recovery.get("attempts") or 0) + 1
        recovery["attempts"] = attempts
        recovery["status"] = "recovering"
        recovery["reason"] = _codex_recovery_activity_text(recovery)
        recovery["saw_agent_output"] = False
        recovery["last_attempt_at"] = now
        recovery["next_attempt_at"] = now + _CODEX_COMPACTION_RECOVERY_RETRY_S
        _save_codex_app_server_state_unlocked()

    result = resume_session_codex(sid, prompt, _from_queue=True)
    started = bool(result and result.get("ok") and not result.get("queued"))
    with _CODEX_APP_SERVER_LOCK:
        state = _CODEX_APP_SERVER_THREAD_STATE.get(sid) or {}
        recovery = state.get("compaction_recovery")
        if not isinstance(recovery, dict):
            return {"ok": False, "started": False, "result": result}
        if started:
            recovery["status"] = "recovering"
            recovery["reason"] = _codex_recovery_activity_text(recovery)
            if result.get("turn_id"):
                recovery["recovery_turn_id"] = str(result["turn_id"])
            _codex_coordination_event_unlocked(
                state,
                _codex_recovery_event_kind(recovery, "started"),
                detail=recovery["reason"],
                now=now,
            )
            _save_codex_app_server_state_unlocked()
            return {"ok": True, "started": True, "result": result}

        error = (result or {}).get("error") or "Codex recovery turn did not start"
        recovery["last_error"] = str(error)
        if int(recovery.get("attempts") or 0) >= _CODEX_COMPACTION_RECOVERY_MAX_ATTEMPTS:
            recovery["status"] = "exhausted"
            recovery["reason"] = (
                "Silent-turn recovery attempts exhausted"
                if _codex_recovery_is_silent_turn(recovery)
                else "Compaction recovery attempts exhausted"
            )
            _codex_coordination_event_unlocked(
                state,
                _codex_recovery_event_kind(recovery, "exhausted"),
                detail=str(error),
                now=now,
            )
            exhausted = True
        else:
            recovery["status"] = "waiting"
            recovery["reason"] = str(error)
            recovery["next_attempt_at"] = now + _CODEX_COMPACTION_RECOVERY_RETRY_S
            exhausted = False
        _save_codex_app_server_state_unlocked()
    return {
        "ok": False,
        "started": False,
        "exhausted": exhausted,
        "result": result,
    }


def _codex_reconcile_recovery_goal_threads(goals, now):
    """Rediscover active goal turns after a CCC server restart.

    Volatile writer/turn status is intentionally not restored from disk. A
    bounded thread/resume read reconnects those goal threads to the app-server;
    the saved activity timestamp remains authoritative for the same turn.
    """
    if not isinstance(goals, dict):
        return
    for sid, goal in goals.items():
        if not isinstance(goal, dict):
            continue
        if str(goal.get("status") or "active").lower() != "active":
            continue
        with _CODEX_APP_SERVER_LOCK:
            state = _CODEX_APP_SERVER_THREAD_STATE.get(str(sid)) or {}
            status = str(state.get("status") or "").lower()
            if status in ("active", "idle") or state.get("active_turn_id"):
                continue
            last = float(_codex_recovery_reconciled_at.get(str(sid), 0.0) or 0.0)
            if now - last < _CODEX_RECOVERY_RECONCILE_S:
                continue
            _codex_recovery_reconciled_at[str(sid)] = float(now)
        try:
            _codex_app_server_thread_is_active(str(sid), start_if_needed=True)
        except Exception:
            continue


def _codex_recovery_watchdog_session_ids(goals, now):
    """Arm silent-turn episodes and return every nonterminal recovery sid."""
    with _pending_resume_lock:
        queued_sids = {
            str(sid) for sid, queue in _pending_resume_queue.items() if queue
        }
    changed = False
    session_ids = []
    with _CODEX_APP_SERVER_LOCK:
        for sid, state in _CODEX_APP_SERVER_THREAD_STATE.items():
            if not isinstance(state, dict):
                continue
            recovery = state.get("compaction_recovery")
            if (
                isinstance(recovery, dict)
                and str(recovery.get("status") or "")
                not in _CODEX_COMPACTION_RECOVERY_TERMINAL
            ):
                session_ids.append(str(sid))
                continue

            active = bool(
                state.get("active_turn_id")
                or str(state.get("status") or "").lower() == "active"
            )
            if not active:
                continue
            source_turn_id = str(
                state.get("active_turn_id") or state.get("last_turn_id") or ""
            )
            if not source_turn_id:
                continue
            goal = goals.get(str(sid)) if isinstance(goals, dict) else None
            active_goal = bool(
                isinstance(goal, dict)
                and str(goal.get("status") or "active").lower() == "active"
            )
            has_user_input = str(sid) in queued_sids
            if not active_goal and not has_user_input:
                continue
            if state.get("thread_needs_approval") or state.get("active_flags"):
                continue
            active_item = (
                state.get("active_item")
                if isinstance(state.get("active_item"), dict)
                else None
            )
            if active_item and active_item.get("in_flight", True):
                continue
            try:
                last_activity_at = float(
                    state.get("last_activity_at") or state.get("last_event_at") or 0.0
                )
            except (TypeError, ValueError):
                last_activity_at = 0.0
            if not last_activity_at or now - last_activity_at < _CODEX_SILENT_TURN_STALL_S:
                continue
            if (
                isinstance(recovery, dict)
                and _codex_recovery_is_silent_turn(recovery)
                and str(recovery.get("source_turn_id") or "") == source_turn_id
                and not has_user_input
            ):
                continue

            episode_id = f"silent-turn-{source_turn_id}"
            recovery = {
                "episode_id": episode_id,
                "trigger": "silent-turn",
                "source_turn_id": source_turn_id,
                # Existing bounded recovery machinery keys completion and
                # interrupt races through this compatibility field.
                "compaction_turn_id": source_turn_id,
                "triggered_at": float(now),
                "compacted_at": float(now),
                "last_progress_at": last_activity_at,
                "status": "waiting",
                "attempts": 0,
                "next_attempt_at": float(now),
                "reason": "Active Codex turn went silent without completing",
                "compaction_in_flight": False,
                "saw_agent_output": False,
            }
            state["compaction_recovery"] = recovery
            _codex_coordination_event_unlocked(
                state,
                "turn_recovery_armed",
                detail="Active goal turn went silent; preparing recovery",
                now=now,
            )
            session_ids.append(str(sid))
            changed = True
        if changed:
            _save_codex_app_server_state_unlocked()
    return session_ids


def _run_codex_recovery_watchdog_once(now=None):
    """Recover compaction episodes and silent active goal turns."""
    now = time.time() if now is None else float(now)
    _codex_load_coordination_state()
    goals = _codex_goals_snapshot()
    _codex_reconcile_recovery_goal_threads(goals, now)
    session_ids = _codex_recovery_watchdog_session_ids(goals, now)
    results = []
    for sid in session_ids:
        try:
            results.append((sid, _run_codex_compaction_recovery_once(sid, now=now)))
        except Exception as exc:
            results.append((sid, {"ok": False, "error": str(exc)}))
    return results


# ── Terminal-queue drain safety (CCC-455) ───────────────────────────────────
# A terminal-queue entry must NEVER be silently consumed: the 2026-07-02
# incident (dd6f2efe) popped an entry while a foreign `claude --resume` still
# owned the session, handed it to `wt send` (rc 0, transport=resume), and wt's
# then-broken resume adapter lost the text — queue empty, transcript never
# advanced. Three defenses below, all used by the watcher drain loop:
#   1. failed deliveries re-queue at the FRONT with a retry backoff;
#   2. wt-send deliveries are only PROVISIONALLY consumed — the receipt
#      (WT-77) is polled until the transcript proves `landed`, and a verified
#      `lost` re-queues the text and forces the retry to bypass wt;
#   3. undeliverable-forever drops (dead session) log loudly instead of
#      vanishing.
_pending_terminal_retry_after = {}
_TERMINAL_QUEUE_RETRY_DELAY_S = 60.0
_terminal_drain_receipts = []          # [{sid, text, receipt_id, deadline, last_check}]
_TERMINAL_DRAIN_RECEIPT_DEADLINE_S = 600.0
_TERMINAL_DRAIN_RECEIPT_POLL_S = 15.0
_terminal_drain_skip_wt = set()        # sids whose next drain attempt bypasses wt


def _terminal_queue_retry_due(sid, now=None):
    now = time.time() if now is None else float(now)
    return now >= float(_pending_terminal_retry_after.get(sid, 0.0) or 0.0)


def _mark_terminal_queue_retry(sid, now=None, delay=None):
    now = time.time() if now is None else float(now)
    delay = _TERMINAL_QUEUE_RETRY_DELAY_S if delay is None else float(delay)
    _pending_terminal_retry_after[sid] = now + max(0.0, delay)


def _requeue_terminal_input_front(sid, text):
    """Put a popped-but-undelivered entry back where it came from (front,
    preserving order relative to anything queued behind it)."""
    with _pending_terminal_input_lock:
        _pending_terminal_input_queue.setdefault(sid, []).insert(0, text)
    _save_pending_inputs()


def _verify_terminal_drain_receipts(now=None):
    """Poll in-flight wt-send receipts for drained terminal-queue entries.

    Bounded work: only entries this watcher actually handed to wt are tracked
    (normally zero), each polled at most every _TERMINAL_DRAIN_RECEIPT_POLL_S.
    `landed` = delivery proven against the transcript, done. `lost` = wt
    verified the text never arrived — re-queue it and make the retry skip wt.
    Deadline expiry with the receipt still unverified does NOT re-send (the
    transcript may have absorbed the text in a form the needle can't match;
    re-sending would double-deliver) — but it logs instead of vanishing."""
    now = time.time() if now is None else float(now)
    for item in list(_terminal_drain_receipts):
        if now - float(item.get("last_check") or 0.0) < _TERMINAL_DRAIN_RECEIPT_POLL_S:
            continue
        item["last_check"] = now
        rec = None
        try:
            proc = subprocess.run(
                ["wt", "receipts", "get", item["receipt_id"]],
                capture_output=True, text=True, timeout=10,
            )
            if proc.returncode == 0:
                rec = json.loads(proc.stdout or "")
        except (OSError, subprocess.TimeoutExpired, ValueError, json.JSONDecodeError):
            rec = None
        rec_status = (rec or {}).get("status") if isinstance(rec, dict) else None
        if rec_status == "landed":
            _terminal_drain_receipts.remove(item)
        elif rec_status == "lost":
            _terminal_drain_receipts.remove(item)
            _terminal_drain_skip_wt.add(item["sid"])
            _requeue_terminal_input_front(item["sid"], item["text"])
            _mark_terminal_queue_retry(item["sid"], delay=5.0)
            print(
                f"[terminal-queue] wt-send receipt {item['receipt_id']} LOST — "
                f"re-queued input for {item['sid']} (next attempt bypasses wt)",
                flush=True,
            )
        elif now > float(item.get("deadline") or 0.0):
            _terminal_drain_receipts.remove(item)
            print(
                f"[terminal-queue] wt-send receipt {item['receipt_id']} still "
                f"unverified after {int(_TERMINAL_DRAIN_RECEIPT_DEADLINE_S)}s — "
                f"treating as delivered for {item['sid']}",
                flush=True,
            )


def _start_resume_queue_watcher() -> None:
    """Drain queued prompts once fire-and-watch engines or live terminal sessions go idle."""
    global _pending_inputs_watcher_lock_file, _pending_inputs_watcher_retry_started
    if _pending_inputs_watcher_lock_file is not None:
        return
    lock_path = PENDING_INPUTS_FILE.with_suffix(".watcher.lock")
    lock_file = _acquire_pending_inputs_watcher_lock(lock_path)
    if lock_file is None:
        print("[pending-inputs] resume watcher owned by another CCC process", flush=True)
        # Do not permanently give up when an older sibling holds the lock. If
        # its watcher thread has died, its process still keeps the flock until
        # restart; this process must be ready to take over as soon as it drops.
        if not _pending_inputs_watcher_retry_started:
            _pending_inputs_watcher_retry_started = True

            def _retry_watcher_lock():
                global _pending_inputs_watcher_retry_started
                while _pending_inputs_watcher_lock_file is None:
                    time.sleep(5)
                    _start_resume_queue_watcher()
                _pending_inputs_watcher_retry_started = False

            threading.Thread(
                target=_retry_watcher_lock,
                daemon=True,
                name="resume-queue-watcher-lock-retry",
            ).start()
        return
    # Keep the lock handle local to the watcher wrapper. A global handle keeps
    # the flock alive if the thread exits unexpectedly, stranding every later
    # server behind a stale sibling process.
    _pending_inputs_watcher_lock_file = True
    _load_pending_inputs()
    # Restore durable Codex coordination events before any app-server
    # notification persists (and would otherwise clobber) the state file.
    try:
        _codex_load_coordination_state()
    except Exception:
        pass
    def _watcher():
        while True:
            time.sleep(5)
            # Another local CCC may have accepted a message since the previous
            # pass. The single watcher owns delivery but always refreshes this
            # durable queue before draining it.
            _load_pending_inputs()
            # Recovery is lower priority than every durable user message. Run
            # this before FIFO draining so a queued message suppresses its
            # conversation's automatic continuation instead of racing it.
            _run_codex_recovery_watchdog_once()
            with _pending_resume_lock:
                queued_sids = list(_pending_resume_queue.keys())
            for sid in queued_sids:
                if _is_codex_session(sid):
                    _pump_codex_resume_queue(sid)
                    continue
                if not _pending_resume_retry_due(sid):
                    continue
                if _resume_queue_engine_busy(sid):
                    continue
                with _pending_resume_lock:
                    queue = _pending_resume_queue.get(sid, [])
                    if not queue:
                        _pending_resume_queue.pop(sid, None)
                        _pending_resume_retry_after.pop(sid, None)
                        text = None
                    else:
                        text = queue.pop(0)
                        if not queue:
                            _pending_resume_queue.pop(sid, None)
                _save_pending_inputs()
                if text is None:
                    continue
                result = None
                try:
                    if _is_codex_session(sid):
                        result = resume_session_codex(sid, text)
                    elif _is_gemini_session(sid):
                        result = resume_session_gemini(sid, text)
                    elif _is_cursor_session(sid):
                        result = resume_session_cursor(sid, text)
                    elif _is_antigravity_session(sid):
                        result = resume_session_antigravity(sid, text)
                    elif _is_hermes_session(sid):
                        result = resume_session_hermes(sid, text)
                except Exception:
                    result = {"ok": False}
                if not result or not result.get("ok"):
                    with _pending_resume_lock:
                        _pending_resume_queue.setdefault(sid, []).insert(0, text)
                    _save_pending_inputs()
                    _mark_pending_resume_retry(sid)
                elif result.get("queued"):
                    _mark_pending_resume_retry(sid)
                else:
                    _pending_resume_retry_after.pop(sid, None)
            with _pending_terminal_input_lock:
                terminal_sids = list(_pending_terminal_input_queue.keys())
            for sid in terminal_sids:
                try:
                    # CHEAP LIVENESS PRE-GATE (perf + stuck-queue cleanup):
                    # terminal input can only ever be injected into a LIVE
                    # session (tty / bg agent / live spawn). If the session
                    # isn't even a live candidate — no fresh sidecar, no live
                    # engine process — it is dead and its queued input is
                    # undeliverable forever. Without this gate the watcher ran
                    # the EXPENSIVE session_live_status() probe (~0.5s each) on
                    # every such dead sid every 5s, pinning a core on a session
                    # that closed weeks ago (observed: a 26-day-dead sid with 13
                    # stuck items). Drop the queue and skip the probe entirely.
                    # The memoized _archive_session_is_live is ~free and is a
                    # strict superset of "injectable", so no live session is lost.
                    if not _archive_session_is_live(sid):
                        dropped = None
                        with _pending_terminal_input_lock:
                            dropped = _pending_terminal_input_queue.pop(sid, None)
                        if dropped:
                            # Loud, not silent (CCC-455): this is the one place
                            # queued user text is deliberately discarded.
                            print(
                                f"[terminal-queue] dropping {len(dropped)} queued "
                                f"input(s) for dead session {sid}: "
                                + "; ".join(repr(t[:80]) for t in dropped),
                                flush=True,
                            )
                            _save_pending_inputs()
                        continue
                    # Backoff gate (CCC-455): a sid whose last drain attempt
                    # failed or re-parked waits out its retry window before we
                    # spend another live-status probe on it.
                    if not _terminal_queue_retry_due(sid):
                        continue
                    # CRITICAL guard — never flush queued input while an
                    # AskUserQuestion is in-flight. The watcher previously
                    # only checked _session_status_is_busy() (status =
                    # busy/running), which can return False even when
                    # sidecar_tool == "AskUserQuestion" is still pending a
                    # user pick. Injecting queued text in that window made
                    # Claude Code synthesize a tool_result for the open
                    # AskUserQuestion (treating the queued text as the
                    # user's "answer") and continue the conversation —
                    # surfacing as "Claude continued silently past the
                    # question". The relay request file is the authoritative
                    # live signal; if a question is genuinely blocking, hold
                    # the queue until the user answers in the UI. Once the
                    # hook resolves it (deny-reply, no tool_result ever lands)
                    # the request file is gone and the queue drains — a plain
                    # transcript scan here would deadlock forever.
                    status = session_live_status(sid, find_session_cwd(sid))
                    if _ask_question_blocking_inject(sid, status):
                        continue
                    if status.get("live") and status.get("tty") and _session_status_is_busy(status):
                        continue
                    if status.get("live") and status.get("kind") == "bg":
                        if not _bg_agent_ready_for_input(sid, status):
                            continue
                        # Channel recently proven broken (pty inject wrote ok
                        # but nothing landed) — hold instead of churning the
                        # queue through it every tick.
                        if time.time() - _bg_pty_inject_failures.get(sid, 0) < 600:
                            continue
                    if status.get("live") and not status.get("tty"):
                        spawn = _find_live_spawn_entry_for_session(sid)
                        if spawn is not None and _spawn_entry_active_tool_child(spawn):
                            continue
                        # Foreign live writer (not ours, no channel): hold the
                        # queue until that process exits — injecting now would
                        # spawn a parallel resume and fork the transcript.
                        if spawn is None and status.get("kind") != "bg" and status.get("pid"):
                            continue
                    with _pending_terminal_input_lock:
                        queue = _pending_terminal_input_queue.get(sid, [])
                        if not queue:
                            removed = _pending_terminal_input_queue.pop(sid, None) is not None
                            text = None
                        else:
                            text = queue.pop(0)
                            removed = True
                            if not queue:
                                _pending_terminal_input_queue.pop(sid, None)
                    if removed:
                        _save_pending_inputs()
                    if text is None:
                        continue
                    # CCC-455: a popped entry is only consumed by a PROVEN
                    # delivery. Failure re-queues at the front (with backoff);
                    # a wt-send handoff is tracked by receipt until the
                    # transcript confirms it landed.
                    result = None
                    try:
                        result = _inject_text_into_session(
                            sid, text, _from_terminal_queue=True,
                            skip_wt=(sid in _terminal_drain_skip_wt),
                        )
                    except Exception:
                        result = None
                    _terminal_drain_skip_wt.discard(sid)
                    if not isinstance(result, dict):
                        result = {"ok": False}
                    if result.get("queued"):
                        # The inject re-parked it itself (foreign live writer,
                        # bg-undeliverable, invalid cwd) — entry is safe; back
                        # off so a held session isn't re-driven every 5s tick.
                        _mark_terminal_queue_retry(sid)
                    elif not result.get("ok"):
                        _requeue_terminal_input_front(sid, text)
                        _mark_terminal_queue_retry(sid)
                    elif result.get("via") == "wt-send" and result.get("receipt_id"):
                        _terminal_drain_receipts.append({
                            "sid": sid,
                            "text": text,
                            "receipt_id": result["receipt_id"],
                            "deadline": time.time() + _TERMINAL_DRAIN_RECEIPT_DEADLINE_S,
                            "last_check": 0.0,
                        })
                    else:
                        _pending_terminal_retry_after.pop(sid, None)
                except Exception:
                    pass
            try:
                _verify_terminal_drain_receipts()
            except Exception:
                pass
    def _watcher_entry():
        global _pending_inputs_watcher_lock_file
        try:
            _watcher()
        finally:
            lock_file.close()
            _pending_inputs_watcher_lock_file = None
            # Restart locally as well: a transient watcher exception must not
            # leave this process dependent on a separate CCC instance.
            _start_resume_queue_watcher()

    threading.Thread(target=_watcher_entry, daemon=True, name="resume-queue-watcher").start()


# ── UX-fixes queue fixer resolution ─────────────────────────────────────────
# The old CCC-100 "continue" nudge watcher was removed: WatchTower now owns
# queue draining end-to-end (it pushes new work to a live worker's stream-json
# FIFO and resumes blocked sessions itself), so CCC injecting "continue" into
# queue workers is redundant — and worse, its loose claimer-resolution could
# match and double-wake a WT-spawned worker. The fixer-resolution helpers below
# survive because /api/ux-fixes/health still reports per-project liveness/stuck.
_UXQ_NUDGE_LOOKBACK_S = 48 * 3600
_UXQ_SESSION_ID_RE = re.compile(
    r"^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$"
)
# A UUID embedded anywhere in a free-form label (e.g. ``codex:<uuid>`` or
# ``codex-<uuid>``) — lets us recover a reachable id from an engine-prefixed
# claim label even when ``claimed_session_id`` was not supplied.
_UXQ_EMBEDDED_SESSION_ID_RE = re.compile(
    r"[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}"
)


def _uxq_resolve_fixer_sid(item, *, registry_by_name=None):
    """Resolve a queue item's claimer to a reachable CCC session UUID, or "".

    Resolution order (cheapest first, all O(1) per item):
      1. ``claimed_session_id`` — the additive real-session field a worker can
         supply at claim time (preferred; exact).
      2. A UUID-shaped ``claimed_by`` (the historical happy path).
      3. A UUID embedded in an engine-prefixed ``claimed_by`` label.
      4. ``registry_by_name`` lookup — best-effort: if the label exactly matches
         a CCC-spawned session's launch ``name``, take that session's id. The
         caller passes a prebuilt name→sid map so this stays O(1) per item and
         the spawn registry is read at most once per health/nudge pass (no
         per-row file read, no subprocess).

    Returns "" when the claimer is a genuinely unreachable label (e.g. a ref
    like ``CCC-59`` or a free-form name with no spawn-registry match)."""
    claimed_sid = str((item or {}).get("claimed_session_id") or "").strip()
    if _UXQ_SESSION_ID_RE.match(claimed_sid):
        return claimed_sid
    label = str((item or {}).get("claimed_by") or (item or {}).get("closed_by") or "").strip()
    if not label:
        return ""
    if _UXQ_SESSION_ID_RE.match(label):
        return label
    m = _UXQ_EMBEDDED_SESSION_ID_RE.search(label)
    if m:
        return m.group(0)
    if registry_by_name:
        hit = registry_by_name.get(label)
        if hit and _UXQ_SESSION_ID_RE.match(hit):
            return hit
    return ""


def _uxq_spawn_names_to_sids():
    """name → session_id map from the spawn registry (read once per pass).

    Cheap: one file read via _load_spawn_registry(), no subprocess, no
    transcript parse. Used only to resolve label-claimed fixers for projects
    that already have open tickets (the candidacy gate is applied by callers)."""
    out = {}
    try:
        for entry in _load_spawn_registry():
            name = str(entry.get("name") or "").strip()
            sid = str(entry.get("session_id") or "").strip()
            if name and sid and _UXQ_SESSION_ID_RE.match(sid):
                out.setdefault(name, sid)
    except Exception:
        return {}
    return out


def _uxq_parse_ts(value):
    try:
        return datetime.fromisoformat(str(value or "").replace("Z", "+00:00")).timestamp()
    except (ValueError, TypeError):
        return 0


# ---------------------------------------------------------------------------
# Queue / ticket-appearance events for replay (W22 / B4)
#
# CCC replays group chats on a message-ordered timeline; this derives queue
# events (a ticket appearing, being claimed, being resolved) from the SAME
# durable ticket store the health strip reads — no parallel event store. The
# item's created_at/claimed_at/closed_at timestamps ARE the event log; we fold
# them in time order so each event carries the queue's depth right after it, and
# the replay UI interleaves them without rescanning tickets per frame.
#
# See docs/superpowers/specs/2026-07-16-queue-replay-design.md.
# ---------------------------------------------------------------------------
_QUEUE_REPLAY_MAX_EVENTS = 300           # newest-wins cap on returned events
_QUEUE_REPLAY_MAX_LOOKBACK_S = 14 * 24 * 3600  # ignore events older than this
_queue_replay_cache = {}  # (mtime_ns, size) -> {"events": [...], "truncated": bool}
_queue_replay_cache_lock = threading.Lock()


def _queue_store_path_for_cache():
    """Resolve the durable queue-store file so we can cache by (mtime, size).

    The active engine (`_q`) owns disk layout: WatchTower exposes
    `_resolve_store_path()`; the stdlib fallback uses `ux_fixes_queue.QUEUE_FILE`
    (the same file). Returns a Path or None."""
    resolve = getattr(_q, "_resolve_store_path", None)
    if callable(resolve):
        try:
            return Path(resolve())
        except Exception:
            pass
    try:
        return Path(ux_fixes_queue.QUEUE_FILE)
    except Exception:
        return None


def _queue_replay_events_uncached():
    """Derive + fold queue events from one _q.list_items() read.

    Depth semantics ("queue filling/draining over time"): a queue's depth is its
    set of ACTIVE tickets — created but not yet resolved. So `created` bumps
    depth +1, `resolved` drops it -1, and `claimed` annotates state without
    moving depth (the ticket is still in the queue, now being worked). Folding
    runs over the FULL history so `depth_after` stays absolute even after the
    lookback trim below drops old events from what we render."""
    try:
        items = _q.list_items()
    except Exception:
        items = []
    raw = []  # (ts, kind, base)
    for it in items:
        if not isinstance(it, dict):
            continue
        base = {
            "ref": str(it.get("ref") or "").strip(),
            "queue": (str(it.get("queue") or "").strip()
                      or str(it.get("project") or "").strip() or "?"),
            "project": str(it.get("project") or ""),
            "note": str(it.get("note") or "")[:200],
            "claimed_by": str(it.get("claimed_by") or ""),
        }
        created = _uxq_parse_ts(it.get("created_at"))
        claimed = _uxq_parse_ts(it.get("claimed_at"))
        closed = _uxq_parse_ts(it.get("closed_at"))
        if created:
            raw.append((created, "created", base))
        if claimed:
            raw.append((claimed, "claimed", base))
        if closed:
            raw.append((closed, "resolved", base))
    # Stable time order; created-before-resolved on identical stamps.
    _kind_rank = {"created": 0, "claimed": 1, "resolved": 2}
    raw.sort(key=lambda r: (r[0], _kind_rank.get(r[1], 1)))
    depth_by_queue = {}
    events = []
    for ts, kind, base in raw:
        q = base["queue"]
        depth = depth_by_queue.get(q, 0)
        if kind == "created":
            depth += 1
        elif kind == "resolved":
            depth = max(0, depth - 1)
        depth_by_queue[q] = depth
        ev = dict(base)
        ev["kind"] = kind
        ev["ts"] = ts
        ev["iso"] = datetime.fromtimestamp(
            ts, timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        ev["depth_after"] = depth
        events.append(ev)
    cutoff = time.time() - _QUEUE_REPLAY_MAX_LOOKBACK_S
    events = [e for e in events if e["ts"] >= cutoff]
    truncated = False
    if len(events) > _QUEUE_REPLAY_MAX_EVENTS:
        events = events[-_QUEUE_REPLAY_MAX_EVENTS:]
        truncated = True
    return {"events": events, "truncated": truncated}


def _queue_replay_events():
    """Queue events for replay, memoised by the store file's (mtime, size).

    An unchanged store returns the cached, pre-folded list with zero JSON parse
    — the replay timeline is built once per group-chat read (already coalesced),
    never per frame (CLAUDE.md § Performance gates)."""
    store = _queue_store_path_for_cache()
    key = None
    if store is not None:
        try:
            st = store.stat()
            key = (st.st_mtime_ns, st.st_size)
        except OSError:
            key = None
    if key is not None:
        cached = _queue_replay_cache.get(key)
        if cached is not None:
            return cached
    result = _queue_replay_events_uncached()
    if key is not None:
        with _queue_replay_cache_lock:
            _queue_replay_cache.clear()  # only the current store snapshot matters
            _queue_replay_cache[key] = result
    return result



# Minutes a fixer can make no closing progress before its project's queue is
# judged STUCK (used by compute_ux_fixes_health). Mirrors the nudge watcher's
# "no progress" intuition; kept generous so a slow-but-working fix isn't flagged.
_UXQ_STUCK_NO_PROGRESS_S = 10 * 60


def compute_ux_fixes_health():
    """Per-project queue-health snapshot used by /api/ux-fixes/health.

    Returns a list of dicts, one per project that has open tickets:

        {project, depth, oldest_open_age_seconds, fixer_session_id,
         fixer_live, fixer_idle_or_stale, stuck}

    `stuck` = depth > 0 AND (no resolvable live fixer OR the fixer has closed
    nothing for _UXQ_STUCK_NO_PROGRESS_S). A stuck project with no resolvable
    fixer is reported (a human / the UI handles spawning) but never auto-spawned.

    PERFORMANCE (CLAUDE.md "Performance gates"): this does ZERO O(all
    sessions/transcripts) work. The queue is one JSON file read once via the
    backend-agnostic list_items() API. Liveness is resolved ONLY for the single
    candidate fixer of a project that already has open tickets, through the
    cheap sidecar/live-id primitive `_archive_session_is_live` (a stat() plus
    the in-memory live-id set) — no per-row transcript parse and no subprocess
    fork per project/row.
    """
    try:
        items = _q.list_items()
    except Exception:
        items = []
    now = time.time()
    # Pre-scan: which projects have open tickets. The fixer-resolution and
    # liveness probe are candidacy-gated to these, so the spawn registry (read
    # below to resolve label-claimed fixers) is touched at most once per pass —
    # and only when there is open work to reach. No per-row file/subprocess.
    open_projects = {
        str(it.get("project") or "?") for it in items if it.get("status") == "open"
    }
    registry_by_name = _uxq_spawn_names_to_sids() if open_projects else {}
    # First pass: group by project. depth + oldest open age, and the most
    # recently active fixer (claimer) plus its highest closed seq (progress).
    by_project = {}  # project → bucket
    for it in items:
        proj = str(it.get("project") or "?")
        b = by_project.setdefault(proj, {
            "depth": 0,
            "oldest_open_ts": None,
            "fixer_session_id": None,
            "fixer_last_ts": 0.0,
            "fixer_progress_ts": 0.0,
            "last_activity_ts": 0.0,
        })
        status = it.get("status")
        if status == "open":
            b["depth"] += 1
            created = _uxq_parse_ts(it.get("created_at"))
            if created and (b["oldest_open_ts"] is None or created < b["oldest_open_ts"]):
                b["oldest_open_ts"] = created
        # Most recent touch across ANY ticket in the project (open or closed) —
        # drives the health-strip's reverse-chronological order (CCC-458), same
        # "newest activity first" convention as Current Sessions (CCC-421).
        touch_ts = max(
            _uxq_parse_ts(it.get("updated_at")),
            _uxq_parse_ts(it.get("closed_at")),
            _uxq_parse_ts(it.get("created_at")),
        )
        if touch_ts and touch_ts > b["last_activity_ts"]:
            b["last_activity_ts"] = touch_ts
        # Only resolve a fixer for projects that have open tickets (candidacy
        # gate). Prefer the additive real-session field, then a UUID label, then
        # a registry name match — see _uxq_resolve_fixer_sid.
        if proj not in open_projects:
            continue
        sid = _uxq_resolve_fixer_sid(it, registry_by_name=registry_by_name)
        if not sid:
            continue
        ts = _uxq_parse_ts(it.get("updated_at") or it.get("claimed_at"))
        if not ts or (now - ts) > _UXQ_NUDGE_LOOKBACK_S:
            continue
        # The fixer is the claimer whose activity is most recent.
        if ts > b["fixer_last_ts"]:
            b["fixer_last_ts"] = ts
            b["fixer_session_id"] = sid
        if status == "closed":
            closed_ts = _uxq_parse_ts(it.get("closed_at") or it.get("updated_at"))
            if closed_ts > b["fixer_progress_ts"]:
                b["fixer_progress_ts"] = closed_ts
    # Second pass: only projects WITH open tickets are candidates for the (cheap)
    # liveness probe — that is the candidacy gate. One probe per such project.
    out = []
    for proj, b in by_project.items():
        if b["depth"] <= 0:
            continue
        fixer = b["fixer_session_id"]
        fixer_live = bool(fixer) and _archive_session_is_live(fixer)
        # "Made no closing progress for N minutes" — also treat a fixer we never
        # saw close anything (progress_ts == 0) as stale once it has a claim.
        last_progress = b["fixer_progress_ts"] or b["fixer_last_ts"]
        idle_or_stale = (not last_progress) or ((now - last_progress) > _UXQ_STUCK_NO_PROGRESS_S)
        stuck = (not fixer_live) or idle_or_stale
        oldest_ts = b["oldest_open_ts"]
        last_activity_ts = b["last_activity_ts"]
        out.append({
            "project": proj,
            "depth": b["depth"],
            "oldest_open_age_seconds": int(now - oldest_ts) if oldest_ts else None,
            "last_activity_seconds": int(now - last_activity_ts) if last_activity_ts else None,
            "fixer_session_id": fixer,
            "fixer_live": fixer_live,
            "fixer_idle_or_stale": idle_or_stale,
            "stuck": stuck,
        })
    # Reverse-chronological (CCC-458): most-recently-touched queue first. A
    # queue with no resolvable activity timestamp sorts last, not first.
    out.sort(key=lambda r: (
        r["last_activity_seconds"] if r["last_activity_seconds"] is not None else float("inf"),
        r["project"],
    ))
    return out


def compute_queues_health(health=None, wt_workers=None):
    """Per-QUEUE snapshot for the dashboard's "Evergreen" sidebar section.

    WatchTower workers are ephemeral (spawned/reaped on a short TTL, so they
    flicker), but queues are durable — the right thing to watch over time. This
    folds three durable/semi-durable sources into one row per queue:

      - the configured-queue list (``watchtower.config.all_queues()``) so a
        queue with zero open work and zero live workers still shows;
      - per-project open depth + stuck flag from ``compute_ux_fixes_health()``;
      - live worker counts from the annotated ``wt_workers`` rows.

    Each row: ``{queue, depth, closed, total, oldest_open_age_seconds, workers,
    auto_drain, stuck, state, fixer_session_id}`` where ``state`` is one of
    ``stuck`` / ``draining`` / ``backlog``. ``depth`` is the open count;
    ``closed`` / ``total`` give a done/total progress count for the queue.

    PERFORMANCE: no O(all sessions/transcripts) work. It consumes the already
    computed ``health`` and ``wt_workers`` and reads the small queue-config file
    once (``all_queues()``). No subprocess, no per-row transcript parse.
    """
    if health is None:
        health = compute_ux_fixes_health()
    if wt_workers is None:
        wt_workers = []

    def _norm(s):
        return str(s or "").strip().upper()

    # Live worker counts per queue (one pass over the annotated worker rows).
    worker_counts = {}
    for w in (wt_workers or []):
        q = _norm(w.get("queue"))
        if not q:
            continue
        worker_counts[q] = worker_counts.get(q, 0) + 1

    # Durable configured-queue list keyed by normalized name → auto_drain + repo_path.
    # Read the config file directly (no watchtower import dependency).
    cfg_drain = {}
    cfg_repo = {}
    cfg_claim = {}
    cfg_names = set()
    try:
        for name, conf in (_wt_read_config() or {}).items():
            qn = _norm(name)
            cfg_names.add(qn)
            cfg_drain[qn] = bool((conf or {}).get("auto_drain", False))
            rp = str((conf or {}).get("repo_path") or "").strip()
            if rp:
                cfg_repo[qn] = rp
            ct = (conf or {}).get("claim_types", [])
            cfg_claim[qn] = [t for t in ct if t in ("bug", "feature")] if isinstance(ct, list) else []
    except Exception:
        cfg_drain = {}
        cfg_repo = {}
        cfg_claim = {}
        cfg_names = set()

    health_by_q = {_norm(r.get("project")): r for r in (health or [])}

    # Closed + total counts per queue from ONE list_items() pass (one JSON file
    # read, no per-row subprocess/transcript parse — see PERFORMANCE note above).
    # `open` stays = depth (from health); these add a done/total progress count.
    closed_by_q = {}
    total_by_q = {}
    claimable_by_q = {}  # queue → open items a worker is ALLOWED to claim (claim_types)
    last_activity_q = {}  # queue → most-recent item-touch epoch (any status)
    try:
        for it in (_q.list_items() or []):
            qn = _norm(it.get("project"))
            if not qn or qn == "?":
                continue
            total_by_q[qn] = total_by_q.get(qn, 0) + 1
            if it.get("status") == "closed":
                closed_by_q[qn] = closed_by_q.get(qn, 0) + 1
            # Claimable depth honors the queue's claim_types filter. A bug-only
            # queue (claim_types=['bug']) whose open tickets are all features has
            # zero claimable work — the drainer is idle BY DESIGN, not stuck.
            # GitHub-backed WatchTower queues expose every open repo issue for
            # inventory, but only issues with the queue label carry
            # claimable=True; un-runnable issues must not trigger drain state.
            if it.get("status") == "open":
                if it.get("claimable") is False:
                    continue
                types = cfg_claim.get(qn, [])
                # Untyped == bug (matches WatchTower's claim filter): a ticket
                # filed without a type must not silently vanish from a bugs-only
                # queue, so it counts as claimable there.
                ty = str(it.get("type") or it.get("item_type") or "").strip().lower()
                if ty not in ("bug", "feature"):
                    ty = "bug"
                if not types or ty in types:
                    claimable_by_q[qn] = claimable_by_q.get(qn, 0) + 1
            # Most recent touch = newest of updated/closed/created — drives the
            # "active in last N days" filter so a drained-but-recent queue still
            # shows while a long-dead queue drops off.
            ts = max(
                _uxq_parse_ts(it.get("updated_at")),
                _uxq_parse_ts(it.get("closed_at")),
                _uxq_parse_ts(it.get("created_at")),
            )
            if ts and ts > last_activity_q.get(qn, 0):
                last_activity_q[qn] = ts
    except Exception:
        closed_by_q = {}
        total_by_q = {}
        last_activity_q = {}

    names = set()
    names.update(cfg_drain.keys())
    names.update(health_by_q.keys())
    names.update(worker_counts.keys())
    names.update(total_by_q.keys())
    names.discard("")
    names.discard("?")

    # Drop explicitly-deleted queues (CCC-425 reopen) unless they've had NEW
    # activity since the deletion — a re-filed ticket legitimately resurrects
    # the queue, but stale closed-ticket history from before the delete must
    # not keep it pinned in the health strip forever.
    try:
        deletions = _wt_read_queue_deletions()
    except Exception:
        deletions = {}
    for qn, deleted_at in deletions.items():
        qn = _norm(qn)
        if qn in cfg_names:
            continue  # re-added to config since deletion — always show
        if last_activity_q.get(qn, 0) <= float(deleted_at or 0):
            names.discard(qn)

    out = []
    for q in names:
        hr = health_by_q.get(q) or {}
        depth = int(hr.get("depth") or 0)
        claimable = int(claimable_by_q.get(q, 0))
        workers = int(worker_counts.get(q, 0))
        auto = bool(cfg_drain.get(q, False))
        # A queue with a live WatchTower worker is NOT stuck — the worker is
        # draining it. The legacy fixer-based `stuck` (compute_ux_fixes_health)
        # only sees stuck because WT workers claim with a non-UUID worker_id and
        # never write their cloud session_id onto the ticket, so it can't resolve
        # a "live fixer". A hung worker is a worker-health concern surfaced on the
        # worker row, not a queue-level stuck. Trust WT ground-truth: workers > 0.
        #
        # `claimable` (not raw `depth`) gates stuck: a bug-only queue whose open
        # tickets are all features has open depth but ZERO claimable work, so the
        # drainer sitting idle is correct, not stuck. Those parked items show as
        # `backlog` (calm), never `stuck` (alarm).
        # Only an auto-drain queue can be "stuck": one with auto_drain OFF is a
        # deliberate parking lot (backlog), not a fire. `claimable` (not raw
        # `depth`) gates it so a bug-only queue full of features reads backlog.
        stuck = bool(hr.get("stuck")) and auto and claimable > 0 and workers == 0
        if stuck:
            state = "stuck"
        elif depth > 0 and claimable == 0:
            state = "backlog"   # open items exist but all filtered out by claim_types
        elif auto:
            state = "draining"
        else:
            state = "backlog"
        out.append({
            "queue": q,
            "depth": depth,
            "claimable": claimable,
            "closed": int(closed_by_q.get(q, 0)),
            "total": int(total_by_q.get(q, 0)),
            "oldest_open_age_seconds": hr.get("oldest_open_age_seconds"),
            "workers": workers,
            "auto_drain": auto,
            "stuck": stuck,
            "state": state,
            "fixer_session_id": hr.get("fixer_session_id"),
            "repo_path": cfg_repo.get(q, ""),
            "claim_types": cfg_claim.get(q, []),
            "configured": q in cfg_names,
            "last_activity_seconds": (
                int(time.time() - last_activity_q[q]) if q in last_activity_q else None
            ),
        })
    # Stuck first, then deepest, then most workers, then name — most-urgent top.
    out.sort(key=lambda r: (0 if r["stuck"] else 1, -r["depth"], -r["workers"], r["queue"]))
    return out


_UX_FIXES_HEALTH_TTL = 5.0
_ux_fixes_health_snapshot = {"ts": 0.0, "data": None}
_ux_fixes_health_snapshot_lock = threading.Lock()


def _build_ux_fixes_health_payload_uncached():
    health = compute_ux_fixes_health()
    # Live WT workers, read straight from workers.json (no watchtower import
    # dependency). Carries each worker's cloud session UUID so the dashboard can
    # link a worker row to its conversation.
    try:
        wt_workers = _wt_read_workers()
    except Exception:
        wt_workers = []
    # Per-queue rollup (durable) for the dashboard's Evergreen section.
    try:
        queues = compute_queues_health(health, wt_workers)
    except Exception:
        queues = []
    # Persistent ledger of every cloud session_id that was ever a WT worker
    # (survives pruning).
    try:
        worker_session_ids = _wt_read_worker_session_ids()
    except Exception:
        worker_session_ids = []
    # Past workers from the last 24h (log files, excluding live).
    try:
        past_workers = _wt_past_workers(hours=24)
    except Exception:
        past_workers = []
    return {
        "ok": True,
        "projects": health,
        "count": len(health),
        "wt_workers": wt_workers,
        "queues": queues,
        "worker_session_ids": worker_session_ids,
        "past_workers": past_workers,
    }


def build_ux_fixes_health_payload(force=False):
    """Coalesced payload for /api/ux-fixes/health.

    The dashboard, detail rail, and foreground refocus paths can all ask for
    queue health at once. The uncached build touches WatchTower queue state and
    recent worker logs, so concurrent polls must share one fresh snapshot
    instead of each request rebuilding it in its own HTTP thread.
    """
    snap = _ux_fixes_health_snapshot
    now = time.time()
    if not force and snap["data"] is not None and now - snap["ts"] < _UX_FIXES_HEALTH_TTL:
        return copy.deepcopy(snap["data"])
    with _ux_fixes_health_snapshot_lock:
        now = time.time()
        if not force and snap["data"] is not None and now - snap["ts"] < _UX_FIXES_HEALTH_TTL:
            return copy.deepcopy(snap["data"])
        data = _build_ux_fixes_health_payload_uncached()
        snap["data"] = data
        snap["ts"] = time.time()
        return copy.deepcopy(data)


def _queue_codex_resume(session_id, text, pid=None, reason=None, *, only_if_pending=False):
    with _pending_resume_lock:
        if only_if_pending and not _pending_resume_queue.get(session_id):
            return None
        _pending_resume_queue.setdefault(session_id, []).append(text)
    _save_pending_inputs()
    _schedule_codex_queue_pump(session_id)
    payload = {
        "ok": True,
        "queued": True,
        "via": "codex-resume-queued",
    }
    if reason:
        # Carry the real reason (e.g. "Codex thread is active") so the client can
        # show "Queued: <reason>" inline instead of a bare "Queued".
        payload["queued_reason"] = reason
        payload["error"] = reason
    if pid is not None:
        payload["pid"] = pid
    return payload


# ── Live Codex wake/turn status (feeds GET /api/codex-wake-status) ──────────
# The conversation pane polls this while "Codex resuming…" is up so the user
# sees the wake broken down moment to moment (stages, live tokens, context %)
# and, critically, learns when a turn produced nothing because the session hit
# its context limit. Everything here is single-session and cheap: the stage
# timeline comes from the in-memory `_CODEX_WAKE_EVENTS` window (NO file scan)
# and the token/context readout comes from a ~16KB TAIL of one rollout file,
# cached by (path, mtime, size) so repeated polls of an unchanged file re-read
# nothing (perf gate).
_CODEX_WAKE_TAIL_CACHE = collections.OrderedDict()
_CODEX_WAKE_TAIL_LOCK = threading.Lock()
_CODEX_WAKE_TAIL_BYTES = 16 * 1024
_CODEX_WAKE_TAIL_MAX = 16


def _codex_wake_rollout_snapshot(session_id):
    """Latest model/effort + token/context numbers for a Codex session, read
    from the TAIL of its rollout jsonl. Cached by (path, mtime, size). Missing
    or unreadable rollout -> an all-None snapshot. Never raises."""
    empty = {
        "model": None, "effort": None,
        "context_used": None, "context_window": None, "context_pct": None,
        "input_tokens": None, "output_tokens": None,
        "task_complete_epoch": 0.0, "no_agent_output": None,
    }
    try:
        path = _resolve_codex_rollout_path(session_id)
    except Exception:
        path = None
    if not path:
        return dict(empty)
    try:
        st = path.stat()
    except OSError:
        return dict(empty)
    key = (str(path), st.st_mtime_ns, st.st_size)
    with _CODEX_WAKE_TAIL_LOCK:
        hit = _CODEX_WAKE_TAIL_CACHE.get(str(path))
        if hit and hit[0] == key:
            _CODEX_WAKE_TAIL_CACHE.move_to_end(str(path))
            return dict(hit[1])
    snap = dict(empty)
    try:
        with open(path, "rb") as f:
            if st.st_size > _CODEX_WAKE_TAIL_BYTES:
                f.seek(-_CODEX_WAKE_TAIL_BYTES, os.SEEK_END)
                f.readline()  # drop the partial first line after the seek
            chunk = f.read()
        for raw in chunk.split(b"\n"):
            if not raw.strip():
                continue
            try:
                ev = json.loads(raw.decode("utf-8", "replace"))
            except (json.JSONDecodeError, ValueError):
                continue
            if not isinstance(ev, dict):
                continue
            payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
            ev_type = ev.get("type")
            ptype = payload.get("type")
            if ev_type == "turn_context":
                model = payload.get("model")
                if model:
                    snap["model"] = model
                settings = ((payload.get("collaboration_mode") or {}).get("settings") or {})
                eff = (
                    payload.get("effort")
                    or payload.get("reasoning_effort")
                    or (settings.get("reasoning_effort") if isinstance(settings, dict) else None)
                )
                if eff:
                    snap["effort"] = eff
                continue
            if ptype == "token_count":
                info = payload.get("info") if isinstance(payload.get("info"), dict) else {}
                window = _codex_int(info.get("model_context_window"))
                last = info.get("last_token_usage") if isinstance(info.get("last_token_usage"), dict) else {}
                inp = _codex_int(last.get("input_tokens"))
                out = _codex_int(last.get("output_tokens"))
                # Live context occupancy is the size of the LAST prompt sent
                # (last_token_usage.input_tokens), NOT the cumulative
                # total_token_usage.total_tokens (which sums every turn and
                # overflows the window). As the conversation fills, input_tokens
                # climbs toward model_context_window; at the cap it reads 100%.
                if window:
                    snap["context_window"] = window
                if inp:
                    snap["context_used"] = inp
                snap["input_tokens"] = inp
                snap["output_tokens"] = out
                continue
            if ptype == "task_complete":
                snap["task_complete_epoch"] = _codex_event_epoch(ev) or snap["task_complete_epoch"]
                text = (payload.get("last_agent_message") or payload.get("message") or "").strip()
                snap["no_agent_output"] = not bool(text)
                continue
    except OSError:
        return dict(empty)
    cu, cw = snap.get("context_used"), snap.get("context_window")
    if cu is not None and cw:
        snap["context_pct"] = round(100.0 * cu / cw, 1)
    with _CODEX_WAKE_TAIL_LOCK:
        _CODEX_WAKE_TAIL_CACHE[str(path)] = (key, dict(snap))
        _CODEX_WAKE_TAIL_CACHE.move_to_end(str(path))
        while len(_CODEX_WAKE_TAIL_CACHE) > _CODEX_WAKE_TAIL_MAX:
            _CODEX_WAKE_TAIL_CACHE.popitem(last=False)
    return snap


def build_codex_wake_status(session_id):
    """Assemble the live wake/turn breakdown for one Codex session. Reads the
    in-memory per-sid wake-event window plus a single rollout tail — no
    all-sessions scan, no subprocess. Never raises (returns a safe shell)."""
    try:
        with _RESUME_LEDGER_LOCK:
            dq = _CODEX_WAKE_EVENTS.get(session_id)
            events = list(dq) if dq else []
    except Exception:
        events = []
    now = time.time()

    def _last(evname, **match):
        for e in reversed(events):
            if e.get("event") != evname:
                continue
            if all(e.get(k) == v for k, v in match.items()):
                return e
        return None

    attempt = _last("codex_wake_attempt")
    connect = _last("codex_wake_stage", stage="connect")
    turnstart = _last("codex_wake_stage", stage="turn-start")
    ok = _last("codex_wake_ok")
    warn = _last("codex_wake_warn")
    exec_ev = _last("codex_wake_exec")
    fail = _last("codex_wake_fail")
    queued = _last("codex_wake_queued")

    attempt_epoch = float((attempt or {}).get("epoch") or 0.0)

    snap = _codex_wake_rollout_snapshot(session_id)
    app_state = _codex_app_server_thread_state(session_id)
    app_transport = _codex_app_server_transport_kind()
    ctx_used = snap.get("context_used")
    ctx_win = snap.get("context_window")
    ctx_pct = snap.get("context_pct")

    running_reached = bool(ok or exec_ev)
    tc_epoch = float(snap.get("task_complete_epoch") or 0.0)
    turn_ended = bool(running_reached and tc_epoch and tc_epoch >= (attempt_epoch - 1.0))

    # A hard failure that will not yield a turn: exec-stage failure, or a
    # queue fallback (message parked for later). A fail whose fallback is
    # "exec" is a retry, not terminal, so it is ignored here.
    hard_error = None
    if fail and float(fail.get("epoch") or 0.0) >= attempt_epoch:
        if fail.get("stage") == "exec" or fail.get("fallback") == "queue":
            hard_error = fail.get("error")
    if not hard_error and queued and float(queued.get("epoch") or 0.0) >= attempt_epoch and not turn_ended:
        hard_error = queued.get("reason") or queued.get("error")

    outcome = None
    outcome_detail = None
    if turn_ended:
        inp = snap.get("input_tokens") or 0
        out = snap.get("output_tokens") or 0
        empty = bool(snap.get("no_agent_output")) or (inp + out == 0)
        if not empty:
            outcome = "reply"
        elif ctx_pct is not None and ctx_pct >= 99:
            outcome = "empty_context_full"
            if ctx_used is not None and ctx_win:
                outcome_detail = f"context {ctx_used}/{ctx_win} ({ctx_pct}%), compact to continue"
            else:
                outcome_detail = "context full, compact to continue"
        else:
            outcome = "empty_other"
            outcome_detail = "turn ended with no output"
    elif hard_error:
        outcome = "error"
        outcome_detail = hard_error
    elif warn and float(warn.get("epoch") or 0.0) >= attempt_epoch:
        outcome = "warning"
        outcome_detail = warn.get("warning")

    active = bool(attempt) and outcome is None

    # Stage timeline. Emit a stage only once it has STARTED; the current stage
    # is the emitted one with done=false (frontend renders a spinner there).
    resume_returned = bool(turnstart or ok or exec_ev or queued or hard_error)
    threadresume_done = bool(turnstart or ok or exec_ev or hard_error)
    turnstart_started = bool(turnstart or ok or exec_ev)
    turnstart_done = bool(ok or exec_ev)
    running_done = outcome is not None

    stages = []
    if attempt or connect:
        stages.append({
            "name": "connect",
            "ts": float((connect or attempt or {}).get("epoch") or 0.0) or None,
            "done": bool(resume_returned),
        })
        stages.append({
            "name": "thread-resume",
            "ts": float((turnstart or connect or attempt or {}).get("epoch") or 0.0) or None,
            "done": bool(threadresume_done),
        })
    if turnstart_started:
        stages.append({
            "name": "turn-start",
            "ts": float((turnstart or ok or exec_ev or {}).get("epoch") or 0.0) or None,
            "done": bool(turnstart_done),
        })
    if running_reached:
        stages.append({
            "name": "running",
            "ts": float((ok or exec_ev or {}).get("epoch") or 0.0) or None,
            "done": bool(running_done),
        })

    # turn_context may sit beyond the tail window on a long session; fall back
    # to the model/effort recorded on the wake attempt row so the readout is
    # never blank during an active wake.
    model = snap.get("model") or (attempt or {}).get("model")
    effort = snap.get("effort") or (attempt or {}).get("effort")

    return {
        "sid": session_id,
        "active": active,
        "stages": stages,
        "model": model,
        "effort": effort,
        "context_used": ctx_used,
        "context_window": ctx_win,
        "context_pct": ctx_pct,
        "input_tokens": snap.get("input_tokens"),
        "output_tokens": snap.get("output_tokens"),
        "app_server_state": app_state,
        "app_server_transport": app_transport,
        "managed_app_server": app_transport == "managed",
        "warning": warn.get("warning") if warn and float(warn.get("epoch") or 0.0) >= attempt_epoch else None,
        "elapsed_s": round(now - attempt_epoch, 1) if attempt_epoch else None,
        "outcome": outcome,
        "outcome_detail": outcome_detail,
    }


def resume_session_codex(session_id, text, *, steer=False, _from_queue=False):
    """Resume a dormant Codex thread with a new prompt via `codex exec resume`."""
    text = _strip_ccc_session_state_instruction(text)
    if not text:
        return {"ok": False, "error": "missing text"}
    if not steer and not _from_queue:
        queued_behind_earlier = _queue_codex_resume(
            session_id,
            text,
            reason="Waiting behind an earlier queued Codex message",
            only_if_pending=True,
        )
        if queued_behind_earlier is not None:
            return queued_behind_earlier
    image_paths = _extract_pasted_image_paths(text)
    resolved = _resolve_codex_bin()
    if not resolved["available"]:
        return {"ok": False, "error": resolved["reason"], "code": resolved.get("code")}
    active_resume_entry = None
    for s in _spawned_sessions:
        if s.get("engine") == "codex" and s.get("resumed_sid") == session_id:
            try:
                if _poll_spawn_entry(s) is None:
                    active_resume_entry = s
                    break
            except Exception:
                pass
    row = _codex_thread_row(session_id) or {}
    spawned_ctx = _spawn_registry_entry_for_session(session_id, "codex") or {}
    cwd = (
        row.get("cwd")
        or spawned_ctx.get("cwd")
        or (active_resume_entry or {}).get("cwd")
        or find_session_cwd(session_id)
    )
    cwd_error = None
    if not cwd or not Path(cwd).is_dir():
        try:
            cwd = repo_from_session(session_id)["cwd"]
        except RepoContextError as e:
            cwd_error = e
            cwd = None
    # Per-session override (set via the click-to-switch picker) wins over
    # the env-var default and the previous run's recorded model.
    override = _get_session_override(session_id)
    override_model = (override or {}).get("model") if override else None
    reasoning_effort = (override or {}).get("reasoning_effort") or ""
    model = override_model or os.environ.get("CCC_CODEX_MODEL") or row.get("model") or _spawn_fallback_model_for_engine("codex")
    if override_model:
        model, model_error = _validate_codex_model(model, require_available=True)
        if model_error:
            return {
                "ok": False,
                "error": model_error,
                "code": "codex_model_unavailable",
                "known_codex_models": list(_ENGINE_KNOWN_MODELS["codex"]),
            }
    _resume_ledger_append(
        "codex_wake_attempt", sid=session_id,
        cwd=cwd, model=model, effort=reasoning_effort, steer=bool(steer),
    )
    if steer:
        return _codex_steer_via_app_server(
            session_id,
            text,
            cwd=cwd,
            model=model,
            image_paths=image_paths,
        )
    app_result = _codex_resume_or_steer_via_app_server(
        session_id,
        text,
        cwd=cwd,
        model=model,
        image_paths=image_paths,
        allow_start=active_resume_entry is None,
        reasoning_effort=reasoning_effort,
    )
    if app_result.get("ok"):
        if (
            app_result.get("accepted")
            and app_result.get("confirmed") is not True
            and not _from_queue
        ):
            reason = (
                app_result.get("warning")
                or "Codex accepted the turn but the input is not visible yet"
            )
            queued = _queue_codex_resume(session_id, text, reason=reason)
            # Close the notification-vs-enqueue race: if the authoritative
            # userMessage arrived just before the durable copy was added, its
            # state marker is still available and can reconcile the copy now.
            delivered = _codex_app_server_thread_state(session_id)
            if (
                str(delivered.get("last_delivered_user_text") or "").strip()
                == str(text or "").strip()
                and (
                    not app_result.get("turn_id")
                    or str(delivered.get("last_delivered_user_turn_id") or "")
                    == str(app_result.get("turn_id"))
                )
            ):
                _consume_matching_pending_input(session_id, text)
                confirmed = dict(app_result)
                confirmed["confirmed"] = True
                confirmed["confirmation_source"] = "app-server-notification"
                return confirmed
            accepted_via = app_result.get("via")
            queued.update({
                key: value
                for key, value in app_result.items()
                if key not in ("via", "queued", "queued_reason", "error")
            })
            if accepted_via:
                queued["accepted_via"] = accepted_via
            queued["queued"] = True
            queued["queued_reason"] = reason
            return queued
        return app_result
    if app_result.get("fallback") == "queue":
        if _from_queue:
            reason = app_result.get("error") or "Codex thread is still active"
            return {
                "ok": True,
                "queued": True,
                "via": "codex-resume-queued",
                "queued_reason": reason,
                "error": reason,
            }
        queued = _queue_codex_resume(
            session_id,
            text,
            pid=(active_resume_entry or {}).get("pid"),
            reason=app_result.get("error"),
        )
        if app_result.get("writer"):
            queued["writer"] = app_result["writer"]
        if app_result.get("desktop_attached"):
            queued["desktop_attached"] = True
        return queued
    if active_resume_entry is not None:
        if _from_queue:
            return {
                "ok": True,
                "queued": True,
                "via": "codex-resume-queued",
                "pid": active_resume_entry.get("pid"),
            }
        return _queue_codex_resume(session_id, text, pid=active_resume_entry.get("pid"))
    if cwd_error is not None:
        return cwd_error.as_payload()
    timestamp = time.strftime("%Y%m%dT%H%M%S")
    log_filename = f"resume-codex-{session_id[:8]}-{timestamp}.log"
    repo_for_logs = _git_toplevel_for_existing_dir(cwd) or cwd
    log_dir = repo_log_dir(repo_for_logs)
    log_dir.mkdir(parents=True, exist_ok=True)
    log_path = log_dir / log_filename
    cmd = [
        resolved["bin"], *_codex_context_window_args(), "exec", "resume",
        "--json",
        "--skip-git-repo-check",
        "--dangerously-bypass-approvals-and-sandbox",
        "--model", model,
    ]
    if reasoning_effort:
        cmd.extend(["-c", f"model_reasoning_effort={reasoning_effort}"])
    for image_path in image_paths:
        cmd.extend(["--image", image_path])
    cmd.extend([session_id, text])
    _resume_ledger_append(
        "codex_wake_exec", sid=session_id,
        stage="exec", log_path=str(log_path),
    )
    log_fh = open(log_path, "w")
    try:
        proc = subprocess.Popen(
            cmd,
            stdin=subprocess.DEVNULL,
            stdout=log_fh,
            stderr=subprocess.STDOUT,
            cwd=cwd,
            start_new_session=True,
        )
    except (FileNotFoundError, OSError) as e:
        log_fh.close()
        _resume_ledger_append(
            "codex_wake_fail", sid=session_id,
            stage="exec", error=str(e),
        )
        return {"ok": False, "error": str(e), "via": "codex-resume", "stage": "exec"}
    entry = {
        "pid": proc.pid,
        "name": f"resume-codex-{session_id[:8]}",
        "log": str(log_path),
        "prompt": text[:200],
        "started": timestamp,
        "proc": proc,
        "log_fh": log_fh,
        "resumed_sid": session_id,
        "fifo": None,
        "stdin_fd": None,
        "engine": "codex",
        "cwd": cwd,
        "repo_path": repo_for_logs,
        "model": model,
    }
    _spawned_sessions.append(entry)
    _record_spawn_to_registry(
        pid=proc.pid,
        name=entry["name"],
        log_path=log_path,
        cwd=cwd,
        spawned_at=timestamp,
        command_summary=text[:200],
        fifo=None,
        engine="codex",
        session_id=session_id,
        repo_path=repo_for_logs,
        model=model,
    )
    return {"ok": True, "pid": proc.pid, "log": str(log_path), "resumed": True, "via": "codex-resume"}


def _extract_codex_usage(session_id):
    empty = {
        "latest_input_tokens": 0,
        "peak_input_tokens": 0,
        "total_output_tokens": 0,
        "total_input_tokens": 0,
        "total_cache_creation_tokens": 0,
        "total_cache_read_tokens": 0,
        "model": "",
        "reasoning_effort": "",
        "context_limit": 0,
        "cost_usd": 0.0,
        "cost_breakdown_usd": {"input": 0.0, "cache_creation": 0.0,
                               "cache_read": 0.0, "output": 0.0},
    }
    path = _resolve_codex_rollout_path(session_id)
    row = _codex_thread_row(session_id) or {}
    if not path:
        return empty
    latest = {}
    totals = {}
    peak = 0
    context_limit = 0
    model = row.get("model") or ""
    reasoning_effort = row.get("reasoning_effort") or ""
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
                if ev.get("type") == "turn_context":
                    model = payload.get("model") or model
                    settings = ((payload.get("collaboration_mode") or {}).get("settings") or {})
                    effort = (
                        payload.get("effort")
                        or payload.get("reasoning_effort")
                        or (settings.get("reasoning_effort") if isinstance(settings, dict) else None)
                    )
                    reasoning_effort = effort or reasoning_effort
                if payload.get("type") != "token_count":
                    continue
                info = payload.get("info") or {}
                context_limit = _codex_int(info.get("model_context_window")) or context_limit
                usage = info.get("last_token_usage") or info.get("total_token_usage") or {}
                total_usage = info.get("total_token_usage") or usage
                if not isinstance(usage, dict):
                    continue
                if isinstance(total_usage, dict):
                    totals = total_usage
                latest = usage
                # Codex/OpenAI usage reports cached input as a subset of
                # input_tokens. Adding it again turns cumulative session usage
                # into impossible context-window numbers.
                window = _codex_int(usage.get("input_tokens"))
                peak = max(peak, window)
    except OSError:
        return empty
    if not latest:
        return {**empty, "override": _get_session_override(session_id)}
    latest_input = _codex_int(latest.get("input_tokens"))
    total_input = _codex_int(totals.get("input_tokens"))
    cache_read = _codex_int(totals.get("cached_input_tokens"))
    total_output = _codex_int(totals.get("output_tokens"))
    return {
        **empty,
        "latest_input_tokens": latest_input,
        "peak_input_tokens": peak,
        "total_output_tokens": total_output,
        "total_input_tokens": max(total_input - cache_read, 0),
        "total_cache_creation_tokens": 0,
        "total_cache_read_tokens": cache_read,
        "model": model,
        "reasoning_effort": reasoning_effort,
        "context_limit": context_limit,
        "cost_usd": 0.0,
        "override": _get_session_override(session_id),
    }


def _extract_codex_timeline(session_id):
    path = _resolve_codex_rollout_path(session_id)
    if not path:
        return {"events": [], "total_turns": 0}
    events = []
    pending_by_id = {}
    turn = 0
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
                ts = _codex_event_timestamp(ev)
                if ev.get("type") == "event_msg" and payload.get("type") == "agent_message":
                    turn += 1
                    continue
                if ev.get("type") != "response_item":
                    continue
                if payload.get("type") == "function_call":
                    name = payload.get("name") or ""
                    args = _codex_args(payload.get("arguments"))
                    cmd = _codex_tool_command(name, args)
                    if not cmd:
                        continue
                    kind = None
                    subject = ""
                    if _TIMELINE_PR_CREATE_RE.search(cmd):
                        kind = "pr"
                        m = _TIMELINE_PR_TITLE_RE.search(cmd)
                        if m:
                            subject = m.group(1)
                    elif _TIMELINE_PUSH_RE.search(cmd):
                        kind = "push"
                    elif _TIMELINE_COMMIT_RE.search(cmd):
                        kind = "commit"
                        m = _TIMELINE_COMMIT_MSG_RE.search(cmd)
                        if m:
                            subject = m.group(1)
                    if not kind:
                        continue
                    events.append({
                        "kind": kind,
                        "turn": max(turn, 1),
                        "ts": ts,
                        "subject": subject,
                        "success": None,
                    })
                    call_id = payload.get("call_id") or ""
                    if call_id:
                        pending_by_id[call_id] = len(events) - 1
                elif payload.get("type") == "function_call_output":
                    call_id = payload.get("call_id") or ""
                    if call_id not in pending_by_id:
                        continue
                    idx = pending_by_id.pop(call_id)
                    entry = events[idx]
                    entry["success"] = True
                    text = payload.get("output") or ""
                    if entry["kind"] == "commit":
                        m = _TIMELINE_COMMIT_RESULT_RE.search(text)
                        if m:
                            entry["sha"] = m.group(1)
                            if not entry.get("subject"):
                                entry["subject"] = m.group(2).strip()[:200]
                    elif entry["kind"] == "pr":
                        m = _TIMELINE_PR_NUMBER_FROM_URL_RE.search(text)
                        if m:
                            entry["pr_number"] = int(m.group(1))
    except OSError:
        return {"events": [], "total_turns": 0}
    return {"events": events, "total_turns": turn}


